gameforge.dragon_soul = {}
gameforge.dragon_soul._010_sayTitle = "\218lomek Dra\232\237ho kamene?! "
gameforge.dragon_soul._020_say = "V rukou m\225\154 \250lomek Dra\232\237ho kamene. Z\225\248\237, jako by[ENTER]byl pln\253 tajemstv\237 a c\237t\237\154, jak ti jeho s\237la[ENTER]pulzuje t\236lem. Jak\253 druh kamene to je? Zanes jej[ENTER]alchymistovi, ten by ti mohl pomoci. "
gameforge.dragon_soul._030_npcChat = "\218lomek Dra\232\237ho kamene?! "
gameforge.dragon_soul._040_say = "Toto je fragment Dra\232\237ho kamene - extr\233mn\236[ENTER]vz\225cn\233ho a cenn\233ho krystalu s velkou silou. \216\237k\225[ENTER]se, \158e tento k\225men je du\154\237 draka. Neuv\236\248iteln\236[ENTER]kr\225sn\253. C\237t\237\154 tu s\237lu, kter\225 tebou za\232ne proudit[ENTER]ihned, kdy\158 jej uchop\237\154 nos\237\154 jej? P\248ines mi[ENTER]celkem deset \250lomk\249 Dra\232\237ho kamene, pak z nich[ENTER]budu moci vyrobit kompletn\237 k\225men. "
gameforge.dragon_soul._050_npcChat = "P\248em\236na Dra\232\237ho kamene "
gameforge.dragon_soul._060_say = "Nebu\239 netrp\236liv\253. Na Dra\232\237 k\225men mohu p\248em\236nit[ENTER]pouze deset \250lomk\249. Pokra\232uj v hled\225n\237! "
gameforge.dragon_soul._070_say = "V\253te\232n\236! Na\154el jsi \250lomek Dra\232\237ho kamene. Ano, to[ENTER]by mohlo na transmutaci sta\232it. Chvilku po\232kej.[ENTER]...[ENTER]Hotovo! Poda\248ilo se n\225m vyrobit Cor Draconis -[ENTER]krystalick\233 dra\232\237 srdce, kter\233 obaluje a chr\225n\237[ENTER]Dra\232\237 k\225men. Abys z\237skal Dra\232\237 k\225men, mus\237\154 jej[ENTER]rozb\237t. Dra\232\237 k\225men se p\248esune p\248\237mo do invent\225\248e[ENTER]Alchymie dra\232\237ch kamen\249. V\236d\236l jsi, \158e m\249\158e\154[ENTER]Dra\232\237 kameny tak\233 zu\154lech\157ovat? "
gameforge.dragon_soul._080_say = "Chce\154 dal\154\237 Cor Draconis? Uf, jsem docela[ENTER]vy\232erpan\253 a v\253robn\237 proces takov\233hoto p\248edm\236tu je[ENTER]dosti n\225ro\232n\253. Ale pro tebe to zkus\237m. Ov\154em i[ENTER]kdy\158 se budu sna\158it sebev\237c, nezvl\225dnu to v\237c ne\158[ENTER]jednou denn\236! "
gameforge.dragon_soul._090_say = "To pro dne\154ek sta\232\237. Prost\236 nezvl\225dnu v\237ce ne\158[ENTER]deset za den. Jsem na konci sil a pot\248ebuji si[ENTER]odpo\232inout. P\248ij\239 zase z\237tra. "
gameforge.dragon_soul._100_npcChat = "Otev\248\237t obchod "
gameforge.dragon_soul._1010_sendLetter = "P\248\237chod \218lomku Dra\232\237ho kamene "
gameforge.dragon_soul._1020_say = "Nejzn\225m\236j\154\237 miner\225ln\237 alchymista v cel\233m[ENTER]kr\225lovstv\237 se po tob\236 pt\225. Zajdi za n\237m co[ENTER]nejd\248\237ve! "
gameforge.dragon_soul._1030_npcChat = "\218lomek Dra\232\237ho kamene?! "
gameforge.dragon_soul._1040_say = "Ach, tady jsi! Objevil jsem n\236co opravdu[ENTER]pozoruhodn\233ho: \250lomek Dra\232\237ho kamene! Dra\232\237 k\225men[ENTER]je extr\233mn\236 vz\225cn\253 a cenn\253 krystal s velkou[ENTER]silou.[ENTER]\216\237k\225 se, \158e to kdysi byla du\154e draka.[ENTER]Neuv\236\248iteln\236 kr\225sn\253! D\225m ti S\237lu Dra\232\237ho oka,[ENTER]abys mohl ty \250lomky nal\233zt tak\233. P\248ines mi celkem[ENTER]deset \250lomk\249 Dra\232\237ho kamene. Pak je budu schopen[ENTER]p\248em\236nit na kompletn\237 Dra\232\237 k\225men. "
gameforge.dragon_soul._1050_sendLetter = "Nasb\237rej \250lomky Dra\232\237ho kamene "
gameforge.dragon_soul._1060_say = "Dones alchymistovi 10 \250lomk\249 Dra\232\237ho kamene. "
gameforge.dragon_soul._1070_say = "Ach, v\253born\236! Nalezl jsi \250lomek Dra\232\237ho kamene.[ENTER]Chvilku po\232kej.[ENTER]...[ENTER]Neuv\236\248iteln\233! Z transmutace vze\154lo Cor Draconis -[ENTER]krystalick\233 dra\232\237 srdce, kter\233 ochra\242uje Dra\232\237[ENTER]k\225men. Kdy\158 jej rozbije\154, tak se do tv\233ho[ENTER]alchymistick\233ho invent\225\248e p\248id\225 Dra\232\237 k\225men,[ENTER]kter\253 je uvnit\248.[ENTER]Pro nal\233z\225n\237 \250lomk\249 Dra\232\237ho kamene bude\154[ENTER]pot\248ebovat S\237lu Dra\232\237ho oka. Mohu ti jej p\249j\232it -[ENTER]sta\232\237 m\236 ka\158d\253 den nav\154t\237vit. Pak je bude\154 tak\233[ENTER]schopen p\248em\236nit na Dra\232\237 kameny! Dnes jsem pro[ENTER]tebe jeden ud\236lal, zb\253vaj\237c\237ch %d bude\154 muset[ENTER]zvl\225dnout s\225m. "
gameforge.dragon_soul._1080_say = "Hej, nepl\253tvej \232asem! Jdi a hledej \250lomky Dra\232\237ho[ENTER]kamene! "
gameforge.dragon_soul._1090_sendLetter = "S\237la Dra\232\237ho oka "
