gameforge.dragon_soul._1130_say = "Zdrav\237m! Dnes jsi ji\158 obdr\158el S\237lu Dra\232\237ho oka.[ENTER]Ten proces m\236 ale vy\232erp\225v\225 tak, \158e ti mohu[ENTER]pomoci pouze jednou za den. Vra\157 se zase z\237tra! "
gameforge.dragon_soul._1140_say = "Zdrav\237m! Vsad\237m se, \158e sis p\248i\154el pro S\237lu[ENTER]Dra\232\237ho oka. Spr\225vn\236? V\253born\236, tady m\225\154. Hodn\236[ENTER]\154t\236st\237 p\248i hled\225n\237! Douf\225m, \158e najde\154 dostatek[ENTER]\250lomk\249 pro deset Dra\232\237ch kamen\249! "
