gameforge.energy_system._010_say = "M\225m to![ENTER]Kone\232n\236 se mi povedlo dokon\232it kompletn\236 novou[ENTER]technologii.[ENTER]Umo\158\242uje mi zpracovat p\248edm\236ty a z\237skat z nich[ENTER]\232istou energii. Je to naprosto dokonal\233! "
gameforge.energy_system._020_say = "Pokud zni\232\237\154 p\248edm\236t za pou\158it\237 m\233 nov\233[ENTER]technologie, pak obdr\158\237\154 Fragment energie. Pokud[ENTER]spoj\237\154 30 fragment\249 energie, tak z\237sk\225\154[ENTER]Energetick\253 krystal! \200ist\225, nefiltrovan\225 energie[ENTER]ukryt\225 v drahokamu! Ta s\237la bude pulzovat celou[ENTER]tvou v\253bavou.[ENTER]Zaj\237m\225 t\236 to? "
gameforge.energy_system._030_say = "P\248ines mi v\236ci, jako jsou zbran\236, oble\232en\237 nebo[ENTER]\154perky, kter\233 b\236hem lovu najde\154. Zm\236n\237m je na[ENTER]Fragmenty energie. D\237ky t\233to technologii se na\154e[ENTER]kr\225lovstv\237 stane neporaziteln\253m! "
