gameforge.energy_system._060_say = "Nem\225\154 dostate\232nou \250rove\242! Vra\157 se, a\158 bude\154 m\237t[ENTER]\250rove\242 alespo\242 35. "
gameforge.energy_system._070_say = "Ach, v\253born\236! Jsi dost siln\253, p\248esn\236 jak jsem[ENTER]p\248edpokl\225dal. Tak mi dej p\248edm\236t, kter\253 chce\154[ENTER]p\248etvo\248it. "
