gameforge.energy_system._180_say = "Nem\225\154 dostatek Fragment\249 energie, s t\237m co m\225\154[ENTER]Energetick\253 krystal nevytvo\248\237m. Vra\157 se, a\158 bude\154[ENTER]m\237t alespo\242 %d fragment\249. "
