gameforge.energy_system._260_say = "Bohu\158el se to nepovedlo, nem\225m \158\225dn\253 Energetick\253[ENTER]krystal. M\225 technologie je brilantn\237, ale bohu\158el[ENTER]proces je riskantn\237. V\236ci se v\158dy nevyv\237j\237 podle[ENTER]pl\225nu. Jsem si ale jist, \158e p\248\237\154t\236 se mi to[ENTER]poda\248\237! "
gameforge.energy_system._270_say = "V\236d\236l jsem to! Moje technologie je brilantn\237. Na,[ENTER]tady m\225\154 sv\249j Energetick\253 krystal. No, je to[ENTER]opravdu p\236kn\253 kousek - c\237t\237\154 jeho s\237lu? "
