gameforge.find_brother_article._280_say = "Rozbal\237\154 odm\236nu od Mirine a najde\154 me\232 s[ENTER]p\248ekr\225sn\236 zdobenou rukojet\237. "
gameforge.find_brother_article._290_say = "N\225dhern\225 zbra\242. Ale... co je tohle? \200epel je[ENTER]zlomen\225! Tenhle n\225dhern\253 kus \158eleza je p\248\237li\154[ENTER]dobr\253 na to aby byl vyhozen. M\236l bych ten kousek[ENTER]odn\233st ke Kov\225\248i. "
