gameforge.find_brother_article._30_say = "Promi\242, nesly\154ela jsem, \158e p\248ich\225z\237\154. Myslela[ENTER]jsem na sv\233ho uboh\233ho bratra. A kdo vlastn\236 jsi? "
gameforge.find_brother_article._310_sendLetter = "Jdi za kov\225\248em "
gameforge.find_brother_article._320_say = "Mirine ti byla tak vde\232n\225 za tvoji pomoc, \158e ti[ENTER]dala jej\237 nejcenn\236j\154\237 majetek: n\225dhern\253 me\232,[ENTER]kter\253 je bohu\158el rozbit\253. Na prvn\237 pohled si[ENTER]uv\236dom\237\154, \158e je to velmi cenn\225 v\236c a tak se[ENTER]rozhodne\154 nechat me\232 opravit. "
gameforge.find_brother_article._330_targetVid = "Oprava me\232e "
gameforge.find_brother_article._340_npcChat = "M\249\158e\154 opravit m\236\232? "
gameforge.find_brother_article._350_say = "To je n\225dhern\253 me\232! Pat\248il Mirine, ne? Sly\154el[ENTER]jsem, \158e jsi j\237 pomohl. V\253born\236, vypad\225 to, \158e[ENTER]jsi \232estn\253 a spravedliv\253 \232lov\236k, tak\158e ti nebudu[ENTER]za opravu nic \250\232tovat. Po\232kej chvilku... "
gameforge.find_brother_article._360_say = "Zde, ost\248\237 je zase jako nov\233. Opravdu dobr\225[ENTER]zbra\242. Vem si ji p\248\237teli. "
gameforge.find_brother_article._370_sayReward = "Obdr\158\237\154 st\248\237brn\253 me\232+3. "
gameforge.find_brother_article._380_sayReward = "Obdr\158el jsi Orchideome\232+2. "
gameforge.find_brother_article._390_sayReward = "Obdr\158el jsi jedenap\249lru\232n\237 me\232+2. "
gameforge.find_brother_article._400_sayReward = "Obdr\158el jsi barbarsk\253 me\232+2. "
gameforge.find_brother_article._40_say = "N\225hodou jsem \154el kolem a vid\236l t\236 plakat.[ENTER]Tu m\225\154 kapesn\237k. "
gameforge.find_brother_article._50_say = "Ach, neuv\236domila jsem si, \158e je n\236kdo pobl\237\158...[ENTER]Jmenuji se Mirine. Mo\158n\225 bys mi mohl pomoci? M\249j[ENTER]star\154\237 bratr je mrtv\253. Byl na cest\236 z\237skat l\233k[ENTER]ale... Jedin\233 co mne po n\236m zbylo je pohled na[ENTER]jeho hrob a jedna pam\225tka: jeho \232ern\225 uniforma. "
gameforge.find_brother_article._60_sayTitle = "Mirine: "
gameforge.find_brother_article._70_say = "Pak se n\225hle p\248ihnala pov\236stn\225 banda \200ern\233ho[ENTER]v\236tru. Kdy\158 jsem p\248ed n\237 ut\237kala, ztratila jsem[ENTER]bohu\158el tu pam\225tku. Te\239 se neodva\158uji tam j\237t a[ENTER]hledat ji. Na\154el bys mi ji, pros\237m? "
