gameforge.find_squareguard._120_say = "M\249\158e\154 koupit \232erven\253 lektvar u obchodnice se[ENTER]sm\237\154en\253m zbo\158\237m. Je tamhle. Pokud ji nevid\237\154, jdi[ENTER]sm\236rem k blikaj\237c\237 kru\158nici na velk\233 map\236 nebo k[ENTER]blikaj\237c\237mu \232erven\233mu bodu na mini map\236. "
gameforge.find_squareguard._130_sayTitle = "Obchodnice: "
gameforge.find_squareguard._131_targetVid = "Obchodnice: "
gameforge.find_squareguard._140_say = "Zdrav\237m t\236, dobrodruhu![ENTER]Aha, pos\237l\225 t\236 ke mn\236 str\225\158ce n\225vsi? Pot\248ebuje[ENTER]\232erven\253 lektvar? D\225m ti jich hned p\236t.[ENTER]Na, vezmi si je. Slou\158\237 ke obnoven\237 energie[ENTER]\158ivota (ZB) a chutnaj\237 v\253born\236. "
gameforge.find_squareguard._150_say = "Ty jsi sice v t\233to oblasti nov\253, ale jsem[ENTER]p\248esv\236d\232en\225 o tom, \158e se brzo stane\154 st\225l\253m[ENTER]z\225kazn\237kem. Z tohoto d\249vodu ti ty elix\237ry[ENTER]p\248enech\225m zdarma. P\248ijd' brzo znovu. "
gameforge.find_squareguard._160_sayReward = "Od obchodnice se sm\237\154en\253m zbo\158\237m jsi obdr\158el 5[ENTER]\232erven\253ch elix\237r\249. "
gameforge.find_squareguard._170_sayReward = "\200erven\233 lektvary jsou na obnoven\237 bod\249 \158ivota[ENTER](ZB). "
gameforge.find_squareguard._180_sendLetter = "N\225vrat ke str\225\158ci "
gameforge.find_squareguard._190_sayReward = "Vra\157 se ke str\225\158ci n\225vsi a p\248edej mu jeden[ENTER]\232erven\253 lektvar. "
gameforge.find_squareguard._200_say = "Ty nem\225\154 \158\225dn\253 \232erven\253 lektvar? \138koda![ENTER]No dob\248e, nech si drobn\233 za to, \158e ses sna\158il.[ENTER]Ach, mimochodem, sh\225n\236j\237 se po tob\236 u\232itel\233. M\236l[ENTER]by ses k nim vydat. "
gameforge.find_squareguard._20_sayReward = "Jdi do st\248edu vesnice a promluv si se str\225\158cem[ENTER]n\225vsi. P\248id\236l\237 ti prvn\237 \250kol. Najde\154 ho v centru[ENTER]vesnice. "
gameforge.find_squareguard._210_say = "D\237ky mockr\225t, \158e jsi mi ten \232erven\253 lektvar[ENTER]donesl![ENTER]Aspo\242 jsem kv\249li tomu nemusel opustit moje[ENTER]stanovi\154t\236 a mohu t\237m l\233pe plnit sv\233 povinnosti.[ENTER]Chce\154 v\236d\236t, co pat\248\237 k m\253m povinnostem? Kr\225tce[ENTER]\248e\232eno, vyhla\154uji u\158ite\232n\233 informace. Nav\237c je\154t\236[ENTER]nab\237z\237m pomoc t\236m, kte\248\237 ji pot\248ebuj\237 nebo kte\248\237[ENTER]se stanou ob\236t\237 \250toku. Ov\154em m\225 hlavn\237 pr\225ce je[ENTER]starost o cechy. A\158 bude\154 jednoho dne cht\237t[ENTER]vstoupit do n\236jak\233ho cechu, p\248ij\239' ke mn\236. "
gameforge.find_squareguard._220_say = "Mimochodem, sh\225n\236j\237 se po tob\236 u\232itel\233.[ENTER]M\236l by ses k nim vydat.[ENTER][ENTER]Aha jo - m\225lem bych zapomn\236l: Na znamen\237 m\233ho[ENTER]uzn\225n\237 si m\249\158e\154 drobn\233 ponechat.[ENTER]Ur\232it\236 se brzo zase uvid\237me. "
gameforge.find_squareguard._30_sayTitle = "Str\225\158ce: "
gameforge.find_squareguard._40_say = "V\237tej v na\154\237 vesnici, dobrodruhu![ENTER]Byl bych ti vd\236\232n\253, kdybys mi prok\225zal malou[ENTER]laskavost. Kdy\158 ti d\225m 200 Yang\249, koup\237\154 mi[ENTER]\232erven\253 lektvar? D\225 se sehnat u obchodnice se[ENTER]sm\237\154en\253m zbo\158\237m. Jsem ve slu\158b\236 a proto nyn\237[ENTER]nem\249\158u opustit n\225ves. "
gameforge.find_squareguard._50_select = "Ano "
gameforge.find_squareguard._60_sayReward = "Obdr\158el jsi od spr\225vce 200 yang\249. Za tento[ENTER]platebn\237 prost\248edek si v obchodech m\249\158e\154 obstarat[ENTER]p\248edm\236ty nebo vyu\158\237t slu\158by \248emesln\237k\249. U[ENTER]obchodnice se sm\237\154en\253m zbo\158\237m si m\249\158e\154 koupit[ENTER]\232erven\253 lektvar. "
