gameforge.fortune_telling = {}
gameforge.fortune_telling._100_sayTitle = "Sta\248enka "
gameforge.fortune_telling._10_npcChat = "Sly\154el jsem, \158e jste v\236\154tkyn\236. "
gameforge.fortune_telling._110_say = "Jsi p\248\237li\154 mlad\253 na to, abys takhle vzdychal![ENTER]Chce\154 si nechat p\248edpov\236d\236t osud od harmonick\233,[ENTER]tajemn\233 moci? "
gameforge.fortune_telling._120_select = "Nechat si p\248edpov\236d\236t "
gameforge.fortune_telling._130_select = "Nenechat si p\248edpov\236d\236t "
gameforge.fortune_telling._140_say = "Spr\225vn\236.[ENTER]V \158ivot\236 je nejd\249le\158it\236j\154\237, nechat se v\233st[ENTER]vlastn\237 v\249l\237 a d\225t ze sebe to nejlep\154\237. \142ijte[ENTER]blaze! "
gameforge.fortune_telling._150_select = "Ano, chci. "
gameforge.fortune_telling._160_select = "Ne, d\237ky. "
gameforge.fortune_telling._170_say = "Jsem sice hodn\225, ale nem\249\158u si dovolit rozd\225vat[ENTER]talismany. Jestli chce\154 zabr\225nit sm\249le a[ENTER]ne\154t\236st\237, zapla\157 mi za ten talisman p\248im\236\248enou[ENTER]cenu.[ENTER]Stoj\237 %s Yang\249. "
gameforge.fortune_telling._180_say = "Ty jde\154 pry\232? Mo\158n\225 m\225\154 pravdu. Ne\154t\236st\237 a[ENTER]tr\225pen\237 pat\248\237 k \158ivotu. D\225vej na sebe pozor a \158ij[ENTER]blaze. Jestli zm\236n\237\154 n\225zor, p\248ijd' si se mnou[ENTER]promluvit pozd\236ji. "
gameforge.fortune_telling._20_say = "Pohled do tv\253ch o\232\237 mi prozrazuje, \158e jsi je\154t\236[ENTER]velmi mlad\253. Pro\232 bys cht\236l zn\225t tv\249j osud tak[ENTER]brzy? M\225\154 pro to n\236jak\253 d\249vod? Osud toho m\225 pro[ENTER]tebe je\154t\236 mnoho p\248ichyst\225no. P\248ij\239 pozd\236ji. "
gameforge.fortune_telling._30_say = "Chce\154 v\233st sv\249j \158ivot tak, jak ti to p\248edpov\237[ENTER]v\236\154tkyn\236? P\248edpov\236di bys nem\236l br\225t tak v\225\158n\236. To[ENTER]jedin\233, co je opravdu d\249le\158it\233, jsou tvoje[ENTER]sm\253\154len\237 a tv\249j v\253raz ve tv\225\248i. Pokud je oboj\237[ENTER]pozitivn\237, nem\249\158e se nic st\225t. "
gameforge.fortune_telling._40_sayTitle = "Sta\248enka "
gameforge.fortune_telling._50_say = "Jak jsem ji\158 \248ekla, tv\225 p\248edpov\236\239 pro dne\154ek je[ENTER]n\225sleduj\237c\237: "
gameforge.fortune_telling._60_say = "Bude\154 m\237t sm\249lu a nav\237c jsi je\154t\236 nekoupil[ENTER]talisman proti zl\253m sil\225m.[ENTER]M\225\154 z\225jem koupit si m\249j talisman na bohatstv\237? "
gameforge.fortune_telling._70_select = "Ano, koup\237m si to. "
gameforge.fortune_telling._80_select = "Ne, nic takov\233ho nepot\248ebuji. "
gameforge.fortune_telling._90_say = "Jsem sice hodn\225, ale nem\249\158u ti \158\225dn\253 talisman jen[ENTER]tak d\225t. Jestli chce\154 zabr\225nit sm\249le a ne\154t\236st\237,[ENTER]zapla\157 mi za talisman p\248im\236\248enou cenu. "
