gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Duch sury: "
gameforge.ghost_story._020_npcChat = "Jsi duch? "
gameforge.ghost_story._030_say = "Ne, jsem tvoje babi\232ka... Jasn\236, \158e jsem duch![ENTER]N\236kdo t\236 snad jako d\237t\236 upustil na hlavu? "
gameforge.ghost_story._040_npcChat = "Pom\243\243\243c, je to duch! "
gameforge.ghost_story._050_say = "Hele ho, neboj\225cn\233ho bojovn\237ka! Baf!! "
gameforge.ghost_story._060_npcChat = "Kdo jsi? "
gameforge.ghost_story._070_say = "M\233 jm\233no je Akuma. Byl jsem jeden z nejv\236t\154\237ch[ENTER]bojovn\237k\249, n\236kte\248\237 \248\237kaj\237, nejlep\154\237 sv\233ho \232asu.[ENTER]Dokonce jsem tomu v\236\248il i j\225 s\225m! Ale pod\237vej se[ENTER]na mne te\239! Pod\237vejte se na to, co ze mne zbylo[ENTER]kdy\158 sem na\154el jeskyni... a zahynul. "
gameforge.ghost_story._080_npcChat = "Zn\225\154 historii tohoto m\237sta? "
gameforge.ghost_story._090_say = "Ach, j\225 v\237m co se tenkr\225t stalo. Dlouhou dobu[ENTER]jsem p\225tral, sna\158il se zjistit d\249vod t\233to snahy[ENTER]naj\237t jeskyni.[ENTER]A od m\233 smrti jsem m\236l hodn\236 \232asu na p\248em\253\154len\237.[ENTER]Jen se ptej, co pot\248ebuje\154 v\236d\236t! "
gameforge.ghost_story._100_npcChat = "Co to je za port\225l? "
gameforge.ghost_story._110_say = "Tento port\225l vede do temn\233 dra\232\237 komnaty, padl\233ho[ENTER]Boha Beran-Setaou. M\249\158e b\253t aktivov\225n pomoc\237[ENTER]magick\233ho kl\237\232e, kter\253 ale mohou m\237t jen[ENTER]bojovn\237ci Beran Setaou... "
gameforge.ghost_story._120_npcChat = "Bo\158sk\225 Trojice "
gameforge.ghost_story._130_say = "Kdysi d\225vno bo\158sk\225 sourozeneck\225 trojice udr\158ovala[ENTER]podstatu \158ivota.[ENTER]Bahar-Taraji, Bohyn\236 stvo\248en\237, byla nejmlad\154\237 z[ENTER]trojice. Jej\237m \250kolem bylo vytv\225\248et nov\233 byt\237 -[ENTER]kudy \154la tam kv\236tiny kvetly a \158ivot vzkv\233tal. "
gameforge.ghost_story._140_say = "Nejstar\154\237 bratr byl naz\253v\225n Beran-Setaou. Byl[ENTER]odpov\236dn\253 za ukon\232en\237 \158ivota a za rozklad.[ENTER]Kdykoli byl \158ivotn\237 cyklus u konce, odd\236lil t\236lo[ENTER]od du\154e a vedl du\154e do posmrtn\233ho \158ivota.[ENTER]A tak byl tedy zaji\154t\236n nep\248etr\158it\253 kolob\236h[ENTER]\158ivota. "
gameforge.ghost_story._150_say = "Prost\248edn\237 bratr byl Baljit-Elvedin. Jako B\249h[ENTER]uchov\225n\237, um\237r\242oval oba sourozence a umo\158\242oval[ENTER]v\236\232n\253 kolob\236h \158ivota pro v\154echna pozemsk\225[ENTER]stvo\248en\237. Byl nap\248\237klad zodpov\236dn\253 za p\248\237chody a[ENTER]odchody ro\232n\237ch obdob\237. "
gameforge.ghost_story._160_npcChat = "Rozep\248e "
gameforge.ghost_story._170_say = "V dob\225ch nouze, lid\233 prosili bohy o pomoc. Av\154ak[ENTER]p\248\237lis se b\225li a z\225rove\242 podce\242ovali[ENTER]Beran-Setaoua, v jejich kr\225tkozrakosti[ENTER]nepochopili, \158e stejn\236 jako existuje sv\236tlo a[ENTER]tma, tak existuje i on jako prot\236j\154ek ke[ENTER]stvo\248en\237. "
gameforge.ghost_story._180_say = "Po dlouhou dobu to b\249h ignoroval, ale po \248adu let[ENTER]v n\236m rostla nevra\158ivost, kter\225 se pomalu m\236nila[ENTER]v nen\225vist a zlomyslnost. Zpo\232\225tku sm\236\248oval sv\249j[ENTER]hn\236v v\249\232i lidem na vyvol\225n\237 v\225lek a nemoc\237. Av\154ak[ENTER]to vedlo jen k jeho dal\154\237mu odm\237t\225n\237 a lid\233 se[ENTER]st\225le v\237ce obraceli k Bahar-Taraji, bohyni[ENTER]stvo\248en\237 nov\233ho \158ivota. A tak vznikl bludn\253 kruh,[ENTER]kter\253 nakonec vedl ke zk\225ze. "
gameforge.ghost_story._190_say = "A jak se st\225val bo\158\237 hn\236v intenzivn\236j\154\237 tak jej[ENTER]ji\158 nemohl d\233le kontrolovat. Zabil svoji sestru,[ENTER]kter\225 byla u lid\237 nejobl\237ben\236j\154\237. Tento \232in byl[ENTER]zcela nevyprovokovan\253, ten den zach\225zela se sv\253m[ENTER]bratrem se stejnou l\225skou a v\237rou jako to[ENTER]d\236l\225vala ka\158d\253 den. Pod\237val do jej\237ch laskav\253ch[ENTER]o\232\237 a jej\237 \158ivot nav\158dy ukon\232il. "
gameforge.ghost_story._200_npcChat = "N\225sledky "
gameforge.ghost_story._210_say = "Smrt Bahar-Taraji m\236la hroziv\233 n\225sledky jak pro[ENTER]sv\236t boh\249 tak pro sv\236t lid\237: P\248i\154la dlouh\225 a[ENTER]krut\225 zima, kter\225 zab\237jela stvo\248en\237 v mo\248i i na[ENTER]zemi. Zem\236 zmrzla tak siln\236, \158e kameny praskaly a[ENTER]dokonce i nejstar\154\237 a nejsiln\236j\154\237 stromy uschly. "
gameforge.ghost_story._220_say = "Mlad\237 lid\233 a zv\237\248ata zahynuli a kdy\158 se kone\232n\236[ENTER]oteplilo, porodnost se stala ni\158\154\237 ne\158 kdykoli[ENTER]p\248edtim.[ENTER]Oslaben\225 zem\236 toho nep\248inesla dost, aby u\158ivila[ENTER]dosp\236lou populaci, nato\158 aby u\158ivila nov\253 \158ivot.[ENTER]Nad\236je um\237rala spolu se \158ivotem a ob\236 pot\248ebovali[ENTER]dlouh\253 \232as na pln\233 zotaven\237. "
gameforge.ghost_story._230_say = "I bohov\233 trp\236li, av\154ak, \232as pro n\236 plynul[ENTER]pomaleji ne\158 pro lidi. Jakmile si Beran-Setaou[ENTER]uv\236domil obludnost \232inu, kter\253 sp\225chal, st\225hl se[ENTER]a vyhledal samotu. Nedok\225zal se v sob\236 vypo\248\225dat[ENTER]se zni\232uj\237c\237 l\237tost\237 a hlubok\253m uspokojen\237m -[ENTER]dokud to druh\233 nezv\237t\236zilo v t\233to du\154evn\237 bitv\236.[ENTER]Jeho srdce zmrzlo a B\249h Rozkladu se stal Bohem[ENTER]Ledu a Chladu, Nen\225visti a Strachu. "
gameforge.ghost_story._240_npcChat = "Bitva "
gameforge.ghost_story._250_say = "Baljit-Elvedin, B\249h uchov\225n\237, dlouho truchlil pro[ENTER]svou sestru. A jakmile pevn\233 dr\225py bolesti[ENTER]kone\232n\236 uvolnili sv\233 sev\248en\237 kolem jeho srdce,[ENTER]vydal se hledat sv\233ho bratra. Porozum\236n\237 a[ENTER]moudrost st\225le domivovali jeho \158ivotn\237 cest\236 a[ENTER]tak i p\248es sv\249j \158al uznal, \158e \158ivot nem\249\158e[ENTER]pokra\232ovat d\225le v nerovnov\225ze. "
gameforge.ghost_story._260_say = "Sledoval stopy sv\233ho bratra po mnoho dlouh\253ch[ENTER]let, a nakonec jej na\154el v jeskyni utvo\248en\233 z[ENTER]ledu, nen\225visti a samoty, daleko od jak\233koli[ENTER]zn\225mky \158ivota. Baljit-Elvedin ud\236lal co ud\236lat[ENTER]musel, i kdyby to m\236lo zasadit dal\154\237 r\225nu jeho[ENTER]srdci - vyzval sv\233ho bratra na souboj.[ENTER]Beran-Setaou byl tak dalece odklon\236n od cesty[ENTER]spravedlnosti, \158e nev\225hal ani na vte\248inu... "
gameforge.ghost_story._270_say = "Bitva byla krut\225 a mimo ch\225p\225n\237. Baljit-Elvedin[ENTER]bitvu vyhr\225l. Z\249stal v\236rn\253 sv\253m z\225sad\225m a nezabil[ENTER]sv\233ho bratra, ale za pomoci sv\233 s\237ly jej uzav\248el[ENTER]do jeskyn\236. A tak zde Beran-Setaou pob\253v\225 s[ENTER]tvory, kter\233 n\236kolik stalet\237 s\225m vytv\225\248\237... "
gameforge.ghost_story._280_npcChat = "Ji\158 jsem sly\154el dost. "
gameforge.ghost_story._290_say = "Mo\158n\225 bude tv\249j osud jin\253 ne\158 m\249j. Hodn\236 \154t\236st\237! "
gameforge.ghost_story._300_sayTitle = "Duch bojovn\237ka: "
gameforge.ghost_story._310_npcChat = "Pro\232 si pr\249hledn\253? "
gameforge.ghost_story._320_say = "Pro\232 asi?! Jsem duch a jsem v t\233to sk\225le uv\236zn\236n[ENTER]po t\237s\237ce let... "
gameforge.ghost_story._330_say = "Pom\243\243\243c, je to duch! "
gameforge.ghost_story._340_say = "Spr\225vn\236, jsem duch. Rychle ute\232 nebo t\236 sn\237m! "
gameforge.ghost_story._350_npcChat = "Kdo jsi? "
gameforge.ghost_story._360_say = "Kdysi jsem byl \158old\225k, prost\253 mu\158. Moji rodi\232e[ENTER]byli farm\225\248i. Necht\236l jsem pracovat jako farm\225\248[ENTER]po zbytek sv\233ho \158ivota, tak jsem se p\248idal k[ENTER]arm\225d\236. Bylo to tvrd\233 a krvav\233, ale nebylo to tak[ENTER]\154patn\233. Ale nakonec jsem byl unaven v\236\232n\253m[ENTER]rozkazov\225nim \154lechtic\249, kter\233 nikam nevedlo a[ENTER]ode\154el jsem. A osud mne nakonec zavedl na toto[ENTER]temn\233 m\237sto. "
gameforge.ghost_story._370_npcChat = "Zn\225te p\248\237b\236h o jeskyni? "
gameforge.ghost_story._380_say = "Nevim, nejsp\237\154e jsem m\236l jenom sm\249lu. Pot\233 co[ENTER]jsem dezertoval jsem se cht\236l ukr\253t v hor\225ch a[ENTER]narazil jsem na tuto jeskyni. Hned od za\232\225tku se[ENTER]mi zd\225la trochu podivn\225, ale byla pohodln\225 a[ENTER]zd\225la se b\253t zcela opu\154t\236n\225. P\225r dn\237 na to jsem[ENTER]se stal sv\236dkem a z\225rove\242 ob\236t\237 neuv\236\248iteln\233[ENTER]bitvy. Pokud se ti to zal\237bilo, mohu ti o tom[ENTER]vypr\225v\236t. "
gameforge.ghost_story._390_npcChat = "Za\232\225tek Bitvy "
gameforge.ghost_story._400_say = "Jednoho dne jsem sb\237ral ko\248\237nky na ubo\232\237 skal,[ENTER]kdy\158 tu najednou se z nebe snesl st\248\237brn\253 drak.[ENTER]Myslel jsem si, \158e je po m\236, ale on mne nevid\236l a[ENTER]zam\237\248il ke vchodu do jeskyn\236. Ani\158 by zpomalil,[ENTER]snesl se dol\249 do \250dol\237 a vlet\236l do jeskyn\236. "
gameforge.ghost_story._410_say = "A pak bylo na chv\237li ticho a j\225 nev\236d\236l co d\236lat.[ENTER]Ve\154ker\233 moje vybaven\237 bylo v jeskyni a j\225 se[ENTER]samoz\248ejm\236 necht\236l s drakem potkat! A pak se zem\236[ENTER]zachv\236la a z hlubin jeskyn\236 se ozval dut\253 \248ev.[ENTER]Ale k m\233mu zd\236\154en\237 jsem zjistil, \158e to nebyl \248ev[ENTER]jeden ale dva! Kr\225tce na to z jeskyn\236 vyst\248elili[ENTER]dva draci, st\248\237brn\253 drak n\225sledov\225n modr\253m[ENTER]drakem. "
gameforge.ghost_story._420_say = "T\233m\236\248 nepopsateln\225 bitva mezi draky. Dr\225sali sv\225[ENTER]t\236la v t\236sn\233m sev\248en\237 a bo\248ili sv\233 zuby do krku[ENTER]protivn\237ka... pr\154ela krev... ale ani jeden[ENTER]nehodlal povolit sv\233 sev\248en\237 ani na vte\248inu. "
gameforge.ghost_story._430_npcChat = "Konec Bitvy "
gameforge.ghost_story._440_say = "Oba draci v\225lcovali hory jako bou\248e, kter\225[ENTER]vyvol\225v\225 sesuvy a chaos. Blesk pop\225lil tlamu[ENTER]modr\233ho draka, ledov\233 kroupy zase prod\236rav\236ly[ENTER]k\248\237dla st\248\237brn\233ho draka. Tlust\233 masy ledu, kter\233[ENTER]pokr\253valy zem po mnoho let se b\236hem tohoto boje[ENTER]zm\236nily na bl\225tiv\233 zbytky. Schov\225val jsem se za[ENTER]sk\225lou, zkamen\236l\253 ale neschopn\253 ignorovat boj,[ENTER]kter\253 se p\248ede mnou odehr\225val. "
gameforge.ghost_story._450_say = "Trvalo n\236kolik hodin, ne\158 jejich moc za\232ala[ENTER]sl\225bnout. A pak jsem kone\232n\236 vid\236l svou[ENTER]p\248\237le\158itost, odtrhl jsem se od sc\233ny a b\236\158el jsem[ENTER]\250dol\237m do jeskyn\236 pro svoje vybaven\237. A tak byl[ENTER]m\249j osud zpe\232et\236n. Byl jsem ji\158 na cest\236 zp\236t,[ENTER]kdy\158 oba draci vyst\248elili z hor, modr\253 drak p\248ed[ENTER]st\248\237brn\253m drakem. Modr\253 drak utrp\236l stra\154liv\225[ENTER]zran\236n\237. "
gameforge.ghost_story._460_say = "T\236sn\236 p\248ed zmizen\237m do jeskyn\236 ho st\248\237brn\253 drak[ENTER]chytil a pak se stalo n\236co zvl\225\154tn\237ho: Obloha[ENTER]za\232ala probleskovat, zvedl se prudk\253 v\237tr a[ENTER]vytvo\248il se v\237r energie, do kter\233ho byl modr\253[ENTER]drak chycen.[ENTER]Modr\253 drak za\232al \248v\225t bolest\237 a vztekem... za\232al[ENTER]se smr\154\157ovat, \248ev se st\225val slab\154\237m a jeho \154upiny[ENTER]ztratily lesk, zmatn\236ly a vybledly. "
gameforge.ghost_story._470_say = "Nakonec st\248\237brn\253 drak pustil modr\233ho draka zp\236t[ENTER]do jeskyn\236. Z posledn\237ch zbytk\249 sil se pora\158en\253[ENTER]drak dovlekl pod horu. Av\154ak, st\248\237brn\253 drak[ENTER]pokra\232oval v uvol\242ov\225n\237 mocn\233 magick\233 bou\248e,[ENTER]kter\225 zape\232etila jeskyni magickou bari\233rou a[ENTER]kter\225 sesula \232\225st hory. Temn\253 drak a j\225 jsme byli[ENTER]v pasti. Odsouzen k mizern\233 a mu\232iv\233 smrti[ENTER]hladem... "
gameforge.ghost_story._480_npcChat = "Ji\158 jsem sly\154el dost. "
gameforge.ghost_story._490_say = "D\236kuji za vyslechnut\237. Posledn\237ch tis\237c let jsem[ENTER]byl opravdu osam\236l\253... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Ne\158 jsem unikl \232ern\233mu v\236tru, p\248i\154el jsem na to,[ENTER]kde skr\253vaj\237 zlato. M\236li tam cel\253 stoh zlat\253ch[ENTER]prut\249! Ani by si nev\154imli, kdy\158 by tam n\236jak\233[ENTER]chyb\236li. Takov\237 hlup\225ci to jsou.[ENTER]Jestli mi zaplat\237\154, p\249jdu a donesu ti prut zlata.[ENTER]Ale nem\249\158u ti p\248in\233st v\237c ne\158 jeden prut najednou. "
gameforge.goldbar._104_say = "\200as "
gameforge.goldbar._108_say = "Minuta (y) "
gameforge.goldbar._10_npcChat = "Ob\236\157 bandy \232ern\233ho v\236tru "
gameforge.goldbar._110_say = "Odn\233st prut zlata trv\225 zhruba %s %s. "
gameforge.goldbar._120_say = "Jestli m\225\154 z\225jem, \248ekni mi. "
gameforge.goldbar._130_say = "Opravdu? Dohodneme se?[ENTER]Sta\232\237 jenom \248\237ct a jeden ti p\248inesu! "
gameforge.goldbar._140_npcChat = "Chci koupit prut zlata. "
gameforge.goldbar._150_say = "Co to pov\237d\225\154? O tom nic nev\237m. "
gameforge.goldbar._160_say = "Co\158e? Ty chce\154 koupit zlat\253 prut?[ENTER]Ne, te\239 ne! Vypad\225 to, \158e \232ern\253 v\237tr je zrovna[ENTER]podez\248\237vav\253. Riskuju vlastn\237 hrdlo, kdy\158 si te\239[ENTER]ned\225m pozor! Zkus\237me to znovu, a\158 se situace[ENTER]uklidn\237. "
gameforge.goldbar._170_sayReward = "Te\239 nem\249\158e\154 kupovat \158\225dn\233 zlat\233 pruty. "
