gameforge.goldbar._190_say = "Mus\237me \232ekat zhruba %s %s. "
gameforge.goldbar._200_say = "P\248inesl jsem zlat\253 prut. Stoj\237 t\236 2,2 mili\243n\249[ENTER]Yang\249. T\236ch 200.000 Yang\249 je poplatek za[ENTER]vy\248\237zen\237. Tak co? Chce\154 ho koupit? "
gameforge.goldbar._20_sayTitle = "Zr\225dce Balso: "
gameforge.goldbar._210_say = "Tady je tv\249j zlat\253 prut. Ud\236lal jsi moudr\233[ENTER]rozhodnut\237. D\236lat investice je dobr\225 my\154lenka. "
