gameforge.goldbar._260_npcChat = "Prodat prut zlata "
gameforge.goldbar._270_say = "Co to pov\237d\225\154? O tom nic nev\237m. "
gameforge.goldbar._280_say = "Co\158e? Ty chce\154 ten prut zlata prodat? Ty\180s to[ENTER]je\154t\236 nesly\154el? Bojovn\237ci \232ern\233ho v\236tru te\239[ENTER]podez\248\237vaj\237 ka\158d\233ho. Kdy\158 prod\225\154 ten prut zlata[ENTER]te\239, nebude\154 u\158 dlouho na\158ivu. Nejlep\154\237 bude,[ENTER]kdy\158 ho nech\225\154 tam, kde je. Dob\248e ho schovej! "
gameforge.goldbar._290_sayReward = "Te\239 nem\249\158e\154 prod\225vat \158\225dn\233 pruty zlata. "
gameforge.goldbar._300_say = "Jestli te\239 ten prut zlata chce\154 vr\225tit, "
gameforge.goldbar._30_say = "Co\158e? Ob\236\157 \232ern\233ho v\236tru? Ha ha ha![ENTER]Vypad\225\154 jako d\237t\236. Kdepak jsi to sly\154el?[ENTER]B\236\158 si hr\225t s divok\253mi psy! "
gameforge.goldbar._310_say = "mus\237\154 po\232kat zhruba %s %s. "
gameforge.goldbar._320_say = "Ty nem\225\154 \158\225dn\233 pruty zlata.[ENTER]Kdy\158 mi p\248inese\154 pruty zlata, d\225m ti za n\236 Yang. "
gameforge.goldbar._330_say = "Co\158e?[ENTER]Ty chce\154 vr\225tit tv\249j prut zlata? Pro\232 jsi ho teda[ENTER]v\249bec kupoval? Pokud ho chce\154 vr\225tit, nic proti[ENTER]tomu nem\225m. \200ern\253 v\237tr je na str\225\158i, proto tam[ENTER]nem\249\158u zas tak \232asto. Je\154t\236 po\248\225d ho chce\154[ENTER]vr\225tit? "
gameforge.goldbar._340_select = "Vr\225tit "
gameforge.goldbar._350_select = "Nevr\225tit "
gameforge.goldbar._360_say = "Tady m\225\154 ti tvoje Yangy.[ENTER]Sakra! Te\239 ho mus\237m don\233st zp\225tky! "
gameforge.goldbar._370_say = "M\225\154 v\249bec n\236jak\233 pruty zlata?[ENTER]M\225m dost na pr\225ci. Necho\239 mi sem, kdy\158 nechce\154[ENTER]d\236lat k\154efty. "
gameforge.goldbar._40_sayReward = "\218kol 'Ob\236\157 bandy \200ern\233ho v\236tru' je k dispozici[ENTER]pouze pro postavy na 30. nebo vy\154\154\237 \250rovni. "
gameforge.goldbar._50_say = "D\225vej si pozor! V\225le\232n\237ci \200ern\233ho v\236tru jsou[ENTER]velmi podez\248\237vav\237. Nejlep\154\237 bude se chovat \250pln\236[ENTER]klidn\236. \142ij blaze. "
gameforge.goldbar._60_sayReward = "\218kol 'Ob\236\157 bandy \200ern\233ho v\236tru' nen\237 moment\225ln\236 k[ENTER]dispozici. "
gameforge.goldbar._70_say = "P\154\154\154t![ENTER]Tady m\249\158ou b\253t schovan\237 v\225le\232n\237ci \200ern\233ho v\236tru.[ENTER]Kde\180s to sly\154el?[ENTER]No nic, u\158 to je v poho. Nen\237 to zas tak[ENTER]d\249le\158it\233. Ale ty v\237\154, co se d\236je? "
