gameforge.guild_building_npc._10_sayTitle = "Zbroj\237\248: "
gameforge.guild_building_npc._20_say = "\193, ty jsi p\248\237slu\154n\237k m\233ho cechu! Pokud chce\154[ENTER]vylep\154it tv\233 zbran\236, p\248ines je m\236 a ne tomu[ENTER]zelen\225\232ovi ve vesnici. J\225 jsem o 10 % \250sp\236\154n\236j\154\237.[ENTER]Na\154i \232lenov\233 tak\233 dostanou slevu 5 %. Prost\236 mi[ENTER]dej zbra\242, kterou chce\154 vylep\154it a j\225 se do toho[ENTER]pust\237m. "
gameforge.guild_building_npc._30_say = "Jmenuji se Stanley a star\225m se o zlep\154ov\225n\237[ENTER]zbran\237. Jsem mnohem lep\154\237 ne\158 vesnick\253 kov\225\248![ENTER]Kdy\158 to nech\225\154 ud\236lat u m\236, m\249\158e\154 si zv\253\154it[ENTER]\250sp\236ch o 10 %.[ENTER]Dej mi tu zbra\242, kter\225 m\225 b\253t zlep\154ena. "
gameforge.guild_building_npc._40_sayTitle = "Platn\233\248: "
gameforge.guild_building_npc._50_say = "\193, ty jsi \232len m\233ho cechu! To znamen\225, \158e mi[ENTER]m\249\158e\154 na vylep\154en\237 d\225t brn\236n\237, \154t\237ty, boty a[ENTER]helmy. Moje \250sp\236\154nost je o 10 % vy\154\154\237 ne\158 u toho[ENTER]\242oumy ve vesnici. \200len\249m cechu tak\233 d\225v\225m 5%[ENTER]slevu! Prost\236 mi dej v\253bavu, co chce\154 vylep\154it. "
gameforge.guild_building_npc._60_say = "Jmenuji se Stanton a star\225m se o zlep\154ov\225n\237[ENTER]brn\236n\237. Jsem mnohem lep\154\237 ne\158 vesnick\253 kov\225\248,[ENTER]moje \154ance na vylep\154en\237 je o 10 % vy\154\154\237![ENTER]Dej mi to brn\236n\237, kter\233 m\225 b\253t zlep\154eno. "
gameforge.guild_building_npc._70_sayTitle = "Klenotn\237k: "
gameforge.guild_building_npc._80_say = "\193, ty jsi \232len m\233ho cechu![ENTER]Zv\253\154\237 se ti \250sp\236ch o 10 %, kdy\158 m\236 nech\225\154[ENTER]vylep\154it ti \154perky.[ENTER]\200len\249m m\233ho cechu d\225v\225m 5% slevu.[ENTER][ENTER]Um\237m zlep\154ovat n\225ramky, n\225u\154nice a n\225hrdeln\237ky.[ENTER]Dej mi ty dopl\242ky, kter\233 maj\237 b\253t zlep\154eny. "
gameforge.guild_building_npc._90_say = "Jmenuji se Starbuck a star\225m se o zlep\154ov\225n\237[ENTER]\154perk\249. Jsem mnohem lep\154\237 ne\158 vesnick\253 kov\225\248![ENTER]Kdy\158 to nech\225\154 ud\236lat u m\236, m\249\158e\154 si zv\253\154it[ENTER]\250sp\236ch o 10 %.[ENTER][ENTER]Um\237m zlep\154ovat n\225ramky, n\225u\154nice a n\225hrdeln\237ky.[ENTER]Dej mi ty \154perky, kter\233 maj\237 b\253t zlep\154eny! "
