gameforge.heavens_cave_keyquest._030_say = "Dob\248e poslouchej synu! \216eknu ti ten p\248\237b\236h jen[ENTER]jednou... "
gameforge.heavens_cave_keyquest._040_say = "Dob\248e poslouchej, dcero! \216eknu ti ten p\248\237b\236h jen[ENTER]jednou... "
gameforge.heavens_cave_keyquest._050_say = "Nyn\237 uct\237v\225me Dra\232\237ho boha, ale v minulosti n\225s[ENTER]ochra\242ovali bozi t\248i. Bohu\158el, Bahar-Taraji,[ENTER]Bohyn\236 stvo\248en\237, byla zavra\158d\236na jej\237m z\225vistiv\253m[ENTER]bratrem Beran-Setaou. A t\248et\237 b\249h,[ENTER]Baljit-Elvedin, kter\233ho dnes zn\225me jako Dra\232\237ho[ENTER]boha, se uzav\248el do hlubok\233ho smutku ze ztr\225ty[ENTER]sv\233 sestry. "
gameforge.heavens_cave_keyquest._060_say = "Mezi dv\236ma bratry se rozho\248ela bitva, kterou[ENTER]Dra\232\237 b\249h vyhr\225l. Pov\236sti \248\237kaj\237, \158e zbytky po[ENTER]t\233to bitv\236 mohou b\253t st\225le nalezeny na m\237st\236[ENTER]jej\237ho kon\225n\237. Beran-Setaou byl po sv\233 por\225\158ce[ENTER]uv\236zn\236n v jeskyni, kter\225 je nyn\237 zn\225ma jako[ENTER]Jeskyn\236 vyhnanstv\237. "
gameforge.heavens_cave_keyquest._070_say = "Baljit-Elvedin rozk\225zal zapa\232etit a str\225\158it[ENTER]v\154echny vstupy do jeskyn\236. Mus\237te se prok\225zat[ENTER]Krvav\253m kamenem, aby V\225m byl povolen vstup. V\237m[ENTER]jak tyto kameny vyr\225b\236t, ale postup nen\237[ENTER]jednoduch\253. "
gameforge.heavens_cave_keyquest._080_say = "V\154e za\232\237n\225 u slz, kter\233 ronil Dra\232\237 b\249h nad[ENTER]ztr\225tou sv\233 sestry a kter\233 zkamen\236ly po p\225du na[ENTER]zem. M\249\158ete je st\225le naj\237t v ohniv\233 zemi[ENTER]Doyyumhwan. Z\237skejte sedm t\236chto slz a 4 kusy[ENTER]obsidi\225nu z plamen\249, kter\233 tam \158ij\237. "
gameforge.heavens_cave_keyquest._090_say_reward = "V Ohniv\233 zemi najdi sedm slz a 4 kusy obsidi\225nu a[ENTER]p\248ines mi je. "
gameforge.heavens_cave_keyquest._100_say = "Pot\248ebuje\154 dal\154\237 Krvav\253 k\225men, aby ses dostal[ENTER]p\248es str\225\158e? Tak posb\237rej dal\154\237ch sedm fosiln\237ch[ENTER]slz a \232ty\248i kusy obsidi\225nu v ohniv\233 zemi[ENTER]Doyyumhwan. "
gameforge.heavens_cave_keyquest._110_say = "Pot\248ebuje\154 dal\154\237 Krvav\253 k\225men? Koe-Pung nen\237 z[ENTER]nejbyst\248ej\154\237ch, ale m\236l bys rad\236ji chv\237li po\232kat,[ENTER]nebo si v\154imne, \158e nepat\248\237\154 k jeho \216\225du. "
gameforge.heavens_cave_keyquest._120_say = "P\225r hodin, \248ekl bych tak %s "
gameforge.heavens_cave_keyquest._130_say = "Hodinu a %s minut. "
gameforge.heavens_cave_keyquest._140_say = "\200ekej dal\154\237ch %s minut. "
gameforge.heavens_cave_keyquest._150_say_title = "Fosiln\237 slza "
gameforge.heavens_cave_keyquest._160_say = "Tady je jedna fosiln\237 slza Dra\232\237ho boha, kter\225[ENTER]spadla na zem. "
gameforge.heavens_cave_keyquest._170_1_select = "Vz\237t slzu "
gameforge.heavens_cave_keyquest._170_2_select = "Pokra\232ovat v hled\225n\237 "
gameforge.heavens_cave_keyquest._170_3_select = "Ned\236lat nic "
gameforge.heavens_cave_keyquest._180_say = "Z\237skal jsi Fosiln\237 slzu. "
gameforge.heavens_cave_keyquest._190_say_title = "Fosiln\237 slza "
gameforge.heavens_cave_keyquest._200_say = "Rozhodl jsi se hledat dal\154\237 slzy a na\154el jsi: %s "
gameforge.heavens_cave_keyquest._210_say = "Bohu\158el, p\248\237\154ery v t\233to oblasti jsou nyn\237 velmi[ENTER]pozorn\233! "
gameforge.heavens_cave_keyquest._220_say = "Jdi do ohniv\233 zem\236 Doyyumhwan a hledej fosiln\237[ENTER]slzy Baljit Elvedina, Dra\232\237ho boha. Tak\233 bys m\236l[ENTER]z\237skat Obsidi\225n zab\237jen\237m Plamen\249. "
gameforge.heavens_cave_keyquest._230_say = "Je t\248eba fosiln\237ch slz: %s "
