gameforge.heavens_cave_keyquest._250_notice = "Nasb\237ral jsi dostatek slz! "
gameforge.heavens_cave_keyquest._260_notice = "V tomto plameni jsi na\154el obsidi\225n. "
gameforge.heavens_cave_keyquest._270_notice = "Nasb\237ral jsi v\154echen pot\248ebn\253 obsidi\225n! "
gameforge.heavens_cave_keyquest._280_say = "Vra\157 se k Seon-Hae a dej mu fosiln\237 slzy a[ENTER]obsidi\225n. "
gameforge.heavens_cave_keyquest._290_say = "Seon-Hae je v: %s "
gameforge.heavens_cave_keyquest._300_say = "Baljit-Elvedinovy slzy! P\248evedu je zp\236t do[ENTER]tekut\233ho stavu a d\225m do obsidi\225nu. Jejich s\237la ti[ENTER]umo\158n\237 zavolat bohyni Bahar-Taraji! "
gameforge.heavens_cave_keyquest._310_say = "Jej\237 duch se st\225le toul\225 sv\236tem. Jej\237 hlas k tob\236[ENTER]bude promlouvat, pokud bude\154 m\237t u sebe slzy.[ENTER]Zkus j\237 hledat v \200erven\233m lese! "
gameforge.heavens_cave_keyquest._320_say = "Tady, vem si tuto v\225zu a zkus naj\237t hlas[ENTER]Bahar-Taraji. "
gameforge.heavens_cave_keyquest._330_say = "Hlas Bahar-Taraji hledej v \200erven\233m lese. I kdy\158[ENTER]mo\158n\225 nebude\154 vid\236t jej\237ho ducha, rozhodn\236 uc\237t\237\154[ENTER]jej\237 p\248\237tomnost. "
gameforge.heavens_cave_keyquest._335_say = "Tich\225 slova se vzn\225\154ej\237 ve v\236tru: Najdi si[ENTER]bezpe\232n\233 m\237sto.... Tady nem\249\158eme mluvit....[ENTER]Klikn\236te na svitek \250kolu pro rozmluvu s duchem. "
gameforge.heavens_cave_keyquest._340_say = "V d\225li zn\237 hlas zavra\158d\236n\233 bohyn\236 Bahar-Taraji[ENTER].... "
gameforge.heavens_cave_keyquest._350_say = "Slzy m\233ho bratra... truchlil pro mne tak dlouho a[ENTER]nyn\237 st\225le je\154t\236 nen\237 schopen potrestat[ENTER]Beran-Setaoua za jeho skutky. "
gameforge.heavens_cave_keyquest._360_say = "Nemohl se m\236\248it s jeho bratrem Beran-Setaouem,[ENTER]ni\232itelem, kter\233ho se v\154ichni boj\237. "
gameforge.heavens_cave_keyquest._370_say = "Ale ty... kdo jsi? Ty jsi jin\253! Neboj\237\154 se ho.[ENTER]A nav\237c, jak tak kouk\225m, hled\225\154 boj! "
gameforge.heavens_cave_keyquest._380_say = "%s! Vezmi si tyto kapky m\233 krve. Vytvo\248 Krvav\253[ENTER]k\225men a donu\157 Beran-Setapoua zaplatit za jeho[ENTER]h\248\237chy. Jeskyn\236 vyhnanstv\237 nen\237 odtud daleko. "
gameforge.heavens_cave_keyquest._390_say = "V d\225li zn\237 hlas zavra\158d\236n\233 bohyn\236 Bahar-Taraji[ENTER].... "
gameforge.heavens_cave_keyquest._400_say = "%s! Pamatuji si t\236! "
gameforge.heavens_cave_keyquest._410_say = "P\248inesl jsi mi slzy m\233ho bratra. Jako odm\236nu[ENTER]obdr\158\237\154 kapky m\233 krve, tak\158e m\249\158e\154 pokra\232ovat v[ENTER]boji. "
gameforge.heavens_cave_keyquest._420_say = "Vra\157 se k Seon-Hae s krv\237 Bahar-Taraji. "
gameforge.heavens_cave_keyquest._430_say = "Seon-Hae m\225 najednou zvlhl\233 o\232i a opatrn\236 si od[ENTER]tebe bere kapky krve... "
gameforge.heavens_cave_keyquest._440_say = "Krev skute\232n\233 bohyn\236! Honem, mus\237m z n\237 ud\236lat[ENTER]Krvav\253 k\225men ne\158 vyschne! "
gameforge.heavens_cave_keyquest._450_say = "Str\225\158n\253 Koe-Pung t\236 n\236ch\225 pou\158\237t port\225l, kter\253[ENTER]vede do Jeskyn\236 vyhnanstv\237, pokud m\225\154 Krvav\253[ENTER]k\225men. Bohu\158el, ten k\225men lze pou\158\237t jen jednou.[ENTER]Pokud jich bude\154 pot\248ebovat v\237ce, vra\157 se sem.[ENTER]Ale mohu vytvo\248it jen jeden k\225men za den, abychom[ENTER]nep\248ivolali hn\236v \216\225du. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae je schopen ti vyrobit pouze jeden kamen[ENTER]denn\236, aby to \216\225d nezjistil. "
gameforge.heavens_cave_keyquest._470_say = "Jdu p\248em\236nit krev Bahar-Taraji na Krvav\253 k\225men.[ENTER]A\157 ti slou\158\237 dob\248e. "
gameforge.heavens_cave_keyquest._480_say_reward = "Mohu ti vyrobit pouze jeden k\225men denn\236. Jinak by[ENTER]Koe-Pung mohl m\237t podez\248en\237. "
