gameforge.horse_guard._20_say = "Abys mohl za\232\237t s \250kolem na kon\236, pot\248ebuje\154[ENTER]ko\242skou medaili. Lze ji z\237skat v opi\232\237 jeskyni. "
gameforge.horse_guard._30_say = "Existuj\237 kon\236 pro t\248i \250rovn\236 jezdc\249: za\232\225te\232n\237ci,[ENTER]pokro\232il\237 a experti. Kdy\158 bude\154 hodn\236 cvi\232it a[ENTER]bude\154 se cht\237t dostat na dal\154\237 \250rove\242, bude\154[ENTER]muset proj\237t testem. "
gameforge.horse_guard._40_say = "Kon\236 pot\248ebuj\237 krmivo podle toho, jakou maj\237[ENTER]\250rove\242. Kon\236 pro za\232\225te\232n\237ky \158erou seno, kon\236 pro[ENTER]pokro\232il\233 mrkev a kon\236 pro experty \158erou jenom[ENTER]\232erven\253 \158en\154en. Kdy\158 jde o j\237dlo, jsou kon\236 velmi[ENTER]vyb\237rav\237. "
gameforge.horse_guard._50_say = "Stav kon\236 zobrazuje jednoduch\253 ukazatel: zelen\225[ENTER]znamen\225, \158e je zdrav\253, \158lut\225 znamen\225, \158e je[ENTER]hladov\253. \200erven\225 je nebezpe\232n\225, proto\158e znamen\225,[ENTER]\158e je tv\249j k\249\242 vyhladov\236l\253. Kon\236 mus\237\154 krmit,[ENTER]kdy\158 je ukazatel \158lut\253 nebo \232erven\253. Pokud k\249\242[ENTER]zem\248e, bude\154 m\237t probl\233my. "
gameforge.horse_guard._60_say = "Kdy\158 jezd\237\154 na koni, zvy\154uje se jeho vy\232erp\225n\237 a[ENTER]kles\225 jeho zdrav\237.[ENTER]Nem\249\158e\154 jezdit na koni, kter\253 nem\225 \158\225dn\233 zdrav\237.[ENTER]Proto ho mus\237\154 \232as od \232asu nechat odpo\232inout. "
gameforge.horse_guard._70_say = "Koluj\237 pov\236sti, \158e se mrtv\253 k\249\242 nech\225 znovu[ENTER]o\158ivit opi\232\237mi bylinami. Ale opice st\248e\158\237 tuto[ENTER]bylinu jako oko v hlav\236 a t\236\158ko se k n\237 dostane\154.[ENTER]Znamen\225 to, \158e kdy\158 t\236 opice zajmou, zaklej\237 t\236 a[ENTER]prom\236n\237 na opici. "
gameforge.horse_guard._80_say = "Schopnosti jezdce se mohou velmi li\154it. Pokud m\225\154[ENTER]Ko\242skou medaili, m\249\158e\154 zv\253\154it \250rove\242 tv\233ho kon\236. "
