gameforge.horse_upgrade2._390_say = "Kdy\158 m\225\154 Vojenskou knihu kon\237, m\249\158e\154 si kamkoliv[ENTER]p\248ivolat kon\236.[ENTER]Kdy\158 ji ztrat\237\154, mus\237\154 znovu zaplatit, abys ji[ENTER]dostal nazp\225tek.[ENTER]Tak\158e na ni d\225vej pozor.[ENTER]To jsou jenom z\225klady. Te\239 z\225le\158\237 na tob\236. "
gameforge.horse_upgrade2._400_say = "Abys obdr\158el Vojenskou knihu kon\237, pot\248ebuje\154[ENTER]Zbrojn\237 knihu kon\237. "
gameforge.horse_upgrade2._40_say = "\218rove\242 tv\233ho kon\236 je p\248\237li\154 n\237zk\225 na to, abys ho[ENTER]mohl zlep\154it. B\236\158 a pocvi\232 se je\154t\236 v jezdeck\233m[ENTER]um\236n\237. A\158 tv\249j k\249\242 dos\225hne \250rovn\236 20, m\249\158e\154[ENTER]p\248ij\237t znovu. "
gameforge.horse_upgrade2._410_say = "Nem\225\154 u sebe 1 000 000 Yang\249. "
gameforge.horse_upgrade2._420_say = "P\248ij\239 znovu, jestli chce\154 Vojenskou knihu kon\237. "
gameforge.horse_upgrade2._430_say = "Opravdu?[ENTER]Kdy\158 to te\239 vzd\225\154, mus\237\154 cel\253 \250kol absolvovat[ENTER]znovu. "
gameforge.horse_upgrade2._440_makequestbutton = "\200as vypr\154el! "
gameforge.horse_upgrade2._450_sayReward = "Nezabil jsi 300 lukost\248elc\249 d\233mon\249, tak\158e jsi[ENTER]zkou\154ku neobst\225l. "
