gameforge.horse_upgrade2._50_say = "Jestli si chce\154 zlep\154it kon\236, mus\237\154 obst\225t u[ENTER]zkou\154ky schopnost\237. Tak jako posledn\236, pot\248ebuje\154[ENTER]ko\242skou medaili, aby ses mohl z\250\232astnit testu.[ENTER]Dostane\154 ji v opi\232\237 jeskyni. Samoz\248ejm\236, \158e ti ji[ENTER]\158iv\233 opice nedaj\237 bez boje a jsou p\248i tom velmi[ENTER]n\225siln\233... "
gameforge.horse_upgrade2._60_say = "Nechci to opakovat je\154t\236 jednou.[ENTER]Kdy\158 chce\154 jezdit na koni, MUS\205\138 m\237t u sebe[ENTER]Zbrojn\237 knihu kon\237! "
gameforge.horse_upgrade2._70_say = "Jenom ti nejsiln\236j\154\237 ode m\236 dostanou Vojenskou[ENTER]knihu kon\237.[ENTER]B\236\158 do v\236\158e d\233mon\249 a zabij 300 lukost\248elc\249[ENTER]d\233mon\249. Kdy\158 se ti to povede, nikdo mi u\158[ENTER]nezabr\225n\237, abych ti nedal Vojenskou knihu kon\237.[ENTER]V\237m, \158e to je nen\237 lehk\253 \250kol.[ENTER]M\249\158e\154 se tam vydat se skupinou, ale TY mus\237\154 b\253t[ENTER]vedouc\237m skupiny! "
