gameforge.locale.forked_man_chat = "Z\250\232astnit se Bitvy kr\225lovstv\237 "
gameforge.locale.forked_man_say = "Spr\225vce bitev:[ENTER]Hal\243 hal\243! Bylo objeveno nov\233 \250zem\237![ENTER]Je mo\158n\233, \158e tvo\248\237 spojen\237 mezi v\154emi[ENTER]kr\225lovstv\237mi.[ENTER]Nestv\249rami se to tam jen hem\158\237, \248\237\154e pot\248ebuje[ENTER]tvoji pomoc![ENTER]M\249\158e\154 se tam vydat?[ENTER]Zahub v\154echny nep\248\225tele, aby v na\154em kr\225lovstv\237[ENTER]nastal znovu m\237r. "
gameforge.locale.forked_man_say_cant = "Hal\243 hal\243! Bylo objeveno nov\233 \250zem\237. Je mo\158n\233, \158e[ENTER]tvo\248\237 spojen\237 mezi v\154emi kr\225lovstv\237mi. Jakmile[ENTER]tam budou ukon\232eny pr\249zkumy, m\249\158e\154 tam vstoupit. "
gameforge.locale.forked_no_enter = "Nez\250\232astnit se "
gameforge.locale.forked_open_gate = "Dve\248e, kter\233 doposud byly zav\248en\233, se otev\248ely.[ENTER]Vzh\249ru do nov\233 zem\236! Zmocn\237me se j\237. V\154ichni[ENTER]budou p\248eneseni do Svat\233 zem\236. "
gameforge.locale.forked_rule = "Pravidla vstupu do Bitvy kr\225lovstv\237:[ENTER]1. Kdo zem\248e na tomto \250zem\237, bude teleportov\225n do[ENTER]vesnice, ale Spr\225vce bitev jej m\249\158e p\248en\233st zp\236t.[ENTER]2. Jakmile byly jednou otev\248eny dve\248e do Svat\233[ENTER]zem\236, nelze na toto ji\158 \250zem\237 vkro\232it.[ENTER]3. Kdo se chce dostat do Svat\233 zem\236, mus\237 naj\237t[ENTER]spr\225vn\253 kl\237\232. "
gameforge.locale.forked_rule_sungzi = "Pravidla Bitvy kr\225lovstv\237:[ENTER]1. Kr\225lovstv\237, kter\233 dos\225hne nejmen\154\237ho po\232tu[ENTER]bod\249 v boji proti jin\233mu kr\225lovstv\237, vypad\225v\225[ENTER]jako prvn\237.[ENTER]2. Budou se objevovat r\249zn\233 nestv\249ry. Kr\225lovstv\237,[ENTER]kter\233 jako prvn\237 zabije ur\232it\253 po\232et nestv\249r,[ENTER]vyhr\225v\225.[ENTER]3. Pokud posl\233ze bude zabit Dev\237tiocas, bitva[ENTER]kon\232\237.[ENTER]4. B\236hem Bitvy kr\225lovstv\237 se neuko\248is\157uj\237 \158\225dn\233[ENTER]p\248edm\236ty.[ENTER]5. Kdo ve Svat\233 zemi t\248ikr\225t zem\248e, vrac\237 se[ENTER]zp\225tky do vesnice a je z Bitvy kr\225lovstv\237[ENTER]vylou\232en. "
gameforge.locale.fortune_words_1_body = "Dnes se na tebe usm\237v\225 sama Fortuna! Dnes m\225\154[ENTER]obrovsk\233 \154t\236st\237! Harmonick\233 proudy Chi zp\249sob\237,[ENTER]\158e se ti dnes p\248ihod\237 n\236co dobr\233ho! "
gameforge.locale.fortune_words_1_title = "Obrovsk\233 \154t\236st\237! "
gameforge.locale.fortune_words_2_body = "To je dob\248e. Jak se zkr\225tka a dob\248e \248\237k\225, jak se[ENTER]do lesa vol\225, tak se z lesa oz\253v\225. Dnes m\225\154[ENTER]velk\233 \154t\236st\237! Dej si trochu n\225mahy a dostane\154[ENTER]v\237c ne\158 kdykoliv p\248edt\237m. "
gameforge.locale.fortune_words_2_title = "Velk\233 \154t\236st\237! "
gameforge.locale.fortune_words_3_body = "To nen\237 tak \154patn\233. Dnes m\225\154 trochu \154t\236st\237.[ENTER]No, znamen\225 to: je to trochu lep\154\237 ne\158 jindy.[ENTER]To je v po\248\225dku. "
gameforge.locale.fortune_words_3_title = "Trochu \154t\236st\237. "
gameforge.locale.fortune_words_4_body = "Ani dobr\233, ani \154patn\233! Dnes m\225\154 norm\225ln\237[ENTER]\154t\236st\237. Nic zvl\225\154tn\237ho. Aspo\242 to neznamen\225, \158e[ENTER]m\225\154 sm\249lu. "
gameforge.locale.fortune_words_4_title = "Norm\225ln\237 \154t\236st\237. "
gameforge.locale.fortune_words_5_body = "Dnes se na tebe \154t\236st\237 moc nesm\236je. A i kdy\158[ENTER]rozhod\237\154 s\237\157, stejn\236 ulov\237\154 jenom m\225lo ryb, ale[ENTER]nebude\154 trp\236t hladem. Dnes m\225\154 trochu sm\249ly![ENTER]Ale nen\237 nad to, b\253t p\248ipraven. Jestli chce\154,[ENTER]zhotov\237m ti talisman, kter\253 to nejhor\154\237 odvr\225t\237.[ENTER]Tak co, chce\154 ten talisman koupit? "
gameforge.locale.fortune_words_5_title = "Trochu sm\249ly. "
gameforge.locale.fortune_words_6_body = "Dneska je hrozn\253 den.[ENTER]Den, b\236hem kter\233ho se i na dob\248e obd\236lan\253ch[ENTER]pol\237ch sotva urod\237. Dnes m\225\154 sm\249lu![ENTER]Mus\237\154 se chr\225nit p\248ed \154patn\253mi v\236cmi.[ENTER]Jestli chce\154, zhotov\237m ti te\239 hned talisman, abys[ENTER]mohl odvr\225tit opravdovou \154kodu.[ENTER]Tak co, chce\154 koupit talisman? "
gameforge.locale.fortune_words_6_title = "Sm\249la. "
gameforge.locale.fortune_words_7_body = "Tohle je pro tebe nejhor\154\237 den. V\154ichni bohov\233 na[ENTER]nebi a na zemi se od tebe odvr\225tili. Nic se ti[ENTER]nepoda\248\237. Kdy\158 bude\154 cht\237t zap\225lit ohe\242, bude[ENTER]pr\154et. Kdy\158 bude\154 m\237t \158\237ze\242, bude \158hnout slunce.[ENTER]Bude\154 pracovat tvrd\236ji ne\158 v\154ichni ostatn\237, ale[ENTER]nic z toho nebude\154 m\237t. Obrovsk\225 sm\249la![ENTER]Bude\154 muset mnoh\233 sn\225\154et: Ve\154ker\233 \250trapy a sv\237zel[ENTER]se t\236 budou dr\158et. Bez talismanu bude pro tebe[ENTER]t\236\158k\233 zamezit \250trap\225m. Tak co, chce\154 si koupit[ENTER]talisman? "
gameforge.locale.fortune_words_7_title = "Obrovsk\225 sm\249la. "
