gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "Hehehee! V\154ichni maj\237 zem\248\237t. Hij\225\225\225!! "
gameforge.locale.monster_chat_1001_2 = "Kousek, kousek, kousek, kousek! "
gameforge.locale.monster_chat_1001_3 = "Nen\237 \250niku! "
gameforge.locale.monster_chat_1001_4 = "Zem\236 bude nas\225kl\225 tvou krv\237! Zem\248i! "
gameforge.locale.monster_chat_1001_5 = "Klidn\236 \158ebrej, ale nep\248inese ti to nic dobr\233ho! "
gameforge.locale.monster_chat_1001_6 = "Copak to tu m\225me za obli\232ej, znetvo\248en\253 strachem! Heh\233! "
gameforge.locale.monster_chat_1002_1 = "Smrt! Smrt v\154em lidem! "
gameforge.locale.monster_chat_1002_2 = "Mizern\225 prasata! "
gameforge.locale.monster_chat_1002_3 = "Lezou mi fakt na nervy. "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "Tady pote\232e krev, \232lov\237\232ku. "
gameforge.locale.monster_chat_1003_1 = "Smrt a zatracen\237! "
gameforge.locale.monster_chat_1003_2 = "O\154t\236p je hor\154\237 ne\158 me\232, co? "
gameforge.locale.monster_chat_1003_3 = "Hej, neut\237kejte! Tak poj\239te, poj\239te! "
gameforge.locale.monster_chat_1003_4 = "Sb\237haj\237 se mi sliny v puse, jenom kdy\158 se na tebe pod\237v\225m. "
gameforge.locale.monster_chat_1003_5 = "Ty m\236 provokuje\154. "
gameforge.locale.monster_chat_1003_6 = "Zem\248e\154! "
gameforge.locale.monster_chat_1004_1 = "Tv\225 du\154e bude moje, \232lov\237\232ku! "
gameforge.locale.monster_chat_1004_2 = "Mmmm, \232erstv\225 krev! "
gameforge.locale.monster_chat_1004_3 = "Dneska bude veselo! "
gameforge.locale.monster_chat_1004_4 = "Ne, je\154t\236 ne! Nesm\237\154 je\154t\236 um\248\237t. Chachaha! "
gameforge.locale.monster_chat_1004_5 = "Co? Co se to tam d\236je? T\248ese se ti \154\237len\236 ruka. "
gameforge.locale.monster_chat_1004_6 = "To je fakt odv\225\158n\233 j\237t k n\225m na n\225v\154t\236vu! Nic si z toho ned\236lej! "
gameforge.locale.monster_chat_1035_1 = "Ne\158 um\248u, pomst\237m se! "
gameforge.locale.monster_chat_1035_2 = "Bude\154 um\237rat a trp\236t velmi, velmi pomalu... "
gameforge.locale.monster_chat_1035_3 = "Bude mi pot\236\154en\237m nechat t\236 trp\236t. "
gameforge.locale.monster_chat_1035_4 = "Hahaha! T\236lo se ti sam\253m strachem t\248ese. Hahaha! "
gameforge.locale.monster_chat_1035_5 = "C\237t\237m tv\249j strach, mali\232k\253.... "
gameforge.locale.monster_chat_1035_6 = "Co to je? Vypad\225 to, \158e ka\158dou chv\237li spadne p\225r rukou na zem. To u\158 je fakt konec? "
gameforge.locale.monster_chat_1036_1 = "S k\253m p\249jde\154 do pekla? "
gameforge.locale.monster_chat_1036_2 = "Hajzlov\233! Vy na m\236 nezapomenete! "
gameforge.locale.monster_chat_1036_3 = "H\225\225hahahaha! "
gameforge.locale.monster_chat_1036_4 = "\142ebrej o vlastn\237 \158ivot, vykup ho vlastn\237 du\154\237! "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Vid\237\154 v\154echno rozmazan\236! Nem\249\158e\154 u\158 ani rozli\154ovat vlevo a vpravo. H\225\225hahahaha! "
gameforge.locale.monster_chat_1037_1 = "Pro\232 nebloum\225\154 na v\236ky v\236k\249 takhle kolem? "
gameforge.locale.monster_chat_1037_2 = "Copak copak? Nem\225\154 r\225d tmu? "
gameforge.locale.monster_chat_1037_3 = "V\237tej v pekle. H\225\225hahahaha! "
gameforge.locale.monster_chat_1037_4 = "Jist\236, jist\236. Jen si k\248i\232! "
gameforge.locale.monster_chat_1037_5 = "H\225\225hahahaha! Takhle m\236 nem\249\158e\154 zab\237t! "
gameforge.locale.monster_chat_1037_6 = "Jo, jo, to u\158 je lep\154\237! "
gameforge.locale.monster_chat_1038_1 = "Tohle je peklo. "
gameforge.locale.monster_chat_1038_2 = "V\237tej v pekle. "
gameforge.locale.monster_chat_1038_3 = "Um\237rej p\236kn\236 pomalu. "
gameforge.locale.monster_chat_1038_4 = "Nem\225 smysl m\236 napadat. Hahaha! "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "Nen\237 dobr\233 um\248\237t p\248\237li\154 rychle. Chceme si p\248edt\237m je\154t\236 trochu u\158\237t. "
gameforge.locale.monster_chat_1039_1 = "Do t\233 doby, ne\158 p\248ijde n\236kdo jin\253... "
gameforge.locale.monster_chat_1039_2 = "Mysl\237\154, \158e m\249\158e\154 uniknout? "
gameforge.locale.monster_chat_1039_3 = "V\154echno, co je tady, nah\225n\237 lidem strach... Hodn\236 moc strachu! "
gameforge.locale.monster_chat_1039_4 = "V\237tej na m\237st\236, kde najde\154 svou smrt! "
gameforge.locale.monster_chat_1039_5 = "Vid\237m ti v o\232\237ch paniku. "
gameforge.locale.monster_chat_1039_6 = "Hmmm, tak mlad\233 a tak bezmocn\233... "
gameforge.locale.monster_chat_1040_1 = "Vid\237me ka\158d\253 tv\249j pohyb. "
gameforge.locale.monster_chat_1040_2 = "Sp\236ch\225\154? Opravdu chce\154 zem\248\237t? "
gameforge.locale.monster_chat_1040_3 = "Smrt si ji\158 na\154la m\237sto kousek od tebe... "
gameforge.locale.monster_chat_1040_4 = "Sly\154\237\154, jak zvon\237 m\249j zvon? Je to posledn\237 v\236c, kterou usly\154\237\154! "
gameforge.locale.monster_chat_1040_5 = "Kdy\158 tahle r\225na nep\248estane krv\225cet, bude to p\236kn\236 nebezpe\232n\233. "
gameforge.locale.monster_chat_1040_6 = "M\249\158e\154 bojovat... nebo m\249\158e\154 nechat prost\236 Smrt, aby si t\236 vzala rovnou... "
gameforge.locale.monster_chat_1041_1 = "Pro\232 jsi zde, kdy\158 chce\154 \158\237t? "
gameforge.locale.monster_chat_1041_2 = "Hmmm, \232erstv\233 maso do ml\253nku.... "
gameforge.locale.monster_chat_1041_3 = "Bylo to tv\233 rozhodnut\237 vydat se sem, lidsk\253 \232erve! A nyn\237 si ponese\154 za to n\225sledky... "
gameforge.locale.monster_chat_1041_4 = "My zase vstaneme z mrtv\253ch, my nem\249\158eme zem\248\237t. "
gameforge.locale.monster_chat_1041_5 = "Nem\225 smysl n\225s napadat. H\225\225hahahaha! "
gameforge.locale.monster_chat_1041_6 = "Co t\236 v\237c zm\249\158e: Vy\232erp\225n\237 nebo smrt? "
gameforge.locale.monster_chat_1091_1 = "Dostal jsi se a\158 sem... a j\225 t\236 te\239 po\154lu za tvou Smrt\237... "
gameforge.locale.monster_chat_1091_2 = "Ob\236tuj svou du\154i a sta\242 se jedn\237m z n\225s! "
gameforge.locale.monster_chat_1091_3 = "Koukni se na sebe! Slab\253 a pomal\253.... "
gameforge.locale.monster_chat_1091_4 = "Tvoje t\236lo a tvoje du\154e pat\248\237 mn\236! H\225\225hahahaha! "
gameforge.locale.monster_chat_1091_5 = "U\158 jsi vy\232erpan\253? T\248esou se ti kolena! "
gameforge.locale.monster_chat_1091_6 = "Jak dlouho to je\154t\236 vydr\158\237\154? H\225\225hahahaha! "
gameforge.locale.monster_chat_1093_1 = "Kdo mohl tu\154it, \158e existuje je\154t\236 n\236co mnohem hor\154\237ho ne\158 smrt? "
gameforge.locale.monster_chat_1093_2 = "V\237tej! "
gameforge.locale.monster_chat_1093_3 = "Za svou troufalost zaplat\237\154. Zaplat\237\154 tvou krv\237 a tvou du\154\237! "
gameforge.locale.monster_chat_1093_4 = "Ob\232erstv\237m se tv\253m t\236lem a tvou du\154\237! "
gameforge.locale.monster_chat_1093_5 = "Jak dlouho mysl\237\154, \158e mi m\249\158e\154 odol\225vat? "
gameforge.locale.monster_chat_1093_6 = "Smrt se ti sm\236je za z\225dy. Hehehe "
gameforge.locale.monster_chat_11000_1 = "V\154ichni, kdo si d\236l\225te starosti o dal\154\237 v\253voj, naslouchejte! "
gameforge.locale.monster_chat_11000_10 = "Jestli chce\154 um\236t ovl\225dat moc p\248\237rody - obzvl\225\154t\236 blesk\249, doporu\232uji ti nauku o l\233\232en\237! "
gameforge.locale.monster_chat_11000_11 = "Jednotliv\237 v\225le\232n\237ci se odli\154uj\237 t\237m, jak\253m zp\249sobem vedou boje. Soust\248e\239 se na nep\248etr\158it\233 zocelov\225n\237 t\236la! "
gameforge.locale.monster_chat_11000_12 = "Magie je silnou str\225nkou Sur\249. Pracujte na va\154\237 inteligenci, rychlosti a siln\233m t\236le! "
gameforge.locale.monster_chat_11000_13 = "Vyu\158\237vej vlastnost\237 Ninj\249! Soust\248e\239 se na rychlost a t\236lesnou s\237lu! "
gameforge.locale.monster_chat_11000_14 = "\138amani vyu\158\237vaj\237 znovuobnoven\237, podporu a kouzla v boji na d\225lku. Na to je pot\248eba inteligence! "
gameforge.locale.monster_chat_11000_15 = "Nezapome\242, co ses nau\232il! "
gameforge.locale.monster_chat_11000_16 = "B\236\158 na v\253cvik, pokud chce\154 tr\233novat tv\233 schopnosti! "
gameforge.locale.monster_chat_11000_17 = "Schopnosti? M\249\158e\154 se vypracovat a\158 na \250rove\242 mistra, kter\225 se n\225hodn\236 nach\225z\237 mezi \250rovn\236mi 17 a 21! "
gameforge.locale.monster_chat_11000_18 = "Chce\154 se st\225t velmistrem? V tom p\248\237pad\236 pot\248ebuje\154 extra p\248\237ru\232ku o schopnostech! "
gameforge.locale.monster_chat_11000_19 = "P\248\237ru\232ka o schopnostech zmiz\237, jakmile ji do\232te\154! "
gameforge.locale.monster_chat_11000_2 = "V\154ichni v\225le\232n\237ci, co nedos\225hli \250rove\242 5, poslouchejte! "
gameforge.locale.monster_chat_11000_20 = "Chce\154 si p\248e\232\237st dal\154\237 knihu schopnost\237? Pak ale mus\237\154 po\232kat jeden den. "
gameforge.locale.monster_chat_11000_21 = "Vylep\154i inteligneci a zlep\154i schopnosti tv\233ho Sury! "
gameforge.locale.monster_chat_11000_22 = "Za\158ij v boji velkou moc, kterou opl\253vaj\237 Surov\233! "
gameforge.locale.monster_chat_11000_23 = "V\237\154, kde se nach\225z\237 chr\225m ezoterick\233 sekty? Le\158\237 uprost\248ed \250dol\237 Seungryong! "
gameforge.locale.monster_chat_11000_24 = "Byl znovu objeven vchod do pavou\232\237ho podzem\237! Nach\225z\237 se v pou\154ti Yongbi! "
gameforge.locale.monster_chat_11000_25 = "Dokon\232i \250kol a pou\158ij odm\236nu na vylep\154en\237! "
gameforge.locale.monster_chat_11000_26 = "Chytat ryby? To zn\237 dob\248e! Ty u\158 jsi p\248ece dostal u ryb\225\248e udici a n\225vnadu - nebo ne? "
gameforge.locale.monster_chat_11000_27 = "Chce\154 naj\237t n\236co siln\236j\154\237ho, co bys cht\236l honit? Vyhledej si port\225l! B\236\158 na m\237sto, na kter\233m se nal\233zaj\237 nestv\249ry kter\233 odpov\237daj\237 tv\233 \250rovni! "
gameforge.locale.monster_chat_11000_28 = "D\225vej si pozor na nep\248\225tele z jin\253ch zem\237. Nikdy nev\237\154, kdy ti vpadnou do zad! "
gameforge.locale.monster_chat_11000_29 = "Chce\154 obnovit svoje schopnosti? Tak b\236\158 ke sta\248ence! Postarej se o to, abys m\236l u sebe dostatek Yang\249. "
gameforge.locale.monster_chat_11000_3 = "Kdy\158 se chce\154 proslavit jako mocn\253 \250to\232n\237k, b\236\158 k u\232iteli boje t\236lo na t\236lo. "
gameforge.locale.monster_chat_11000_30 = "Usiluj o dokonalou \250rove\242 mistra. Pak bude\154 pat\248it k opravdov\253m hrdin\249m! "
gameforge.locale.monster_chat_11000_31 = "Hledej star\233 lidi na v\154ech kontinentech, jestli chce\154 vstoupit do jin\233ho m\236sta nebo bojov\233ho \250zem\237! "
gameforge.locale.monster_chat_11000_4 = "Zvol si v\253cvik v ment\225ln\237m boji, jestli se chce\154 st\225t odborn\237kem ve schopnostech v\225le\232n\237ka! "
gameforge.locale.monster_chat_11000_5 = "Pokud chce\154 pat\248it k Sur\249m, kte\248\237 ovl\225daj\237 magick\233 me\232e, zvol si v\253cvik v magick\253ch zbran\237ch! "
gameforge.locale.monster_chat_11000_6 = "P\248ihla\154 se na v\253cvik v \232ern\233 magii, jestli se chce\154 st\225t odborn\237kem v pou\158\237v\225n\237 nekal\253ch kouzel! "
gameforge.locale.monster_chat_11000_7 = "Ve v\253cviku v boji na d\225lku jsou akceptov\225ni Ninjov\233, kte\248\237 dos\225hli \250rovn\236 5! "
gameforge.locale.monster_chat_11000_8 = "Zvol si v\253cvik v boji zbl\237zka, jestli se chce\154 st\225t Ninjou, kter\253 p\249sob\237 skryt\236! "
gameforge.locale.monster_chat_11000_9 = "Seznam se s naukou o dra\232\237 moci, pokud chce\154 jako v\225le\232n\237k dra\232\237ho boha ovl\225dat v\154echny bitvy! "
gameforge.locale.monster_chat_11002_1 = "V\154ichni, kdo si d\236l\225te starosti o va\154e zdrav\237, naslouchejte! "
gameforge.locale.monster_chat_11002_10 = "Doporu\232uji nauku o l\233\232en\237, pokud chce\154 um\236t ovl\225dat moc p\248\237rody a obzvl\225\154\157 blesk\249! "
gameforge.locale.monster_chat_11002_11 = "Jednotliv\237 v\225le\232n\237ci se odli\154uj\237 t\237m, jak\253m zp\249sobem vedou boje. Soust\248e\239 se se na nep\248etr\158it\233 tr\233nov\225n\237 t\236la! "
gameforge.locale.monster_chat_11002_12 = "Nejsiln\236j\154\237 str\225nkou Sur\249 je magie. Pracuj bez p\248est\225n\237 na sv\233 inteligenci, rychlosti a t\236lesn\233 s\237le! "
gameforge.locale.monster_chat_11002_13 = "Zdokonal typick\233 schopnosti Ninj\249 na vy\154\154\237 \250rove\242! Soust\248e\239 se na rychlost a t\236lesnou s\237lu! "
gameforge.locale.monster_chat_11002_14 = "\138amani vyu\158\237vaj\237 l\233\232en\237, podporu a kouzla boje na d\225lku. Na to je pot\248eba inteligence! "
gameforge.locale.monster_chat_11002_15 = "Nezapome\242, co ses nau\232il! "
gameforge.locale.monster_chat_11002_16 = "Pokud chce\154 tr\233novat svoje schopnosti, sta\242 se u\232edn\237kem! "
gameforge.locale.monster_chat_11002_17 = "Schopnosti? M\249\158e\154 se vypracovat a\158 na \250rove\242 mistra, kter\225 se n\225hodn\236 nach\225z\237 mezi \250rovn\236mi 17 a 21! "
gameforge.locale.monster_chat_11002_18 = "Chce\154 se st\225t velmistrem? V tom p\248\237pad\236 pot\248ebuje\154 extra p\248\237ru\232ku o schopnostech! "
gameforge.locale.monster_chat_11002_19 = "P\248\237ru\232ka o schopnostech zmiz\237, jakmile ji do\232te\154! "
gameforge.locale.monster_chat_11002_2 = "V\154ichni v\225le\232n\237ci, co nedos\225hli \250rove\242 5, poslouchejte! "
gameforge.locale.monster_chat_11002_20 = "Chce\154 si p\248e\232\237st dal\154\237 knihu schopnost\237? Pak ale mus\237\154 po\232kat jeden den. "
gameforge.locale.monster_chat_11002_21 = "Vylep\154i inteligneci a zlep\154i schopnosti tv\233ho Sury! "
gameforge.locale.monster_chat_11002_22 = "Za\158ij v boji velkou moc, kterou opl\253vaj\237 Surov\233! "
