gameforge.locale.monster_chat_11004_9 = "Seznam se s naukou o dra\232\237 moci, pokud chce\154 jako v\225le\232n\237k dra\232\237ho boha ovl\225dat v\154echny bitvy! "
gameforge.locale.monster_chat_1105_1 = "Zamrzl\253 stav je dobr\253. "
gameforge.locale.monster_chat_1105_2 = "Hora Sohan je nepochybn\236 nejlep\154\237. "
gameforge.locale.monster_chat_1105_3 = "Jak\233 kr\225sn\233 po\232as\237. "
gameforge.locale.monster_chat_1105_4 = "Ud\236l\225m z tebe m\233ho dvojn\237ka. "
gameforge.locale.monster_chat_1105_5 = "M\249\158e\154 \158\237t v\236\232n\236 - aspo\242 dokud neroztaje ten led... "
gameforge.locale.monster_chat_1105_6 = "Jak dlouho to bude trvat, ne\158 z tebe bude kus ledu? "
gameforge.locale.monster_chat_1106_1 = "Lid\233... tady? "
gameforge.locale.monster_chat_1106_2 = "Jsem unaven\253... ale na tebe budu sta\232it... "
gameforge.locale.monster_chat_1106_3 = "N\236kdo je na m\233m kopci?  "
gameforge.locale.monster_chat_1106_4 = "Ty sem nepat\248\237\154! "
gameforge.locale.monster_chat_1106_5 = "M\236l bys rad\236ji zmizet! "
gameforge.locale.monster_chat_1106_6 = "Cizinec... a co tak s\225m? "
gameforge.locale.monster_chat_1191_1 = "U\158 je to dlouho, co jsem vid\236la zku\154en\233ho v\225le\232n\237ka. "
gameforge.locale.monster_chat_1191_2 = "Nen\237 co d\236lat... jen \232ekat a le\154tit zbran\236... "
gameforge.locale.monster_chat_1191_3 = "M\225m na nich pracovat? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "N\236co chyb\237. Nejsem spokojen\225. "
gameforge.locale.monster_chat_1191_6 = "Ukon\232\237m tu bolest, kterou bys jinak c\237til na v\236ky! "
gameforge.locale.monster_chat_1301_1 = "M\225\154 dlouh\253 krk! "
gameforge.locale.monster_chat_1301_2 = "Tvoje bled\225 k\249\158e bude brzy je\154t\236 bled\154\237! "
gameforge.locale.monster_chat_1301_3 = "Ty mne chce\154 vyzvat? No pros\237m... "
gameforge.locale.monster_chat_1301_4 = "Ty\180s m\236 napadl! Pvou! Nen\237 ti dovoleno p\248e\158\237t! "
gameforge.locale.monster_chat_1301_5 = "Slab\253, slab\253 \232lov\236k! "
gameforge.locale.monster_chat_1301_6 = "Tak se pod\237v\225me, co snese\154! "
gameforge.locale.monster_chat_1302_1 = "Chce\154 zmizet? Ani na to nemysli! "
gameforge.locale.monster_chat_1302_2 = "Spr\225vn\236. Jen se p\248ibli\158. Pvou! "
gameforge.locale.monster_chat_1302_3 = "Me\232 v m\233 ruce se jenom t\248ese. Pvou! "
gameforge.locale.monster_chat_1302_4 = "Tenhle \250tok nem\249\158e\154 p\248e\158\237t! "
gameforge.locale.monster_chat_1302_5 = "Tum\225\154, m\249j me\232! "
gameforge.locale.monster_chat_1302_6 = "Bol\237 to, \158e jo? Hahah\225! "
gameforge.locale.monster_chat_1303_1 = "Dokonce ne\154\157astnou n\225hodou po\154lapan\225 tr\225va m\249\158e zab\237jet. "
gameforge.locale.monster_chat_1303_2 = "D\225vej si na tu tr\225vu pozor. "
gameforge.locale.monster_chat_1303_3 = "Spr\225vn\236. Tak, p\236kn\236 ke mn\236. Hahah\225 "
gameforge.locale.monster_chat_1303_4 = "Ni\232emo! P\248i\154el jsi ke mn\236 a j\225 t\236 te\239 zabiju! "
gameforge.locale.monster_chat_1303_5 = "Zem\248i! Zem\248i! "
gameforge.locale.monster_chat_1303_6 = "Lituje\154 toho, \158e\180s p\248i\154el? "
gameforge.locale.monster_chat_1305_1 = "Kdo m\236 p\248em\249\158e? "
gameforge.locale.monster_chat_1305_2 = "Ty? Chce\154 si to se mnou rozdat? "
gameforge.locale.monster_chat_1305_3 = "Tak pojd', jestli chce\154! "
gameforge.locale.monster_chat_1305_4 = "Pojd', rozd\225me si to! Nechod' pry\232! "
gameforge.locale.monster_chat_1305_5 = "Tak co, jak\253 m\225m me\232? "
gameforge.locale.monster_chat_1305_6 = "Boj\237\154 se? Hahah\225 "
gameforge.locale.monster_chat_1901_1 = "Mysl\237m \158e dnes zem\248e\154 m\253ma rukama! "
gameforge.locale.monster_chat_1901_2 = "Hmm, ty se mi l\237b\237\154. "
gameforge.locale.monster_chat_1901_3 = "Tak co? Moje mil\233 rozpt\253len\237... "
gameforge.locale.monster_chat_1901_4 = "Hej! To ti nepom\249\158e, kdy\158 ute\232e\154 jako zbab\236lec! "
gameforge.locale.monster_chat_1901_5 = "U\158 jsem ti u\232aroval? Hm? "
gameforge.locale.monster_chat_1901_6 = "Ty u\158 si nechce\154 ani tro\154ku zak\248i\232et? Hahah\225! "
gameforge.locale.monster_chat_20001_1 = "Vypad\225\154 nerv\243zn\236... neboj, nic tu nevybouchne. "
gameforge.locale.monster_chat_20001_2 = "\200as od \232asu bych cht\236l j\237t jen tak na proch\225zku. "
gameforge.locale.monster_chat_20001_3 = "Je tu takov\225 nuda. Ani moje vnou\232ata m\236 u\158 nenav\154t\236vuj\237. "
gameforge.locale.monster_chat_20001_4 = "Kdy\158 \232lov\236k zest\225rne, pot\248ebuje spole\232nost. "
gameforge.locale.monster_chat_20001_5 = "Moje nejlep\154\237 doby u\158 pominuly. "
gameforge.locale.monster_chat_20002_1 = "To slunce tak p\225l\237. "
gameforge.locale.monster_chat_20002_2 = "N\225dhern\233 po\232as\237 na to, usu\154it mokr\233 pl\225tno, \158e? "
gameforge.locale.monster_chat_20002_3 = "Kdepak je ten l\237n\253 budi\158kni\232emu, co si \248\237k\225 man\158el? "
gameforge.locale.monster_chat_20002_4 = "\216\237k\225 si otec a ani p\248ed sv\253mi d\236tmi se za svoje vrtochy nestyd\237! "
gameforge.locale.monster_chat_20002_5 = "Knihy jsou knihy. Nechod\237 do pr\225ce a nic nevyd\236l\225. Po\248\225d jenom \232te! "
gameforge.locale.monster_chat_20003_1 = "J\233\233, \157u\157u\157u, miminko. P\236kn\236 ses vyspinkal? "
gameforge.locale.monster_chat_20003_2 = "Sm\236je\154 se jako and\237lek. "
gameforge.locale.monster_chat_20003_3 = "Tvoje maminka m\225 radost, \158e jsi tak zdravou\232k\253. "
gameforge.locale.monster_chat_20003_4 = "Nikdo si t\236 nev\154\237m\225? M\225\154 hlad? "
gameforge.locale.monster_chat_20003_5 = "Hodn\233 d\236\157\225tko, na\154e d\236\157\225tko. Spi d\236\157\225tko, spi. "
gameforge.locale.monster_chat_20004_1 = "Prost\236 jenom nov\253 den... "
gameforge.locale.monster_chat_20004_2 = "Hmm, kde asi dostanu dneska naj\237st? "
gameforge.locale.monster_chat_20004_3 = "Tihle chl\225pci s me\232ema jsou st\225le tak nudn\237... "
gameforge.locale.monster_chat_20004_4 = "Uvid\237me... mo\158n\225 n\236co vy\158ebr\225m u Octavia. "
gameforge.locale.monster_chat_20004_5 = "Jo, a mimochodem: u\158 pr\253 nezu\248\237 \158\225dn\225 v\225lka... "
gameforge.locale.monster_chat_20005_1 = "Du\154e mistra hrn\232\237\248e prot\233k\225 skrz kone\232ky jeho prst\249. "
gameforge.locale.monster_chat_20005_2 = "Od t\233 doby, co je zem\236 zavalen\225 chaosem, se v\154ude poflakuj\237 bojovn\237ci. "
gameforge.locale.monster_chat_20005_3 = "Ka\158d\253 chce po\248\225d bojovat. "
gameforge.locale.monster_chat_20005_4 = "Modl\237m se za klidn\253 a pokojn\253 sv\236t. "
gameforge.locale.monster_chat_20005_5 = "Hej, ty tam! Ud\236lej si aspo\242 na chvilku \232as vypnout a zamyslet se. "
gameforge.locale.monster_chat_20006_1 = "Panebo\158e, co te\239 budu d\236lat? "
gameforge.locale.monster_chat_20006_2 = "Po m\233m bratru nen\237 ani vidu ani slechu a p\248itom \248\237kal, \158e p\248ijde. "
gameforge.locale.monster_chat_20006_3 = "A te\239 tady vid\237m jenom tyhle bojovn\237ky s t\236mi me\232i. "
gameforge.locale.monster_chat_20006_4 = "St\253sk\225 se mi po m\233m bratrovi. "
gameforge.locale.monster_chat_20006_5 = "Vid\236l n\236kdo m\233ho bratra? "
gameforge.locale.monster_chat_20007_1 = "Hmmm, \232erstv\233 maso! "
gameforge.locale.monster_chat_20007_2 = "To je dob\248e, \158e lidi zase jed\237 v\237c masa. "
gameforge.locale.monster_chat_20007_3 = "K\154efty rostou, ale masa je m\225lo. "
gameforge.locale.monster_chat_20007_4 = "Kdy kone\232n\236 doraz\237 to maso, co jsme objednali? "
gameforge.locale.monster_chat_20007_5 = "Kdy\158 nedojde zav\232as, mus\237me j\237t na lov! "
gameforge.locale.monster_chat_20008_1 = "Douf\225m, \158e p\248i takov\233m po\232as\237 se n\225m z\225kazn\237ci jen pohrnou. "
gameforge.locale.monster_chat_20008_2 = "Ten l\237n\253 budi\158kni\232emu u\158 ur\232it\236 brzo p\248ijde a bude cht\237t n\236co k j\237dlu. "
gameforge.locale.monster_chat_20008_3 = "Panebo\158e, copak to je za ubo\158\225ka! "
gameforge.locale.monster_chat_20008_4 = "D\248\237v to byl jeden hodn\236 dobr\253 v\225le\232n\237k. "
gameforge.locale.monster_chat_20008_5 = "Pt\225m se s\225m sebe, pro\232 u\158 nebojuje? "
gameforge.locale.monster_chat_20009_1 = "Ti mlad\237 chlap\237ci jsou dost \232il\237 a jenom z\225\248\237 vitalitou! "
gameforge.locale.monster_chat_20009_2 = "Bojovn\237ci vypadaj\237 mnohem l\237p, kdy\158 nos\237 zbran\236. "
gameforge.locale.monster_chat_20009_3 = "Tenhle vra\158edn\253 duch zaplav\237 ka\158d\233ho. "
gameforge.locale.monster_chat_20009_4 = "Ovl\225dej sv\233 srdce, spo\232i\242 ve vlastn\237ch my\154lenk\225ch a uklidni svou du\154i. "
gameforge.locale.monster_chat_20009_5 = "Neexistuje \158\225dn\253 z\225zra\232n\253 recept, ale je n\236kolik postup\249, kter\233 lze n\225sledovat. "
gameforge.locale.monster_chat_20010_1 = "P\248inesl jsem jeden dobr\253 p\248edm\236t! "
gameforge.locale.monster_chat_20010_2 = "Zbo\158\237 ze vzd\225len\253ch zem\237! P\248ekr\225sn\233, vyj\237me\232n\233 kousky! "
gameforge.locale.monster_chat_20010_3 = "V\154ichni sem, pojd'te v\154ichni sem! "
gameforge.locale.monster_chat_20010_4 = "Kupujte, kupujte dokud je je\154t\236 n\236co k m\225n\237. To nese\158enete v\154ude a rozhodn\236 ne ka\158d\253 den! "
gameforge.locale.monster_chat_20010_5 = "Mimochodem, pro\232 je tady tolik zlod\236j\249? "
gameforge.locale.monster_chat_20011_1 = "V dne\154n\237 dob\236 je tady dost sucho. "
gameforge.locale.monster_chat_20011_2 = "\218roda obil\237 u\158 nen\237 tak vydatn\225 jako d\248\237v. "
gameforge.locale.monster_chat_20011_3 = "Co zpomaluje r\249st na pol\237ch? "
gameforge.locale.monster_chat_20011_4 = "To obil\237 chutn\225 jako mo\248sk\225 voda. "
gameforge.locale.monster_chat_20011_5 = "To je \154patn\233 znamen\237. Zem\236d\236lstv\237 je z\225klad v\154eho. "
gameforge.locale.monster_chat_20012_1 = "R\253\158ov\233 buchty! Vynikaj\237c\237 r\253\158ov\233 buchty! "
gameforge.locale.monster_chat_20012_2 = "Prod\225v\225m sladk\233 r\253\158ov\233 buchty! "
gameforge.locale.monster_chat_20012_3 = "Ach jo! Obchody v\225znou. "
gameforge.locale.monster_chat_20012_4 = "Mo\158n\225 bych to m\236la zkusit v jin\233m m\236st\236. "
gameforge.locale.monster_chat_20012_5 = "Ale tam je mnoho divok\253ch pred\225tor\249... "
gameforge.locale.monster_chat_20013_1 = "Nejlep\154\237 je, kdy\158 \232lov\236k str\225v\237 takov\253 den v \232lunu. "
gameforge.locale.monster_chat_20013_2 = "Perfektn\237 po\232as\237 na chyt\225n\237 ryb. "
gameforge.locale.monster_chat_20013_3 = "A te\239 dal\154\237 uzl\237k... Tak! \142\225dn\225 ryba z tohohle h\225\232ku neute\232e! "
gameforge.locale.monster_chat_20013_4 = "Tenhle zatracen\253 medv\236d mi zni\232il udici. "
gameforge.locale.monster_chat_20013_5 = "M\236l bych znovu zkouknout sv\233 s\237t\236. "
gameforge.locale.monster_chat_20014_1 = "H\249\249! "
gameforge.locale.monster_chat_20014_2 = "Ned\236lej si kv\249li mn\236 \158\225dn\233 starosti. J\225 jsem prost\236 takov\253. "
gameforge.locale.monster_chat_20014_3 = "\193\225\225\225\225\225! "
gameforge.locale.monster_chat_20014_4 = "Co mus\237m ud\236lat, aby... Panebo\158e, co jsem to pr\225v\236 \248ekla? "
gameforge.locale.monster_chat_20014_5 = "V\249bec neum\237m b\253t state\232n\253. Hu! "
gameforge.locale.monster_chat_20015_1 = "Tahle sekera mi u\158 20 let prokazuje v\236rnou slu\158bu. "
gameforge.locale.monster_chat_20015_2 = "Je je\154t\236 po\248\225d ostr\225, ale u\158 ne tak dobr\225 jako d\248\237v. "
gameforge.locale.monster_chat_20015_3 = "Cht\236l bych ji pos\237lit t\237m, \158e ji budu pou\158\237vat a s n\237 sekat. "
gameforge.locale.monster_chat_20015_4 = "Ale na to pot\248ebuju n\236kolik kamen\249, kter\233 obsahuj\237 miner\225ly. "
gameforge.locale.monster_chat_20015_5 = "Ale jak se k nim dostanu? "
gameforge.locale.monster_chat_20016_1 = "Z\225kazn\237ci se ke mn\236 jenom hrnou. "
gameforge.locale.monster_chat_20016_2 = "Douf\225m, \158e v\154e dokon\232\237m v\232as. "
gameforge.locale.monster_chat_20016_3 = "Vypad\225 zachmu\248en\236. "
gameforge.locale.monster_chat_20016_4 = "Takhle m\225 zn\237t kladivo! "
gameforge.locale.monster_chat_20016_5 = "Tady nen\237 ticho. "
gameforge.locale.monster_chat_20017_1 = "Nem\225m na hudbu n\225ladu. "
gameforge.locale.monster_chat_20017_2 = "M\249j hudebn\237 n\225stroj je v hrozn\233m stavu. "
gameforge.locale.monster_chat_20017_3 = "Mo\158n\225 bych si m\236l po\248\237dit nov\253 n\225stroj? "
gameforge.locale.monster_chat_20017_4 = "M\249j n\225stroj je star\253 a hodn\236 pou\158it\253... m\225m r\225d star\233 v\236ci! "
gameforge.locale.monster_chat_20017_5 = "Douf\225m, \158e najdu n\236co, \232\237m bych mohl ty struny opravit. "
gameforge.locale.monster_chat_20018_1 = "M\225m toho tolik na pr\225ci! "
gameforge.locale.monster_chat_20018_2 = "Ka\158d\253 den p\248ijde tolik zran\236n\253ch. "
gameforge.locale.monster_chat_20018_3 = "Nem\225m v\249bec \232as si vyj\237t nebo se s n\236k\253m setkat! "
gameforge.locale.monster_chat_20018_4 = "A my nem\225me l\233ky nazbyt. "
gameforge.locale.monster_chat_20018_5 = "P\248eju si, aby n\236kdo sehnal p\225r p\248\237sad do l\233k\249. "
gameforge.locale.monster_chat_20019_1 = "30 let se potuluju s m\253m lukem po hor\225ch. "
gameforge.locale.monster_chat_20019_2 = "U\158ivil jsem t\237m \158enu a zaplatil vzd\236l\225n\237 m\253ch t\248ech d\236t\237. "
gameforge.locale.monster_chat_20019_3 = "Bylo to t\236\158k\233, ale st\225lo to za to. "
gameforge.locale.monster_chat_20019_4 = "Ale te\239 se p\248etrhla t\236tiva luku. Znamen\225 to, \158e pat\248\237m do star\233ho \158eleza? "
gameforge.locale.monster_chat_20019_5 = "Jestli se mi nepoda\248\237 ten luk spravit, tak si budu muset koupit nov\253. Ale na to nem\225m pen\237ze. "
gameforge.locale.monster_chat_20020_1 = "Hej! Co \232um\237\154? "
gameforge.locale.monster_chat_20020_2 = "V\249bec se sem nep\248ibli\158uj! "
gameforge.locale.monster_chat_20020_3 = "Ach, jak dlouho se je\154t\236 mus\237m takhle schov\225vat? "
gameforge.locale.monster_chat_20020_4 = "Zem\248u s\225m, zapomenut\253 n\236kde v kout\236? "
gameforge.locale.monster_chat_20020_5 = "\193\225\225, douf\225m, \158e mi n\236kdo pom\249\158e! "
gameforge.locale.monster_chat_20021_1 = "Tenhle den skon\232\237 tak jako ka\158d\253 jin\253. "
gameforge.locale.monster_chat_20021_2 = "Co te\239 m\249\158u asi tak ud\236lat? Hmm? "
gameforge.locale.monster_chat_20021_3 = "Nikdy bych nepomyslela, \158e takhle skon\232\237m. "
gameforge.locale.monster_chat_20021_4 = "Po\248\225d nemohu uv\236\248it tomu, \158e on tu ji\158 nen\237. "
gameforge.locale.monster_chat_20021_5 = "To si nezaslou\158il. "
gameforge.locale.monster_chat_20022_1 = "A zase nov\253 p\236kn\253 den. "
gameforge.locale.monster_chat_20022_2 = "Man\158el Ariyoung zmizel. "
gameforge.locale.monster_chat_20022_3 = "Cht\236l jsem pomoct, ale tahle zatvrzelost... "
gameforge.locale.monster_chat_20022_4 = "Kdyby si m\236 vzala, mohla uniknout jej\237mu dosavadn\237mu nudn\233mu \158ivotu. "
gameforge.locale.monster_chat_20022_5 = "Mo\158n\225 jsem j\237 m\236l d\225t v\237c najevo, co k n\237 c\237t\237m. "
gameforge.locale.monster_chat_20023_1 = "Proboha, ne! Co budeme d\236lat, kdy\158 na to p\248ijde moje star\225? "
gameforge.locale.monster_chat_20023_2 = "Kdybych tak mohl \158\237t jenom ze \232ten\237 kn\237\158ek! "
gameforge.locale.monster_chat_20023_3 = "Knihy jsou tak tajupln\233... "
gameforge.locale.monster_chat_20023_4 = "Nem\249\158u takhle \158\237t napo\248\225d, ale... "
gameforge.locale.monster_chat_20023_5 = "Douf\225m, \158e pro moji \158enu m\249\158u n\236co ud\236lat, ale... "
gameforge.locale.monster_chat_20024_1 = "Tak d\236lej, d\236lej! Trochu v\237c usil\237! "
gameforge.locale.monster_chat_20024_2 = "Chlape, co to tam prov\225d\237\154? Nejde to rychlejc? "
gameforge.locale.monster_chat_20024_3 = "P\248edstav si v\225le\232n\237ka tas\237c\237ho me\232 a ud\236lej to tak\233! "
gameforge.locale.monster_chat_20024_4 = "Kde je zas ten bl\225zen? "
gameforge.locale.monster_chat_20024_5 = "Chce\154 se st\225t mu\158em? "
gameforge.locale.monster_chat_2091_1 = "St\248ih, st\248ih.... vlasy, hrdla... "
gameforge.locale.monster_chat_2091_2 = "N\236co pro tebe m\225m: v\236\232n\253 sp\225nek! "
gameforge.locale.monster_chat_2091_3 = "Zhluboka se nadechni. A neboj, je to jen jed! "
gameforge.locale.monster_chat_2091_4 = "Nech\225m si jen tvou tv\225\248! To bude p\236kn\225 dekorace! "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "V\154echno pevn\236 omot\225m hedv\225b\237m a pak to chutn\225 l\233pe. "
gameforge.locale.monster_chat_2092_1 = "U\158 n\225s mnoho nezb\253v\225. "
gameforge.locale.monster_chat_2092_2 = "Nejsou to \158\225dn\233 dvounoh\233 p\248\237\154ery, kter\253m by bylo souzeno zde vl\225dnout. "
gameforge.locale.monster_chat_2092_3 = "\193\225! Vypad\225 to, \158e se n\236kdo chytil do pavou\232\237 s\237t\236. "
gameforge.locale.monster_chat_2092_4 = "Jsem kli\239as. Jen nem\225m r\225d, kdy\158 jsem vyru\154ov\225n. "
gameforge.locale.monster_chat_2092_5 = "To je v\154e, co dok\225\158e\154? "
gameforge.locale.monster_chat_2092_6 = "Nikdo se se mnou nem\249\158e m\236\248it! "
gameforge.locale.monster_chat_2104_1 = "Pro\232 jsou lid\233 zevnit\248 mok\248\237? Tak mi jen zrezav\237 me\232! "
gameforge.locale.monster_chat_2104_2 = "U\158 ti vyschl jed v \158ihadle? "
gameforge.locale.monster_chat_2104_3 = "Co si takhle zabojovat? "
gameforge.locale.monster_chat_2104_4 = "U\158 jsi t\237m vedrem vy\232erpan\253? "
gameforge.locale.monster_chat_2104_5 = "R\225d nech\225v\225m lidi v pou\154ti. "
gameforge.locale.monster_chat_2104_6 = "Chud\225ku, jen tak zahraban\253 v pou\154ti. "
gameforge.locale.monster_chat_2105_1 = "Prozrad\237m ti tajemstv\237. Nen\225vid\237m \154p\237nu. "
gameforge.locale.monster_chat_2105_2 = "To je horko, co? "
gameforge.locale.monster_chat_2105_3 = "Tohle m\237sto je nebezpe\232n\233. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "Tref\237m t\236 p\248esn\236 mezi o\232ima. "
gameforge.locale.monster_chat_2106_1 = "Ssss... c\237t\237m n\236co k ssssn\236dku. "
gameforge.locale.monster_chat_2106_2 = "Vid\237m ko\248isssst! "
gameforge.locale.monster_chat_2106_3 = "Sssskv\236l\233! L\237b\237 sssse mi to! "
gameforge.locale.monster_chat_2106_4 = "Tenhle je p\236kn\236 tlusssst\253. Ten je m\249j! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Miluju v\249ni \232erssstv\233 krve. "
gameforge.locale.monster_chat_2107_1 = "Sssss! Nen\237 co zab\237t! "
gameforge.locale.monster_chat_2107_2 = "Ssss! Tihle jsou tlussst\237! "
gameforge.locale.monster_chat_2107_3 = "To sssse bude v\249dci l\237bit... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "Ssss! Do toho! "
gameforge.locale.monster_chat_2107_6 = "Ten \154\154\154\154\154\237p je jen pro tebe! "
gameforge.locale.monster_chat_2108_1 = "Kdy\158 ho na\232ap\225m, tak... "
gameforge.locale.monster_chat_2108_2 = "Pro\232 se tak rozhl\237\158\237\154? "
gameforge.locale.monster_chat_2108_3 = "Ty si mysl\237\154, \158e se nade mnou d\225 lehce vyhr\225t? Co? "
gameforge.locale.monster_chat_2108_4 = "Takov\225 sm\249la, potkat tady v pou\154ti zrovna m\236! "
gameforge.locale.monster_chat_2108_5 = "Hmm, to je pocit! Vychutn\225m si ho na v\236ky v\236k\249! "
gameforge.locale.monster_chat_2108_6 = "D\236kuji p\236kn\236! "
gameforge.locale.monster_chat_2191_1 = "C\237t\237m lidi. Jak\225 to lib\225 v\249n\236! "
gameforge.locale.monster_chat_2191_2 = "Dob\248e. Pojd'te v\154ichni ke mn\236, pojd'te, pojd'te... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "To m\236 t\236\154\237, n\236koho potkat tady v pou\154ti! "
gameforge.locale.monster_chat_2191_5 = "Okam\158it\236 z\249stat st\225t! "
gameforge.locale.monster_chat_2191_6 = "Vyrvu ti maso kousek po kousku... "
gameforge.locale.monster_chat_2202_1 = "Poj\239 bl\237\158, a\157 ti mohu sp\225lit k\249\158i. "
gameforge.locale.monster_chat_2202_2 = "V\237\154, jak\253 druh bolesti m\249\158e zp\249sobit takov\253 \158\225r? "
gameforge.locale.monster_chat_2202_3 = "Mo\158n\225 se m\249\158u ochladit jejich krv\237. "
gameforge.locale.monster_chat_2202_4 = "Tvoje krev.... nech m\236 ochutnat! "
gameforge.locale.monster_chat_2202_5 = "Nen\237 d\249vod za\232\237nat boj. "
gameforge.locale.monster_chat_2202_6 = "Sta\242 se to co j\225! Jen plameny a \158\225r. "
gameforge.locale.monster_chat_2204_1 = "Dokud jsem tady j\225, nikdo se nedostane dovnit\248! "
gameforge.locale.monster_chat_2204_2 = "Z n\236jak\233ho d\249vodu jsi mi na obt\237\158. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Plump, v\237\154, kde se nach\225z\237\154? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "Jsi pro mne sm\236\154n\253 protivn\237k. "
gameforge.locale.monster_chat_2205_1 = "Me\232 je u\158ite\232n\253 jenom v rukou v\225le\232n\237ka. "
gameforge.locale.monster_chat_2205_2 = "Dr\158 me\232 po\248\225d p\236kn\236 v ruce. "
gameforge.locale.monster_chat_2205_3 = "Nast\225v\225 v\225lka. "
gameforge.locale.monster_chat_2205_4 = "A te\239 budeme bojovat na smrt! "
gameforge.locale.monster_chat_2205_5 = "Chce\154 je\154t\236 dlouho odol\225vat \250tok\249m? "
gameforge.locale.monster_chat_2205_6 = "Ano, nem\236l bys um\248\237t tak rychle. "
gameforge.locale.monster_chat_2206_1 = "L\225va je elix\237r \158ivota. "
gameforge.locale.monster_chat_2206_2 = "L\225va mne dr\158\237 na\158ivu - tob\236 p\248inese smrt! "
gameforge.locale.monster_chat_2206_3 = "Nen\237 tenhle sv\236t bublaj\237c\237 l\225vy n\225dhern\253? "
gameforge.locale.monster_chat_2206_4 = "Ty m\225\154 odvahu mne ru\154it? "
gameforge.locale.monster_chat_2206_5 = "M\236l bys odej\237t, pokud si v\225\158\237\154 \158ivota. "
gameforge.locale.monster_chat_2206_6 = "Bude\154 litovat m\233 p\248\237tomnosti. "
gameforge.locale.monster_chat_2291_1 = "N\225dhern\233 po\232as\237. Bylo by kr\225sn\233 trochu si pospat. "
gameforge.locale.monster_chat_2291_2 = "Nic se nem\249\158e vyrovnat zemi Doyyumhwan. "
gameforge.locale.monster_chat_2291_3 = "Tro\154ka \232erstv\233 krve by byla v\237tan\225 zm\236na. "
gameforge.locale.monster_chat_2291_4 = "Ty mus\237\154 hledat smrt, jinak bys mne neru\154il.  "
gameforge.locale.monster_chat_2291_5 = "Vypad\225 to, \158e lituje\154 toho, \158e\180s m\236 vyru\154il. "
gameforge.locale.monster_chat_2291_6 = "Te\239 u\158 je pozd\236, abys utekl. Stejn\236 by ti to nepomohlo. "
gameforge.locale.monster_chat_301_1 = "J\225 se tak nud\237m. Copak tady nen\237 nic zaj\237mav\233ho na pr\225ci? "
gameforge.locale.monster_chat_301_2 = "P\248ed dv\236ma dny tu byla roztrh\225na divok\253mi zv\237\248aty mlad\225 d\237vka. "
gameforge.locale.monster_chat_301_3 = "Divok\225 zv\237\248ata jsou \232\237m d\225l t\237m v\237c agresivn\237. M\236ly bychom jich p\225r pob\237t. "
gameforge.locale.monster_chat_301_4 = "Dnes nem\225m dobrou n\225ladu. Cizinci by se m\236li rad\236ji klidit... "
gameforge.locale.monster_chat_301_5 = "Posledn\237 v\225le\232n\237k, kter\253 zem\248el moj\237 rukou, \158ebral o \158ivot... "
gameforge.locale.monster_chat_302_1 = "N\236kdo by m\236l s t\236mi kameny u\158 n\236co d\236lat! "
gameforge.locale.monster_chat_302_2 = "Ned\249v\236\248uji tomu klidu r\225no! "
gameforge.locale.monster_chat_302_3 = "To nap\236t\237 ve vzduchu m\236 ni\232\237! "
gameforge.locale.monster_chat_302_4 = "Tyhle hlavice \154\237p\249 byly vyrobeny poctiv\236! "
gameforge.locale.monster_chat_302_5 = "Vid\237\154? M\237\248\237 ti p\248\237mo na srdce. "
gameforge.locale.monster_chat_302_6 = "Svat\225 dobroto! Trefa do \232ern\233ho! "
gameforge.locale.monster_chat_303_1 = "Dobr\253 bojov\253 v\253cvik je v dne\154n\237 dob\236 nezbytn\253. "
gameforge.locale.monster_chat_303_2 = "Vojsko u\158 d\225le nezvl\225d\225 chaos v zemi. "
gameforge.locale.monster_chat_303_3 = "Pro\232 se na m\236 tak d\237v\225\154? "
gameforge.locale.monster_chat_303_4 = "Zbab\236lci maj\237 malou \154anci na p\248e\158it\237! "
gameforge.locale.monster_chat_303_5 = "Nep\248ece\242uj se. "
gameforge.locale.monster_chat_303_6 = "Tenhle boj bude t\236\158\154\237 ne\158 jsem o\232ek\225vala! "
gameforge.locale.monster_chat_304_1 = "Dokonce i m\237 p\248edkov\233 se uplatnili v bitv\225ch na tomto \250zem\237. "
gameforge.locale.monster_chat_304_2 = "Tady mus\237\154 b\253t obez\248etn\253 a zku\154en\253. "
gameforge.locale.monster_chat_304_3 = "Leze\154 mi na nervy. "
gameforge.locale.monster_chat_304_4 = "Tak jak se c\237t\237\154, kdy\158 je tv\249j \158ivot v nebezpe\232\237? "
gameforge.locale.monster_chat_304_5 = "No ne! To u\158 to vzd\225v\225\154? "
gameforge.locale.monster_chat_304_6 = "Utrpen\237 p\248ijde nenad\225le. "
gameforge.locale.monster_chat_305_1 = "Sakra! Ten me\232 vypad\225 skv\236le! "
gameforge.locale.monster_chat_305_2 = "Zvy\154 svoji odolnost, svoji s\237lu! "
gameforge.locale.monster_chat_305_3 = "Ty si mysl\237\154, \158e m\249\158e\154 b\253t tak siln\253 jako j\225? "
gameforge.locale.monster_chat_305_4 = "No dobr\225. Tak to teda vezmeme v\225\158n\236? "
gameforge.locale.monster_chat_305_5 = "Panebo\158e! Jsem jenom slab\225 \158ena! "
gameforge.locale.monster_chat_305_6 = "Vypad\225\154 unaven\236. Pro\232 to jednodu\154e nevzd\225\154? Chachacha! "
gameforge.locale.monster_chat_306_1 = "Co bude Serangyi dneska asi d\236lat? "
gameforge.locale.monster_chat_306_2 = "Stra\154n\236 se nud\237m. Hraj si se mnou! "
gameforge.locale.monster_chat_306_3 = "J\225 sama d\225v\225m p\248ednost chl\225pk\249m z \248ad Sur\249... "
gameforge.locale.monster_chat_306_4 = "Hej! Co bys \248ekl na boj? "
gameforge.locale.monster_chat_306_5 = "Nepodce\242uj m\236 jenom proto, \158e jsem \158ena! "
gameforge.locale.monster_chat_306_6 = "Bolest trv\225 jenom chvili\232ku. "
gameforge.locale.monster_chat_307_1 = "Chci odsud pry\232, pro v\154echno na sv\236t\236. "
gameforge.locale.monster_chat_307_2 = "Jak bezpe\232n\233 jsou domovy jednotliv\253ch \232len\249? Hodn\236? "
gameforge.locale.monster_chat_307_3 = "Holky, dr\158te huby! "
gameforge.locale.monster_chat_307_4 = "Nech m\236, vy\248\237d\237m t\236 jednou r\225nou. "
gameforge.locale.monster_chat_307_5 = "Na to, \158e ute\232e\154, ani nepomysli. "
gameforge.locale.monster_chat_307_6 = "No tak, na co je\154t\236 \232ek\225me? "
gameforge.locale.monster_chat_394_1 = "A nezapome\242te na to: v\154ichni mu\158i jsou nep\248\225tel\233. "
gameforge.locale.monster_chat_394_2 = "Kdy\158 n\236kdo bude m\237t mil\253 obli\232ej, m\249\158eme b\253t na n\236j trochu hodn\236j\154\237. "
gameforge.locale.monster_chat_394_3 = "Co\158e, ty chce\154 bojovat? "
