gameforge.locale.monster_chat_394_5 = "Hmm, vypad\225 to, \158e m\225\154 p\236kn\233 bolesti. "
gameforge.locale.monster_chat_394_6 = "Sbohem, t\225hn\236te do pekla! "
gameforge.locale.monster_chat_401_1 = "Tak co, co d\236l\225\154 u klanu B\237l\233 p\248\237sahy? "
gameforge.locale.monster_chat_401_2 = "Kampak m\225\154 nam\237\248eno? "
gameforge.locale.monster_chat_401_3 = "Hej! Chce\154 bojovat? "
