gameforge.locale.monster_chat_401_5 = "Ty si mysl\237\154, \158e m\249\158e\154 uniknout? "
gameforge.locale.monster_chat_401_6 = "Tady m\225\154 r\225nu! "
gameforge.locale.monster_chat_402_1 = "Bo\158e, jsem tak unaven\253! "
gameforge.locale.monster_chat_402_2 = "Hmm! P\236kn\233 brn\236n\237. St\225lo hodn\236? "
gameforge.locale.monster_chat_402_3 = "Ale m\225me p\248ece p\236kn\233 po\232as\237. "
gameforge.locale.monster_chat_402_4 = "\193! Vypad\225 to, \158e jsi opravdu tr\233noval. V\253born\236! "
gameforge.locale.monster_chat_402_5 = "Jak ti p\248ipadaj\237 moje schopnosti? Dobr\233, \158e? Chachacha! "
gameforge.locale.monster_chat_402_6 = "Co se d\236je? Samoz\248ejm\236! To je ta \154\237len\225 rychlost! "
gameforge.locale.monster_chat_403_1 = "Pro\232 nejdu lovit? "
gameforge.locale.monster_chat_403_2 = "Dneska nikdo ne\250to\232\237 na na\154i vesnici. "
gameforge.locale.monster_chat_403_3 = "Jestli chce\154 bojovat, bojuj! Mizero! "
gameforge.locale.monster_chat_403_4 = "Chachacha! Ty jsi p\248ece jenom pouh\253 amat\233r! "
gameforge.locale.monster_chat_403_5 = "M\225m t\236 nejd\248\237v zas\225hnout do nohy nebo do ruky? "
gameforge.locale.monster_chat_403_6 = "Pozor - vyst\248eluju \154\237p! "
gameforge.locale.monster_chat_404_1 = "N\236kdy p\248\237\154t\236 mus\237m j\237t do vesnice a tr\233novat. "
gameforge.locale.monster_chat_404_2 = "Jsem \250pln\236 ztuhl\253. "
gameforge.locale.monster_chat_404_3 = "Co je dneska k j\237dlu? "
gameforge.locale.monster_chat_404_4 = "Pozoruju, tak\158e si \248vi jak chce\154. "
gameforge.locale.monster_chat_404_5 = "V\225hal jsi moc dlouho, co? Ze v\154eho nejd\248\237v p\236kn\236 \154vihnout me\232em! "
gameforge.locale.monster_chat_404_6 = "Ten me\232 m\225 takov\253 vzru\154uj\237c\237 zvuk! "
gameforge.locale.monster_chat_405_1 = "Tenhle me\232 je p\248ipraven za\232\237t! "
gameforge.locale.monster_chat_405_2 = "Uvid\237me, koho ten me\232 skol\237 jako prvn\237! "
gameforge.locale.monster_chat_405_3 = "Hej! Co tak \232um\237\154? "
gameforge.locale.monster_chat_405_4 = "Nejd\248\237v tvoje b\248icho! "
gameforge.locale.monster_chat_405_5 = "Copak nen\237 pochva standard pro bojovn\237ka s me\232em? "
gameforge.locale.monster_chat_405_6 = "Cht\236l bych m\237t tebe jako pochvu na me\232. "
gameforge.locale.monster_chat_406_1 = "Hynu hlady! "
gameforge.locale.monster_chat_406_2 = "M\225me tady n\236co k j\237dlu? "
gameforge.locale.monster_chat_406_3 = "Jak to, \158e m\225m po tom v\154em j\237dle po\248\225d je\154t\236 hlad? "
gameforge.locale.monster_chat_406_4 = "\193\225\225\225, zem\248i! "
gameforge.locale.monster_chat_406_5 = "M\249j \158aludek rozhodne o tomto boji! "
gameforge.locale.monster_chat_406_6 = "Je to volba mezi nebem a zem\237! "
gameforge.locale.monster_chat_491_1 = "U\158 to nevydr\158\237m! Brn\237 m\236 cel\233 t\236lo! "
gameforge.locale.monster_chat_491_2 = "A jo. Vid\237m tam n\236kolik prasat. "
