gameforge.locale.monster_chat_491_4 = "Vy\248\237d\237m t\236 jednou ranou. "
gameforge.locale.monster_chat_491_5 = "To bude p\236kn\225 vzpom\237nka! "
gameforge.locale.monster_chat_491_6 = "Zem\248i! "
gameforge.locale.monster_chat_492_1 = "Zm\236klo mi \250pln\236 t\236lo. "
gameforge.locale.monster_chat_492_2 = "Pro\232 netr\233nuju v\237c? "
