gameforge.locale.monster_chat_493_4 = "M\225m t\236 zml\225tit? Jestli ne, tak rad\154i rychle ute\232, jo? "
gameforge.locale.monster_chat_493_5 = "Te\239 demonstruji moji velkou r\225nu! "
gameforge.locale.monster_chat_493_6 = "V\237m, \158e z\237r\225\154 na moji ruku! "
gameforge.locale.monster_chat_494_1 = "Jestli chce\154 bojovat, p\248ijd' sem! "
gameforge.locale.monster_chat_494_2 = "P\248ipad\225m si absolutn\236 \250chvatn\253. "
