gameforge.locale.monster_chat_494_6 = "Se\154 skoro mrtv\253. "
gameforge.locale.monster_chat_501_1 = "Hraj si se mnou! Z\249sta\242 tady! "
gameforge.locale.monster_chat_501_2 = "Um\236l bych vyrobit n\236co p\236kn\233ho z tv\253ch kost\237... "
