gameforge.locale.monster_chat_501_5 = "Od ted'ka bude pro tebe t\236\158k\233, ignorovat moje \250toky! "
gameforge.locale.monster_chat_501_6 = "Chachacha! P\248ekvapen\253, \158e? "
