gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "V\253born\236! "
gameforge.locale.monster_chat_503_1 = "Ty tam, nedot\253kat se! "
gameforge.locale.monster_chat_503_2 = "Vypad\225 to, jako by byla t\236tiva m\233ho luku p\248e\248\237znut\225! "
