gameforge.locale.monster_chat_703_4 = "Nepochybuj! "
gameforge.locale.monster_chat_703_5 = "P\248ijmi nebesk\253 hrom! "
gameforge.locale.monster_chat_703_6 = "R\225na soudu! "
gameforge.locale.monster_chat_704_1 = "Pravda ezoterick\233 v\237ry spo\232\237v\225 v porozum\236n\237 nebesk\233ho \248\225du. "
gameforge.locale.monster_chat_704_2 = "Ezoterick\225 pravda! Pravda tyg\248\237ho boha! Sabaha! Sabaha! "
gameforge.locale.monster_chat_704_3 = "Mysl\237\154 si, \158e jsem klaun, co? No, nebude\154 si to myslet dlouho! "
gameforge.locale.monster_chat_704_4 = "V\249dce sekty je svat\253 a je nad\248azen v\154em \158iv\253m tvor\249m! "
gameforge.locale.monster_chat_704_5 = "Sho\248 v plamenech pekeln\253ch! "
gameforge.locale.monster_chat_704_6 = "Je\154t\236 jsi nikdy tak velkou ladi\232ku nevid\236l, co? "
gameforge.locale.monster_chat_705_1 = "Ezoterick\225 pravda! Pravda tyg\248\237ho boha! Sabaha! Sabaha! "
gameforge.locale.monster_chat_705_2 = "Pravda ezoterick\233 v\237ry spo\232\237v\225 v porozum\236n\237 nebesk\233ho \248\225du. "
gameforge.locale.monster_chat_705_3 = "Jen proto, \158e jsem men\154\237 ne\158 m\249j bratr neznamen\225, \158e m\236 snadno dostane\154! "
gameforge.locale.monster_chat_705_4 = "V\236\232n\225 bolest a tma t\236 ji\158 \232ekaj\237! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Tohle je\154t\236 nen\237 konec. Naopak, te\239 to bude je\154t\236 lep\154\237! "
gameforge.locale.monster_chat_706_1 = "Pros\237me o m\237r a klid! Pros\237m! "
gameforge.locale.monster_chat_706_2 = "Kdy\158 v\154ude panuje jenom strach, pom\249\158e pravda tyg\248\237ho boha. "
gameforge.locale.monster_chat_706_3 = "Pravda ezoterick\233 pravdy spo\232\237v\225 v \248\225du a porozum\236n\237 nebe. "
gameforge.locale.monster_chat_706_4 = "P\249jdeme v\154ichni do pekla! "
gameforge.locale.monster_chat_706_5 = "Nepust\237m t\236! "
gameforge.locale.monster_chat_706_6 = "Snesu ti k noh\225m v\154echno, co vlastn\237m! "
gameforge.locale.monster_chat_707_1 = "Proboha t\236 pros\237m. Zachra\242 n\225s! "
gameforge.locale.monster_chat_707_2 = "Pravda ezoterick\233 v\237ry spo\232\237v\225 v porozum\236n\237 nebesk\233ho \248\225du. "
gameforge.locale.monster_chat_707_3 = "Ezoterick\225 pravda! Pravda tyg\248\237ho boha! Sabaha! Sabaha! "
gameforge.locale.monster_chat_707_4 = "Pekeln\225 br\225na je do\154iroka otev\248en\225. Vejdi! "
gameforge.locale.monster_chat_707_5 = "Varuji t\236 - nenu\157 m\236 k n\225sil\237! "
gameforge.locale.monster_chat_707_6 = "U\158 vid\237m p\248ich\225zet tvou smrt! "
gameforge.locale.monster_chat_791_1 = "Jak bych ti mohl v kr\225tkosti povypr\225v\236t v\154echno o \248\225du nebe a vesm\237ru? "
gameforge.locale.monster_chat_791_2 = "Sly\154\237m zp\236v v\236\248\237c\237ch. "
gameforge.locale.monster_chat_791_3 = "Tak je to spr\225vn\236! Pokej se a bude\154 spasen. "
gameforge.locale.monster_chat_791_4 = "Bude\154 trp\236t v\236\232nou bolest\237, proto\158e pochybuje\154 o prav\233 v\237\248e. "
gameforge.locale.monster_chat_791_5 = "Nech se ode m\236 pou\232it. "
gameforge.locale.monster_chat_791_6 = "Nesm\237\154 to vn\237mat jako bolest. To je jenom pou\232en\237. "
gameforge.locale.monster_chat_901_1 = "Mo\158n\225 se ti to nebude l\237bit tolik jako m\236. "
gameforge.locale.monster_chat_901_2 = "Mus\237 se z tebe st\225t to, co jsme my! "
gameforge.locale.monster_chat_901_3 = "No jen poj\239 bl\237\158... "
gameforge.locale.monster_chat_901_4 = "HAHAHAHAHA! "
gameforge.locale.monster_chat_901_5 = "Tak jdeme na to! "
gameforge.locale.monster_chat_903_1 = "To je peklo! "
gameforge.locale.monster_chat_903_2 = "\193\225\225\225h! "
gameforge.locale.monster_chat_903_3 = "Nem\249\158eme to zvl\225dnout sami! Ne! "
gameforge.locale.monster_chat_903_4 = "I ty mus\237\154 za\158\237t, jak chutn\225 tahle bolest! "
gameforge.locale.monster_chat_903_5 = "Chce\154 tohle utrpen\237 a strach sm\236nit za tvou du\154i? "
gameforge.locale.monster_chat_903_6 = "Za okam\158ik vstoup\237\154 do v\236\232n\233ho m\237ru! "
gameforge.locale.monster_chat_904_1 = "Ta bolest! To je bolest! "
gameforge.locale.monster_chat_904_2 = "K \232ertu! Ho\248\237 mi ruka! "
gameforge.locale.monster_chat_904_3 = "Pro\232 mus\237me tak trp\236t? Pro\232? "
