gameforge.locale.monster_chat_904_6 = "\193\225\225\225h! "
gameforge.locale.monster_chat_905_1 = "\193\225\225\225h! "
gameforge.locale.monster_chat_905_2 = "Zabiju t\236\236\236\236\236! "
gameforge.locale.monster_chat_905_3 = "Nekoukej kolem. D\236lej n\236co! "
gameforge.locale.monster_chat_905_4 = "Pojd', usm\237\248\237me se! "
gameforge.locale.monster_chat_905_5 = "U\158 ses nakazil. "
gameforge.locale.monster_chat_905_6 = "Te\239 jsi m\249j p\248\237tel. "
gameforge.locale.monster_chat_906_1 = "Hihihi! "
gameforge.locale.monster_chat_906_2 = "Jen p\248ijd' a nap\237chni se na m\249j \154\237p. "
gameforge.locale.monster_chat_906_3 = "Ty mi fakt leze\154 na nervy! "
gameforge.locale.monster_chat_906_4 = "Nakaz\237m t\236 tou z\225hadnou nemoc\237. hehehe "
gameforge.locale.monster_chat_906_5 = "Lahodn\253 z\225pach! "
gameforge.locale.monster_chat_906_6 = "Zem\248i! "
gameforge.locale.monster_chat_907_1 = "A kdy\158 najdu jin\233 choroboplodn\233 z\225rodky... "
