gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Nesm\237 nikoho nakazit! Mus\237\154 ho za\232\237t okam\158it\236[ENTER]l\233\232it. K tomu pot\248ebujeme vzorek choroboplodn\233ho[ENTER]z\225rodku t\233 z\225hadn\233 nemoci. Ten vzorek se d\225[ENTER]sehnat u nemocn\253ch, kte\248\237 se nach\225z\237 v hojn\233m[ENTER]po\232tu na ho\248e Sohan na severu. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Tak\180s to zvl\225dnul! Po\232kej chvilku na ten l\233k![ENTER][DELAY value;1000] [/DELAY][ENTER][ENTER]Vyrobil jsem ho tak rychle, \158e ani nev\237m, jestli[ENTER]p\249sob\237. Ale p\248i nejmen\154\237m se mu ud\236l\225 l\237p. Dones[ENTER]mu ten l\233k tak rychle, jak jen to jde. "
