gameforge.locale.old_pirate.etc_shop_start_say = "Obchodnice:[ENTER]Star\253 pir\225t? Samoz\248ejm\236 \158e ho zn\225m. Ty mysl\237\154[ENTER]toho chl\225pka, co v jednom kuse kleje a po\248\225d se[ENTER]\154kr\225be, \158e? Stavuje se tady dost \232asto a kupuje[ENTER]tekutou medic\237nu. Za ten \232erven\253 elix\237r u\158[ENTER]utratil hodn\236 tis\237c Yang\249. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Obchodnice:[ENTER]Ale odkud proboha bere tolik Yang\249, v\158dy\157 ani[ENTER]nepracuje? U\158 jsem mu kolikr\225t \248\237kala, \158e m\225 j\237t[ENTER]na prohl\237dku k l\233ka\248i, ale v\249bec m\236 neposlouch\225.[ENTER]\200erven\253 l\233k jen p\248ekr\253v\225 symptomy, ale nel\233\232\237[ENTER]nemoc. Ob\225v\225m se, \158e to s n\237m \154patn\236 dopadne. "
