gameforge.locale.old_pirate.order_say2 = "Star\253 pir\225t:[ENTER]\200lov\236k nikdy nev\237, jestli se najednou n\225hodou[ENTER]neobjev\237 n\236jak\253 dareba a jednodu\154e t\236 nezap\237chne![ENTER]Ale sv\236d\237 to tak \154\237len\236, \158e u\158 to fakt nevydr\158\237m![ENTER]Tak co? M\249\158e\154 mi sko\232it k doktorovi a sehnat mi[ENTER]l\233k proti sv\236d\236n\237? Kdy\158 mi ten l\233k se\158ene\154, dob\248e[ENTER]se ti odm\236n\237m. "
