gameforge.locale.questscroll5.mission_40_text = "U\158 jsi sly\154el o v\236\158i d\233mon\249? Ezoterick\233 sekty tam[ENTER]za\248\237k\225valy voj\225ky d\233mon\249 s pomoc\237 mocn\233 magie.[ENTER]Bojuj proti nim a zjisti, do jak\233 m\237ry jsou mocn\237. "
gameforge.locale.questscroll5.mission_41_hunt = "Tajemstv\237 t\236\158k\233 opi\232\237 jeskyn\236 2 "
gameforge.locale.questscroll5.mission_41_mis = "Zabij 15 siln\253ch opi\232\237ch bojovn\237k\249 a 15 siln\253ch[ENTER]opi\232\237ch gener\225l\249 "
gameforge.locale.questscroll5.mission_41_text = "Bylo zji\154t\236no, kde se nach\225z\237 m\237sto t\236\158k\225 opi\232\237[ENTER]jeskyn\236. Tyto opice nep\248edstavuj\237 za norm\225ln\237ch[ENTER]okolnost\237 \158\225dn\233 nebezpe\232\237. Ale kdy\158 se srot\237[ENTER]dohromady, m\249\158ou ohrozit kr\225lovstv\237.[ENTER]Vydej se k t\236\158k\233 opi\232\237 jeskyni a zjisti, co se[ENTER]tam d\236je. "
gameforge.locale.questscroll5.mission_42_hunt = "Led jednoho dne roztaje "
gameforge.locale.questscroll5.mission_42_mis = "Zabij 25 ledov\253ch golem\249 na ho\248e Sohan. "
gameforge.locale.questscroll5.mission_42_text = "Zn\225\154 horu Sohan, pokrytou v\236\232n\253m ledem? Mnoho[ENTER]v\253zkumn\237k\249 a v\225le\232n\237k\249 se tam vydalo, ale nikdy[ENTER]se nevr\225tili. Najdi d\249vod a zda byli napadeni.[ENTER]Mo\158n\225 zjist\237\154 v\237ce, kdy\158 tam bude\154 lovit bestie. "
gameforge.locale.questscroll5.mission_43_hunt = "Tajemstv\237 t\236\158k\233 opi\232\237 jeskyn\236 1 "
gameforge.locale.questscroll5.mission_43_mis = "Zabij 30 siln\253ch opi\232\237ch voj\225k\249 a 30 siln\253ch[ENTER]opi\232\237ch vrha\232\249. "
gameforge.locale.questscroll5.mission_43_text = "Bylo zji\154t\236no, kde se nach\225z\237 m\237sto t\236\158k\225 opi\232\237[ENTER]jeskyn\236. Tyto opice nep\248edstavuj\237 za norm\225ln\237ch[ENTER]okolnost\237 \158\225dn\233 nebezpe\232\237. Ale kdy\158 se srot\237[ENTER]dohromady, m\249\158ou ohrozit kr\225lovstv\237.[ENTER]Vydej se k t\236\158k\233 opi\232\237 jeskyni a zjisti, co se[ENTER]tam d\236je. "
gameforge.locale.questscroll5.mission_44_hunt = "\142lut\253 duch tygra "
gameforge.locale.questscroll5.mission_44_mis = "Zabij 30 gener\225l\249-ob\248\237ch ropuch. "
gameforge.locale.questscroll5.mission_44_text = "Jsem si jist, \158e jsi si v\154iml, \158e zv\237\248ata se v[ENTER]posledn\237 dob\236 chovaj\237 divoce. Tajn\225 slu\158ba[ENTER]kr\225lovstv\237 si mysl\237, \158e d\249vodem je \142lut\253 duch[ENTER]tygra, kr\225l zv\237\248at na kontinentu, kter\253 zv\237\248ata[ENTER]podn\236cuje. Jako odplatu bychom m\236li eliminovat[ENTER]v\249dce, kte\248\237 jsou jeho pravou rukou. "
gameforge.locale.questscroll5.mission_45_hunt = "Majitel hory Sohan? "
gameforge.locale.questscroll5.mission_45_mis = "Zabij 35 ledov\253ch mu\158\249 a 30 yeti. "
gameforge.locale.questscroll5.mission_45_text = "Dev\237tiocas, vl\225dce hory Sohan, kolem sebe[ENTER]shroma\158\239uje d\233mony. D\248\237v ne\158 se jeho jednotky[ENTER]shrom\225\158d\237, mus\237me ub\237t ledov\233 mu\158e a yeti, ti[ENTER]jsou jejich nejd\249le\158it\236j\154\237m \232l\225nkem.[ENTER]Pros\237m pomo\158 n\225m. Dostane\154 velkorysou odm\236nu. "
gameforge.locale.questscroll5.mission_46_hunt = "Chunwa Bong-ki "
gameforge.locale.questscroll5.mission_46_mis = "Zabij 45 \158abovoj\225k\249 a 35 v\249dc\249 \158abovoj\225k\249. "
gameforge.locale.questscroll5.mission_46_text = "O\232ividn\236 se \158lut\253 duch tygra spol\232il se \158ab\237mi[ENTER]nestv\249rami. Neprodlen\236 pobij jejich spole\232n\233[ENTER]jednotky. Jestli je bude\154 ignorovat, skon\232\237 to s[ENTER]tv\253m kr\225lovstv\237m bled\236. "
gameforge.locale.questscroll5.mission_47_hunt = "Ledov\233 nestv\249ry! Jejich prav\225 povaha "
gameforge.locale.questscroll5.mission_47_mis = "Zabij 45 za\232arovan\253ch ledovi\154\157 "
gameforge.locale.questscroll5.mission_47_text = "V\237me, jak nestv\249ry na ho\248e Sohan mezi sebou[ENTER]komunikuj\237. Roz\154i\248uj\237 informace pomoc\237 ledov\253ch[ENTER]bytost\237 na ho\248e Sohan. Je nezbytn\236 nutn\233 oslabit[ENTER]bojov\233 jednotky na ho\248e Sohan t\237m, \158e budou ubity[ENTER]ledov\233 nestv\249ry. Ujmi se toho, pros\237m. Zabij[ENTER]ledov\233 nestv\249ry na ho\248e Sohan. "
gameforge.locale.questscroll5.mission_48_hunt = "Tajemstv\237 v\236\158e d\233mon\249 "
gameforge.locale.questscroll5.mission_48_mis = "Zabij 45 hnusn\253ch duch\249 bojovn\237ka. "
gameforge.locale.questscroll5.mission_48_text = "Pov\237d\225 se, \158e Hnusn\237 o\154t\236pa\248i ve V\236\158i d\233mon\249 jsou[ENTER]neporaziteln\237. Ob\158ivnou\237 v\158dy, kdy\158 je zabije\154.[ENTER]Pokud je to pravda, nast\225vaj\237 n\225m temn\233 \232asy.[ENTER]Pros\237m, zjisti o tom v\237ce. "
gameforge.locale.questscroll5.mission_49_hunt = "P\225n v\236\158e d\233mon\249 "
gameforge.locale.questscroll5.mission_49_mis = "Zabij 60 hnusn\253ch duch\249 \154amana. "
gameforge.locale.questscroll5.mission_49_text = "Podrobn\253 rozbor uk\225zal, \158e voj\225ci ducha byli[ENTER]pr\249b\236\158n\236 o\158ivov\225ni. Mus\237me zni\232it hnusn\233 duchy[ENTER]\154aman\249, abychom zabr\225nili, \158e se v budoucnosti[ENTER]vr\225t\237 nazp\236t. "
gameforge.locale.questscroll5.mission_4_hunt = "V\253skyt \154ed\253ch vlk\249 1 "
gameforge.locale.questscroll5.mission_4_mis = "Zabij 35 \154ed\253ch vlk\249. "
gameforge.locale.questscroll5.mission_4_text = "U\158 jsi sly\154el o \154ed\253ch vlc\237ch? D\248\237v se potulovali[ENTER]v\236t\154inou jako samot\225\248i, ale v posledn\237 dob\236[ENTER]za\232ali honit ve sme\232k\225ch lidi na cest\225ch.[ENTER]M\249\158e\154 zeliminovat tyhle \154ed\233 vlky? Za to dostane\154[ENTER]odm\236nu. "
gameforge.locale.questscroll5.mission_50_hunt = "Prozkoumej Doyyumhwan "
gameforge.locale.questscroll5.mission_50_mis = "Zabij 45 zotro\232en\253ch bojov\253ch tygr\249. "
gameforge.locale.questscroll5.mission_50_text = "Ohniv\225 zem\236 je l\225vov\225 oblast, kter\225 je os\237dlen\225[ENTER]zat\237m je\154t\236 neobjeven\253mi nestv\249rami.[ENTER]Mus\237me tuhle oblast prozkoumat.[ENTER]Pom\249\158e\154 n\225m s t\237m? "
gameforge.locale.questscroll5.mission_51_hunt = "Ohniv\253 duch! Jeho identita "
gameforge.locale.questscroll5.mission_51_mis = "Zabij 45 ohniv\253ch duch\249. "
gameforge.locale.questscroll5.mission_51_text = "Byla zdecimov\225na jedna skupina, kter\225 m\236la[ENTER]vyhubit bojov\233 tygry. Maj\237 to na sv\236dom\237 zat\237m[ENTER]nezn\225m\237 soupe\248i. \216\237k\225 se, \158e tito soupe\248i[ENTER]vypadaj\237 jako ho\248\237c\237 d\236v\232\225tka, tak\158e zjisti, o co[ENTER]se jedn\225. "
gameforge.locale.questscroll5.mission_52_hunt = "Sni\158 po\232et bojov\253ch tygr\249. "
gameforge.locale.questscroll5.mission_52_mis = "Zabij 60 ni\158\154\237ch bojov\253ch tygr\249 a 40 bojov\253ch[ENTER]tygr\249. "
gameforge.locale.questscroll5.mission_52_text = "Te\239 m\225me mo\158nost bojovat s ohniv\253mi duchy a[ENTER]jejich kompletn\237 eliminaci mus\237me prov\233st v[ENTER]otev\248en\233m boji.[ENTER]N\236kter\233 \250koly p\248evezme arm\225da, tak\158e n\225m pomo\158te[ENTER]se sn\237\158en\237m po\232tu bojov\253ch tygr\249. "
gameforge.locale.questscroll5.mission_53_hunt = "Prozkoumej plameny "
gameforge.locale.questscroll5.mission_53_mis = "Zni\232 40 plamen\249. "
gameforge.locale.questscroll5.mission_53_text = "Ty plameny jsou neuv\236\248iteln\236 brut\225ln\237. Bolest[ENTER]\232lov\236ka, jeho\158 k\249\158i pr\225v\236 \158erou, je neobvykle[ENTER]rozja\248uje. Zat\237m je\154t\236 po\248\225d netu\154\237me, jak je[ENTER]m\249\158eme zeliminovat.[ENTER]M\249\158e\154 toho o t\236ch plamenech zjistit v\237c? "
gameforge.locale.questscroll5.mission_54_hunt = "Ohniv\253 v\225le\232n\237k "
gameforge.locale.questscroll5.mission_54_mis = "Zabij 60 ohniv\253ch v\225le\232n\237k\249. "
gameforge.locale.questscroll5.mission_54_text = "P\248ed ned\225vnem zabil jeden ohniv\253 v\225le\232n\237k d\237t\236[ENTER]jednoho \154lechtice, kter\253 se vydal do Ohniv\233 zem\236.[ENTER]Kdy\158 toho ohniv\233ho v\225le\232n\237ka zabije\154, obdr\158\237\154[ENTER]odm\236nu. Tak pro\232 to nezkus\237\154? "
gameforge.locale.questscroll5.mission_55_hunt = "Prozkoumej stromy duch\249 "
gameforge.locale.questscroll5.mission_55_mis = "Zni\232 30 strom\249 duch\249. "
gameforge.locale.questscroll5.mission_55_text = "Za norm\225ln\237ch okolnost\237 stoj\237 jako oby\232ejn\233[ENTER]stromy a pak n\225hle napadaj\237 zv\237\248ata a lidi.[ENTER]Zjisti, jak se daj\237 zni\232it stromy duch\249. "
gameforge.locale.questscroll5.mission_56_hunt = "Tajemstv\237 lesa duch\249 "
gameforge.locale.questscroll5.mission_56_mis = "Zni\232 40 pa\248ez\249 duch\249 a 30 dry\225d. "
gameforge.locale.questscroll5.mission_56_text = "Pr\249zkumy uk\225zaly, \158e les duch\249 je oblast, kterou[ENTER]ob\253vaj\237 p\248edev\154\237m pa\248ezy ducha a dry\225dy.[ENTER]Kdy\158 je zni\232\237\154, zabr\225n\237\154 mo\158n\225 tomu, \158e se stromy[ENTER]duch\249 budou d\225le roz\154i\248ovat. "
gameforge.locale.questscroll5.mission_5_hunt = "Starost o vesnice "
gameforge.locale.questscroll5.mission_5_mis = "Zabij 40 divo\232\225k\249. "
gameforge.locale.questscroll5.mission_5_text = "Starosti ve vesnic\237ch nedaleko m\236sta se v[ENTER]posledn\237 dob\236 rozmno\158ily. Divo\232\225ci, kte\248\237 doposud[ENTER]nanejv\253\154 napadali drobn\225 zv\237\248ata v hor\225ch, jsou[ENTER]te\239 dost agresivn\237. Vtrhli na pole a napadli tam[ENTER]zem\236d\236lce. M\249\158e\154 tyhle divo\232\225ky zahnat? "
gameforge.locale.questscroll5.mission_6_hunt = "Tyg\248i a medv\236di "
gameforge.locale.questscroll5.mission_6_mis = "Zabij 25 tygr\249 a 30 medv\236d\249. "
gameforge.locale.questscroll5.mission_6_text = "U\158 jsi to zaslechl? Kdy\158 tyg\248i a medv\236di \158erou[ENTER]100 dn\237 jenom \232esnek a cibuli, m\249\158ou se potom[ENTER]prom\236nit na velkotygry a ohniv\233 medv\236dy. Ur\232it\236[ENTER]to nen\237 pravda, ale neza\154kod\237, kdy\158 se pod\237v\225\154,[ENTER]co je na tom pravdy. Prozkoumej to tak, \158e skol\237\154[ENTER]tygry a medv\236dy. "
gameforge.locale.questscroll5.mission_7_hunt = "Zni\232it Metin la\232nosti "
gameforge.locale.questscroll5.mission_7_mis = "Zni\232it 2 Metiny la\232nosti. "
gameforge.locale.questscroll5.mission_7_text = "V posledn\237 dob\236 pr\154\237 nedaleko m\236sta kameny s[ENTER]\239\225belsk\253m Chi. Pr\249zkumy uk\225zaly, \158e zv\237\248ata pod[ENTER]vlivem Chi z t\236chto kamen\249 za\232\237naj\237 b\236snit.[ENTER]Zni\232 tyto kameny. Pros\237m t\236 o to. Ur\232it\236 za to[ENTER]bude\154 odm\236n\236n. "
gameforge.locale.questscroll5.mission_8_hunt = "Zni\232it Metin bitvy "
gameforge.locale.questscroll5.mission_8_mis = "Zni\232it 2 Metiny bitvy. "
gameforge.locale.questscroll5.mission_8_text = "V posledn\237 dob\236 pr\154\237 nedaleko m\236sta kameny s[ENTER]\239\225belsk\253m Chi. Pr\249zkumy uk\225zaly, \158e zv\237\248ata pod[ENTER]vlivem Chi z t\236chto kamen\249 za\232\237naj\237 b\236snit.[ENTER]Zni\232 tyto kameny. Pros\237m t\236 o to. Ur\232it\236 za to[ENTER]bude\154 odm\236n\236n. "
gameforge.locale.questscroll5.mission_9_hunt = "Starost o vesnice 2 "
gameforge.locale.questscroll5.mission_9_mis = "Zabij 30 \232erven\253ch divo\232\225k\249. "
gameforge.locale.questscroll5.mission_9_text = "V posledn\237 dob\236 vyhled\225vaj\237 vesnice v bl\237zkosti[ENTER]hlavn\237ho m\236sta divo\232\225ci a jeden \232erven\253 divo\232\225k,[ENTER]kter\253 je jejich v\249dce. Vl\225da vydala rozkaz k[ENTER]usmrcen\237 \232erven\233ho divo\232\225ka. Od v\225le\232n\237k\249 je[ENTER]vy\158adov\225no, \158e ka\158d\253 z nich zabije 30 \232erven\253ch[ENTER]divo\232\225k\249. Pros\237me t\236, aby ses taky z\250\232astnil. "
gameforge.locale.questscroll_10_hunt = "Voj\225ci had\237ch lid\237 "
gameforge.locale.questscroll_10_mis = "Zab\237t voj\225ky, kte\248\237 jsou nap\249l \232lov\236k, nap\249l had. "
gameforge.locale.questscroll_10_text = "Nedaj\237 se za\248adit mezi lidi. Ale stejn\236 tak je[ENTER]omylem je ozna\232it za hady. Vypadaj\237 jako lidi,[ENTER]ale hlava, k\249\158e a jejich chov\225n\237 je jako u[ENTER]jedovat\253ch had\249. Pro\232es\225vaj\237 pou\154\157 a napadaj\237[ENTER]obchodn\237ky.[ENTER]Zabij 20 t\236chto voj\225k\249, kte\248\237 jsou nap\249l \232lov\236k a[ENTER]nap\249l had. Kdy\158 je zni\232\237\154, obdr\158\237\154 n\225sleduj\237c\237[ENTER]odm\236nu: "
gameforge.locale.questscroll_11_hunt = "St\248elci had\237ch lid\237 "
gameforge.locale.questscroll_11_mis = "Zab\237t st\248elce, kte\248\237 jsou nap\249l lidi, nap\249l had. "
gameforge.locale.questscroll_11_text = "Jsou inteligentn\237 jako \232lov\236k. Jsou lstiv\237 a um\237[ENTER]v\253born\236 zach\225zet se zbran\236mi. Lukost\248elci, kte\248\237[ENTER]jsou nap\249l \232lov\236k a nap\249l had, napadaj\237[ENTER]obchodn\237ky zd\225lky. Mnoho obchodn\237k\249 u\158 zem\248elo.[ENTER][ENTER]Zabij 20 lukost\248elc\249, kte\248\237 jsou nap\249l \232lov\236k a[ENTER]nap\249l had. Kdy\158 tento \250kol dokon\232\237\154, obdr\158\237\154[ENTER]n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_12_hunt = "Pou\154tn\237 bandit\233 "
gameforge.locale.questscroll_12_mis = "Zabij pou\154tn\237 bandity "
gameforge.locale.questscroll_12_text = "V pou\154ti Yongbi \158ij\237 zl\233 bytosti. Jsou zn\225mi jako[ENTER]zlod\236ji pou\154tn\237ch ke\248\249 a jejich zlo\232iny volaj\237 do[ENTER]nebes. P\248epadaj\237 a usmrcuj\237 obchodn\237ky jen tak[ENTER]pro z\225bavu. Zni\232ili vesnice v pou\154ti.[ENTER][ENTER]Zabij 12 zlod\236j\249 pou\154tn\237ch ke\248\249. Kdy\158 je[ENTER]zeliminuje\154, dostane\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_13_hunt = "Bojov\253 tygr "
gameforge.locale.questscroll_13_mis = "Zabij bojov\233 tygry. "
gameforge.locale.questscroll_13_text = "Existuj\237 bytosti, kter\253m se \248\237k\225 bojov\237 tyg\248i. V[ENTER]jejich \158il\225ch koluje ohe\242 a jejich t\236la jsou[ENTER]ztvarov\225ny ze sope\232n\233 \158uly. Jsou to neoby\232ejn\236[ENTER]mocn\233 nestv\249ry![ENTER]Tyto zr\249dy se \158iv\237 l\225vou a sope\232n\253m ohn\236m. \200as od[ENTER]\232asu sestoup\237 ze sope\232n\233ho vrcholu, napadaj\237 lidi[ENTER]a \158erou je.[ENTER][ENTER]Zabij 20 bojov\253ch tygr\249. Kdy\158 je zni\232\237\154, obdr\158\237\154[ENTER]n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_14_hunt = "Mu\158i v\225lky "
gameforge.locale.questscroll_14_mis = "Zabij mu\158e v\225lky. "
gameforge.locale.questscroll_14_text = "Doyyumhwan je rozlehl\253, hork\253 a \158ije v n\236m div\225[ENTER]zv\236\248. Setk\225vaj\237 se tam v\225le\232n\237ci z Chunjo, Jinno[ENTER]a Shinsoo. Na v\225le\232n\237ky tam \232\237haj\237 hroziv\233, mocn\233[ENTER]nestv\249ry. Mu\158i v\225lky jsou vl\225dci Doyyumhwan.[ENTER][ENTER]Chce\154 je vyzvat na souboj? Kdy\158 jich 20 poraz\237\154,[ENTER]obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_15_hunt = "V\225le\232n\237ci Taehwa "
gameforge.locale.questscroll_15_mis = "Zv\237t\236zit nad v\225le\232n\237kem Taehwa. "
gameforge.locale.questscroll_15_text = "V\154ichni, kdo se po\232\237t\225te k siln\253m bojovn\237k\249m,[ENTER]naslouchejte![ENTER]Tohle je ohniv\233 boji\154t\236 slz, utrpen\237, boje a[ENTER]smrti! \142iju tady spolu s po\232etn\253mi nestv\249rami a[ENTER]zlo\232inci![ENTER]Kdo se odv\225\158\237 m\236 vyzvat na souboj? Najde se[ENTER]n\236kdo, kdo proti mn\236 nastoup\237 s me\232em v ruce?[ENTER][ENTER]Pokud pevn\236 v\236\248\237\154 vlastn\237 ruce s me\232em, vystup a[ENTER]vyzvi m\236! Pokud zv\237t\236z\237\154 nade mnou a m\253mi 12[ENTER]kamar\225dy, dostane\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_16_hunt = "Tmav\237 medv\236di "
gameforge.locale.questscroll_16_mis = "Zab\237t tmav\233 medv\236dy. "
gameforge.locale.questscroll_16_text = "Ob\225v\225m se, \158e jsem na konci m\253ch sil. Ale dovol[ENTER]mi je\154t\236 povypr\225v\236t o jedn\233 d\249le\158it\233 ud\225losti.[ENTER]A\158 bude\154 \232\237st tenhle dopis, jsem u\158 po smrti nebo[ENTER]nezv\236stn\253. D\248\237ve jsem \158il v \250dol\237 Seungryong, kde[ENTER]jsem sb\237ral l\233\232iv\233 byliny. Ale nestv\249ry, kter\253m[ENTER]se \248\237k\225 tmav\237 medv\236di, se za\232ali dopou\154t\236t[ENTER]odporn\253ch \232in\249. Zabili celou moji rodinu.[ENTER][ENTER]Pros\237m pomsti ze za m\236 i za moji rodinu. Kdy\158[ENTER]zabije\154 25 tmav\253ch medv\236d\249, obdr\158\237\154 n\225sleduj\237c\237[ENTER]odm\236nu: "
gameforge.locale.questscroll_17_hunt = "Ob\248\237 tmav\237 medv\236di "
gameforge.locale.questscroll_17_mis = "Zab\237t ob\248\237 tmav\233 medv\236dy. "
gameforge.locale.questscroll_17_text = "Medv\236d\237 nestv\249ry stvo\248ili novou zr\249du t\237m, \158e se[ENTER]p\225\248ili s je\154t\236 stra\154n\236j\154\237mi nestv\249rami. Vzniknul[ENTER]tak ob\248\237 tmav\253 medv\236d, kter\253 je v\236t\154\237 a siln\236j\154\237[ENTER]ne\158 tmav\253 medv\236d a s neuv\236\248iteln\236 zlou povahou.[ENTER]Dokud budou tyto nestv\249ry v \250dol\237 Seungryong,[ENTER]budou lidi za\158\237vat utrpen\237.[ENTER][ENTER]Zabij 20 ob\248\237ch tmav\253ch medv\236d\249. Kdy\158 to \250sp\236\154n\236[ENTER]zvl\225dne\154, obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_18_hunt = "Voj\225ci, kte\248\237 trp\237 z\225hadnou nemoc\237 "
gameforge.locale.questscroll_18_mis = "Zab\237t voj\225ky, kte\248\237 trp\237 z\225hadnou nemoc\237. "
gameforge.locale.questscroll_18_text = "Vesnice byla vyhlazena. Ti, kte\248\237 trp\237 z\225hadnou[ENTER]nemoc\237, napadaj\237 ne\154\157astn\237ky, kte\248\237 sem zabloud\237.[ENTER]Napadaj\237 obchodn\237 cestuj\237c\237 a \158erou lidi. Jsou[ENTER]extr\233mn\236 nebezpe\232n\237. "
gameforge.locale.questscroll_19_hunt = "St\248elci, kte\248\237 trp\237 z\225hadnou nemoc\237 "
gameforge.locale.questscroll_19_mis = "Zab\237t st\248elce, kte\248\237 trp\237 z\225hadnou nemoc\237. "
gameforge.locale.questscroll_19_text = "Z\225hadn\225 nemoc je p\248\237\232ina \154kod, kter\233 zp\249sobuj\237[ENTER]ti, kte\248\237 j\237 trp\237. Ale nejnebezpe\232n\236j\154\237 jsou[ENTER]lukost\248elci, kter\233 z\225hadn\225 nemoc zas\225hla.[ENTER]Tito lukost\248elci vyst\248eluj\237 otr\225ven\233 \154\237py, kter\233[ENTER]ochromuj\237 lidi na cest\225ch. Pak se jich zmocn\237 a[ENTER]zavle\232ou je do nezn\225ma.[ENTER][ENTER]Zabij 25 lukost\248elc\249, kte\248\237 trp\237 z\225hadnou nemoc\237.[ENTER]Kdy\158 bude\154 m\237t \250sp\236ch, obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_1_hunt = "Ohniv\237 medv\236di "
gameforge.locale.questscroll_1_mis = "Skolit 25 ohniv\253ch medv\236d\249 "
gameforge.locale.questscroll_1_text = "S ohniv\253mi medv\236dy se m\249\158e\154 setkat v bl\237zkosti[ENTER]hlavn\237ho m\236sta. Potuluj\237 se pr\233ri\237 a \154irok\253mi[ENTER]ulicemi. \200\237m d\225l v\237c lid\237 se st\225v\225 jejich ob\236t\237.[ENTER]U\158 bylo zabito n\236kolik lid\237.[ENTER][ENTER]Ho\242 ohniv\233 medv\236dy. A\158 jich zabije\154 25, obdr\158\237\154[ENTER]n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "Zab\237t 4 nep\248\225tele. "
gameforge.locale.questscroll_20_text = "Ob\225v\225m se, \158e jsem vy\248\237zen\253! Vid\237m v\154echno[ENTER]rozmazan\236. A\158 bude\154 \232\237st tenhle dopis, bude u\158[ENTER]moje t\236lo prohnil\233 skrz naskrz. Ti mizerov\233 m\236[ENTER]popadli a zat\225hli pry\232. Uniknul jsem jim sice,[ENTER]ale m\236l jsem tak hlubok\233 r\225ny, \158e jsem se[ENTER]zhroutil. Nev\237m, kdo jsi. Ale pros\237m - pomsti se[ENTER]za m\236![ENTER]Pozab\237jej na m\237st\236 m\233ho posledn\237ho boje hodn\236[ENTER]nep\248\225tel. Kdy\158 se ti to povede, dostane\154[ENTER]n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_2_hunt = "Velk\253 tygr "
gameforge.locale.questscroll_2_mis = "Skolit 20 velk\253ch tygr\249 "
gameforge.locale.questscroll_2_text = "Ve vzduchu je c\237tit jm\233no zloby a vzteku, velk\253[ENTER]tygr. Tito tyg\248i se v\236t\154inou nach\225zej\237 bl\237zko[ENTER]hlavn\237ho m\236sta. Napadaj\237 lidi a \158erou mrtvoly[ENTER]obchodn\237k\249. Za ob\236\157 jim padl nespo\232et nevinn\253ch[ENTER]ob\236t\237.[ENTER][ENTER]Lov velk\233 tygry. Kdy\158 skol\237\154 20 velk\253ch tygr\249,[ENTER]dostane\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_3_hunt = "Ps\237 b\249h hory "
gameforge.locale.questscroll_3_mis = "Zabij ps\237ho boha hory "
gameforge.locale.questscroll_3_text = "Ps\237 b\249h hory je v\249dcem sme\232ky ps\237ch nestv\249r,[ENTER]kter\225 se potuluje nedaleko odsud. Je siln\253 a[ENTER]divok\253. Ned\225vno se objevil pobl\237\158 vesnice a za\232al[ENTER]napadat obchodn\237ky. T\233to nestv\249\248e u\158 padlo hodn\236[ENTER]lid\237 za ob\236\157. Proti jeho odporn\253m \232in\249m se[ENTER]kone\232n\236 mus\237 n\236co ud\236lat.[ENTER][ENTER]Zabij ps\237ho boha hory. V p\248\237pad\236 \250sp\236chu obdr\158\237\154[ENTER]n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_4_hunt = "Prase\232\237 b\249h "
gameforge.locale.questscroll_4_mis = "Zab\237t prase\232\237ho boha. "
gameforge.locale.questscroll_4_text = "V t\233to ro\232n\237 dob\236 jsou klasy na poli obt\236\158k\225ny[ENTER]zral\253m obil\237m. Nast\225v\225 obdob\237 \250rod, pro zem\236d\236lce[ENTER]je na \232ase sklidit plody jejich celoro\232n\237 d\248iny.[ENTER]Ale prase\232\237 b\249h a jeho kump\225ni po\158\237raj\237 v\154echno[ENTER]obil\237. Jejich la\232nost ohro\158uje \158ivoty zem\236d\236lc\249,[ENTER]proto se jich mus\237me zbavit.[ENTER][ENTER]Zabij prase\232\237ho boha. Nach\225z\237 se v\236t\154inou v[ENTER]bl\237zkosti hlavn\237ho m\236sta. Kdy\158 nad n\237m zv\237t\236z\237\154,[ENTER]obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_5_hunt = "Medv\236d\237 b\249h "
gameforge.locale.questscroll_5_mis = "Zab\237t medv\236d\237ho boha "
gameforge.locale.questscroll_5_text = "Ve sv\233m p\248irozen\233m prost\248ed\237 se medv\236d\237 b\249h[ENTER]choval norm\225ln\236. Ale v posledn\237 dob\236 se objevuje[ENTER]nedaleko hlavn\237ho m\236sta a napad\225 lidi. Vyb\237r\225 si[ENTER]\232\237m d\225l v\237c ob\236t\237. Kolik jich doposud zem\248elo, se[ENTER]u\158 ani ned\225 spo\232\237tat. Proto mus\237 odsud zmizet.[ENTER][ENTER]Zabij medv\236d\237ho boha. Kdy\158 se ho doopravdy[ENTER]zbav\237\154, obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_6_hunt = "Tyg\248\237 b\249h "
gameforge.locale.questscroll_6_mis = "Zab\237t tyg\248\237ho boha. "
gameforge.locale.questscroll_6_text = "Sotva tomu m\249\158u uv\236\248it. Jak jenom tyg\248\237 b\249h mohl[ENTER]nap\225chat n\236co tak hrozn\233ho? Jsem jenom prost\225[ENTER]\158ena, klan\236la jsem se ka\158d\253 den tyg\248\237mu bohu,[ENTER]kter\253 se \232as od \232asu objevoval na horsk\253ch[ENTER]stezk\225ch. Ale jednoho dne napadl tyg\248\237 b\249h a jeho[ENTER]stoupenci moji rodinu! V\154ichni byli na m\237st\236[ENTER]mrtv\237 a j\225 jsem p\248i\154la o ruku.[ENTER][ENTER]Pros\237m, pomsti se za moji rodinu. Kdy\158 tyg\248\237ho[ENTER]boha zabije\154, obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_7_hunt = "V\249dkyn\236 klanu B\237l\233 p\248\237sahy "
gameforge.locale.questscroll_7_mis = "Zab\237t v\249dkyni klanu b\237l\233 p\248\237sahy. "
gameforge.locale.questscroll_7_text = "Klan B\237l\233 p\248\237sahy je skupina \158en, kter\233 jejich[ENTER]mu\158i opustili a cel\253 sv\236t je nechal na holi\232k\225ch.[ENTER]Jsou sice chud\233, ale zp\249sob, jak\253m t\253raj\237[ENTER]obyvatele vesnice, je dost brut\225ln\237. Jedna \158ena[ENTER]byla ukamenov\225na, kdy\158 ve\154la do vesnice. Nem\249\158eme[ENTER]dopustit, aby se dostaly do vesnice a napadaly[ENTER]vesni\232any.[ENTER][ENTER]Zabij 20 v\249dky\242 B\237l\233 P\248\237sahy. Kdy\158 tento \250kol[ENTER]\250sp\236\154n\236 zvl\225dne\154, obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
gameforge.locale.questscroll_8_hunt = "N\225\232eln\237k bandy \200ern\233ho v\236tru "
gameforge.locale.questscroll_8_mis = "Zab\237t n\225\232eln\237ka bandy \200ern\233ho v\236tru. "
gameforge.locale.questscroll_8_text = "Zlod\236jov\233 z bandy \200ern\233ho v\236tru maj\237 u\158 dlouho[ENTER]nam\237\248eno na obchodn\237 cestuj\237c\237. Vzbuzuj\237 tolik[ENTER]strachu, \158e se nikdo neodva\158uje zah\225jit[ENTER]proti\250tok. Ale tomu se mus\237 u\232init konec, proto\158e[ENTER]zp\249sobuj\237 opravdu nesnesitelnou \154kodu.[ENTER][ENTER]Zabij 20 v\249dc\249 bandy \200ern\233ho v\236tru. Kdy\158 tenhle[ENTER]\250kol \250sp\236\154n\236 dokon\232\237\154, obdr\158\237\154 n\225sleduj\237c\237[ENTER]odm\236nu: "
gameforge.locale.questscroll_9_hunt = "N\225\232eln\237k barbar\249 "
gameforge.locale.questscroll_9_mis = "Zab\237t n\225\232eln\237ka barbar\249. "
gameforge.locale.questscroll_9_text = "U\158 uplynul n\236jak\253 \232as od t\233 doby, co barba\248i[ENTER]p\248ekro\232ili hranice a p\248epadli vesnici. Pozab\237jeli[ENTER]stovky lid\237 a po\232et lid\237, kte\248\237 utrp\236li \154kody na[ENTER]majetku nebo na zdrav\237, je mnohem vy\154\154\237. Zlovoln\237[ENTER]barba\248i jsou tak brut\225ln\237, \158e se nikdo neodva\158uje[ENTER]zah\225jit pomstu. Ale my to u\158 nebudeme d\225l[ENTER]tolerovat.[ENTER]Zabij 25 n\225\232eln\237k\249 barbar\249. Kdy\158 \250sp\236\154n\236 dokon\232\237\154[ENTER]tenhle \250kol, obdr\158\237\154 n\225sleduj\237c\237 odm\236nu: "
