gameforge.locale.skill_group.board = "V let\225ku stoj\237:[ENTER]Rekrutujeme state\232n\233 mu\158e a \158eny, kte\248\237 jsou[ENTER]p\248ipraveni bojovat za m\237r v kr\225lovstv\237 a za jeho[ENTER]ob\232any![ENTER][ENTER]P\248edpoklad pro vstup do arm\225dy: minim\225ln\236 \250rove\242[ENTER]5. "
gameforge.locale.skill_group.dialog_assassin_1 = "Tady vzd\236l\225v\225me Ninjy, kte\248\237 jsou obzvl\225\154\157 dob\248\237[ENTER]v ukr\253v\225n\237 se a v z\225ke\248n\253ch \250toc\237ch. Soust\248ed\237 se[ENTER]na zach\225zen\237 s d\253kou a jedy. K n\225m m\249\158ou vstoupit[ENTER]pouze Ninjov\233, kte\248\237 se nach\225z\237 ve v\253cviku a maj\237[ENTER]minim\225ln\236 level 5. A\158 pravideln\253m tr\233ninkem[ENTER]dos\225hne\154 ur\232it\233 \250rovn\236, dostane\154 nab\237dku ke[ENTER]vstupu. Jestli jsi p\248ipraven na to, se na v\236ky[ENTER]schov\225vat v temnot\236, porozhl\233dni se po mn\236. Pak[ENTER]si o tom m\249\158eme promluvit. "
gameforge.locale.skill_group.dialog_assassin_2 = "Tady prob\237h\225 v\253cvik Ninj\249, kte\248\237 jsou[ENTER]specializov\225ni na ukr\253v\225n\237 se a z\225ke\248n\233 \250toky.[ENTER]Soust\248ed\237 se na zach\225zen\237 s d\253kou a jedy. Jestli[ENTER]jsi p\248ipraven na to, se jako Ninja na v\236ky v\236k\249[ENTER]schov\225vat v temnot\236, porozhl\233dni se po m\236. Budeme[ENTER]bojovat bok po boku. V\237t\225m ka\158d\233ho, kdo je k tomu[ENTER]odhodl\225n. "
gameforge.locale.skill_group.dialog_assassin_3 = "Tady prob\237h\225 v\253cvik Ninj\249, kte\248\237 jsou mist\248i v[ENTER]zach\225zen\237 s lukem. Vyu\232uj\237 se tady schopnosti,[ENTER]kter\233 jsou v lukost\248elb\236 pot\248eba.[ENTER]Nau\232\237\154 se vyst\248elovat cel\233 salvy \154\237p\249 na[ENTER]nep\248\225tele v dosahu.[ENTER]M\249\158ou vstoupit jenom Ninjov\233 ve v\253cviku, kte\248\237[ENTER]maj\237 minim\225ln\236 \250rove\242 5. A\158 d\237ky tr\233ninku[ENTER]dos\225hne\154 ur\232it\233 \250rovn\236, bude ti nab\237dnuto, abys[ENTER]vstoupil. Stav se u m\236, jestli m\225\154 z\225jem. "
gameforge.locale.skill_group.dialog_assassin_4 = "Tady prob\237h\225 v\253cvik Ninj\249, kte\248\237 jsou mist\248i v[ENTER]zach\225zen\237 s lukem. Vyu\232uj\237 se tady schopnosti,[ENTER]kter\233 jsou v lukost\248elb\236 pot\248eba.[ENTER]Nau\232\237\154 se vyst\248elovat cel\233 salvy \154\237p\249 na v\154echny[ENTER]nep\248\225tele v dosahu.[ENTER]N\225sleduj m\236. Ud\236l\225m z tebe nejlep\154\237ho lukost\248elce[ENTER]na cel\233m kontinentu. "
gameforge.locale.skill_group.dialog_assassin_5 = "Rozhodni se mezi bojem zbl\237zka a bojem t\236lo na[ENTER]t\236lo a obdr\158\237\154 pat\248i\232n\233 schopnosti. "
gameforge.locale.skill_group.dialog_shaman_1 = "Tohle je m\237sto, na kter\233m se sch\225z\237 \154amani, kte\248\237[ENTER]n\225sleduj\237 stezku dra\232\237ho boha. Vyu\232uj\237 schopnosti[ENTER]v zach\225zen\237 s amulety a s\237lou ducha. Odr\225\158\237[ENTER]nazp\236t techniky, kter\233 pou\158il jejich nep\248\237tel,[ENTER]d\237ky ochran\236 dra\232\237ho boha zvy\154uj\237 vlastn\237 hodnotu[ENTER]obrany a podporuj\237 sp\248\225telen\233 bojovn\237ky.[ENTER]M\249\158ou vstoupit \154amani ve v\253cviku, kte\248\237 maj\237[ENTER]minim\225ln\236 \250rove\242 5. A\158 tr\233ninkem dos\225hne\154 ur\232it\233[ENTER]\250rovn\236, bude ti nab\237dnut vstup. Jestli jsi[ENTER]p\248ipraven na u\232en\237 dra\232\237 moci, vyhledej m\236. "
gameforge.locale.skill_group.dialog_shaman_2 = "Tohle je m\237sto \154aman\249, kte\248\237 n\225sleduj\237 dra\232\237[ENTER]moci. Vyu\232uj\237 schopnosti v zach\225zen\237 s amulety a[ENTER]silou ducha. Odr\225\158ej\237 nazp\236t techniky, kter\233[ENTER]pou\158il jejich nep\248\237tel, d\237ky ochran\236 dra\232\237ho boha[ENTER]zvy\154uj\237 vlastn\237 hodnotu obrany a podporuj\237[ENTER]sp\248\225telen\233 bojovn\237ky.[ENTER]\216ekl bys, \158e jsi p\248ipraven spolu se mnou \154\237\248it[ENTER]u\232en\237 dra\232\237ho boha?[ENTER]Pokorn\237 v\236\248\237c\237 jsou kdykoliv v\237t\225ni. "
gameforge.locale.skill_group.dialog_shaman_3 = "Zde vyzn\225vaj\237 \154amani moc p\248\237rody a sv\236tla.[ENTER]Vyu\232uj\237 schopnosti, kter\233 souvis\237 s blesky, v\236try[ENTER]a l\233\232en\237m. \200asto pracuj\237 ve skupin\236, aby se mohli[ENTER]navz\225jem podporovat. M\249\158ou vstoupit jenom \154amani[ENTER]ve v\253cviku, kte\248\237 maj\237 minim\225ln\236 \250rove\242 5.[ENTER]Jestli nem\225\154 pot\248ebnou kvalifikaci, zvy\154 si[ENTER]\250rove\242 pravideln\253m tr\233ninkem. Budu t\236 tady[ENTER]o\232ek\225vat. "
gameforge.locale.skill_group.dialog_shaman_4 = "Tady vyzn\225vaj\237 \154amani moc p\248\237rody a sv\236tla.[ENTER]Vyu\232uj\237 schopnosti, kter\233 souvis\237 s blesky, v\236try[ENTER]a l\233\232en\237m. \200asto pracuj\237 ve skupin\236, aby se mohli[ENTER]navz\225jem podporovat. Chce\154 spolu se mnou pom\225hat[ENTER]druh\253m? Tvoje podpora by byla prosp\236\154n\225 v\154em[ENTER]trp\237c\237m. Pros\237m pomo\158 mi s t\237m. "
gameforge.locale.skill_group.dialog_shaman_5 = "Rozhodni se mezi dra\232\237 moc\237 a l\233\232en\237m a hned[ENTER]obdr\158\237\154 pot\248ebn\233 schopnosti. "
gameforge.locale.skill_group.dialog_sura_1 = "Vyu\232uji lidi, jak m\249\158ou vyu\158\237vat magii, kter\225[ENTER]byla \239\225belsk\253m semenem zasazen\253m do m\233 lev\233 pa\158e.[ENTER]Tuto magii aplikuji do me\232\249 a brn\236n\237 a t\237m p\225dem[ENTER]zvy\154uji \250tok a obranu. Za\248\237k\225v\225m zl\233 duchy v[ENTER]pekle, kte\248\237 oslabuj\237 mor\225lku nep\248\237tele. M\249\158ou[ENTER]vstoupit jenom Surov\233 ve v\253cviku a kte\248\237 maj\237[ENTER]minim\225ln\236 \250rove\242 5. A\158 dos\225hne\154 ur\232it\233 \250rovn\236,[ENTER]dostane\154 nab\237dku k zrekrutov\225n\237. Jestli jsi[ENTER]p\248ipraven vrhat me\232e noci nebo vyslovovat v\236\232n\233[ENTER]klatby tmy, p\248ij\239 sem. "
gameforge.locale.skill_group.dialog_sura_2 = "Vyu\232uji lidi, jak m\249\158ou vyu\158\237vat magii, kter\225[ENTER]byla \239\225belsk\253m semenem zasazen\253m do m\233 lev\233 pa\158e.[ENTER]Tuto magii aplikuji do me\232\249 a brn\236n\237 a t\237m p\225dem[ENTER]zvy\154uji \250tok a obranu. Za\248\237k\225v\225m zl\233 duchy v[ENTER]pekle, kte\248\237 oslabuj\237 mor\225lku nep\248\237tele. Jsi[ENTER]p\248ipraven vrhat me\232e noci nebo vyslovovat v\236\232n\233[ENTER]klatby tmy? M\249\158u t\236 ujistit, \158e se tady dostane\154[ENTER]k po\248\225dn\233 moci. "
gameforge.locale.skill_group.dialog_sura_3 = "Pro p\248\237pad, \158e t\236 zaj\237m\225 toto m\237sto: Tady najde\154[ENTER]ty, kte\248\237 se upsali temnot\236. Vyu\232uj\237 zach\225zen\237 s[ENTER]plameny \239\225bla a schopnosti zl\253ch duch\249 a d\233mon\249.[ENTER]M\249\158ou vstoupit Surov\233 ve v\253cviku, kte\248\237 maj\237[ENTER]minim\225ln\236 \250rove\242 5. A\158 dos\225hne\154 ur\232it\233 \250rovn\236,[ENTER]obdr\158\237\154 ozn\225men\237 k rekrutov\225n\237. Jestli chce\154 \158\237t[ENTER]v temnot\236, pak je to spr\225vn\233 m\237sto na to, abys[ENTER]objevil, co v\154echno ti sk\253t\225 takov\253 sv\236t. "
gameforge.locale.skill_group.dialog_sura_4 = "Pro p\248\237pad, \158e t\236 zaj\237m\225 toto m\237sto: Tady najde\154[ENTER]ty, kte\248\237 se upsali temnot\236. Vyu\232uj\237 zach\225zen\237 s[ENTER]plameny \239\225bla a schopnosti zl\253ch duch\249 a d\233mon\249.[ENTER]Jestli m\225\154 z\225jem uzav\248\237t p\248\225telstv\237 se zl\253mi[ENTER]duchy, kte\248\237 t\236 kousek po kousku pohlt\237, tak[ENTER]vstup. Kdy\158 vstoup\237\154, ponech ve\154kerou lidskost[ENTER]venku. "
gameforge.locale.skill_group.dialog_sura_5 = "Rozhodni se mezi \232ernou magi\237 a magickou zbran\237 a[ENTER]hned obdr\158\237\154 pat\248i\232n\233 schopnosti. "
gameforge.locale.skill_group.dialog_warrior_1 = "V\237\154, kde se pr\225v\236 nach\225z\237\154? Tady prob\237h\225 v\253cvik[ENTER]\250to\232n\237k\249. V\225le\232n\237ci, kte\248\237 budou pat\248it k[ENTER]nejrychlej\154\237m a nejodv\225\158n\236j\154\237m v cel\233 jednotce.[ENTER]Vyu\232uj\237 se tady techniky, jak opakovan\236 ude\248it[ENTER]rychle za sebou a jak vyu\158\237t schopnost\237 b\236hem[ENTER]\250toku. M\249\158ou vstoupit jenom v\225le\232n\237ci ve v\253cviku,[ENTER]kte\248\237 jsou minim\225ln\236 \250rovn\236 5. A\158 dos\225hne\154 ur\232it\233[ENTER]\250rovn\236, sd\236l\237 ti arm\225da, \158e\180s byl p\248ijat. Jestli[ENTER]chce\154 v\236d\236t, v \232em spo\232\237v\225 opravdov\225 s\237la tv\233ho[ENTER]t\236la, p\248ij\239 ke mn\236! "
gameforge.locale.skill_group.dialog_warrior_2 = "V\237\154, kde se pr\225v\236 nach\225z\237\154? Tady prob\237h\225 v\253cvik[ENTER]\250to\232n\237k\249, kte\248\237 pat\248\237 k t\236m nejrychlej\154\237m a[ENTER]nejodv\225\158n\236j\154\237m. Vyu\232uje se tady, jak opakovan\236 v[ENTER]rychl\233m sledu \250to\232it nebo jak vyu\158\237t schopnost\237[ENTER]p\248i \250toku. Obzvl\225\154t\236 se zdokonal\237\154 v zach\225zen\237 s[ENTER]me\232em a o\154t\236pem. Tak jak to vypad\225? Chce\154[ENTER]tr\233novat? "
gameforge.locale.skill_group.dialog_warrior_3 = "Tady vyu\232uj\237 v\225le\232n\237ci vyu\158it\237 Chi. Vyu\232uj\237 \250toky[ENTER]v boji zbl\237zka, kter\233 se opakuj\237 v pomal\233m sledu[ENTER]a jsou du\154evn\236 vy\232erp\225vaj\237c\237. Tyto \250toky jsou[ENTER]z\225rove\242 velmi mocn\233 a \250\232inn\233. M\249\158ou vstoupit[ENTER]pouze v\225le\232n\237ci ve v\253cviku, kte\248\237 maj\237 minim\225ln\236[ENTER]\250rove\242 5. A\158 dos\225hne\154 ur\232it\233 \250rovn\236, obdr\158\237\154 od[ENTER]arm\225dy povol\225vac\237 rozkaz. Jestli m\225\154 z\225jem, stav[ENTER]se u m\236. "
gameforge.locale.skill_group.dialog_warrior_4 = "Tady vyu\232uj\237 v\225le\232n\237ci vyu\158it\237 Chi. Vyu\232uj\237 \250toky[ENTER]v boji zbl\237zka, kter\233 se opakuj\237 v pomal\233m sledu[ENTER]a jsou du\154evn\236 vy\232erp\225vaj\237c\237. Tyto \250toky jsou[ENTER]z\225rove\242 velmi mocn\233 a \250\232inn\233. Schopnosti v[ENTER]ment\225ln\237m boji se prok\225\158ou v z\225vislosti na tv\233m[ENTER]ur\232en\237. M\225\154 z\225jem o ment\225ln\237 boj? "
gameforge.locale.skill_group.dialog_warrior_5 = "Rozhodni se mezi bojem t\236lo na t\236lo a ment\225ln\237m[ENTER]bojem a hned obdr\158\237\154 pat\248i\232n\233 schopnosti. "
gameforge.locale.skill_group.invite = "Ozn\225men\237 rekrutovac\237ho v\253boru arm\225dy "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Ozn\225men\237 o rekrutov\225n\237[ENTER]v\225le\232n\237k\249[/COLOR][ENTER]Pokud obdivuje\154 v\225le\232n\237ky kv\249li jejich schopnosti[ENTER]\250to\232it rychle za sebou, doporu\232uji ti tr\233nink[ENTER]boje t\236lo na t\236lo. Pokud chce\154 nar\225z vyhladit[ENTER]cel\233 skupiny nestv\249r, doporu\232uji ti tr\233nink[ENTER]ment\225ln\237ho boje. O\232ek\225v\225m t\236 na n\225m\236st\237 ve m\236st\236. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Ozn\225men\237 rekrutov\225n\237[ENTER]ninj\249[/COLOR][ENTER]Jestli se chce\154 proslavit jako v\253born\253[ENTER]lukost\248elec, vyu\232 se boji na d\225lku. Jestli jsi[ENTER]p\248ipraven jako Ninja pod rou\154kou tmy prov\225d\236t[ENTER]tajn\233 mise, pak je pro tebe nejlep\154\237 boj zbl\237zka.[ENTER]O\232ek\225v\225m t\236 na n\225m\236st\237 ve m\236st\236. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Ozn\225men\237 rekrutov\225n\237[ENTER]Sur\249[/COLOR][ENTER]Chce\154 se st\225t opravdov\253m poslem a jezdcem a[ENTER]vykonat n\236co, co je nad lidsk\233 s\237ly? V tom[ENTER]p\248\237pad\236 ti doporu\232uji zdokonalit se v um\236n\237[ENTER]magick\253ch zbran\237. Pokud si ale sp\237\154 p\248eje\154, aby[ENTER]se t\236 ka\158d\253 ob\225val jako \232arod\236je temnoty a[ENTER]klateb, tak si zvol um\236n\237 \232ern\233 magie. O\232ek\225v\225m[ENTER]t\236 na n\225m\236st\237 ve m\236st\236. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]Ozn\225men\237 rekrutov\225n\237[ENTER]\154aman\249[/COLOR][ENTER]Jestli se chce\154 st\225t kouzeln\237kem, kter\253 ovl\225d\225[ENTER]nasazen\237 nejen amulet\249, ale i magi\237 a po\158ehn\225n\237,[ENTER]doporu\232uji ti nau\232it se dra\232\237 moci. Pokud ale[ENTER]chce\154 m\237rnit bolesti trp\237c\237ch, prov\225d\236t[ENTER]obnovov\225n\237 a l\233\232it, pak ti doporu\232uji nauku o[ENTER]l\233\232en\237. O\232ek\225v\225m t\236 na n\225m\236st\237 ve m\236st\236. "
