gameforge.locale.stamina_food.butcher.start_say2 = "Star\253 mu\158 v restauraci Suhpyung:[ENTER]Chcete v\236d\236t, co je zelen\225 \158ab\237 pol\233vka? Kdy\158 j\237[ENTER]misku sn\237te, nebudete unaven\237! I kdybyste[ENTER]pracovali t\248eba cel\253 t\253den na poli, m\236li byste[ENTER]ve\232er je\154t\236 po\248\225d dost energie! Jeden m\249j[ENTER]kamar\225d, jmenuje se Oakgu, um\237 zelenou \158ab\237[ENTER]pol\233vku nejl\237p ze v\154ech kucha\248\249, kter\233 zn\225m. Ale[ENTER]z n\236jak\233ho d\249vodu u\158 ji neva\248\237. "
