gameforge.main_quest_flame_lv101._280_say = "Mus\237me zjistit, co je v t\233 pevnosti schov\225no.[ENTER]Pod\237vej, tady na stran\236 N\253tovan\233ho n\225hrdeln\237ku je[ENTER]n\236jak\253 n\225pis. Zept\225m se na radu Yon-I-Walkera.[ENTER]Pokud bude pot\248ebovat tvou pomoc, vzk\225\158e pro tebe. "
