gameforge.main_quest_flame_lv105._340_say = "To bylo v\154e ty \232erve? To bylo jak za\154imr\225n\237 - s[ENTER]t\237m m\236 nevypud\237\154! Znovu p\248ivedu Razadora z \248\237\154e[ENTER]mrtv\253ch. Osvobod\237 m\236 z m\233ho v\236zen\237 a ty poc\237t\237\154[ENTER]m\249j hn\236v! "
