gameforge.main_quest_lv1._60_sayTitle = "Str\225\158ce vesnice: "
gameforge.main_quest_lv1._70_say = "Ty jsi tady ur\232it\236 nov\253! Jak vid\237m, je\154t\236 z tebe[ENTER]neud\236lali voj\225ka. M\225\154 aspo\242 za sebou n\236jak\253[ENTER]v\253cvik? Pod\237vej se na sebe, jak vypad\225\154![ENTER]M\225\154 v\249bec pon\236t\237, jak se zach\225z\237 se zbran\236mi?[ENTER]Mus\237\154 b\253t neust\225le ve st\248ehu, pokud chce\154 p\248e\158\237t[ENTER]ve v\225lce. Do t\233 doby, ne\158 se dostane\154 na \250rove\242[ENTER]10, ti budu n\225pomocn\253.[ENTER]Nespol\233hej se na to, \158e to bude jednoduch\233![ENTER]Tak d\236lej! Hybaj hybaj! "
gameforge.main_quest_lv1._80_say = "B\236\158 a u\232 se z\225kladn\237 metody boje a lovu! Jakmile[ENTER]se dostane\154 na vy\154\154\237 \250rove\242, m\236l by ses vr\225tit do[ENTER]vesnice, abychom si zase promluvili.[ENTER][ENTER]Tak na co je\154t\236 \232ek\225\154? B\236\158! Kdy\158 tady bude\154 jenom[ENTER]post\225vat, nic se nenau\232\237\154! "
