gameforge.main_quest_lv10._110_sayTitle = "V\253cvik u velitele "
gameforge.main_quest_lv10._120_sayReward = "Velitel\249v prvn\237 \250kol t\236 zavede do sousedn\237[ENTER]vesnice. Tam bys m\236l naj\237t hudebn\237ka Yu-Hwana a[ENTER]zeptat se ho na tajn\233 dokumenty pro velitele. "
gameforge.main_quest_lv10._130_sayTitle = "Hudebn\237k Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "\142ivot je jenom sen, tak jako v\154echno ostatn\237.[ENTER]Odkud poch\225z\237me a kam sm\236\248ujeme? Sv\236t je pln\253[ENTER]nesv\225ru. Poctiv\225 pr\225ce se nevypl\225c\237.[ENTER]P\248i\154el jsi, abys naslouchal m\233mu zp\236vu? "
gameforge.main_quest_lv10._150_say = "Ah\225, tebe pos\237l\225 velitel![ENTER]P\154\154t, nemluv tak nahlas...[ENTER][ENTER]Nikdo z vesnice se nesm\237 dozv\236d\236t, kdo jsem.[ENTER]Mus\237\154 budit d\249v\236ru, kdy\158 t\236 pos\237l\225 velitel![ENTER]Tady to je. Ten dokument obsahuje informace,[ENTER]kter\233 jsem nasb\237ral.[ENTER]Dones je veliteli. "
gameforge.main_quest_lv10._160_sayTitle = "Hudebn\237k Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Chv\225tej a odejdi! Pokud tu bude\154 moc dlouho, tak[ENTER]se n\236co \154patn\233ho stane. Pamatuj si - \158ivot je[ENTER]kr\225tk\253, tak si ho u\158\237vej tak dlouho, jak jenom[ENTER]m\249\158e\154. "
gameforge.main_quest_lv10._180_targetVid = "Zp\225tky k veliteli. "
gameforge.main_quest_lv10._190_sayReward = "Hudebn\237k Yu-Hwan, kter\253 je ale tajn\253 \154pi\243n, ti[ENTER]dal d\249le\158it\233 dokumenty. Dones je veliteli v prvn\237[ENTER]vesnici. "
gameforge.main_quest_lv10._200_say = "To je ten dokument od hudebn\237ka? Na nov\233ho[ENTER]dobrodruha to nen\237 \154patn\233![ENTER]Vkl\225d\225m do tebe velkou nad\236ji. Vezmi si tohle[ENTER]jako uzn\225n\237 za tvoji vykonanou pr\225ci. A pracuj i[ENTER]nad\225le s takov\253m z\225palem pro tvoji zemi. "
gameforge.main_quest_lv10._20_sayReward = "Te\239 m\225\154 dostatek zku\154enost\237 slou\158it tv\233mu[ENTER]kr\225lovstv\237 jako opravdov\253 v\225le\232n\237k. Odte\239 ti[ENTER]p\248ed\225 dal\154\237 \250koly velitel. Najde\154 ho v prvn\237[ENTER]vesnici. B\236\158 k n\236mu, u\158 na tebe \232ek\225. "
gameforge.main_quest_lv10._30_sayTitle = "Velitel "
gameforge.main_quest_lv10._40_say = "P\248ipad\225\154 mi pov\236dom\253... \193h, jo. Ano, u\158 jsem o[ENTER]tob\236 ur\232it\236 sly\154el. Ty jsi p\248ece ten nov\253[ENTER]dobrodruh a u\158 jsi prok\225zal, \158e n\236co um\237\154.[ENTER]Nev\237m, jak\253m v\253cvikem jsi doposud pro\154el, ale v[ENTER]budoucnosti dostane\154 hodn\236 \250kol\249. "
gameforge.main_quest_lv10._50_say = "\200ek\225 na tebe p\236kn\253ch p\225r p\248ek\225\158ek, tak\158e se na to[ENTER]dob\248e p\248iprav. V\237\154, jak to bylo se t\248emi[ENTER]kr\225lovstv\237mi na Kontinentu Sv\236tl\233ho nebe? Ty ten[ENTER]p\248\237b\236h nezn\225\154? Co t\236 tam p\248i v\253cviku v\249bec[ENTER]nau\232ili? Mus\237m ti takov\233hle z\225kladn\237 informace[ENTER]zprost\248edkovat j\225? "
gameforge.main_quest_lv10._60_say = "Je to d\249le\158it\233, proto\158e je to historie[ENTER]kontinentu. Ve stru\232nosti ti ji \248eknu. Kdysi[ENTER]existovala sjednocen\225 \248\237\154e. Pot\233 se objevily[ENTER]kameny Metin a p\248inesly v\225lku a konflikty.[ENTER]Kontinent byl rozpolcen na t\248i kr\225lovstv\237:[ENTER]Shinsoo je kr\225lovstv\237 obchodu, Chunjo n\225bo\158enstv\237[ENTER]a Jinno je kr\225lovstv\237 vojska. "
gameforge.main_quest_lv10._70_say = "Ka\158d\233 kr\225lovstv\237 se pokou\154\237 o to, p\248ekonat[ENTER]neklid, kter\253 se nad n\237m rozprost\237r\225 od t\233 doby,[ENTER]co sem pronikly kameny Metin. V\154ichni si p\248ej\237[ENTER]znovu sjednocen\253 kontinent.[ENTER]I ty mus\237\154 tvrd\236 pracovat na sjednocen\237[ENTER]kontinentu! Je d\249le\158it\233, abys to m\236l v\158dy na[ENTER]v\236dom\237. "
gameforge.main_quest_lv10._80_say = "Pov\236\248\237m t\236 prvn\237m \250kolem![ENTER]Uklidni se, jedn\225 se o opravdu lehk\253 \250kol...[ENTER]V nejbli\158\154\237 vesnici \158ije hudebn\237k jm\233nem Yu-Hwan.[ENTER]Lid\233 si mysl\237, \158e opustil arm\225du, aby se mohl[ENTER]st\225t hudebn\237kem. Ale ve skute\232nosti to je \154pi\243n.[ENTER]M\225 jeden dokument, kter\253 od n\236j pot\248ebuji. Dones[ENTER]mi ho. Nezapome\242 na to, \158e to je tajn\233 posl\225n\237! "
gameforge.main_quest_lv10._90_say = "Stiskni kl\225vesu M, aby ses dozv\236d\236l, jak se[ENTER]dostane\154 do nejbli\158\154\237 vesnice na map\236. Jdi p\248es[ENTER]Warpov\253 port\225l s n\225zvem vesnice.[ENTER]Posp\236\154 si![ENTER]Hudebn\237k Yu-Hwan je vysok\253 chl\225pek s hudebn\237m[ENTER]instrumentem. "
