gameforge.main_quest_lv15._10_qSetTitle = "Sou\232asn\225 situace "
gameforge.main_quest_lv15._110_say = "Je\154t\236 po\248\225d m\225me nejmocn\236j\154\237 arm\225du ze v\154ech[ENTER]kr\225lovstv\237, a\232koliv kv\249li kamen\249m Metin nic[ENTER]nepodnik\225me. Kdy\158 budeme doopravdy cht\237t, m\249\158eme[ENTER]nad ostatn\237mi zem\236mi snadno zv\237t\236zit. M\236l bys[ENTER]tvrd\236 tr\233novat, aby z tebe byl dobr\253 voj\225k. "
gameforge.main_quest_lv15._120_say = "P\248id\236l\237m ti nov\253 \250kol. Dones tuhle munici[ENTER]Yu-Hwanovi v sousedn\237 vesnici. Ulo\158\237me tuto[ENTER]munici na n\236kolika bezpe\232n\253ch m\237stech, tak\158e k n\237[ENTER]budeme m\237t rychl\253 p\248\237stup v p\248\237pad\236 nutnosti.[ENTER]Pokud tohle doru\232\237\154 Yu-Hwanovi, pod\225\154 pomocnou[ENTER]ruku vesnici. "
