gameforge.main_quest_lv15._180_say = "Dobr\225 pr\225ce! Pokud takhle bude\154 pokra\232ovat, mohl[ENTER]by z tebe b\253t d\249le\158it\253 pomocn\237k pro na\154i vesnici.[ENTER]Zde je tv\225 odm\236na. "
gameforge.main_quest_lv15._20_say = "Jak jsi mo\158n\225 zaslechl, m\237rov\233 vztahy mezi[ENTER]kr\225lovstv\237mi nejsou v tuto chv\237li zrovna dobr\233.[ENTER]Jdi za velitelem, m\225 pro tebe v\237ce informac\237. "
gameforge.main_quest_lv15._30_say = "Mysl\237m si, \158e bys m\236l v\236d\236t v\237ce o na\154\237 sou\232asn\233[ENTER]situaci. Nejprve zam\236\248 svoji pozornost na na\154e[ENTER]kr\225lovstv\237. Chceme-li vyhr\225t v\225lku pot\248ebujeme[ENTER]poznat sami sebe p\248edt\237m ne\158 pozn\225me nep\248\237tele. "
gameforge.main_quest_lv15._40_say = "Na\154e kr\225lovstv\237, Shinsoo, bylo odjak\158iva centrem[ENTER]obchodu. M\236li jsme rozs\225hl\233 obchodn\237 cesty a[ENTER]proto obchod v na\154em kr\225lovstv\237 jenom rozkv\233tal.[ENTER]Ale od t\233 doby, co se zde objevily kameny Metin,[ENTER]se trh rozpad\225 a na\154e hospod\225\248stv\237 se zhor\154uje.[ENTER]V\158dycky jsme kladli d\249raz na hospod\225\248stv\237 a nikdy[ENTER]jsme nepat\248ili k vojensk\253m mocnostem, co\158 je[ENTER]d\249vod pro\232 jsme najali \158oldn\233\248e.Tito bojovn\237ci[ENTER]jsou velmi spolehliv\253 a loaj\225ln\237 k t\236m, kte\248\237 je[ENTER]plat\237. "
gameforge.main_quest_lv15._50_say = "D\237ky \158oldn\233\248\249m se na\154e zem\236 znovu pom\236rn\236 dob\248e[ENTER]stabilizovala. Ale abychom se mohli dob\248e[ENTER]p\248ipravit na nast\225vaj\237c\237 v\225lky, pot\248ebujeme je\154t\236[ENTER]v\237ce \158oldn\233\248\249 a siln\233 hospod\225\248stv\237. To bude od[ENTER]n\225s v\154ech vy\158adovat velk\233 ob\236ti. "
gameforge.main_quest_lv15._60_say = "Te\239 t\236 pov\236\248\237m nov\253m \250kolem. Dones tuhle[ENTER]specialitu Yu-Hwanovi v sousedn\237 vesnici. Na\154e[ENTER]zem\236 je kr\225lovstv\237m obchodu, obchodujeme s[ENTER]r\249zn\253mi region\225ln\237mi specialitami. Kdy\158 tohle[ENTER]donese\154 bude to pro blaho vesnice. "
gameforge.main_quest_lv15._70_say = "Na\154e kr\225lovstv\237 Chunjo je pod vl\225dou guvern\233ra[ENTER]Yoon Younga a je zbudov\225no na z\225klad\236[ENTER]n\225bo\158enstv\237. D\237ky tomu jsme v\236d\236li o existenci[ENTER]Sung Mahi. Na\154i \154amani n\225s p\248ipravili na v\253skyt[ENTER]kamen\249 Metin. Na\154i nejv\236t\154\237 \154amani pracuj\237 tvrd\236[ENTER]na bezpe\232\237 na\154\237 zem\236. D\237ky sv\233 v\237\248e maj\237 hodn\236[ENTER]schopnost\237. Bez nich by bylo jenom ot\225zkou \232asu,[ENTER]ne\158 by n\225s pohltilo jin\233 kr\225lovstv\237. "
gameforge.main_quest_lv15._80_say = "Obyvatelstvo na\154\237 zem\236 je siln\236 v\236\248\237c\237 a modl\237 se[ENTER]ka\158d\253 den k dra\232\237mu bohovi. Milosrdn\253 dra\232\237 b\249h[ENTER]n\225s ochra\242uje p\248ed znovuzrozen\237m Sung Mahi\249.[ENTER]S jeho pomoc\237 bychom se m\236li i nad\225le br\225nit p\248ed[ENTER]\250toky barbar\249 a znovu sjednotit kontinent pod[ENTER]na\154\237 kontrolu. "
gameforge.main_quest_lv15._90_say = "P\248id\236l\237m ti nov\253 \250kol. Dones tuhle kamennou sochu[ENTER]dra\232\237ho boha Yu-Hwanovi v sousedn\237 vesnici.[ENTER]Na\154e zem\236 je n\225bo\158ensky zalo\158en\225 a hlubok\225 v\237ra v[ENTER]dra\232\237ho boha je pro n\225s velmi d\249le\158it\225. Kdy\158[ENTER]tuhle sochu donese\154 Yu-Hwanovi, v\253znamn\236 si[ENTER]zaslou\158\237\154 o podporu v\237ry v na\154\237 vesnici. "
