gameforge.main_quest_lv30._150_say = "U\232enec Uriel pot\248ebuje v\237ce star\253ch text\249, aby si[ENTER]ud\236lal p\248edstavu o p\237smenech, kter\225 nezn\225.[ENTER]Jdi do \250dol\237 Seungryong a hledej texty na[ENTER]Kamenn\233m pomn\237ku Seul Rong. "
