gameforge.main_quest_lv32._350_sayTitle = "Prvn\237 str\225nka z den\237ku: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop v \248\237\154i Taejo roz\154i\248uje svoje teritorium[ENTER]dob\253v\225n\237m jin\253ch \250zem\237. Chce si ostatn\237 \250zem\237[ENTER]podrobit pomoc\237 vojensk\233 s\237ly. Mus\237me zabr\225nit[ENTER]tomu, aby si podrobil i na\154i \248\237\154i. Nem\225me ale[ENTER]tolik mo\158nost\237, proto\158e jeho arm\225da je obrovsk\225 a[ENTER]siln\225. Proto jsme se rozhodli, \158e budeme vyu\158\237vat[ENTER]i zak\225zan\233 \232\225ry. "
gameforge.main_quest_lv32._370_sayTitle = "Pokra\232ov\225n\237 prvn\237 strany: "
gameforge.main_quest_lv32._380_sayReward = "Tohle je jedin\225 mo\158nost, jak p\248e\158\237t. Nev\237me,[ENTER]jestli budeme m\237t \250sp\236ch, ale v ka\158d\233m p\248\237pad\236 to[ENTER]mus\237me zkusit.[ENTER]Mus\237me m\237t informace o \232ern\233 magii d\248\237ve, ne\158 n\225s[ENTER]napadnou. Podle star\253ch p\248\237b\236h\249 lze informace o[ENTER]n\237 naj\237t v Dra\232\237m \250dol\237. "
gameforge.main_quest_lv32._390_say = "Podle obsahu vid\237m, \158e v t\233 zemi panovala[ENTER]starobyl\225 v\237ra. P\248edt\237m ne\158 Lee Seop v\154echno[ENTER]sjednotil, m\236la ka\158d\225 zem\236 vlastn\237[ENTER]charakteristick\233 znaky. Pokud v\237m, m\236la ka\158d\225[ENTER]zem\236 dokonce i vlastn\237 n\225bo\158enstv\237. Autor t\233to[ENTER]knihy vypad\225, \158e byl vzd\236lan\253 \232lov\236k.[ENTER]Pravd\236podobn\236 pat\248il k jednomu z cech\249 a mo\158n\225[ENTER]byl i jej\237 velitel. \200lenov\233 cech\249 byli pova\158ov\225ni[ENTER]za horn\237 vrstvu spole\232nosti. "
gameforge.main_quest_lv32._400_say = "O Dra\232\237m \250dol\237 se vypr\225v\237 mnoho legend.[ENTER]I j\225 jich p\225r zn\225m. Mo\158n\225 tam ale najdeme dal\154\237[ENTER]str\225nky z den\237ku. Bohu\158el ale nev\237m, kde se \250dol\237[ENTER]Seungryong \250dol\237 nach\225z\237. Jdi za lovcem Yang-Shin[ENTER]ze sousedn\237 vesnice, zn\225 do \250dol\237 cestu. Mo\158n\225,[ENTER]\158e i n\236co o t\233 star\233 kn\237\158ce v\237. "
gameforge.main_quest_lv32._40_say = "Zdrav\237m t\236.[ENTER]Tvoje pomoc posledn\236 byla velmi u\158ite\232n\225. D\237ky[ENTER]tomu jsem mohl opravdu hodn\236 pokro\232it. Ale nyn\237[ENTER]m\225m probl\233m. P\248i v\253zkumu informac\237 o meteorech[ENTER]jsem na\154el starou knihu. Pokud j\237 dob\248e rozum\237m,[ENTER]tak jsou tam d\249le\158it\233 poznatky o zm\236n\225ch, kter\233[ENTER]maj\237 dopad na celouzemi.[ENTER]Je to opravdu d\249le\158it\233. "
gameforge.main_quest_lv32._410_say = "Jak vzru\154uj\237c\237! A m\225lem bych zapom\236l: tady je[ENTER]odm\236na za tu prvn\237 str\225nku! "
