gameforge.main_quest_lv32._470_sayTitle = "Zeptej se Yang-Shina na Dra\232\237 \250dol\237. "
gameforge.main_quest_lv32._480_say = "Na prvn\237 str\225nce tajn\233 knihy je zmi\242ov\225no Dra\232\237[ENTER]\250dol\237. Uriel o n\236m zn\225 pov\236sti, ale nev\237, kde se[ENTER]nach\225z\237. Jdi do sousedn\237 vesnice a zeptej se[ENTER]lovce Yang-Shina, jestli o n\236m v\237 v\237ce. "
