gameforge.main_quest_lv32._500_npcChat = "Informace o Dra\232\237m \250dol\237 "
gameforge.main_quest_lv32._50_say = "Probl\233m v\236z\237 v tom, \158e ty str\225nky jsou dost[ENTER]potrh\225ny. Proto je obt\237\158n\233 je rozlu\154tit.[ENTER]Pravd\236podobn\236 kolovala ta kn\237\158ka z ruky do ruky,[ENTER]proto je tak siln\236 po\154kozen\225. V t\233to kn\237\158ce chyb\237[ENTER]13 str\225nek. M\249\158e\154 mi je sehnat?[ENTER]Pravd\236podobn\236 obsahuj\237 pr\225v\236 tyto str\225nky[ENTER]d\249le\158it\233 informace, na jejich\158 z\225klad\236 by se dala[ENTER]ukon\232it v\225lka. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Ty chce\154 v\236d\236t, kde je Dra\232\237 \250dol\237? Ti je velmi[ENTER]star\233 jm\233no pro \250dol\237 Seungryong. Nejsou tam[ENTER]\158\225dn\237 draci, ale velmi mnoho ork\249 a dokonce tam[ENTER]\158ije tajn\225 sekta. Pro\232 chce\154 j\237t na tak[ENTER]nebezpe\232n\233 m\237sto? Dokonce i j\225, zku\154en\253 lovec,[ENTER]tam nerad chod\237m. Bylo by lep\154\237, aby ses dr\158el[ENTER]d\225t odtud. "
gameforge.main_quest_lv32._530_say = "Co\158e? Ty hled\225\154 ty star\233 str\225nky?[ENTER]Hm! Druz\237 lovci mi kdysi \248\237kali, \158e or\232\237 \154amani[ENTER]vlastn\237 n\236jak\233 pap\237ry. Ale jestli to je pravda?[ENTER]Kdy\158 jsi tak zv\236dav\253, vydej se tam s\225m.[ENTER]U\158 jsem se p\248ece zm\237nil, \158e to tam je dost[ENTER]nebezpe\232n\233. D\225vej na sebe dobr\253 pozor! "
gameforge.main_quest_lv32._540_sendLetter = "Hledej druhou str\225nku "
gameforge.main_quest_lv32._550_say = "Podle toho, co \248\237kal ten lovec, mus\237 m\237t tu[ENTER]druhou str\225nku or\232\237 kouzeln\237k, kter\253 se nach\225z\237 v[ENTER]Dra\232\237m \250dol\237. Zabij Siln\233ho or\232\237ho \154amana a seber[ENTER]mu tu druhou str\225nku. Pak ji dones u\232enci[ENTER]Urielovi. "
