gameforge.main_quest_lv32._570_sayTitle = "Druh\225 str\225nka nalezena "
gameforge.main_quest_lv32._580_say = "Lov siln\253ch or\232\237ch \154aman\249 byl \250sp\236\154n\253: na\154el jsi[ENTER]druhou str\225nku z tajn\233 knihy. Dones ji u\232enci[ENTER]Urielovi. "
gameforge.main_quest_lv32._590_say = "To je ta druh\225 str\225nka?[ENTER]Uka\158. Hm. Nen\237 v\249bec jednoduch\233 ji rozlu\154tit. Je[ENTER]tam naps\225no... "
gameforge.main_quest_lv32._600_sayTitle = "Druh\225 str\225nka z den\237ku: "
gameforge.main_quest_lv32._60_say = "Jakmile najde\154 ty star\233 str\225nky, dones mi je. Pak[ENTER]se pokus\237m je rozlu\154tit.[ENTER]Hmmmm... Kde by se tak dalo hledat ze v\154eho[ENTER]nejd\248\237v? P\248ed n\236jak\253m \232asem jsem od jednoho[ENTER]obchodn\237ho cestuj\237c\237ho ve vedlej\154\237 vesnici[ENTER]zaslechl, \158e na\154el str\225nku z jedn\233 star\233 knihy.[ENTER]B\236\158 k n\236mu a pod\237vej se, jestli se od n\236j n\236co[ENTER]dozv\237\154. "
gameforge.main_quest_lv32._610_sayReward = "Byli objeveni n\225sledovn\237ci \232ern\233 magie. Schovali[ENTER]se v Dra\232\237m \250dol\237. Vyznaj\237 se dob\248e v zak\225zan\253ch[ENTER]\232\225r\225ch, kter\233 se zachovaly z d\248\237v\236j\154\237ch dob. Kdy\158[ENTER]jim bylo na v\154echny mo\158n\233 zp\249soby vyhro\158ov\225no,[ENTER]sl\237bili, \158e n\225m pomohou. V\253sledkem je, \158e na[ENTER]vykon\225v\225n\237 magie je t\248eba zvl\225\154tn\237 m\237sto, pln\233[ENTER]zl\233 energie. \200as se kr\225t\237, tak\158e pot\248ebuji[ENTER]takov\233to m\237sto rychle naj\237t. "
gameforge.main_quest_lv32._620_say = "Hmm, na \232ernou magii je pot\248eba m\237sto, kter\233 je[ENTER]zapln\236no negativn\237 energi\237? Ale kdepak jenom m\249\158e[ENTER]b\253t v\154echno zahlcen\233 negativn\237 energi\237? Kde se[ENTER]asi m\249\158e takov\233 m\237sto jen tak nach\225zet?[ENTER]Hmm... \193\225! Ur\232it\236 to je Chr\225m Hwang. Lid\233 jej[ENTER]nenaz\253vaj\237 Temn\253 chr\225m pro nic za nic. Je to[ENTER]m\237sto, kam nikdo nechce j\237t, a dokonce ani[ENTER]zv\237\248ata. A ta tajn\225 sekta v n\236m tak\233 nen\237 nic[ENTER]dobr\233ho. "
gameforge.main_quest_lv32._630_say = "Krom\236 toho existuje souvislost mezi zak\225zanou[ENTER]\232ernou magi\237 a tajnou sektou. V Chr\225mu Hwang se[ENTER]d\225 k tomu naj\237t kl\237\232. Zjisti, co se d\236je v Chr\225mu[ENTER]Hwang a zkus tam naj\237t dal\154\237 str\225nky z knihy![ENTER]Tady je tvoje odm\236na za tu druhou str\225nku... "
