gameforge.main_quest_lv40._320_say = "Hm. Opi\232\237 jeskyn\236 nen\237 to m\237sto, kter\233 hled\225me...[ENTER]Podle toho, co je tady naps\225no, se mus\237me vydat k[ENTER]pavou\232\237mu podzem\237. Ov\154em nejprve je t\248eba vy\248\237dit[ENTER]urgentn\236j\154\237 z\225le\158itost: velitel \248\237k\225, \158e kolem[ENTER]vesnice je spousta cizinc\249, kte\248\237 kladou lidem[ENTER]podivn\233 ot\225zky. M\236l bys za n\237m zaj\237t a zjistit,[ENTER]co pot\248ebuje. "
