gameforge.main_quest_lv40._470_say = "Co\158e? Co ta ot\225zka m\225 znamenat? Lituji. Nemohu ti[ENTER]pomoci. Nem\225m ani nejmen\154\237 tu\154en\237, o \232em mluv\237\154.[ENTER]Ne ne. Je te\239 t\236\158k\233 naj\237t pr\225ci. Co bych asi tak[ENTER]d\236lal? "
gameforge.main_quest_lv40._480_say = "No dobr\225, je to pravda. Ale souhlasil jsem jen[ENTER]kv\249li tomu, \158e mi sl\237bili velkou spoustu Yang\249.[ENTER]Nev\237m, co ti cizinci tady cht\236j\237. Ale dali mi[ENTER]\250kol: m\225m zab\237jet brut\225ln\237 velitele. "
