gameforge.main_quest_lv40._510_say = "Nakajima prozradil, \158e cizinci cht\236j\237 zab\237t[ENTER]brut\225ln\237 velitele. Proto\158e se p\248edt\237m ptali na[ENTER]str\225nky z den\237ku, pravd\236podobn\236 budou brut\225ln\237[ENTER]velitel\233 n\236jakou m\237t. Abych zjistil v\237ce, budu[ENTER]muset p\225r brut\225ln\237ch velitel\249 zab\237t. Najdu je[ENTER]kolem druh\233 vesnice. "
