gameforge.main_quest_lv40._60_sayTitle = "T\248et\237 str\225nka: "
gameforge.main_quest_lv40._70_sayReward = "Dorazili jsme na m\237sto, kde je v\154echno zapln\236no[ENTER]negativn\237 energi\237. Ale stejn\236 to je\154t\236 po\248\225d[ENTER]nesta\232\237...[ENTER]Kde se daj\237 prov\225d\236t zak\225zan\233 \232\225ry?[ENTER]Podle jedn\233 nov\233 informace existuje jedno ukryt\233[ENTER]m\237sto v pou\154ti Yongbi. Pln\237 nad\236je se te\239 vyd\225me[ENTER]do pou\154t\236 Yongbi. "
gameforge.main_quest_lv40._80_say = "V Dra\232\237m \250dol\237 nemohli dos\225hnout sv\233ho c\237le.[ENTER]Hm... V pou\154ti Yongbi m\249\158e \232lov\236k jen z\248\237dka[ENTER]narazit na lidi a ta oblast je zat\237m[ENTER]neprozkouman\225. Je to dost slo\158it\233.[ENTER]Kde p\248esn\236 je ta oblast, o kter\233 mluv\237? Mysl\237m,[ENTER]\158e maj\237 na mysli opi\232\237 jeskyni Jungsun Dong. Je[ENTER]to hlubok\225 jeskyn\236 s dobr\253mi p\248edpoklady pro[ENTER]shroma\158\239ov\225n\237 negativn\237 energie. "
gameforge.main_quest_lv40._90_say = "Pros\237m, jdi do Jungsun Dong a hledej dal\154\237[ENTER]kamenn\233 pam\225tn\237ky. S trochou \154t\236st\237 u nich najde\154[ENTER]dal\154\237 str\225nky. Ach, a samoz\248ejm\236 t\236 nesm\237me[ENTER]zapomenout odm\236nit za t\248et\237 str\225nku. "
