gameforge.main_quest_lv47._160_npcChat = "\138est\225 str\225nka "
gameforge.main_quest_lv47._170_say = "Tak jak\233 to bylo v pavou\232\237m podzem\237? Na\154el jsi[ENTER]\154estou str\225nku? To je skv\236l\233! M\236l jsem strach, \158e[ENTER]p\248ijde\154 pozd\236. Po\248\225d sly\154\237m o dal\154\237ch lidech,[ENTER]kte\248\237 hledaj\237 informace o \232ern\233 magii.[ENTER]Asi to bude velmi d\249le\158it\233. Tak se pod\237vejme, co[ENTER]str\225nka \248\237k\225. "
gameforge.main_quest_lv47._180_say = "Ach ne, tahle str\225nka se skoro ned\225 p\248e\232\237st. Bude[ENTER]mi to trvat rozlu\154tit d\233le, ne\158 obvykle. Ale[ENTER]obsah vypad\225 velmi d\249le\158it\236. Tenhle symbol[ENTER]znamen\225 '\200ern\225 magie', tak\158e jsme opravdu na[ENTER]spr\225vn\233 stop\236. Docela by m\236 zaj\237malo, pro\232 byla[ENTER]\232ern\225 magie zak\225z\225na. Asi pro to m\236li dobr\253[ENTER]d\249vod. "
gameforge.main_quest_lv47._190_say = "Zat\237mco se budu sna\158it rozlu\154tit tuhle str\225nku,[ENTER]m\236l bys zaj\237t za hudebn\237kem Yu-Hwanem. Sly\154el[ENTER]jsem, \158e m\225 n\236jak\233 informace, kter\233 jsou d\249le\158it\233[ENTER]pro n\225\154 v\253zkum. A\158 se vr\225t\237\154, \248eknu ti, co je na[ENTER]t\233hle str\225nce naps\225no. Ov\154em odm\236nu za jej\237[ENTER]p\248inesen\237 ti d\225m hned te\239. "
