gameforge.main_quest_lv47._270_npcChat = "N\236co nov\233ho? "
gameforge.main_quest_lv47._280_say = "U\158\237vej si \158ivota, nebo\157 je velmi kr\225tk\253.[ENTER]Tralalalala...[ENTER]\193, to jsi zase ty. Asi t\236 pos\237l\225 u\232enec Uriel,[ENTER]\158e? \142\225dal m\236, abych se trochu vypt\225val. Dozv\236d\236l[ENTER]jsem se, \158e lid\233 ze v\154ech t\248ech kr\225lovstv\237[ENTER]hledaj\237 d\249le\158it\233 dokumenty. Ov\154em nikdo mi nebyl[ENTER]schopen p\248esn\236 \248\237ci, jak\233 to jsou. "
gameforge.main_quest_lv47._290_say = "Je to k ni\232emu, kdy\158 se tyto divn\233 postavy[ENTER]potuluj\237 kolem, zat\237mco jsme ve v\225lce. Krom\236[ENTER]tebe, samoz\248ejm\236! Tak\233 jsem zaslechl, \158e pou\154tn\237[ENTER]bandit\233 uloupili n\236co, co by pro n\225s mohlo m\237t[ENTER]velk\253 v\253znam. Mo\158n\225 bys mohl zkusit, co se od[ENTER]nich d\225 z\237skat. "
