gameforge.main_quest_lv47._40_say = "Z\237skal jsi p\225tou str\225nku? Neuv\236\248iteln\233. M\225me[ENTER]opravdu \154t\236st\237, \158e ty str\225nky je\154t\236 po tolika[ENTER]letech existuj\237. Tak se pod\237vejme, co ta str\225nka[ENTER]\248\237k\225. "
