gameforge.main_quest_lv47._420_say = "Zdrav\237m, r\225d t\236 zase vid\237m. M\225m dobr\233 zpr\225vy:[ENTER]dokon\232il jse roz\154ifrov\225n\237 \154est\233 str\225nky. To nen\237[ENTER]\154patn\233, \158e? Mus\237m se p\248iznat, \158e jsem na sebe[ENTER]docela py\154n\253. Proto\158e to co zaujalo mou[ENTER]pozornost, byly tyhle znaky... Pros\237m? Ty jsi[ENTER]na\154el dal\154\237? M\249j bo\158e! To bylo opravdu rychl\233.[ENTER]Uka\158. Odkud je? Pokud se nem\253l\237m, tak tohle jsou[ENTER]znaky, kter\233 pou\158\237vala c\237sa\248sk\225 rodina. "
gameforge.main_quest_lv47._430_say = "Proto\158e tyhle znaky byly m\225lo pou\158\237v\225ny a znalo[ENTER]je jen p\225r lid\237, je velmi t\236\158k\233 je p\248elo\158it. Ale[ENTER]mysl\237m, \158e trocha usil\237 nikoho nezabije, haha![ENTER]T\236\154\237m se na to. Pou\154tn\237 bandit\233 tu str\225nku[ENTER]ukradli podivn\233mu cizinci? Hmm... Znamen\225 to[ENTER]snad, \158e ten cizinec rozum\236l t\236m znak\249m? To m\236[ENTER]mate. Mus\237me si b\253t jisti, \158e nic nep\248ehl\233dneme. "
gameforge.main_quest_lv47._440_say = "Ne\158 se pust\237m do t\233 nov\233 str\225nky, m\236l bych ti[ENTER]ned\248\237ve \248\237ct, co bylo na t\233 \154est\233 str\225nce. "
gameforge.main_quest_lv47._450_sayTitle = "\138est\225 str\225nka: "
gameforge.main_quest_lv47._460_sayReward = "\200as se kr\225t\237. Zkou\154eli jsme zak\225zan\233 \232\225ry i v[ENTER]pavou\232\237m podzem\237, ale nezda\248ilo se.[ENTER]Co n\225m chyb\237? N\236kte\248\237 z na\154ik mystik\249 si mysl\237,[ENTER]\158e temn\225 kouzla pot\248ebuj\237 v\236t\154\237 ob\236ti. Pokud je[ENTER]to pravda, pak by to musela b\253t opravdu velk\225[ENTER]s\237la. "
gameforge.main_quest_lv47._470_sayReward = "Podle p\248\237b\236h\249 a legend tento typ kouzel v\158dy[ENTER]vy\158aduje lidsk\233 ob\236ti. Ov\154em pokud zabiji rodinn\233[ENTER]p\248\237slu\154n\237ky na olt\225\248i, m\225 reputace mezi lidmi[ENTER]hodn\236 klesne. Pot\248ebujeme adekv\225tn\237 n\225hradu.[ENTER]Poj\239me to zkusit s had\237mi lu\232i\154tn\237ky z pou\154t\236. "
gameforge.main_quest_lv47._480_say = "Aha. Vzhledem k tomu, \158e nemohli pou\158\237t \158ij\237c\237[ENTER]lidi jako ob\236\157, rozhodli se pro had\237 bojovn\237ky.[ENTER]No, moc se mi to nezamlouv\225. \138patn\236 to skon\232\237...[ENTER]Ale st\225le pot\248ebujeme sledovat jejich stopu. Jdi[ENTER]do pou\154t\236 a zabij tam n\236jak\233 Had\237 bojovn\237ky s[ENTER]me\232em a Had\237 lukost\248elce. A mimochodem: tvoje[ENTER]odm\236na je v t\233hle ta\154ce! "
