gameforge.main_quest_lv47._560_sayTitle = "Osm\225 str\225nka: "
gameforge.main_quest_lv47._570_sayReward = "Po\158adovan\233 ob\236ti byly nalezeny. M\225me \154t\236st\237. Jsem[ENTER]zv\236dav\253, jestli je to znamen\237? Pot\248ebujeme[ENTER]ob\248adn\237 zvon. Pokud si dob\248e pamatuji, pavouci[ENTER]n\236co takov\233ho maj\237. Tak tam vyraz\237me. "
gameforge.main_quest_lv47._580_say = "Hm, znovu pavou\232\237 podzem\237, divn\233. Bude\154 tam muset[ENTER]j\237t a naj\237t ten zvon. Asi to bude vy\232erp\225vaj\237c\237[ENTER]cesta, tak\158e si nejprve trochu odpo\232i\242. J\225 budu[ENTER]zat\237m trochu p\248em\253\154let a pokus\237m se p\248elo\158it[ENTER]n\236jak\233 \250tr\158ky. A\158 se vr\225t\237\154, d\225m ti nov\253 \250kol. A[ENTER]neboj, odm\236nu za osmou str\225nku dostane\154 hned te\239. "
gameforge.main_quest_lv47._590_sayReward = "Obdr\158\237\154 3 000 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 70 000 Yang\249.[ENTER]Obdr\158\237\154 20x Pl\225\154\157 state\232nosti.[ENTER]Tip: Na dal\154\237 \250kol mus\237\154 m\237t minim\225ln\236 \250rove\242 50 "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop dorazil se svou jezdeckou jednotkou do[ENTER]\248\237\154e Taejo a nyn\237 to vypad\225, \158e tam chv\237li[ENTER]z\249stane. B\236hem posledn\237 doby pad\225 na zem mnoho[ENTER]mal\253ch i velk\253ch meteorit\249. Zp\249sobuj\237 chaos,[ENTER]ni\232en\237 a konflikty. \216\237\154e se rozd\236lila do t\248\237[ENTER]kr\225lovstv\237ch, kter\233 bojuj\237 mezi sebou, m\237sto aby[ENTER]\232elili zlu spole\232n\236. Dra\232\237 b\249h k n\225m ji\158 tak\233[ENTER]nepromlouv\225. N\236kdy podpo\248\237 jednu stranu, jindy[ENTER]druhou. Tak\158e ka\158d\253 bojuje, aby jej pot\236\154il, a[ENTER]mezit\237m se ta katastrofa st\225v\225 hor\154\237 a hor\154\237... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel: "
gameforge.main_quest_lv47._80_say = "Tohle je sv\236dectv\237 konce jedn\233 \233ry. Ach ano,[ENTER]zaplatit. Na, tady je odm\236na za tvou vynikaj\237c\237[ENTER]pr\225ci. A je\154t\236 n\236co: n\236kdo dal\154\237 d\236l\225 ur\232it\236 ten[ENTER]sam\253 v\253zkum jako my. Tak\158e nesm\237me ztr\225cet \232as.[ENTER]Na konci str\225nky je naps\225no, \158e Lee Seop hledal[ENTER]negativn\237 energii v pavou\232\237m podzem\237. Pokud tam[ENTER]n\236co najde\154, p\248ij\239 mi to hned ozn\225mit. Nemohu se[ENTER]do\232kat! "
