gameforge.main_quest_lv50._240_sayReward = "Poda\248ilo se n\225m odvr\225tit prvn\237 \250tok. Ale brzy[ENTER]bude n\225sledovat dal\154\237. Lee Seop m\225 je\154t\236 v z\225loze[ENTER]jednotku voj\225k\249. Pronik\225 sem \232\237m d\225l v\237c[ENTER]nep\248\225tel. Navzdory \250nav\236 a \232etn\253m padl\253m[ENTER]kamar\225d\249m jsme se rozhodli dokon\232it pr\249zkum[ENTER]star\253ch kouzel.[ENTER]M\236li bychom se kv\249li tomu vydat do pavou\232\237ho[ENTER]podzem\237. Ne pro v\237t\236zstv\237, ale pro trochu[ENTER]nad\236je... "
gameforge.main_quest_lv50._250_say = "\193\225\225! \216ekl bych, \158e stoj\237me t\236sn\236 p\248ed c\237lem[ENTER]rozlu\154tit zak\225zanou \232ernou magii. U\158 se nem\249\158u[ENTER]do\232kat! M\236l by ses vr\225tit zp\225tky do pavou\232\237ho[ENTER]podzem\237. Douf\225m, \158e jeden\225ct\225 str\225nka den\237ku je[ENTER]tam. "
