gameforge.main_quest_lv50._350_say = "Nalezl jsi n\236jak\233 nov\233 informace? Ah\225, jeden\225ct\225[ENTER]str\225nka! Uka\158 ji...[ENTER]Ach ano, vypad\225 to jednodu\154e. St\225v\225 se ze mne[ENTER]docela dobr\253 \232ten\225\248 t\236chto znak\249. Nyn\237 se pod\237vej[ENTER]na tohle! "
gameforge.main_quest_lv50._355_sayTitle = "Jeden\225ct\225 str\225nka: "
gameforge.main_quest_lv50._360_sayReward = "\193h ne! Kouzla se nezda\248ila. Kv\249li vedlej\154\237m[ENTER]\250\232ink\249m t\236ch \232ar jsme utrp\236li ment\225ln\237 zran\236n\237.[ENTER]Na\154e zklam\225n\237 n\225s p\248ipravilo o ve\154kerou s\237lu a[ENTER]nad\236ji a to pr\225v\236 v tom okam\158iku, kdy n\225m jsou v[ENTER]pat\225ch Lee Seopovi \158elezn\237 jezdci.[ENTER]Nem\225me dost mu\158\249 na to ubr\225nit se mu, budeme[ENTER]um\237rat tak jako tak. "
gameforge.main_quest_lv50._365_sayTitle = "Pokra\232ov\225n\237 jeden\225ct\233 str\225nky: "
gameforge.main_quest_lv50._370_sayReward = "Posledn\237 my\154lenka dr\158\237 zbytek vojska pohromad\236 a[ENTER]d\225v\225 n\225m s\237lu: Na\154i inform\225to\248i v Dra\232\237m \250dol\237[ENTER]lhali. \218mysln\236 n\225s navedli na \154patnou stopu aby[ENTER]na n\225s po\154tvali stra\154liv\233 vedlej\154\237 \250\232inky \232ern\233[ENTER]magie. Za to n\225m zaplat\237. Bude to n\225\154 posledn\237[ENTER]\232in v t\233to zemi. "
gameforge.main_quest_lv50._380_say = "No, nakonec to dopadlo trochu jinak ne\158 doufali.[ENTER]Smutn\253 p\248\237b\236h. Ale bohu\158el nem\249\158e\154 v\236\248it nikomu[ENTER]kdo je spojen s \232ernou magi\237. M\236li to tu\154it. Je[ENTER]dost zvl\225\154tn\237, \158e se autorovi t\236chto \248\225dk\249[ENTER]poda\248ilo z\237skat tyto zak\225zan\233 informace. Kdo v\237,[ENTER]co m\236li jeho inform\225to\248i v pl\225nu. M\236li bychom to[ENTER]dokon\232it, i p\248esto, \158e je to nebezpe\232n\233. V\237me[ENTER]toho u\158 tolik, \158e by byla \154koda toho nechat. "
gameforge.main_quest_lv50._390_say = "U\158 jsi byl v \218dol\237 Seungryong. Nemysl\237m si, \158e[ENTER]tam budeme hledat n\236co dal\154\237ho. Hmm, zaj\237malo by[ENTER]mne, kde jinde se m\249\158eme pod\237vat... J\225 v\237m![ENTER]Pam\225tn\237ky hr\225ly velkou roli b\236hem na\154eho hled\225n\237.[ENTER]A v okol\237 tam jsou pam\225tn\237ky, kter\233 jsme doposud[ENTER]neprozkoumali. Ty v ostatn\237ch kr\225lovstv\237ch! Je to[ENTER]tam velmi nebezpe\232n\233. Bude\154 pravd\236podobn\236 st\225le[ENTER]napad\225n. Tak\158e se dob\248e p\248iprav a p\248ij\239 za mnou[ENTER]a\158 bude\154 p\248ipraven. "
