gameforge.main_quest_lv50._60_say = "Nalezl jsi dev\225tou str\225nku v pavou\232\237m podzem\237.[ENTER]Dones ji u\232enci Urielovi. "
gameforge.main_quest_lv50._70_say = "Zjistil jsi n\236co o \232ern\233 magii? Wow, dev\225t\225[ENTER]str\225nka! Jsem opravdu nat\236\154en, zda jim to[ENTER]fungovalo nebo ne. Pod\237vejme se na to. Hmm, tady[ENTER]se \248\237k\225... "
gameforge.main_quest_lv50._75_sayTitle = "Dev\225t\225 str\225nka: "
gameforge.main_quest_lv50._80_sayReward = "Lee Seop zah\225jil \250tok.[ENTER]Je\154t\236 nebylo vyzkou\154eno, jak to star\233 kouzlo[ENTER]funguje, proto ho zat\237m je\154t\236 nem\249\158eme pou\158\237t.[ENTER]Jsem dost nerv\243zn\237. Jsme tady a budeme br\225nit[ENTER]na\154i \248\237\154i z nej\232eln\236j\154\237 pozice. Na\154i nep\248\225tel\233[ENTER]maj\237 velmi siln\233 vojsko, mohli bychom tu bitvu[ENTER]prohr\225t. Mus\237me si naj\237t v\253hodn\236j\154\237 pozici. Mo\158n\225[ENTER]bychom m\236li j\237t do ledov\233 pou\154t\236 a odtamtud[ENTER]podniknout \250tok na na\154e nep\248\225tele. S trochou[ENTER]\154t\236st\237 budeme m\237t dost \232asu na pr\249zkum.[ENTER]Bo\158e, ochra\242uj n\225s... "
gameforge.main_quest_lv50._90_say = "Hmm... \216\237\154e byla napadena d\248\237v, ne\158 mohli[ENTER]vyzkou\154et star\233 kouzlo. Lid\233 se zabarik\225dovali v[ENTER]ledov\233 pou\154ti, aby tam mohli pokra\232ovat v[ENTER]pr\249zkumu star\233ho kouzla. Mus\237 myslet horu Sohan,[ENTER]tak se dneska \248\237k\225 ledov\233 zemi. M\236li bychom naj\237t[ENTER]dal\154\237 stopy. Jdi na horu Sohan a hledej tam dal\154\237[ENTER]stopu. "
