gameforge.main_quest_lv55._130_sayTitle = "Dvan\225ct\225 str\225nka: "
gameforge.main_quest_lv55._140_sayReward = "Na\154li jsme inform\225tory, kte\248\237 za sv\233 l\158i[ENTER]zaplatili \158ivotem. Ale d\249le\158it\236j\154\237 je, \158e jsme[ENTER]byli schopni z nich dostat n\236jak\233 informace:[ENTER]Nepot\248ebujeme pavou\232\237 podzem\237, ale Temn\253 chr\225m.[ENTER]To je to m\237sto, kter\233 m\225 hodn\236 spole\232n\233ho se[ENTER]starou v\237rou a temn\253mi ritu\225ly. "
gameforge.main_quest_lv55._145_sayTitle = "Pokra\232ov\225n\237 dvan\225ct\233 str\225nky: "
gameforge.main_quest_lv55._150_sayReward = "M\225me jen jeden zp\249sob jak zastavit Lee Seopa.[ENTER]Mus\237me odcestovat do Temn\233ho chr\225mu abychom mohli[ENTER]prov\225d\236t \232ernou magii. Neni n\225s mnoho a n\225maha za[ENTER]n\236kolik posledn\237ch m\236s\237c\249 si na n\225s vyb\237r\225 svou[ENTER]da\242. Ale i hrstka unaven\253ch mu\158\249 m\249\158e zm\236nit osud[ENTER]sv\236ta kdy\158 m\225 mocn\233 informace. Nem\249\158eme sej\237t z[ENTER]cesty na\154eho c\237le. Jdeme. "
gameforge.main_quest_lv55._160_say = "Aha, tak oni na\154li spr\225vn\233 m\237sto. P\248ece jen jsem[ENTER]m\236l pravdu! Je to opravdu Chr\225m Hwang.[ENTER]Pravd\236podobn\236 si uv\236domili, \158e to je to m\237sto, ze[ENTER]kter\233ho vych\225z\237 negativn\237 energie. Tak dlouho jak[ENTER]n\236kdo m\249\158e pamatovat se ve\154ker\233 ritu\225ly prov\225dej\237[ENTER]pr\225v\236 tam. To m\237sto je pln\233 negativn\237 energie. "
gameforge.main_quest_lv55._170_say = "V sou\232asn\233 dob\236 chr\225m ob\253vaj\237 nestv\249ry, tam[ENTER]nevkro\232ila lidsk\225 noha po dlouh\225 l\233ta. Je to[ENTER]velmi nebezpe\232n\233 ale jsem si jist\253, \158e to[ENTER]zvl\225dne\154. Jdi do \250dol\237 Seungryong a pod\237vej se[ENTER]tam v Chr\225mu Hwang po posledn\237 str\225nce. P\248\237b\236h,[ENTER]kter\253 n\225m vypr\225v\237 tento den\237k kon\232\237 pr\225v\236 tam.[ENTER]Mus\237m zjistit jak to skon\232ilo. Hodn\236 \154t\236st\237! A[ENTER]tady je tvoje odm\236na za dvan\225ctou str\225nku. "
