gameforge.main_quest_lv55._210_sayTitle = "Zabij zloducha v chr\225mu "
gameforge.main_quest_lv55._220_say = "Doposud jsi na\154el dvan\225ct str\225nek ze t\248in\225cti.[ENTER]Te\239 na n\225s \232ek\225 posledn\237 krok. Uriel \248\237k\225, \158e se[ENTER]nekal\233 \232\225ry prov\225d\236ly v Chr\225mu Hwang. Proto by[ENTER]ses m\236l vydat na cestu tam a hledat v\237ce[ENTER]informac\237. Zabij n\236kolik zloduch\249, ti maj\237 ur\232it\236[ENTER]n\236kolik d\249le\158it\253ch informac\237. "
