gameforge.main_quest_lv55._250_sayTitle = "Negativn\237 energie z chr\225mu "
gameforge.main_quest_lv55._260_sayReward = "Pot\233 co jsi str\225vil trochu \232asu v chr\225mu za\232\237n\225\154[ENTER]poci\157ovat n\236co divn\233ho, temn\233 m\237sto: Pomalu[ENTER]problik\225vaj\237c\237 st\237ny na ka\158d\233m rohu. Temn\225[ENTER]energie prosakuje z ka\158d\233 trhliny jako olej.[ENTER]Vypad\225 to, \158e to je t\237m chr\225mem. Tohle je m\237sto[ENTER]kde to v\154echno za\232alo... "
gameforge.main_quest_lv55._270_say = "Pot\233, co jsi zjistil, \158e \232\237m d\225l \232lov\236k pronik\225[ENTER]do hlubin chr\225mu, t\237m v\237c zesiluje negativn\237[ENTER]energie, by ses m\236l m\236l vydat do st\248edu chr\225mu.[ENTER]M\236l bys naj\237t st\248ed chr\225mu. Tam mus\237 b\253t zdroj[ENTER]temnoty. "
