gameforge.main_quest_lv55._30_say = "Kdy\158 jsi nalezl n\236kolik str\225nek z den\237ku okolo[ENTER]pam\225tn\237k\249, Uriel si mysl\237, \158e bys mohl naj\237t v\237ce[ENTER]informac\237 o \232ern\233 magii pobl\237\158 neprozkouman\233ho[ENTER]pam\225tn\237ku. Jdi do kr\225lovstv\237 Jinno a prozkoumej[ENTER]pam\225tn\237k v oblasti Pyungmoo. "
gameforge.main_quest_lv55._310_say = "To je posledn\237 str\225nka, t\248in\225ct\225 str\225nka! Ani ti[ENTER]nemohu \248\237ct jak jsem ti vde\232n\253 za to co jsi pro[ENTER]mne ud\236lal. Pod\237vej jak se mi t\248esou ruce. Jsem[ENTER]na to tak nat\236\154en\253. Uf...[ENTER]Tak dob\248e, pod\237v\225me se jak p\248\237b\236h kon\232\237. "
gameforge.main_quest_lv55._320_sayTitle = "T\248in\225ct\225 str\225nka: "
gameforge.main_quest_lv55._330_sayReward = "Kone\232n\236 jsme dorazili.[ENTER]Po v\154ech t\236ch \250trap\225ch m\225me n\225sleduj\237c\237 posl\225n\237:[ENTER]Mus\237me prov\233st ob\248ad a aktivovat \232ernou magii.[ENTER]Jen douf\225m, \158e m\225me dost sil. Mnoz\237 z n\225s se[ENTER]m\237rn\236 kym\225cej\237, proto\158e jsme vy\232erpan\237 z dlouh\233[ENTER]cesty a neust\225l\253ch \250t\236k\249 p\248ed bojovn\237ky Lee[ENTER]Seopa. Nicm\233n\236 se o to mus\237me pokusit jinak na\154e[ENTER]kr\225lovstv\237 zahyne. "
gameforge.main_quest_lv55._335_sayTitle = "Pokra\232ov\225n\237 t\248in\225ct\233 str\225nky: "
gameforge.main_quest_lv55._340_sayReward = "Je n\225s zde sedm. Obl\233kli jsme si na to na\154e[ENTER]nejlep\154\237 oble\232en\237, i kdy\158 nyn\237 vypadalo jako[ENTER]hadry. Shrom\225\158dili jsme se v kruhu a dr\158eli se za[ENTER]ruce tak, aby byla zape\232et\236na linie energie. Pak[ENTER]jsme za\232ali zp\237vat magick\225 slova a doufali, \158e[ENTER]\232ern\225 magie nezp\249sob\237 dal\154\237 ob\236ti.[ENTER]... "
gameforge.main_quest_lv55._350_sayReward = "... Je po v\154em...[ENTER]Na za\232\225tku to vypadalo velmi slibn\236. M\237stnost[ENTER]byla napln\236na energi\237 a p\237sn\237, ale najednou jsem[ENTER]se c\237til opravdu divn\236. M\253ch \154est koleg\249 padlo na[ENTER]kolena. Chr\225m se za\232al t\248\225st. Potom ude\248il blesk[ENTER]a my jsme hnali zp\236t. A pak se linie s\237ly[ENTER]zlomila... Nyn\237 je ticho. Moji p\248\225tel\233 le\158\237 mrtv\237[ENTER]na zemi. Kouzlo nefungovalo.[ENTER]Selhali jsme. "
gameforge.main_quest_lv55._360_say = "Co? To je v\154e?!?[ENTER]To je \154\237len\233! V\154echna ta pr\225ce pro nic? Nemohu[ENTER]tomu uv\236\248it. Cestovali jsme, na\154li jsme,[ENTER]p\248elo\158ili jsme a zabralo to cel\233 hodiny. V\154e pro[ENTER]nic! Jsme na tom stejn\236 jako na za\232\225tku. Nicm\233n\236,[ENTER]zd\225 se, \158e bude lep\154\237 kdy\158 se budeme dr\158et d\225le[ENTER]od \232ern\233 magie, co\158 je to co jsem si myslel od[ENTER]za\232\225tku. Ale v\236d\236t je lep\154\237 ne\158 v\236\248it ne? "
gameforge.main_quest_lv55._370_say = "Jako prvn\237 si d\225me pauzu. Bol\237 mne hlava a ty jsi[ENTER]asi dost unaven\253. Mus\237m si to nap\248ed nechat[ENTER]proj\237t hlavou. A\158 skon\232\237m budeme mluvit d\225le.[ENTER]P\248es v\154echno jsi mi poskytl neocenitelnou slu\158bu.[ENTER]Nebude to bez odm\236ny! "
