gameforge.main_quest_lv6._180_say = "Pot\248ebuje\154 n\236co... Ah\225, tebe pos\237l\225 Kov\225\248 kv\249li[ENTER]tomu prase\232\237mu nosu. "
gameforge.main_quest_lv6._190_say = "Jsem unaven\253, \232\237m jsem star\154\237 t\237m jsem[ENTER]zapomn\236tliv\236j\154\237. D\248\237ve by se mne n\236co takov\233ho[ENTER]nestalo. Zde je ten prase\232\237 nos. Vem ho pros\237m[ENTER]okam\158it\236 ke Kov\225\248i. Uvid\237me se pozd\236ji. "
