gameforge.main_quest_lv6._210_sayReward = "Spr\225vce skladi\154t\236 \250pln\236 zapomn\236l na dod\225vku. Dal[ENTER]ti prase\232\237 nos. Rychle ho odnes ke Kov\225\248i aby u\158[ENTER]nemusel d\233le \232ekat. "
