gameforge.main_quest_lv6._230_say = "U\158 v\237\154 n\236co o zlep\154ov\225n\237?[ENTER]Samoz\248ejm\236 \158e ne! Jsi st\225le mlad\253 dobrodruh! Jde[ENTER]o tohle: Kdy\158 mi d\225\154 \232\225st tvoj\237 v\253stroje, m\249\158u ji[ENTER]za p\225r Yang\249 zlep\154it, aby m\236la lep\154\237 vlastnosti. "
gameforge.main_quest_lv6._240_say = "Zlep\154ovat se m\249\158e n\236kolika zp\249soby - \232\237m lep\154\237 je[ENTER]zlep\154en\237 t\237m je to t\236\158\154\237. Do +3 mus\237\154 zaplatit[ENTER]jenom p\225r Yang\249 a na cokoli dal\154\237ho bude\154[ENTER]pot\248ebovat n\236jak\233 p\248edm\236ty. Nap\248\237klad ten prase\232\237[ENTER]nos co jsi mi donesl. Av\154ak, n\236kdy se m\249\158e st\225t,[ENTER]\158e se p\248edm\236t p\248i vylep\154ov\225n\237 i tak dobr\233mu[ENTER]kov\225\248i jako jsem j\225 zni\232\237. Stav se a\158 bude\154 m\237t[ENTER]\232as. M\249\158u ti ukovat fantastick\233 zbran\236. "
