gameforge.main_quest_lv6._270_sayReward = "Obdr\158el jsi Vl\232\237 ko\158e\154inu +. "
gameforge.main_quest_lv6._30_say = "Hej, ty tam! Te\239 neni \232as na to se poflakovat a[ENTER]nic ned\236lat. Pot\248ebuje\154 dal\154\237 tvrd\253 tr\233nink![ENTER]Tr\233nink je jedin\225 \154ance jak zv\253\154it tvoje \154ance na[ENTER]p\248e\158it\237! "
gameforge.main_quest_lv6._40_say = "Ale kdy\158 jsi zde, m\225m pro tebe \250kol: Kov\225\248 zde[ENTER]p\248ed chv\237l\237 byl a \248ikal n\236co o prasatech a[ENTER]probl\233mech s dod\225vkou. Mo\158n\225 pot\248ebuje pomoc. Jdi[ENTER]za nim a \248ekni mu, \158e t\236 pos\237l\225m. M\249\158e\154 hned[ENTER]vyrazit! "
