gameforge.main_quest_lv60._250_counter = "Zb\253v\225 str\225nek: "
gameforge.main_quest_lv60._260_say = "Temn\253 n\225rod je obklopen mnoha tajemstv\237mi. D\237ky[ENTER]tob\236 jsem byl schopen n\236kter\225 poodhalit, ale[ENTER]po\248\225d n\225m chyb\237 podstatn\225 \232\225st. Pros\237m, vydej se[ENTER]na cestu a hledej star\253 dokument. M\236l by b\253t[ENTER]um\237st\236n v Lese duch\249 nedaleko Hory Sohan. "
