gameforge.main_quest_lv60._280_say = "Kone\232n\236! na\154el jsi star\253 dokument. Douf\225m, \158e do[ENTER]na\154\237 z\225le\158itosti vnese sv\236tlo. "
gameforge.main_quest_lv60._290_say = "Ale co to...? Skoro nic na n\236m nen\237! Dokument se[ENTER]skl\225d\225 z deseti str\225nek! Vydej se zp\236t do lesa a[ENTER]najdi zb\253vaj\237c\237ch dev\236t stran! "
