gameforge.main_quest_lv60._30_say = "Jak se m\225\154? Pamatuje\154 si na di\225\248 a p\248\237b\236h v n\236m?[ENTER]M\225m na mysli ten den\237k, kter\253 kon\232il na t\248in\225ct\233[ENTER]str\225nce? "
