gameforge.main_quest_lv60._360_say = "Tak si poj\239me shrnout, co zat\237m v\237me: Kdysi tu[ENTER]existovali lid\233, kte\248\237 sami sebe naz\253vali Temn\253[ENTER]n\225rod a kte\248\237 slou\158ili bohu d\233mon\249 Sung Mahi. Aby[ENTER]ho bylo mo\158n\233 vyvolat, zajali sedm Dra\232\237ch kn\236\158ek[ENTER]a pou\158ili jejich s\237lu pro zak\225zan\253 ritu\225l \232ern\233[ENTER]magie. Ov\154em to vy\158adovalo jej prov\233st na sedmi[ENTER]m\237stech v ten sam\253 \232as. "
gameforge.main_quest_lv60._370_say = "Dra\232\237 kn\236\158ky provedli ritu\225l \232ern\233 magie pouze v[ENTER]t\233to jedn\233 v\236\158i a ne na sedmi r\249zn\253ch m\237stech...[ENTER]A to je d\249vod, pro\232 vyvol\225n\237 boha d\233mon\249 Sung[ENTER]Mahi selhalo! "
gameforge.main_quest_lv60._380_say = "Temn\253 n\225rod musel d\225t sedmi Dra\232\237m kn\236\158k\225m chybn\233[ENTER]informace. "
gameforge.main_quest_lv60._390_say = "Mo\158n\225 nev\236d\236li, jak to prov\233st... Mo\158n\225 je to[ENTER]\154ance, proto\158e star\253 svitek zmi\242uje tuto v\236\158 v[ENTER]souvislosti s pam\225tn\237kem Glum. Zd\225 se, \158e hovo\248\237[ENTER]o V\236\158i d\233mon\249 v chr\225mu Hwang. "
gameforge.main_quest_lv60._400_say = "Kone\232n\236 jsme na\154li v\154echny stopy, t\253kaj\237c\237 se[ENTER]sedmi Dra\232\237ch kn\236\158ek! Trochu se uklidni a pak si[ENTER]uv\236dom, co bude n\225sledovat. Celkem jsem si jist,[ENTER]\158e je p\248ed tebou v\253let do V\236\158e d\233mon\249... "
gameforge.main_quest_lv60._40_say = "Ano, p\248esn\236. Sedm osob zb\236hlo od Lee Seopa a jeho[ENTER]kaval\233rie a ukryli se v chr\225mu Hwang. V naprost\233m[ENTER]zoufalstv\237 pou\158ili zakl\237nadla ze zak\225zan\233 \232ern\233[ENTER]magie... p\248e\158il to z nich pouze jeden. "
gameforge.main_quest_lv60._410_sayReward = "Dal\154\237 \232\225st dobrodru\158stv\237 bude dostupn\225 a\158[ENTER]dos\225hne\154 \250rovn\236 66. "
gameforge.main_quest_lv60._50_say = "Spr\225vn\236. Provedl jsem je\154t\236 dal\154\237 zkoum\225n\237 a[ENTER]zjistil jsem, \158e t\236ch sedm osob byly Dra\232\237[ENTER]kn\236\158ky. Ve star\253ch svitc\237ch jsou zmi\242ov\225ny v[ENTER]souvislosti s lidmi, pojmenovan\253mi jako Temn\253[ENTER]n\225rod. Byly tyhle Dra\232\237 kn\236\158ky sou\232\225st\237 tohoto[ENTER]tajemn\233ho n\225roda? Na, tady m\225\154 svitek, pozorn\236 si[ENTER]jej p\248e\232ti a pak p\248ij\239 znovu za mnou. "
gameforge.main_quest_lv60._60_sendLetter = "Temn\253 n\225rod I "
gameforge.main_quest_lv60._70_say = "Podle Urielova v\253zkumu bylo sedm Dra\232\237ch kn\236\158ek[ENTER]p\248\237slu\154nicemi temn\233ho n\225roda. Je t\248eba prozkoumat[ENTER]star\253 n\225hrobn\237 k\225men na Ho\248e Sohan. P\248edpokl\225d\225[ENTER]se, \158e tam kdysi bylo hlavn\237 m\236sto Temn\233ho[ENTER]n\225roda. Ale je\154t\236 ne\158 se tam vyd\225\154, tak si[ENTER]promluv s Urielem. "
gameforge.main_quest_lv60._80_say = "Jejich neuv\236\248iteln\236 pokro\232il\233 \232arod\236jnictv\237 a[ENTER]fakt, \158e podle di\225\248e byly zabity Lee Seopem,[ENTER]nasv\236d\232uj\237 tomu, \158e sedm Dra\232\237ch kn\236\158ek bylo[ENTER]p\248\237slu\154nicemi Temn\233ho n\225roda. "
