gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Neuv\236\248iteln\233! Ch\225pe\154, co to znamen\225? P\249vodn\236 ve[ENTER]V\236\158i d\233mon\249 \158\225dn\237 d\233moni nebo du\154e nemrtv\253ch[ENTER]nebyly! Jsou odkazem smrti Dra\232\237 kn\236\158ky! P\248i sv\233m[ENTER]posledn\237m zoufal\233m pokusu ubr\225nit se mu\158\249m Lee[ENTER]Seopa otev\248ela pomoc\237 \232ern\233 magie dve\248e tohoto[ENTER]sv\236ta d\233mon\249m . A zaplatila za to \158ivotem. "
gameforge.main_quest_lv66._10_sendLetter = "Den\237k "
