gameforge.main_quest_lv66._160_say = "Pap\237r, na kter\233m je dopis naps\225n, vypad\225 hodn\236[ENTER]sta\248e. Zd\225 se, \158e n\236kdo p\248i psan\237 velmi[ENTER]posp\237chal: M\225m d\249le\158it\233 informace o sedmi Dra\232\237ch[ENTER]kn\236\158k\225ch a Sung Mahi. \200ek\225m na tebe za V\236\158\237[ENTER]d\233mon\249 v Chr\225mu Hwang, ve st\237nu stromu. Posp\236\154[ENTER]si, nen\237 moc \232asu! "
