gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "V\237tej! Dovol, abych se nejprve p\248edstavil: m\233[ENTER]jm\233no je Lee Chung. Je od tebe velmi state\232n\233, \158e[ENTER]jsi poslechl instrukce od n\236koho, o kom nev\237\154,[ENTER]kdo to je. Zd\225 se, \158e jsem se p\248i v\253b\236ru nespletl[ENTER]- a ty jsi opravdu nezklamal m\225 o\232ek\225v\225n\237.[ENTER]Poslouchej, co ti chci \248\237ci. "
gameforge.main_quest_lv66._20_say = "Uriel m\225 nov\233 informace o posledn\237 p\248e\158iv\154\237 Dra\232\237[ENTER]kn\236\158ce. Jej\237 den\237k by m\236l b\253t ve V\236\158i d\233mon\249.[ENTER]Zajdi za Urielem a zeptej se ho na detaily. "
gameforge.main_quest_lv66._210_sendLetter = "Nov\233 Zlo "
