gameforge.main_quest_lv66._230_say = "Existuje jeden d\249vod, pro\232 by ses m\236l vydat do[ENTER]Chr\225mu Hwang - d\236j\237 se tam velmi podivn\233 v\236ci. A[ENTER]zrovna ned\225vno jsme objevili vchod do obrovsk\233[ENTER]jeskyn\236 vzadu za V\236\158\237 d\233mon\249! "
