gameforge.main_quest_lv66._250_say = "V t\233to jeskyni na n\225s \232ek\225 nov\233, nep\248edstaviteln\233[ENTER]Zlo. Na\154i zv\236di hovo\248\237 o ohavn\233 kreatu\248e, p\248ed[ENTER]kterou se dokonce schov\225vaj\237 i d\233moni! Podle[ENTER]z\225pachu a snahou zahubit v\154e \158iv\233 si mysl\237me, \158e[ENTER]to nen\237 nic jin\233ho, ne\158 legend\225rn\237 Agwi - jeden z[ENTER]nejv\236t\154\237ch d\233mon\249 z jejich sv\236ta. Pokud se[ENTER]nepleteme, pak jsme v\154ichni v opravdu velk\233m[ENTER]nebezpe\232\237. "
gameforge.main_quest_lv66._260_say = "Je\154t\236 hroziv\236j\154\237 ne\158 d\233moni... Tato kreatura mus\237[ENTER]b\253t opravdu siln\225 a nemilosrdn\225. "
gameforge.main_quest_lv66._270_say = "Tak je to. J\225 a m\237 mu\158i jsme se ji\158 n\236kolikr\225t[ENTER]pokou\154eli probojovat se \207\225blovou katakombou, ale[ENTER]v\158dy jsme utrp\236li t\236\158k\233 ztr\225ty, ani\158 by se n\225m to[ENTER]poda\248ilo. Je jasn\233, \158e pot\248ebujeme pomoci od[ENTER]v\253jime\232n\233ho v\225le\232n\237ka - co\158 je d\249vod, pro\232 jsem[ENTER]pro tebe poslal. Pom\249\158e\154 n\225m? "
gameforge.main_quest_lv66._280_say = "Ano, pomohu. "
gameforge.main_quest_lv66._290_say = "Tak to n\225m d\225v\225 novou nad\236ji! A nyn\237, kdy\158 jsi na[ENTER]na\154\237 stran\236, ti pov\237m celou pravdu: j\225, Lee[ENTER]Chung, jsem velitele St\237nov\253ch v\225le\232n\237k\249. Jsme[ENTER]tajn\225 elitn\237 jednotka arm\225dy Lee Seopa. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ach, je dobr\233 t\236 vid\236t zdrav\233ho a znovu[ENTER]p\248ipraven\233ho do akce! Jsi p\248ipraven na nov\233[ENTER]dobrodru\158stv\237? Po\248\225d n\225m chyb\237 d\249le\158it\225 informace[ENTER]o Temn\233m n\225rodu a t\236ch sedmi Dra\232\237ch kn\236\158k\225ch.[ENTER]Posledn\237 Dra\232\237 kn\236\158ka musela ukr\253t sv\249j den\237k[ENTER]n\236kde ve V\236\158i d\233mon\249 je\154t\236 p\248ed t\237m, ne\158 byla[ENTER]donucena prov\233st kouzlo \232ern\233 magie. Vydej se tam[ENTER]a p\248ines mi ten den\237k. Je dost mo\158n\233, \158e jej m\225 v[ENTER]dr\158en\237 Kr\225l d\233mon\249. "
gameforge.main_quest_lv66._310_say = "St\237nov\237 v\225le\232n\237ci maj\237 po celou dobu pouze jeden[ENTER]\250kol - zabr\225nit vyvol\225n\237 Sung Mahi. To je n\225\154[ENTER]\250kol. Te\239 n\225m pomoz poslat Agwi zp\236t do pekla, a[ENTER]zjistit, jak se mohl dostat do na\154eho sv\236ta. "
gameforge.main_quest_lv66._320_sendLetter = "Nen\237 \232as "
gameforge.main_quest_lv66._330_say = "Hled\225 t\236 Lee Chung, velitel St\237nov\253ch v\225le\232n\237k\249.[ENTER]Je to opravdu urgentn\237! "
gameforge.main_quest_lv66._340_say = "M\225m urgentn\237 po\158adavek. Vid\237\154 tamhle toho[ENTER]zran\236n\233ho voj\225ka? Je to jeden z m\253ch zv\236d\249, kter\253[ENTER]na m\249j rozkaz prohled\225val \207\225blovu katakombu.[ENTER]B\236hem toho jej napadl Agwi a otr\225vil ho. Jed se[ENTER]nyn\237 pomalu rozl\233v\225 po cel\233m jeho t\236le - nezb\253v\225[ENTER]mu mnoho \232asu. "
gameforge.main_quest_lv66._350_say = "Pot\248ebuje protijed a pot\248ebuje jej zatracen\236[ENTER]rychle! M\249\158e\154 mu n\236jak\253 sehnat? Najde\154 jej v[ENTER]\200erven\233m lese nedaleko \200erven\253ch dry\225d. Je to[ENTER]jeden z m\253ch nejlep\154\237ch mu\158\249 - zachra\242 mu \158ivot a[ENTER]j\225 ti jako odm\236nu d\225m %s. "
gameforge.main_quest_lv66._360_say = "P\248inesu ten protijed! "
gameforge.main_quest_lv66._370_say = "D\237ky! St\225le d\253ch\225, ale ka\158dou minutu je slab\154\237 a[ENTER]slab\154\237. Nem\225me ji\158 mnoho \232asu! "
gameforge.main_quest_lv66._380_notice = "Zb\253v\225 ti %d minut. "
gameforge.main_quest_lv66._390_sendLetter = "Protijed "
gameforge.main_quest_lv66._400_say = "Z toho co ti Lee Chung \248ekl je z\248ejm\233, \158e[ENTER]protijed lze nal\233zt v \200erven\233m lese. Je na to[ENTER]t\248eba chytit %d \200erven\253ch dry\225d.[ENTER][ENTER]V \200erven\233m lese jsou mnohem nebezpe\232n\236j\154\237[ENTER]tvorov\233, ne\158 v Lese duch\249, tak bu\239 opatrn\253. "
gameforge.main_quest_lv66._40_say = "Porazil jsi Kr\225le d\233mon\249 a z\237skal jsi di\225\248 Dra\232\237[ENTER]kn\236\158ky. Dones jej Urielovi, kter\253 jej zanalyzuje. "
gameforge.main_quest_lv66._410_say = "\200as vypr\154el. Voj\225k um\237r\225, dones mu protijed tak[ENTER]rychle, jak to jenom bude mo\158n\233. "
gameforge.main_quest_lv66._420_say = "Zb\253v\225 ti %d minut. "
gameforge.main_quest_lv66._430_say = "Kone\232n\236 jsi nalezl protijed! Rychle, dones je Lee[ENTER]Chungovi. "
gameforge.main_quest_lv66._440_say = "Tady, rychle! Mysl\237m, \158e jsi dorazil pr\225v\236 v\232as.[ENTER]To mi ale ze srdce spadl opravdu velk\253 k\225men! J\225[ENTER]i m\237 mu\158i jsme ti neoby\232ejn\236 zav\225z\225ni za to, co[ENTER]jsi pro na\154eho kamar\225da ud\236lal. "
gameforge.main_quest_lv66._450_say = "D\237ky tv\233 pomoci m\249j voj\225k p\248e\158il. Tady je tv\225[ENTER]odm\236na za jeho z\225chranu. "
gameforge.main_quest_lv66._460_say = "Dal sis na \232as. Bojuje o sv\249j \158ivot z posledn\237ho[ENTER]zbytku jeho sil. Na\154t\236st\237 jsi to ale stihl. "
gameforge.main_quest_lv66._470_say = "Zd\225 se, \158e p\248ich\225z\237 k sob\236. Ale bylo to jen o[ENTER]chlup - m\225lem zem\248el, proto\158e jsi protijed hledal[ENTER]p\248\237li\154 dlouho. Je mi to l\237to, ale toto je v\154e, co[ENTER]ti mohu d\225t jako odm\236nu. "
gameforge.main_quest_lv66._480_sendLetter = "Zpr\225va "
gameforge.main_quest_lv66._490_say = "Zv\236d se za\232al uzdravovat. Poslechni si, co se mu[ENTER]poda\248ilo zjistit b\236hem jeho mise v \207\225blov\236[ENTER]katakomb\236. "
gameforge.main_quest_lv66._500_say = "D\237ky, \158e jsi mi zachr\225nil \158ivot. V \207\225blov\236[ENTER]katakomb\236 jsem vid\236l neuv\236\248iteln\233 v\236ci. Jen\158e pak[ENTER]m\236 objevili a... "
gameforge.main_quest_lv66._50_say = "Na\154el jsi ho! Di\225\248 posledn\237 Dra\232\237 kn\236\158ky! Ruce se[ENTER]mi chv\236j\237 nedo\232kavost\237! Budu ale pot\248ebovat[ENTER]trochu \232asu, abych zjistil, co se v n\236m p\237\154e. Ty[ENTER]si zat\237m odpo\232i\242. D\225m ti v\236d\236t, a\158 budu se \232ten\237m[ENTER]hotov. "
gameforge.main_quest_lv66._510_say = "Co jsi vid\236l? "
gameforge.main_quest_lv66._520_say = "Byli tam lid\233 v \232ern\253ch pl\225\154t\237ch s kapucemi[ENTER]sta\158en\253mi p\248es obli\232ej. Z \250tr\158k\249 jejich hovoru[ENTER]jsem poznal, \158e se jedn\225 o P\248isluhova\232e temnot.[ENTER]Ale to nen\237 v\154echno: nad jejich hlavami se[ENTER]vzn\225\154el duch, vypadaj\237c\237 jako \158ena. P\248isluhova\232i[ENTER]temnot ji oslovovali Smrtko. "
gameforge.main_quest_lv66._530_say = "To nezn\237 dob\248e. Poda\248ilo se ti zjistit, co[ENTER]P\248isluhova\232i temnot a Smrtka pl\225nuj\237? "
gameforge.main_quest_lv66._540_say = "Smrtka vyvolala Agwi za pou\158it\237 \232ern\233 magie.[ENTER]P\248\237\154eru p\248\237mo z hlubin pekla. Kr\225lem Agwi je[ENTER]Azrael. "
gameforge.main_quest_lv66._550_say = "Jen tak tak se mi povedlo se vr\225tit, abych[ENTER]informoval Lee Chunga. Bohu\158el jsem byl ale p\248i[ENTER]m\233m n\225vratu odhalen.[ENTER][ENTER]Ach, m\225lem jsem zapomn\236l, \158e velitel Lee Chung m\225[ENTER]pro tebe d\249le\158itou zpr\225vu. B\253t tebou, za\154el bych[ENTER]za n\237m. "
gameforge.main_quest_lv66._560_sendLetter = "Temn\225 hrozba "
gameforge.main_quest_lv66._570_say = "Zajdi za Lee Chungem a promluv si s n\237m o nov\233[ENTER]hrozb\236, kter\225 \232\237h\225 v \207\225blov\236 katakomb\236. "
gameforge.main_quest_lv66._580_say = "To, co m\249j zv\236d zjistil, je p\236kn\236 d\236siv\233, co? Za[ENTER]objeven\237 Agwiho jsou zodpov\236dn\237 P\248isluhova\232i[ENTER]temnot. Dokonce se jim povedlo vyvolat du\154i[ENTER]posledn\237 Dra\232\237 kn\236\158ky. V podob\236 Smrtky se vr\225tila[ENTER]na tento sv\236t a d\237ky sv\233 magick\233 s\237le m\249\158e[ENTER]vyvolat Sung Mahi. "
gameforge.main_quest_lv66._590_say = "Co\158e? Smrtka je du\154\237 posledn\237 Dra\232\237 kn\236\158ky? "
gameforge.main_quest_lv66._600_say = "O tom nen\237 pochyb. I bez sv\253ch sester z Dra\232\237ho[ENTER]kultu byla schopna p\248ivolat \232ty\248i Ochr\225nce nebes[ENTER]a prov\233st \232ernou magii. Ale te\239 aspo\242 v\237me, kdo[ENTER]za tou novou hrozbou stoj\237: P\248isluhova\232i temnot.[ENTER]A pomoc\237 Smrtky maj\237 v pl\225nu dokon\232it pr\225ci[ENTER]Temn\233ho n\225roda a probudit Sung Mahi. "
gameforge.main_quest_lv66._60_sendLetter = "\216e\154en\237 skl\225danky "
gameforge.main_quest_lv66._610_say = "Je toho hodn\236, za co ti mus\237me pod\236kovat:[ENTER]zachr\225nil jsi jednoho z m\253ch mu\158\249 p\248ed jistou[ENTER]smrt\237 a jen d\237ky tomu jsme byli schopni zjistit,[ENTER]jak se tu Agwi mohl n\225hle objevit a st\225t se tak[ENTER]velk\253m nebezpe\232\237m v \207\225blov\236 katakomb\236. Trochu si[ENTER]te\239 odpo\232i\242, pak za\232neme p\248em\253\154let o vhodn\233[ENTER]taktice postupu. "
gameforge.main_quest_lv66._620_say = "Dobrodru\158stv\237 bude pokra\232ovat, a\158 se dostane\154 na[ENTER]\250rove\242 72. "
gameforge.main_quest_lv66._70_say = "Hled\225 t\236 Uriel. Ji\158 do\232etl den\237k. "
gameforge.main_quest_lv66._80_say = "Skv\236l\233, tady jsi. Z\225znamy posledn\237 Dra\232\237 kn\236\158ky[ENTER]jsou ohromuj\237c\237. Poslouchej: "
gameforge.main_quest_lv66._90_say = "M\249j osud je nyn\237 zpe\232et\236n! Zabarik\225dovala jsem se[ENTER]v nejvy\154\154\237m pat\248e v\236\158e, ale mu\158i Lee Seopa se ji\158[ENTER]skoro dost\225vaj\237 dovnit\248. Nem\225m mo\158nost jak[ENTER]uniknout![ENTER]Ale ne! Nemohu skon\232it takhle! To p\248eci nem\249\158e[ENTER]b\253t konec! Mohu pou\158\237t \232ernou magii, vyu\158it[ENTER]starov\236k\233ho Zla a vyvolat temn\233 s\237ly.[ENTER]Bude to ale bohu\158el znamenat mou smrt. Ale m\237[ENTER]nep\248\225tel\233 se k m\233mu utrpen\237 p\248idaj\237, i kdy\158 je to[ENTER]posledn\237 v\236c, co mohu ud\236lat. "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Co\158e, tys mu ji je\154t\236 nedal? Prut je pro ryb\225\248e u[ENTER]\248eky! Honem, dost ji pot\248ebuje! "
gameforge.main_quest_lv7._10_targetVid = "Je\154t\236 jedna laskavost "
gameforge.main_quest_lv7._110_npcChat = "Kov\225\248 poslal tuhle novou udici! "
gameforge.main_quest_lv7._120_say = "D\237ky, nyn\237 se kone\232n\236 mohu zbavit m\233 dobr\233, ale[ENTER]p\248eci jen ji\158 hodn\236 star\233, udice. Z chyt\225n\237 ryb[ENTER]nem\225m jen ob\158ivu, ale je to i moje velk\225 v\225\154e\242.[ENTER]V\237\154 n\236co o ryba\248en\237? "
gameforge.main_quest_lv7._130_say = "Nejd\248\237v uchop udici a pak pou\158ij n\225vnadu tak, \158e[ENTER]na ni klikne\154. Potom nahod' udici t\237m, \158e[ENTER]pou\158ije\154 schopnost 'Chytat ryby'. Kdy\158 bude\154 m\237t[ENTER]pocit, \158e ti zab\237r\225 ryba (objev\237 se bublina),[ENTER]pou\158ij tuto schopnost je\154t\236 jednou. Bud' to te\239[ENTER]klaplo nebo to mus\237\154 zkusit je\154t\236 jednou.[ENTER]Existuje hojn\253 po\232et ryb, kter\233 m\249\158e\154 lovit. Ryba[ENTER]prosp\237v\225 tv\233mu zdrav\237 a n\236kdy v sob\236 skr\253v\225[ENTER]hodnotn\233 poklady. Tak\158e a\158 bude\154 m\237t n\225ladu,[ENTER]vyzkou\154ej to. "
gameforge.main_quest_lv7._140_say = "Jo, tady je stvrzenka k t\233 udici. M\236l bys ji[ENTER]don\233st kov\225\248i. "
gameforge.main_quest_lv7._150_sayItem = "Stvrzenka k udici "
gameforge.main_quest_lv7._160_sayReward = "P\248inesl jsi ryb\225\248ovi udici od kov\225\248e. Vra\157 se se[ENTER]stvrzenkou zp\225tky ke kov\225\248i. Pak dostane\154 odm\236nu. "
gameforge.main_quest_lv7._170_say = "Na\154el jsi ryb\225\248e?[ENTER]Super, tou don\225\154kou jsi mi u\154et\248il spoustu \232asu.[ENTER]Jako odm\236nu ti d\225m p\225r Yang\249 a 1 500 bod\249[ENTER]zku\154enost\237. "
gameforge.main_quest_lv7._180_sendLetter = "Pouk\225zka "
gameforge.main_quest_lv7._190_sayReward = "Za tuto pouk\225zku ti kov\225\248 zadarmo zlep\154\237 jeden[ENTER]kus tvoj\237 v\253stroje. Vezmi n\236jak\253 kus z tv\233ho[ENTER]invent\225\248e a p\248et\225hni ho na kov\225\248e, aby se[ENTER]otev\248elo okno se zlep\154ov\225n\237m. "
gameforge.main_quest_lv7._200_sayItem = "Pouk\225zka na 1 zlep\154en\237 zdarma "
gameforge.main_quest_lv7._20_sayReward = "B\236\158 ke kov\225\248i.[ENTER]Pot\248ebuje n\236koho, kdo by pro n\236j n\236co za\248\237dil. "
gameforge.main_quest_lv7._210_sayTitle = "Upozorn\236n\237: "
gameforge.main_quest_lv7._220_sayReward = "1) Pouk\225zka se nezobrazuje v invent\225\248i[ENTER]2) \218sp\236ch p\248i zlep\154en\237 nen\237 stoprocentn\236 zaru\232en. "
gameforge.main_quest_lv7._230_sayTitle = "Pouk\225zka u\158 byla pou\158ita "
gameforge.main_quest_lv7._240_sayReward = "Pouk\225zka na 1 zlep\154en\237 zdarma u\158 byla jednou[ENTER]pou\158ita. Pouk\225zku lze pou\158\237t jen jednou. "
gameforge.main_quest_lv7._30_say = "Hej, dobrodruhu! Mohl bys n\236co za m\236 vy\248\237dit? Za[ENTER]norm\225ln\237ch okolnost\237 se druh\253ch lid\237 nepros\237m,[ENTER]aby mi prok\225zali laskavost, ale ty mi p\248ipad\225\154[ENTER]d\249v\236ryhodn\253. Ber to jako projev \250cty! "
gameforge.main_quest_lv7._40_say = "Zhotovil jsem udici pro ryb\225\248e. Bohu\158el m\225m moc[ENTER]pr\225ce na to, abych za n\237m \154el s\225m. Mohl bys to[ENTER]ud\236lat za mn\236? "
gameforge.main_quest_lv7._50_sayItem = "Ryb\225\248sk\253 prut s vysokou pru\158nost\237 "
gameforge.main_quest_lv7._60_say = "Ryb\225\248 by m\236l b\253t n\236kde u \248eky.[ENTER]Kdy\158 donese\154 ryb\225\248ovi prut, tak ti zu\154lecht\237m[ENTER]\232\225st v\253zbroje \250pln\236 zdarma.[ENTER]To je p\248eci dobr\225 nab\237dka, nemysl\237\154? "
gameforge.main_quest_lv7._70_sendLetter = "Najdi ryb\225\248e "
gameforge.main_quest_lv7._80_sayReward = "Kov\225\248 vyrobil pro ryb\225\248e prut. Najdi u \248eky[ENTER]ryb\225\248e a dej mu ten prut. "
gameforge.main_quest_lv7._90_npcChat = "Pro koho je udice? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "Nebesk\225 slza z\237sk\225v\225 svou perfektn\237 jedine\232nost z[ENTER]magick\233ho souzn\236n\237 Klovatiny Svat\233ho stromu,[ENTER]Esence Modr\233ho krystalu a \200erven\233ho pekeln\233ho[ENTER]k\248emene. Esence Modr\233ho krystalu mus\237 b\253t z\237sk\225na[ENTER]od vl\225dce Ledov\233 zem\236. "
gameforge.main_quest_lv72._10_sendLetter = "Pou\158it\225 kamenn\225 tabulka "
gameforge.main_quest_lv72._110_say = "Poznamenal sis tento jedine\232n\253 objev. Vra\157 se[ENTER]zp\236t k Lee Chungovi a \248ekni mu, co jsi zjistil. "
gameforge.main_quest_lv72._120_say = "Sl\225va, vr\225til jsi se \158iv a zdr\225v! A z v\253raze tv\233[ENTER]tv\225\248e soud\237m, \158e jsi byl \250sp\236\154n\253, \158e? "
gameforge.main_quest_lv72._130_say = "No vlastn\236 ano! D\237ky n\225pisu na pou\158it\233 kamenn\233[ENTER]tabulce jsem zjistil, jak lze vyvolat svat\233 s\237ly[ENTER]za pou\158it\237 magick\233ho drahokamu, nazvan\233ho Nebesk\225[ENTER]slza. "
gameforge.main_quest_lv72._140_say = "Nebesk\225 slza... tak\158e p\248eci jen existuje. M\225\154[ENTER]n\236jak\233 stopy, jak bychom ji mohli z\237skat? "
gameforge.main_quest_lv72._150_say = "Abys mohl vyrobit Nebeskou slzu, pot\248ebuje\154[ENTER]Klovatinu Svat\233ho stromu, Esenci Modr\233ho krystalu[ENTER]a \200erven\253 pekeln\253 k\248emen. \216\237k\225 se, \158e Esenci[ENTER]Modr\233ho krystalu lze z\237skat od vl\225dce Ledov\233[ENTER]zem\236. "
gameforge.main_quest_lv72._160_say = "Vl\225dce Ledov\233 zem\236? Hm.... Mus\237 asi myslet Horu[ENTER]Sohan. Uk\225\158i tv\233 pozn\225mky m\225g\249m St\237nov\253ch[ENTER]v\225le\232n\237k\249 a spole\232n\236 se je pokus\237me zanalyzovat.[ENTER]Jakmile budu v\236d\236t v\237c, tak se ti ozvu! "
gameforge.main_quest_lv72._170_say = "P\248ijmi toto jako d\237ky za tv\233 skutky. I nad\225le ale[ENTER]po\232\237t\225m s tvou pomoc\237! "
gameforge.main_quest_lv72._180_sendLetter = "Ledov\253 poklad "
gameforge.main_quest_lv72._190_say = "Velitel Lee Chung t\236 informoval o tom, \158e prvn\237[ENTER]element pot\248ebn\253 pro v\253robu Nebesk\233 slzy, Esence[ENTER]Modr\233ho krystalu, m\225 n\236co spole\232n\233ho s[ENTER]legend\225rn\237m pokladem Dev\237tiocase na Ho\248e Sohan.[ENTER]Str\225\158\237 ho Ledov\237 golemov\233, Yeti a Ledov\237 mu\158i.[ENTER]Lov tato monstra, abys z\237skal Esenci Modr\233ho[ENTER]krystalu. Jakmile ji bude\154 m\237t, promluv si op\236t s[ENTER]Lee Chungem. "
gameforge.main_quest_lv72._200_say = "M\225gov\233 St\237nov\253ch v\225le\232n\237k\249 zjistili, \158e ob\225van\253[ENTER]Dev\237tiocas na Ho\248e Sohan hl\237d\225 modrou esenci jako[ENTER]oko v hlav\236. "
gameforge.main_quest_lv72._20_say = "Lee Chung, velitel St\237nov\253ch v\225le\232n\237k\249, by si s[ENTER]tebou r\225d promluvil. Povedlo se mu p\248ij\237t na to,[ENTER]jak porazit Agwiho v \207\225blov\236 katakomb\236. "
gameforge.main_quest_lv72._210_say = "Dev\237tiocas\249v poklad str\225\158\237 Ledov\237 golemov\233, Yeti[ENTER]a Ledov\237 mu\158i.[ENTER][ENTER]Na v\253robu Nebesk\233 slzy je t\248eba 50 Esenc\237 Modr\233ho[ENTER]krystalu. "
gameforge.main_quest_lv72._220_say = "\216\237k\225 se, \158e \200erven\253 pekeln\253 k\248emen lze z\237skat bu\239[ENTER]v chr\225mu Hwang, nebo v Ohniv\233 zemi. Poslal jsem[ENTER]zv\236dy, aby zjistili v\237ce. "
gameforge.main_quest_lv72._230 = "Velitel Lee Chung t\236 informoval o tom, \158e prvn\237[ENTER]element pot\248ebn\253 pro v\253robu Nebesk\233 slzy, Esence[ENTER]Modr\233ho krystalu, m\225 n\236co spole\232n\233ho s[ENTER]legend\225rn\237m pokladem Dev\237tiocase na Ho\248e Sohan.[ENTER]Str\225\158\237 ho Ledov\237 golemov\233, Yeti a Ledov\237 mu\158i.[ENTER]Lov tato monstra, abys z\237skal Esenci Modr\233ho[ENTER]krystalu. "
gameforge.main_quest_lv72._240_notice = "P\248i prohled\225v\225n\237 t\236l mrtv\253ch monster jsi na\154el[ENTER]bl\253skav\253 modr\253 drahokam. Mus\237 to b\253t Esence[ENTER]Modr\233ho krystalu. "
gameforge.main_quest_lv72._250_notice = "Mus\237\154 je\154t\236 naj\237t %d Esenc\237 Modr\233ho krystalu. "
gameforge.main_quest_lv72._260_say = "Mysl\237m, \158e pro dne\154ek jsi obdr\158el dostatek rad.[ENTER]Vra\157 se zase z\237tra r\225no. "
gameforge.main_quest_lv72._270_say = "Tyhle krystaly jsou nepou\158iteln\233. Pod\237vej se s\225m:[ENTER]maj\237 praskliny. Abychom je byli schopni pou\158\237t,[ENTER]nesm\237 b\253t po\154kozen\233! Pokra\232uj v hled\225n\237! "
gameforge.main_quest_lv72._280_say = "Tak ty jsou opravdu kvalitn\237! Jen pokra\232uj![ENTER]Pot\248ebuji jich je\154t\236 %d. "
gameforge.main_quest_lv72._290_say = "Nasb\237ral jsi tolik Esence Modr\233ho krystalu, kolik[ENTER]bylo pot\248eba. \218pln\236 z nich c\237t\237m s\237lu[ENTER]Dev\237tiocase! Neuv\236\248iteln\233... \250pln\236 tou energi\237[ENTER]vibruj\237. V\253born\236! "
gameforge.main_quest_lv72._300_say = "Dobrodru\158stv\237 bude pokra\232ovat, jakmile dos\225hne\154[ENTER]\250rovn\236 78. "
gameforge.main_quest_lv72._30_say = "Bohu\158el, Agwiho nelze zab\237t tak, jako d\233mony. My,[ENTER]St\237nov\237 v\225le\232n\237ci jsme ji\158 zkou\154eli v\154echny mo\158n\233[ENTER]zp\249soby, kter\233 si jen um\237\154 p\248edstavit. "
gameforge.main_quest_lv72._40_say = "Ale nyn\237 se mi povedlo zjistit, \158e Dra\232\237 kn\236\158ky[ENTER]pou\158\237vali k ni\232en\237 zl\253ch du\154\237 svat\233 s\237ly. "
gameforge.main_quest_lv72._50_say = "V \200erven\233m lese kdysi existoval svat\253 chr\225m[ENTER]Dra\232\237ch kn\236\158ek. Prohledej jeho ruiny a zkus naj\237t[ENTER]n\236jak\233 zn\225mky jejich kultu. Zv\236di kdysi mluvili o[ENTER]pou\158it\253ch kamenn\253ch tabulk\225ch, kter\233 byly[ENTER]rozh\225zeny v k\248ov\237... Mo\158n\225 je na nich naps\225no[ENTER]n\236co u\158ite\232n\233ho... "
gameforge.main_quest_lv72._60_sendLetter = "Objev "
gameforge.main_quest_lv72._70_say = "Lee Chung ti \248ekl, \158e Dra\232\237 kn\236\158ky byly schopny[ENTER]vyvolat svat\233 s\237ly pomoc\237 b\237l\233 magie, kter\233[ENTER]ni\232ily zl\233 du\154e. Hledej v \200erven\233m lese pou\158itou[ENTER]kamennou tabulku, o kter\233 mluvil Lee Chung, a[ENTER]z\237skej z n\237 dal\154\237 informace. "
gameforge.main_quest_lv72._80_say = "Po dlouh\233m hled\225n\237 jsi narazil na kamennou[ENTER]tabulku, kter\225 vypad\225, jako by zde ji\158 le\158ela[ENTER]cel\225 stalet\237. To mus\237 b\253t ta star\225 tabulka, o[ENTER]kter\233 mluvil Lee Chung! Horliv\236 se sna\158\237\154[ENTER]roz\154ifrovat ji\158 t\233m\236\248 ne\232iteln\253 n\225pis. "
gameforge.main_quest_lv72._90_say = "Nebesk\225 slza je t\237m nejcenn\236j\154\237m tajemstv\237m[ENTER]Dra\232\237ch kn\236\158ek. Tajemstv\237 jej\237 v\253roby bylo dr\158eno[ENTER]v tajnosti po cel\225 stalet\237 a v extr\233mn\237ch[ENTER]p\248\237padech bylo br\225n\236no i krv\237. Agwi a d\233moni[ENTER]nemohou nositele tohoto magick\233ho p\248edm\236tu[ENTER]napadnout. Pokud je nav\237c Nebesk\225 slza nejprve[ENTER]napln\236na svat\253mi silami, jej\237 efekt je[ENTER]ohromuj\237c\237. Z\225\248\237 stejn\236 jako hv\236zda na nebes\237ch[ENTER]\154iroko daleko. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Vynikaj\237c\237! Fungovalo to. Tady m\225\154 sv\249j \200erven\253[ENTER]pekeln\253 k\248emen! "
gameforge.main_quest_lv78._10_sendLetter = "\200erven\253 pekeln\253 k\248emen "
gameforge.main_quest_lv78._110_sendLetter = "Fin\225ln\237 element "
gameforge.main_quest_lv78._120_say = "Lee Chung a koncil m\225g\249 zjistili, \158e posledn\237[ENTER]element, Klovatinu Svat\233ho stromu, lze z\237skat z[ENTER]\200erven\253ch zl\253ch strom\249. Vydej se na jejich lov do[ENTER]\200erven\233ho lesa a p\248ines 100 d\225vek klovatiny.[ENTER]Ov\154em nejprve si promluv s Lee Chungem. "
gameforge.main_quest_lv78._130_say = "Lee Chung a koncil m\225g\249 zjistili, \158e posledn\237[ENTER]element, Klovatinu Svat\233ho stromu, lze z\237skat z[ENTER]\200erven\253ch zl\253ch strom\249. Vydej se na jejich lov do[ENTER]\200erven\233ho lesa a p\248ines 100 d\225vek klovatiny. "
gameforge.main_quest_lv78._140_say = "Toto je posledn\237 krok p\248ed v\253robou Nebesk\233 slzy.[ENTER]Bu\239 opatrn\253, \200erven\253 les se jen hem\158\237[ENTER]nebezpe\232n\253mi tvory! "
gameforge.main_quest_lv78._150_say = "St\225le pot\248ebuje\154 %d d\225vek Klovatiny Svat\233ho[ENTER]stromu. "
gameforge.main_quest_lv78._160_notice = "Na\154el jsi dostatek Klovatiny Svat\233ho stromu![ENTER]Dones ji veliteli Lee Chungovi. "
gameforge.main_quest_lv78._170_say = "To je Klovatina Svat\233ho stromu? \218pln\236 c\237t\237m jej\237[ENTER]enormn\237 s\237lu. Fantastick\233! Bohu\158el jsem musel[ENTER]poslat v\154echny m\233 m\225gy na jinou v\253pravu a budou[ENTER]tak chv\237li pry\232. Nen\237 n\225hodou v tv\233 vesnici[ENTER]chemik, kter\253 si \248\237k\225 Baek-Go? "
gameforge.main_quest_lv78._180_say = "Ano, mysl\237m \158e je. "
gameforge.main_quest_lv78._190_say = "Tak to je super! Dones mu v\154echny t\248i elementy.[ENTER]Baek-Go by m\236l b\253t schopen vyrobit z nich[ENTER]Nebeskou slzu. "
gameforge.main_quest_lv78._200_say = "M\225\154 za sebou dlouhou, vy\232erp\225vaj\237c\237 cestu.[ENTER]Pros\237m, vezmi si toto jako odm\236nu za tv\233 \250sil\237. "
gameforge.main_quest_lv78._20_say = "Lee Chung, velitel St\237nov\253ch v\225le\232n\237k\249, zjistil[ENTER]v\237ce informac\237 o \200erven\233m pekeln\233m k\248emeni. Abys[ENTER]jej mohl vyrobit, pot\248ebuje\154 t\248i substance:[ENTER]Vyv\248elinu z Ohniv\233 zem\236, Ohnivou h\248\237vu a[ENTER]Z\225kladov\253 k\225men.[ENTER]Vydej se na lov Plamen\249, Ohniv\253ch v\225le\232n\237k\249 a[ENTER]Bojov\253ch tygr\249, abys tyto substance z\237skal.[ENTER]Nasb\237rej 20 od ka\158d\233 z nich. Ale je\154t\236 ne\158 se[ENTER]vyd\225\154 na cestu, tak si promluv s Lee Chungem. "
gameforge.main_quest_lv78._210_sendLetter = "Nebesk\225 slza "
gameforge.main_quest_lv78._220_say = "Vra\157 se zp\236t do sv\233 vesnice, najdi chemika jm\233nem[ENTER]Beak-Go a jm\233nem Lee Chunga jej po\158\225dej ho o[ENTER]v\253robu Nebesk\233 slzy ze t\248ech element\249. "
gameforge.main_quest_lv78._230_say = "Byl jsi n\236jakou dobu pry\232. Ptal jsem se s\225m sebe,[ENTER]jestli se ti n\236co \154patn\233ho nestalo. Co mi tedy[ENTER]p\248in\225\154\237\154? "
gameforge.main_quest_lv78._240_say = "Lee Chung m\236 po\158\225dal, abych t\236 vyhledal a[ENTER]poprosil o laskavost. "
gameforge.main_quest_lv78._250_say = "Lee Chung? Velitel St\237nov\253ch v\225le.... Ach![ENTER]Psssst! Ticho! P\248ed tebou stoj\237 m\225g St\237nov\253ch[ENTER]v\225le\232n\237k\249. Ale ta informace je p\248\237sn\236 tajn\225,[ENTER]nikdo ve vesnici to nesm\237 v\236d\236t. Co ode mne Lee[ENTER]Chung pot\248ebuje za laskavost? "
gameforge.main_quest_lv78._260_say = "Pot\248ebuje, abys vyrobil Nebeskou slzu ze t\248ech[ENTER]element\249, kter\233 jsem p\248inesl. "
gameforge.main_quest_lv78._270_say = "Ufff, Nebeskou slzu.... V\158dy\157 m\225 u sebe spoustu[ENTER]m\225g\249, pro\232 v\158dycky to nejt\236\158\154\237 nech\225 na m\236?[ENTER][ENTER]Ale v po\248\225dku. Tak tedy Nebesk\225 slza. Po\154lu ji[ENTER]p\248\237mo Lee Chungovi po kur\253rovi a on ti pak d\225[ENTER]v\236d\236t, a\158 ji bude m\237t. \216ekne\154 mi, k \232emu ji[ENTER]pot\248ebuje? "
gameforge.main_quest_lv78._280_say = "Bohu\158el ti nemohu prozradit \158\225dn\233 detaily. Pouze[ENTER]toto: tento k\225men vyvol\225v\225 svat\233 s\237ly, kter\233[ENTER]mohou porazit d\233mony a dal\154\237 tvory Zla. "
gameforge.main_quest_lv78._290_say = "Velmi zaj\237mav\233. P\248eji ti v\154e nejlep\154\237 p\248i pln\236n\237[ENTER]tv\233ho \250kolu. Jako odm\236nu za tv\233 \250sil\237 si vezmi[ENTER]tyto dv\236 Vysu\154en\233 hlavy. Jsem celkem r\225d, \158e ti[ENTER]mohu b\253t n\225pomocen p\248i v\253rob\236 Nebesk\233 slzy i v[ENTER]budoucnu.[ENTER][ENTER]A pros\237m t\236, m\249\158e\154 Lee Chungovi p\248edat m\233[ENTER]pozdravy? "
gameforge.main_quest_lv78._300_say = "Dobrodru\158stv\237 bude pokra\232ovat, jakmile dos\225hne\154[ENTER]\250rovn\236 84. "
gameforge.main_quest_lv78._30_say = "Na\154i m\225gov\233 zjistili, \158e \200erven\253 pekeln\253 k\248emen,[ENTER]kter\253 pot\248ebujeme na v\253robu Nebesk\233 slzy, v sob\236[ENTER]obsahuje s\237lu ohn\236. To mus\237 b\253t asi d\249vod, pro\232[ENTER]jsou p\248\237\154ery v Ohniv\233 zemi tak siln\233. "
gameforge.main_quest_lv78._40_say = "\200erven\253 pekeln\253 k\248emen lze vyrobit z[ENTER]n\225sleduj\237c\237ch substanc\237: Vyv\248elina, Ohniv\225 h\248\237va[ENTER]a Z\225kladov\253 k\225men. V\154echny je najde\154 v Ohniv\233[ENTER]zemi. "
gameforge.main_quest_lv78._50_say = "Ty jsi to zvl\225dl! Kone\232n\236 m\225me pot\248ebn\253ch %d kus\249[ENTER]\200erven\233ho pekeln\233ho k\248emene. Tv\225 odvaha a s\237la[ENTER]op\236t p\248ed\232ily m\225 o\232ek\225v\225n\237! "
gameforge.main_quest_lv78._60_say = "Chyb\237 jedna substance. Pot\248ebujeme Vyv\248elinu,[ENTER]Ohnivou h\248\237vu a Z\225kladov\253 k\225men. "
gameforge.main_quest_lv78._70_say = "Je mi l\237to, ale jsem schopen vyrobit pouze sedm[ENTER]kus\249 \200erven\233ho pekeln\233ho k\248emene denn\236. Ta v\253roba[ENTER]je opravdu zkou\154kou m\253ch magick\253ch schopnost\237.[ENTER]Konec konc\249, nejsem \158\225dn\253 m\225g! "
gameforge.main_quest_lv78._80_say = "Tak jo! Nyn\237 sm\237ch\225m v\154echny t\248i substance a[ENTER]pokus\237m se vyrobit \200erven\253 pekeln\253 k\248emen. "
gameforge.main_quest_lv78._90_say = "N\233\233\233! Magie selhala. Bohu\158el jsem p\248ecenil sv\233[ENTER]magick\233 schopnosti. Mo\158n\225 se mi to povede p\248\237\154t\236. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Te\239, kdy\158 jsi porazil gener\225la Tartara, objevil[ENTER]se vstup do p\248edt\237m skryt\233 \232\225sti \207\225blovy[ENTER]katakomby. Tam mus\237 b\253t princ Charon! Teleportuj[ENTER]se do \154est\233ho podla\158\237 a postav se Agwi princi.[ENTER]Ale bu\239 opatrn\253, je extr\233mn\236 siln\253 a mocn\253 jako[ENTER]\239\225bel. "
gameforge.main_quest_lv84._10_sendLetter = "Boj za\232\237n\225... "
gameforge.main_quest_lv84._110_say = "Cesta, kterou se beze strachu vyd\225v\225\154 hloub\236ji do[ENTER]\207\225blovy katakomby, za\232\237n\225 b\253t pro smrteln\237ka[ENTER]t\233m\236\248 nemo\158nost\237. \200edi\232ov\253 obelisk na p\225t\233m[ENTER]podla\158\237 slou\158\237 jako teleport do tajn\233ho \154est\233ho[ENTER]podla\158\237. "
gameforge.main_quest_lv84._120_say = "Odtud princ Charon p\248ed\225v\225 sv\233 rozkazy Agwi[ENTER]gener\225lovi Tartarovi. Tak na co \232ek\225\154? Poraz[ENTER]Charona a p\248ekaz zlov\236stn\233 pl\225ny P\248isluhova\232\249[ENTER]temnot a Smrtky. "
gameforge.main_quest_lv84._130_sayReward = "Ty jsi to dok\225zal! Charon, Agwi princ, byl[ENTER]zne\154kodn\236n. "
gameforge.main_quest_lv84._140_say = "Vy\232erpan\253 ale uvoln\236n\253 si ot\237r\225\154 z tv\225\248e pot.[ENTER]N\225hle se ale \207\225blovou katakombou rozlehne sm\237ch,[ENTER]kter\253 se ti za\248ez\225v\225 a\158 do morku kost\237:[ENTER]Ahahahahaha! P\248\237li\154 pozd\236, ty patetick\253 \232lov\237\232ku![ENTER]N\225\154 p\225n Sung Mahi ji\158 povstal a ji\158 nen\237 nic, co[ENTER]by ho mohlo zastavit! Ji\158 brzy dos\225hne sv\233 pln\233[ENTER]s\237ly na ostrov\236, kdy sp\237 zl\237 draci. Tv\249j sv\236t[ENTER]bude zni\232en! "
gameforge.main_quest_lv84._150_sendLetter = "Nedokon\232en\253 p\248\237b\236h "
gameforge.main_quest_lv84._160_say = "Jdi za Lee Chungem a p\248edej mu zpr\225vu od Smrtky. "
gameforge.main_quest_lv84._170_say = "Pot\233, co jsi veliteli popsal sv\225 v\237t\236zstv\237 nad[ENTER]Tartarem a Charonem, pov\236d\236l jsi mu o znepokojiv\233[ENTER]zpr\225v\236 od Smrtky. Lee Chung s v\225\158nou tv\225\248\237 za\232\237n\225[ENTER]vypr\225v\236t: "
gameforge.main_quest_lv84._180_say = "P\248edpokl\225dal jsem, \158e kdy\158 poraz\237me Agwi prince,[ENTER]tak se n\225m poda\248\237 p\248ekazit pl\225ny P\248isluhova\232\249[ENTER]temnot a Smrtky. Jak jsem se jen m\253lil... "
gameforge.main_quest_lv84._190_say = "Smrtce se muselo poda\248it dokon\232it o\158iven\237 Sung[ENTER]Mahi spole\232n\236 s Azraelem, kr\225lem Agwi. Z toho[ENTER]pomy\154len\237 se mi d\236l\225 mdlo... "
gameforge.main_quest_lv84._200_say = "Ostrov, na kter\233m sp\237 zl\237 draci... Hm, asi m\225 na[ENTER]mysli Temnou dra\232\237 sk\225lu. Je to zem\236 daleko[ENTER]odtud. A i kdy\158 se n\225m nepoda\248ilo dos\225hnout toho,[ENTER]v co jsme doufali, dlu\158\237me ti velk\233 d\237ky za to,[ENTER]co jsi pro n\225s ud\236lal. Bez tv\233 pomoci bychom[ENTER]nikdy nebyli schopni odhalit to, co se schov\225valo[ENTER]v temn\253ch hlubin\225ch \207\225blovy katakomby. "
gameforge.main_quest_lv84._20_say = "Lee Chung obdr\158el Nebeskou slzu a m\225 v\154e[ENTER]p\248ipraveno pro misi v \207\225blov\236 katakomb\236. Jdi za[ENTER]n\237m a zjisti v\237ce. "
gameforge.main_quest_lv84._210_say = "Vykonal jsi opravdu hrdinsk\233 skutky, skutky,[ENTER]kter\253ch by nikdo jin\253 nebyl schopen. Jsem[ENTER]p\248ipraven st\225t ti po boku, kdykoliv to bude\154[ENTER]pot\248ebovat, a\158 do konce m\233ho \158ivota. Sbohem! "
gameforge.main_quest_lv84._30_say = "Te\239 kdy\158 m\225me Nebeskou slzu, je jenom ot\225zkou[ENTER]\232asu, ne\158 poraz\237me P\248isluhova\232e temnot a vy\158eneme[ENTER]Agwiho pry\232 z na\154eho sv\236ta! Bohu\158el ale pln\225 s\237la[ENTER]Nebesk\233 slzy je uvoln\236na pouze na velmi[ENTER]specifick\233m m\237st\236 v \207\225blov\236 katakomb\236. "
gameforge.main_quest_lv84._40_say = "V\237me o p\236ti podla\158\237ch \207\225blovy katakomby. Na p\225t\233m[ENTER]a posledn\237m podla\158\237, kter\233 zn\225me, se potk\225\154 s[ENTER]Tartarem, hrozn\253m Agwi gener\225lem a t\248et\237m v[ENTER]po\248ad\237 velen\237 po kr\225li Azraelovi a Charonovi.[ENTER]Poraz jej s pomoc\237 Nebesk\233 slzy. "
gameforge.main_quest_lv84._50_say = "Ale kde je Charon? "
gameforge.main_quest_lv84._60_sendLetter = "Gener\225l Tartaros "
gameforge.main_quest_lv84._70_say = "Pou\158ij Nebeskou slzu pouze a\158 dos\225hne\154 p\225t\233ho[ENTER]podla\158\237 v \207\225blov\236 katakomb\236. Vstup do \207\225blovy[ENTER]katakomby je za V\236\158\237 d\233mon\249. "
gameforge.main_quest_lv84._80_say = "Svat\233 s\237ly Nebesk\233 slzy za\232\237naj\237 m\237t efekt.[ENTER]C\237t\237\154, jak tv\253m t\236lem pulsuje obrovsk\225 s\237la. Moc[ENTER]tohoto kamene je omra\232uj\237c\237![ENTER][ENTER]Poraz Gener\225la Tartara. "
gameforge.main_quest_lv84._90_sendLetter = "Princ Charon "
gameforge.main_quest_lv9 = {}
gameforge.main_quest_lv9._10_targetVid = "Najdi str\225\158ce m\236sta "
gameforge.main_quest_lv9._20_sendLetter = "Promluv si se str\225\158cem m\236sta "
gameforge.main_quest_lv9._30_sayReward = "Ud\236lal jsi prvn\237 kroky na cest\236 st\225t se[ENTER]opravdov\253m hrdinou. Nyn\237 je \232as na v\236t\154\237 v\236ci.[ENTER]Jdi ke Str\225\158ci vesnice a p\248ijmi od n\236j svou[ENTER]posledn\237 za\232\225te\232nickou misi. "
gameforge.main_quest_lv9._40_say = "Jsi p\248ipraven zvl\225dnout obt\237\158n\236j\154\237 \250koly? Nebude[ENTER]to tak snadn\233 jako doposud. Bude\154 muset tvrd\236[ENTER]pracovat na budoucnosti tv\233ho kr\225lovstv\237. Za\158ije\154[ENTER]hodn\236 bitev a pot\237\158\237. Tak\158e bud' st\225le opatrn\253.[ENTER]Doposud jsi vy\248\237dil n\236kolik \250kol\249. Proto sis[ENTER]vyslou\158il tuhle cenu jako uzn\225n\237 za tvoji n\225mahu.[ENTER]Douf\225m, \158e ti bude slou\158it. "
gameforge.main_quest_lv9._50_say = "Nad\225le t\236 bude v\233st velitel. Do budoucna bude na[ENTER]tebe dohl\237\158et a d\225vat ti \250koly on. Nasb\237rej je\154t\236[ENTER]trochu zku\154enost\237 a pak jdi za n\237m.[ENTER]P\248eji hodn\236 \250sp\236chu do budoucna! "
gameforge.main_quest_lv90 = {}
gameforge.main_quest_lv90._010_sendLetter = "Temn\225 dra\232\237 sk\225la "
gameforge.main_quest_lv90._020_say = "Tv\225 cesta byla dlouh\225 a n\225ro\232n\225. Ale nyn\237 jsi[ENTER]kone\232n\236 dos\225hl sv\233ho c\237le: Temn\233 dra\232\237 sk\225ly.[ENTER]Hledej Admir\225l Angura. Najde\154 ho v Z\225livu dra\232\237ho[ENTER]ohn\236. "
gameforge.main_quest_lv90._030_say = "V\237tej na Temn\233 dra\232\237 sk\225le cizin\232e! P\248i\154el jsi[ENTER]n\225m pomoci v boji proti Sung Mahi? "
gameforge.main_quest_lv90._040_say = "Ano, jist\236. Pos\237l\225 m\236 Lee Chung, velitel[ENTER]St\237nov\253ch v\225le\232n\237k\249. "
gameforge.main_quest_lv90._050_say = "Lee Chung! Je to m\249j dlouholet\253 p\248\237tel. Tak\158e jsi[ENTER]tu na jeho rozkaz. Fajn, te\239 v\237m, \158e ti mohu[ENTER]v\236\248it. "
gameforge.main_quest_lv90._060_say = "D\236kuji. Jak tady vypad\225 situace? "
gameforge.main_quest_lv90._070_say = "D\233moni ovl\225daj\237 velkou \232\225st \250zem\237. Nic a nikdo[ENTER]p\248ed nimi nen\237 v bezpe\232\237. Dokonce se po\158\237raj\237[ENTER]navz\225jem. Temn\253 vliv Sung Mahi je \250pln\236 zbavil[ENTER]rozumu. "
gameforge.main_quest_lv90._080_say = "Hodila by se mi tv\225 pomoc. Mohl by jsi prozkoumat[ENTER]ostrov a p\248in\233st mi nejnov\236j\154\237 zpr\225vy o situaci? "
gameforge.main_quest_lv90._090_say = "Samoz\248ejm\236. "
gameforge.main_quest_lv90._1000_say = "Dob\248e. "
gameforge.main_quest_lv90._100_say = "D\236kuji. Po\232kej, je\154t\236 ti uk\225\158u tvou cestu. "
gameforge.main_quest_lv90._1010_say = "Jsi velmi sna\158iv\253, ale bohu\158el to nen\237 dost.[ENTER]Pokra\232uj ve sb\237r\225n\237! "
gameforge.main_quest_lv90._1020_sayTitle = "Sb\237rej j\237lov\233 cihly "
gameforge.main_quest_lv90._1030_say = "Vydej se do boje proti Mantikor\225m, abys nasb\237ral[ENTER]J\237lov\233 cihly. "
gameforge.main_quest_lv90._1040_1_notice = "Nasb\237ral jsi dostatek J\237lov\253ch cihel. "
gameforge.main_quest_lv90._1040_2_notice = "Dones je admir\225lovi Angmurovi. "
gameforge.main_quest_lv90._1050_say = "Promluv si s admir\225lem Angmurem. "
gameforge.main_quest_lv90._1060_say = "V\253born\236, d\237ky tob\236 m\225me dostatek materi\225lu na[ENTER]zes\237len\237 na\154ich palis\225d. Jakmile s t\237m budeme[ENTER]hotovi, tak ti d\225m v\236d\236t. "
