gameforge.main_quest_lv91._430_say = "Hled\225 t\236 Yon-I-Walker. Zajdi za n\237m a zjisti, zda[ENTER]ji\158 byl schopen dekryptovat dopis \232i nikoliv. "
gameforge.main_quest_lv91._440_say = "*mhmhmmhm* .. ano! Tady jsi! D\237ky tv\233 pomoci jsem[ENTER]byl schopen dekryptovat velkou \232\225st zpr\225vy. Ov\154em[ENTER]neda\248\237 se mi s posledn\237 \232\225st\237. Ob\225v\225m se, \158e budu[ENTER]tvou pomoc pot\248ebovat znovu. Urgentn\236 pot\248ebuji[ENTER]Carapaxsk\253 pr\225\154ek. Najde\154 jej u Gener\225la Humra[ENTER]nebo Kr\225lovsk\233ho kraba. "
gameforge.main_quest_lv91._450_say = "Carapaxsk\253 pr\225\154ek "
gameforge.main_quest_lv91._460_say = "Ano, pouze \232lenov\233 kmene Crustacean jej maj\237.[ENTER]Dokonce i mal\225 hrstka tohoto prachu je smrteln\225![ENTER]T\248i d\243zi\232ky by m\236ly b\253t dost. Hodn\236 \154t\236st\237. "
