gameforge.main_quest_lv91._480_sayTitle = "Carapaxsk\253 pr\225\154ek "
gameforge.main_quest_lv91._490_say = "Najdi Gener\225la Humra a Kr\225lovsk\233ho kraba a z\237skej[ENTER]od nich t\248i d\243zi\232ky Carapaxsk\233ho pr\225\154ku. "
gameforge.main_quest_lv91._500_say = "Carapaxsk\253 pr\225\154ek je extr\233mn\236 jedovat\253. Mus\237m[ENTER]po\232kat cel\253 den, aby se jeho \250\232inek[ENTER]neutralizoval.[ENTER]Vra\157 se zase z\237tra, douf\225m, \158e ti budu moci[ENTER]sd\236lit v\237ce. "
