gameforge.main_quest_lv91._520_say = "Dobr\225 pr\225ce. nyn\237 budu moci kone\232n\236 dekryptovat[ENTER]cel\253 dopis. Pros\237m, vezmi si toto jako odm\236nu. "
gameforge.main_quest_lv91._530_say = "P\248ines mi dal\154\237ch %d kus\249. "
gameforge.main_quest_lv91._540_say = "Tenhle Carapaxsk\253 pr\225\154ek je kontaminovan\253. P\248ines[ENTER]mi pros\237m jin\253. "
