gameforge.main_quest_lv91._590_say = "Cht\236l si posp\237\154it a nebyl dost opatrn\253. A co je[ENTER]nejhor\154\237, na\154e z\225soby l\233k\249 nejsou dostate\232n\233.[ENTER]Vydej se hledat Devatern\237k - jeho ko\248eny[ENTER]neutralizuj\237 jed. Ozna\232il jsem na map\236 m\237sta, kde[ENTER]roste. "
