gameforge.main_quest_lv91._650_say = "*chrrr*[ENTER]*ahhhgr*[ENTER]Ach, to jsi ty. Nen\237 mi n\236jak dob\248e. Na\154el jsi[ENTER]Ko\248en devatern\237ku? "
