gameforge.main_quest_lv92._010_sendLetter = "Dopis \200erven\253m zlod\236j\249m "
gameforge.main_quest_lv92._020_say = "Posledn\237 dopis, poslan\253 P\248isluhova\232i temnot, byl[ENTER]odesl\225n Gangu \200erven\253ch zlod\236j\249. Admir\225l Angmur[ENTER]m\225 pro tebe v\237ce informac\237. "
gameforge.main_quest_lv92._030_say = "Dost\225v\225me se st\225le bl\237\158 k pl\225n\249m P\248isluhova\232\249[ENTER]temnot. Posledn\237 dopis se nach\225z\237 v ruk\225ch Gangu[ENTER]\200erven\253ch zlod\236j\249. "
gameforge.main_quest_lv92._040_say = "Gang \200erven\253ch zlod\236j\249? "
gameforge.main_quest_lv92._050_say = "Je to banda krimin\225ln\237k\249, kte\248\237 byli vyhn\225ni z[ENTER]Temn\233 dra\232\237 sk\225ly. Co je na nich divn\233 je to, \158e[ENTER]jsou to lidsk\233 bytosti, kte\248\237 se spojili s[ENTER]d\233mony. "
gameforge.main_quest_lv92._060_say = "D\233moni se spojili s lidmi, m\237sto aby je se\158rali?[ENTER]To je divn\233. "
gameforge.main_quest_lv92._070_say = "Spojuje je spole\232n\253 z\225jem: zlato. Kemp Gangu[ENTER]\200erven\253ch zlod\236j\249 odtud nen\237 daleko. Pora\158[ENTER]Poprav\232\237ho \200erven\253ch zlod\236j\249 a \200ern\233ho gener\225la.[ENTER]Jeden z nich m\225 ten dopis. "
gameforge.main_quest_lv92._080_say = "Bohu\158el byli varov\225ni o na\154ich z\225m\236rech v\232as a[ENTER]proto roztrhli dopis na 4 \232\225sti. Pot\248ebujeme je[ENTER]naj\237t v\154echny. "
