gameforge.main_quest_lv92._100_say = "D\236kuji! "
gameforge.main_quest_lv92._110_sayTitle = "Dopis \200erven\253m zlod\236j\249m "
gameforge.main_quest_lv92._120_say = "Bojuj s Poprav\232\237m \200erven\253ch zlod\236j\249 a \200ern\253m[ENTER]gener\225lem. Najdi v\154echny \232ty\248i \232\225sti dopisu. "
gameforge.main_quest_lv92._130_say = "Dopis je\154t\236 nen\237 kompletn\237. Najdi v\154echny jeho[ENTER]\232\225sti. "
gameforge.main_quest_lv92._140_1_notice = "Na\154el jsi v\154echny \232\225sti Dopisu \200erven\253m zlod\236j\249m. "
gameforge.main_quest_lv92._140_2_notice = "Uka\158 ji Admir\225lovi Angmurovi. "
gameforge.main_quest_lv92._150_say = "Promluv si s admir\225lem Angmurem. "
gameforge.main_quest_lv92._160_say = "Dobr\225 pr\225ce. Tady, p\248ijmi toto jako v\253raz m\233[ENTER]vd\236\232nosti. "
gameforge.main_quest_lv92._170_sendLetter = "Dopis \200erven\253m zlod\236j\249m "
gameforge.main_quest_lv92._180_say = "Admir\225l Angmur pot\248ebuje tvou pomoc. "
gameforge.main_quest_lv92._190_say = "Dob\248e \158e jsi tady. M\225me probl\233m. "
gameforge.main_quest_lv92._200_say = "Co se d\236je? "
gameforge.main_quest_lv92._210_say = "Existuje toti\158 p\225t\253 kus Dopisu \200erven\253m zlod\236j\249m.[ENTER]Bez t\233to \232\225sti je to co jsi zat\237m p\248inesl[ENTER]bezcenn\233. U\158 jsem pro n\236j poslal Bae-Yonga,[ENTER]jednoho z m\253ch nejstate\232n\236j\154\237ch mu\158\249, ale muselo[ENTER]se mu n\236co st\225t. U\158 d\225vno m\236l b\253t zp\236t. Mohl by[ENTER]ses po n\236m pod\237vat? "
gameforge.main_quest_lv92._220_say = "Samoz\248ejm\236! M\225\154 p\248edstavu, kde by mohl b\253t? "
gameforge.main_quest_lv92._230_say = "P\248edstavu, to ano. Naposledy se zmi\242oval, \158e se[ENTER]chce pod\237vat do Nefritov\233ho z\225livu. Ov\154em nikdo[ENTER]nedok\225\158e potvrdit, zda tam opravdu \154el \232i[ENTER]nikoliv. "
gameforge.main_quest_lv92._240_say = "Ihned se vyd\225m na cestu! "
gameforge.main_quest_lv92._250_sayTitle = "Poh\248e\154ovan\253 voj\225k "
gameforge.main_quest_lv92._260_say = "Najdi p\225t\253 kus dopisu. Pravd\236podobn\236 ho m\225[ENTER]Bae-Young, kter\253 se vydal do Nefritov\233ho z\225livu. "
gameforge.main_quest_lv92._270_say = "Je\154t\236 jsi nena\154el Bea-Younga? V\158dy\157 je to[ENTER]z\225le\158itost \158ivota \232i smrti! Pros\237m, pokra\232uj v[ENTER]hled\225n\237. "
gameforge.main_quest_lv92._280_say = "*chrrr*[ENTER]D\237ky, \158e jsi m\236 hledal. Byl jsem v bitv\236 t\236\158ce[ENTER]zran\236n a ob\225v\225m se, \158e mi ji\158 nezb\253v\225 mnoho[ENTER]\232asu...[ENTER]Tady, tohle jsem sebral \200erven\253m zlod\236j\249m. Dones[ENTER]to admir\225lovi. B\236\158! Budu v po...[ENTER](Um\248el ti v n\225ru\232\237.) "
gameforge.main_quest_lv92._290_1_notice = "Je\154t\236 ne\158 Bae-Young zem\248el, tak ti p\248edal[ENTER]chyb\236j\237c\237 \232\225st dopisu. "
gameforge.main_quest_lv92._290_2_notice = "Vydej se zp\236t za admir\225lem Angmurem. "
gameforge.main_quest_lv92._300_say = "Jsi zp\236t? Na\154el jsi Bae-Younga? "
gameforge.main_quest_lv92._310_say = "Ano, ale... "
gameforge.main_quest_lv92._320_say = "Ale?[ENTER]Ach ne... je mrtv\253? "
gameforge.main_quest_lv92._330_say = "U\158 jsem pro n\236j nemohl nic ud\236lat. Up\248\237mnou[ENTER]soustrast. Byl to state\232n\253 mu\158 - br\225nil posledn\237[ENTER]kus dopisu sv\253m \158ivotem. Tady je. "
gameforge.main_quest_lv92._340_say = "Ztr\225ta Bae-Younga je opravdu bolestn\225. Ale jsem[ENTER]na n\236j velmi hrd\253. Dokon\232il sv\249j \250kol - nyn\237 m\225me[ENTER]v\154echny \232\225sti dopisu. "
gameforge.main_quest_lv92._350_say = "D\236kuji ti za v\154echno. Tady, tohle si vezmi jako[ENTER]odm\236nu.[ENTER]Jdu do kostela zap\225lit sv\237\232ku za Bae-Younga.[ENTER]Promluv\237me si pozd\236ji. "
gameforge.main_quest_lv92._360_say = "Jdi za Admir\225lem Angmurem. "
gameforge.main_quest_lv92._370_sendLetter = "Dekryptov\225n\237 Dopisu \200erven\253m zlod\236j\249m "
gameforge.main_quest_lv92._380_say = "Admir\225l Angmur m\225 d\249le\158it\233 zpr\225vy o Dopisu[ENTER]\200erven\253ch zlod\236j\249.[ENTER]Poslechni si, co ti chce sd\236lit. "
gameforge.main_quest_lv92._390_say = "\193, tady jsi. Z t\236ch P\248isluhova\232\249 temnot u\158 m\236[ENTER]bol\237 hlava. Tenhle dopis je tak\233 zakryptov\225n.[ENTER]Pros\237m, dones jej Yon-I-Walkerovi. "
gameforge.main_quest_lv92._400_say = "Ch\225pu. "
gameforge.main_quest_lv92._410_say = "Dones zakryptovan\253 dopis Yon-I-Walkerovi. "
gameforge.main_quest_lv92._420_say = "Ach! To se ke m\236 mus\237\154 v\158dycky takhle p\248ipl\237\158it?[ENTER]Co pro tebe mohu ud\236lat? "
gameforge.main_quest_lv92._430_say = "Tady je Dopis \200erven\253m zlod\236j\249m. Tak jako ty[ENTER]p\248edchoz\237 je i on zakryptovan\253. "
gameforge.main_quest_lv92._440_say = "Uka\158, pod\237v\225m se na to. Hmmm, to vypad\225 jako[ENTER]tritonsk\233 znaky. Jejich dekryptov\225n\237 by nem\236lo[ENTER]b\253t tak t\236\158k\233. "
gameforge.main_quest_lv92._450_say = "Vynikaj\237c\237. Kolik na to pot\248ebuje\154 \232asu? "
gameforge.main_quest_lv92._460_say = "Ne tak rychle. Samotn\233 dekryptov\225n\237 nen\237 nijak[ENTER]slo\158it\233, ale pot\248ebuje\154 k tomu n\236jak\233 v\236ci. "
gameforge.main_quest_lv92._470_say = "No samoz\248ejm\236. P\248i\154lo mi to n\236jak snadn\233. "
gameforge.main_quest_lv92._480_say = "Kouk\225m, \158e jsi ztratil smysl pro humor, hehehe.[ENTER]Abych dekryptoval dopis, pot\248ebuji Oinovy \154upiny.[ENTER]V kmeni Trioton\249 nos\237 tyhle \154upiny pouze Gener\225l[ENTER]Kappa a samotn\253 Triton. Pros\237m, p\248ines mi jich[ENTER]deset. "
gameforge.main_quest_lv92._490_say = "Dob\248e, vyd\225m se ihned na cestu. "
