gameforge.main_quest_lv92._510_say = "Pouze Triton, kr\225l Triton\249 a gener\225l Kappa nos\237[ENTER]Oinovi \154upiny. "
gameforge.main_quest_lv92._520_say = "Bez t\236ch \154upin nemohu dopis dekryptovat. Nutn\236 je[ENTER]pot\248ebuji. "
gameforge.main_quest_lv92._530_1_notice = "Na\154el jsi tritonskou Oinovu \154upinu. "
gameforge.main_quest_lv92._530_2_notice = "Rychle je dones Yon-I-Walkerovi. "
gameforge.main_quest_lv92._540_say = "Vedl sis dob\248e. Jakmile budu m\237t dopis[ENTER]dekryptovan\253, d\225m v\236d\236t admir\225lovi Angmurovi. Ty[ENTER]by sis m\236l zat\237m trochu odpo\232inout. Tady, vezmi[ENTER]si tohle jako v\253raz m\253ch d\237k\249. "
gameforge.main_quest_lv92._550_say = "Chce s tebou mluvit Yon-I-Walker. "
gameforge.main_quest_lv92._560_sendLetter = "Temn\233 pl\225ny "
gameforge.main_quest_lv92._570_say = "Dopis od P\248isluhova\232\249 temnot byl dekryptov\225n.[ENTER]Admir\225l Angmur ti chce \248\237ci o temn\253ch pl\225nech. "
gameforge.main_quest_lv92._580_say = "Povedlo se n\225m kompletn\236 dekryptovat tajnou[ENTER]zpr\225vu. Pamatuje\154 si na dopis, poslan\253 Gnoll\249m?[ENTER]Tam mluvili o drac\237ch, kte\248\237 sp\237 na ostrov\236, a[ENTER]tak\233 o postupu, jak\253m je vzbudit a naplnit je[ENTER]hn\236vem. Nyn\237 jsme zjistili d\249vod, pro\232 to na n\225s[ENTER]P\248isluhova\232i temnot chystaj\237. "
gameforge.main_quest_lv92._590_say = "Kdy\158 v prav\253 okam\158ik zabije\154 draka, tak je jeho[ENTER]mysl \232ern\225 jako samotn\253 ch\248t\225n pekla a vyplivne[ENTER]ven Perlu noci. D\237ky s\237le t\233to perly m\249\158e b\253t[ENTER]o\158iven Sung Mahi a lze jej p\248iv\233st do tohoto[ENTER]sv\236ta. To je jejich \154\237len\253 pl\225n! "
gameforge.main_quest_lv92._600_say = "Mus\237me si na\154e dal\154\237 kroky opravdu dob\248e[ENTER]promyslet. Jakmile pro tebe budu m\237t n\236jak\233[ENTER]zpr\225vy, tak t\236 zavol\225m. Zat\237m ti za v\154e d\236kuji. "
gameforge.main_quest_lv92._610_say = "Dobrodru\158stv\237 bude pokra\232ovat jakmile dos\225hne\154[ENTER]\250rovn\236 93. "
