gameforge.main_quest_lv93._230_say = "Promluv si s Yon-I-Walkerem. "
gameforge.main_quest_lv93._240_say = "Vnit\248n\237 sv\236tlo Kr\225le Wubby m\225 enormn\237 energii.[ENTER]V\236\248\237m tomu, \158e je takov\225 d\237ky jeho velikosti.[ENTER]Mus\237m ho samoz\248ejm\236 vy\232istit. Bude to n\236jakou[ENTER]chvilku trvat. "
gameforge.main_quest_lv93._250_sendLetter = "Sb\237r\225n\237 s\237ly III "
gameforge.main_quest_lv93._260_say = "Hled\225 t\236 Yon-I-Walker. "
gameforge.main_quest_lv93._270_say = "Jsi tady, v\253born\236. Pot\248ebuji tvou pomoc. Abych[ENTER]mohl m\249j n\225poj \250pln\236 dokon\232it, pot\248ebuji je\154t\236[ENTER]jednu p\248\237sadu: Esenci mil\233nia. "
gameforge.main_quest_lv93._280_say = "Esence mil\233nia? Nikdy jsem o n\237 nesly\154el. "
gameforge.main_quest_lv93._290_say = "Je to velmi \250\232inn\225 sm\236s, vyroben\225 ze sm\236si[ENTER]r\249zn\253ch l\233\232iv\253ch bylin. Zn\225\154 Octavia? \142ije v[ENTER]hlavn\237 vesnici a je jedin\253, kdo je schopen Esenci[ENTER]mil\233nia vyrobit. Zajdi za n\237m. Douf\225m, \158e n\225m[ENTER]pom\249\158e.[ENTER]Ob\232as um\237 b\253t p\236kn\236 tvrdohlav\253... "
gameforge.main_quest_lv93._300_say = "Dob\248e. "
gameforge.main_quest_lv93._310_sayTitle = "Promluv si s Octaviem! "
gameforge.main_quest_lv93._320_say = "Vyhledej Octavia. \142ije v hlavn\237 vesnici a je[ENTER]jedin\253, kdo um\237 vyrobit Esenci mil\233nia. "
gameforge.main_quest_lv93._330_say = "Zdrav\237m! Co pro tebe mohu ud\236lat? Co t\248eba[ENTER]Samgyetang? Je to m\237stn\237 specialita... "
gameforge.main_quest_lv93._340_say = "Octacio, nejsem tady kv\249li j\237dlu! Pot\248ebuji n\236co[ENTER]mnohem vz\225cn\236j\154\237ho: Esenci mil\233nia! "
gameforge.main_quest_lv93._350_say = "Uff, psst, ne tak hlasit\236! Esence mil\233nia... Ne,[ENTER]to nen\237 mo\158n\233. Jak jsi se o n\237 dozv\236d\236l? Jen p\225r[ENTER]lid\237 zvl\225dne s\237lu, kterou d\225v\225. Nechci to[ENTER]riskovat. B\236\158 pry\232, ne\158 t\236 n\236kdo usly\154\237. "
gameforge.main_quest_lv93._360_say = "Octavio, st\249j a poslouchej! Pos\237l\225 m\236[ENTER]Yon-I-Walker z Temn\233 dra\232\237 sk\225ly. Pot\248ebuje tu[ENTER]esenci okam\158it\236![ENTER]Bez n\237 nem\225me proti P\248isluhova\232\249m temnot \154anci. A[ENTER]to pak bude sv\236t, jak jej zn\225me, zni\232en. A jen ty[ENTER]m\249\158e\154 tu esenci vyrobit. Pros\237m! "
gameforge.main_quest_lv93._370_say = "\216\237k\225\154 Yon-I-Walker? Hm, to je m\249j star\253 p\248\237tel.[ENTER]Urazili jsme hrdla mnoha dobr\253m lahv\237m v\237na a[ENTER]str\225vili spoustu \232asu vypr\225v\236n\237m historek. Mus\237m[ENTER]si o tom pop\248em\253\154let. Vra\157 se r\225no a j\225 ti pak[ENTER]\248eknu, jak jsem se rozhodl. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "Je\154t\236 jsem se nerozhodl. P\248ij\239 pozd\236ji. "
gameforge.main_quest_lv93._400_npcChat = "Esence mul\233nia "
gameforge.main_quest_lv93._410_say = "Chce s tebou mluvit Octavio. "
gameforge.main_quest_lv93._420_say = "No, p\248em\253\154lel jsem o tom celou noc. Sice t\237m[ENTER]hodn\236 riskuji, ale jsem si jist, \158e ud\236l\225m[ENTER]spr\225vnou v\236c.[ENTER]Ano, pomohu ti. "
gameforge.main_quest_lv93._430_say = "V\253born\236! "
gameforge.main_quest_lv93._440_say = "Bohu\158el ale moment\225ln\236 nem\225m \158\225dn\233 p\248\237sady.[ENTER]Mysl\237\154, \158e bys je mohl pro m\236 obstarat? Vyrob\237m[ENTER]ti pak esenci. "
gameforge.main_quest_lv93._450_say = "Samoz\248ejm\236. Co pot\248ebuje\154? "
gameforge.main_quest_lv93._460_say = "Pot\248ebuji Ko\248en gango, Houby tue a Rododendron. A[ENTER]pot\248ebuji 200 kus\249 od ka\158d\233ho. "
gameforge.main_quest_lv93._470_say = "Dob\248e, hned se vyd\225m na cestu. Kde je vlastn\236[ENTER]v\154echny najdu? "
gameforge.main_quest_lv93._480_say = "Tyto rostliny nalezne\154 v r\249zn\253ch \232\225stech[ENTER]kontinentu. Zat\237mco bude\154 hledat, j\225 se budu[ENTER]v\236novat p\248\237prav\225m. "
gameforge.main_quest_lv93._490_sayTitle = "Recept "
gameforge.main_quest_lv93._500_say = "Hledej Ko\248en gango, Houby tue a Rododendron.[ENTER]Pot\248ebuje\154 200 kus\249 od ka\158d\233ho. "
gameforge.main_quest_lv93._510 = "Tyto rostliny nalezne\154 v r\249zn\253ch \232\225stech[ENTER]kontinentu. Zat\237mco bude\154 hledat, j\225 se budu[ENTER]v\236novat p\248\237prav\225m. "
gameforge.main_quest_lv93._520_say = "Ach, jsi zp\236t, v\253born\236. A m\225\154 v\154e, co pot\248ebuji.[ENTER]Tak to se mohu d\225t hned do d\237la! Ale nesm\237m b\253t[ENTER]b\236hem t\233to doby vyru\154ov\225n. Vra\157 se z\237tra touhle[ENTER]dobou. To by u\158 esence mohla b\253t hotova. "
gameforge.main_quest_lv93._530_say = "Ch\225pu. Vr\225t\237m se z\237tra. "
gameforge.main_quest_lv93._540_say = "Celkem ch\225pu, \158e ji pot\248ebuje\154 rychle, ale bude\154[ENTER]muset je\154t\236 chvilku po\232kat. Vra\157 se pros\237m[ENTER]pozd\236ji. "
gameforge.main_quest_lv93._550_say = "Hled\225 t\236 Octavio. "
gameforge.main_quest_lv93._560_say = "\193, p\248ich\225z\237\154 pr\225v\236 v\232as: Esence mil\233nia je[ENTER]p\248ipravena k pou\158it\237! M\249\158e\154 ji nyn\237 don\233st[ENTER]Yon-I-Walkerovi. "
gameforge.main_quest_lv93._570_say = "D\236kuji! "
gameforge.main_quest_lv93._580_sendLetter = "Esence mil\233nia "
gameforge.main_quest_lv93._590_say = "Hled\225 t\236 Yon-I-Walker. "
gameforge.main_quest_lv93._600_say = "Ty m\225\154 Esenci mil\233nia! Tak to m\225m v\154e pro m\249j[ENTER]n\225poj pohromad\236! Jakmile bude hotov, tak t\236[ENTER]zavol\225m. "
gameforge.main_quest_lv93._610_say = "Dob\248e. "
gameforge.main_quest_lv93._620_say = "Dobrodru\158stv\237 bude pokra\232ovat jakmile dos\225hne\154[ENTER]\250rovn\236 94. "
gameforge.main_quest_lv93._630_say = "%s: %d kus\249, %s: %d kus\249,[ENTER]%s: %d kus\249 "
gameforge.main_quest_lv93._640_say = "Star\225m se z\225jezdn\237 hostinec - nem\225m v\154echen \232as[ENTER]na sv\236t\236. P\248ines mi v\154echny chyb\236j\237c\237 p\248\237sady a[ENTER]posp\236\154 si pros\237m. "
gameforge.main_quest_lv93._650_1_notice = "Na\154el jsi v\154echny pot\248ebn\233 p\248\237sady do Esence[ENTER]mil\233nia. "
