gameforge.main_quest_lv94._030_say = "M\225m to. Povedlo se mi zkombinovat ty nejlep\154\237[ENTER]zn\225m\233 esence mezi sebou. A tohle ti d\225m:[ENTER]Leviatansk\233 perly! "
gameforge.main_quest_lv94._040_say = "D\236kuji! "
gameforge.main_quest_lv94._050_say = "Pokud si vezme\154 tyto kapsle, nemus\237\154 c\237tit \158\225dnou[ENTER]zm\236nu. Ale dob\248e tr\233novan\233 oko, jako je to moje[ENTER]nebo Angmurovo, to pozn\225. Angmur si chce s tebou[ENTER]promluvit. Zajdi za n\237m. "
