gameforge.main_quest_lv94._090_say = "Admir\225l Angmur m\225 pro tebe nov\233 zpr\225vy. "
gameforge.main_quest_lv94._1000_say = "Budu pot\248ebovat trochu \232asu, abych mohl prov\233st[ENTER]anal\253zu t\236chto vzork\249. Vra\157 se z\237tra a j\225 douf\225m,[ENTER]\158e ti budu moci \248\237ci n\236jak\233 v\253sledky. "
gameforge.main_quest_lv94._100_say = "Ach, Leviatansk\233 perly ji\158 ukazuj\237 sv\249j \250\232inek:[ENTER]kr\225sn\236 kolem tebe vid\237m auru s\237ly. M\237 zv\236di maj\237[ENTER]p\248edstavu, kde by se mohlo nach\225zet velitelstv\237[ENTER]P\248isluhova\232\249 temnot. Ov\154em je dob\248e str\225\158eno.[ENTER]Mohl by ses tam pod\237vat? "
gameforge.main_quest_lv94._1010_say = "Nahl\225s\237m m\225 zji\154t\236n\237 Angmurovi. Bude pak s tebou[ENTER]v kontaktu. "
gameforge.main_quest_lv94._1020_say = "Admir\225l Angmur m\225 informace o \200ern\233m zlatu. Zajdi[ENTER]za n\237m. "
gameforge.main_quest_lv94._1030_say = "Ano, tady jsi. Anal\253za \200ern\233ho zlata ale je\154t\236[ENTER]nen\237 dokon\232ena. Douf\225m, \158e ti budu moci brzy \248\237ci[ENTER]v\237ce. Na, tohle si vezmi jako odm\236nu za tv\233[ENTER]\250sil\237. "
gameforge.main_quest_lv94._1040_say = "Nem\249\158eme ji\158 ztr\225cet \158\225dn\253 \232as. Rychle, p\248ines mi[ENTER]vzorky \200ern\233ho zlata! "
gameforge.main_quest_lv94._1050_say = "Dobrodru\158stv\237 bude pokra\232ovat, jakmile dos\225hne\154[ENTER]\250rovn\236 95. "
