gameforge.main_quest_lv94._290_sendLetter = "Oslaben\237 \200erven\253ch zlod\236j\249 "
gameforge.main_quest_lv94._300_say = "Hled\225 t\236 admir\225l Angmur. "
gameforge.main_quest_lv94._310_say = "P\248\237m\253 \250tok se mi moment\225ln\236 zd\225 p\248\237li\154 riskantn\237.[ENTER]Ne\158 p\248ejdeme do ofenz\237vy, mus\237me nejprve oslabit[ENTER]nep\248\225telsk\233 jednotky. "
gameforge.main_quest_lv94._320_say = "V Bou\248n\253ch hor\225ch \158ij\237 n\225sleduj\237c\237 skupiny:[ENTER]Giganti, Kyklopov\233 a \200erven\237 zlod\236ji. Nejprve[ENTER]za\250to\232\237me na \200erven\233 zlod\236je! "
gameforge.main_quest_lv94._330_say = "Jakou slabinu maj\237 \200erven\237 zlod\236ji? "
gameforge.main_quest_lv94._340_say = "Rud\253 \154\233f v\158dy nos\237 speci\225ln\237 k\225pi, symbol s\237ly a[ENTER]nedotknutelnosti. Odeber mu jeho k\225pi - to \250pln\236[ENTER]zni\232\237 motivaci \200erven\253ch zlod\236j\249! "
