gameforge.main_quest_lv94._380_say = "Pora\158 Rud\233ho \154\233fa a seber mu k\225pi. "
gameforge.main_quest_lv94._390_say = "... nepovedlo se? Tak tomu nemohu v\236\248it. Mus\237\154 se[ENTER]s n\237m utkat znovu. Jsem si jist, \158e ho tentokr\225t[ENTER]poraz\237\154. "
gameforge.main_quest_lv94._400_1_notice = "Porazil jsi Rud\233ho \154\233fa. "
gameforge.main_quest_lv94._400_2_notice = "Vezmi mu jeho k\225pi a dones ji zp\236t Admir\225lovi[ENTER]Angmurovi. "
gameforge.main_quest_lv94._410_say = "Admir\225l Angmur t\236 o\232ek\225v\225. "
gameforge.main_quest_lv94._420_say = "K\225p\236! V\236d\236l jsem, \158e to dok\225\158e\154. Pov\236s\237me ji[ENTER]bl\237zko jejich t\225bora, aby ji mohli vid\236t - to by[ENTER]s nervy Gangu \200erven\253ch zlod\236j\249 m\236lo trochu[ENTER]zam\225vat.[ENTER]M\237 lid\233 se o to postaraj\237. Ty si zat\237m m\249\158e\154[ENTER]odpo\232inout. "
gameforge.main_quest_lv94._430_sendLetter = "Oslaben\237 Kyklop\249 "
gameforge.main_quest_lv94._440_say = "Admir\225l Angmur by s tebou r\225d mluvil. "
gameforge.main_quest_lv94._450_say = "N\225\154 pl\225n funguje: kdy\158 \200erven\237 zlod\236ji uvid\236li tu[ENTER]k\225pi, tak se v nich n\236co zlomilo. Skon\232ilo to[ENTER]bojem mezi lidmi a d\233mony. Nyn\237 je ten gang[ENTER]kompletn\236 rozlo\158en\253. Jako dal\154\237 n\225s \232ekaj\237[ENTER]Kyklopov\233. "
gameforge.main_quest_lv94._460_say = "Jak budeme pokra\232ovat? "
gameforge.main_quest_lv94._470_say = "Kyklopov\233 uct\237vaj\237 sv\233ho velitele. Pokud se n\225m[ENTER]poda\248\237 eliminovat jeho odd\237l, Kyklopov\233 se[ENTER]rozute\232ou v panice a strachu. Pora\158 Gener\225la[ENTER]Outise %d kr\225t, Arg\233se %d kr\225t a Polyphema %d[ENTER]kr\225t. "
gameforge.main_quest_lv94._480_say = "Bude mi pot\236\154en\237m. "
gameforge.main_quest_lv94._490_say = "Bu\239 opatrn\253. "
gameforge.main_quest_lv94._500_sayTitle = "Bojuj s Kyklopy! "
gameforge.main_quest_lv94._510_say = "Pora\158 Gener\225la Outise %d kr\225t, Arg\233se %d kr\225t a[ENTER]Polyphema %d kr\225t. "
gameforge.main_quest_lv94._520 = "Nechce se mi ani v\236\248it, \158e m\225\154 s Kyklopy soucit![ENTER]Jdi! V\237m, \158e to dok\225\158e\154! "
gameforge.main_quest_lv94._530_1_notice = "Mus\237\154 porazit v\249dce Kyklop\249. "
gameforge.main_quest_lv94._530_2_notice = "Hlas se zp\236t u admir\225la Angmura "
gameforge.main_quest_lv94._540_say = "Jdi za admir\225lem Angmurem. "
gameforge.main_quest_lv94._550_say = "Zpr\225vy o tv\253ch skutc\237ch t\236 p\248edch\225zej\237! Kyklopov\233[ENTER]jsou na \250t\236ku.[ENTER]Tak\158e u\158 n\225m zb\253vaj\237 pouze Giganti. Shrom\225\158d\237m[ENTER]informace o jejich slabin\225ch a pak t\236 zavol\225m. "
gameforge.main_quest_lv94._560_sendLetter = "Oslaben\237 Gigant\249 "
gameforge.main_quest_lv94._570_say = "Vol\225 t\236 Admir\225l Angmur. "
gameforge.main_quest_lv94._580_say = "Moji zv\236di odhalili slabinu Gigant\249. "
gameforge.main_quest_lv94._590_say = "Pov\236z mi to! "
gameforge.main_quest_lv94._600_say = "Giganti maj\237 totem, kter\233mu p\248ipisuj\237 velkou[ENTER]du\154evn\237 hodnotu. Pokud jim ho sebereme, tak dojde[ENTER]k oslaben\237 jejich odhodl\225n\237. "
gameforge.main_quest_lv94._610_say = "Kde ten totem najdu? "
