gameforge.main_quest_lv94._630_say = "Rozum\237m. "
gameforge.main_quest_lv94._640_sayTitle = "Totem gigant\249 "
gameforge.main_quest_lv94._650_say = "Z\237skej v\154echny kusy totemu. "
gameforge.main_quest_lv94._660_say = "Giganti jsou velmi siln\237 protivn\237ci. Ale ty je[ENTER]mus\237\154 porazit a p\248in\233st mi ten totem! "
gameforge.main_quest_lv94._670_say_1_notice = "Z\237skal jsi v\154echny \232\225sti totemu. "
gameforge.main_quest_lv94._670_say_2_notice = "Vra\157 se Admir\225lovi Angmurovi. "
gameforge.main_quest_lv94._680_say = "\193, u\158 jsem za\232\237nal m\237t obavy. Ale ty jsi to[ENTER]opravdu dok\225zal. Nyn\237 m\225me totem, kter\253 uct\237vali[ENTER]Giganti. Tv\225 odm\236na za tento \232in bude velk\225. "
gameforge.main_quest_lv94._690_sendLetter = "Do Bou\248n\253ch hor "
