gameforge.main_quest_lv94._710_say = "M\237 zv\236di zahl\233dli Kyklopy, kte\248\237 n\236co sebrali v[ENTER]Bou\248n\253ch hor\225ch a odnesli to pry\232. "
gameforge.main_quest_lv94._720_say = "Zjisti, co Kyklopov\233 na\154li. Ob\225v\225m se, \158e to[ENTER]nebude nic dobr\233ho... A pochybuji, \158e by se toho[ENTER]vzdali bez boje. "
gameforge.main_quest_lv94._730_say = "Rozum\237m. "
gameforge.main_quest_lv94._740_sayTitle = "Co pl\225nuj\237 Kyklopov\233? "
gameforge.main_quest_lv94._750_say = "Zjisti, co Kyklopov\233 hledali v Bou\248n\253ch hor\225ch. "
gameforge.main_quest_lv94._760_say = "Zjisti, co maj\237 Kyklopov\233 za lubem. Ur\232it\236 to[ENTER]nebude nic dobr\233ho... Pochybuji, \158e se sv\233ho[ENTER]tajemstv\237 vzdaj\237 bez boje. "
gameforge.main_quest_lv94._770_1_notice = "Dr\158\237\154 v ruce bl\253skav\253 \232ern\253 k\225men a tak\233 Kus[ENTER]pap\237ru. "
gameforge.main_quest_lv94._770_2_notice = "Uka\158 sv\233 n\225lezy Admir\225lovi Angmurovi. "
gameforge.main_quest_lv94._780_say = "Jdi za Admir\225lem Angmurem. "
gameforge.main_quest_lv94._790_say = "Zjistil jsi, co d\236lali Kyklopov\233 v Bou\248n\253ch[ENTER]hor\225ch? "
gameforge.main_quest_lv94._800_say = "Kyklop\249m se zrovna dvakr\225t necht\236lo moc mluvit,[ENTER]ale nakonec se mi je povedlo p\248esv\236d\232it, aby mi[ENTER]dali tohle: \232ern\253 k\225men a tenhle kousek pap\237ru. "
gameforge.main_quest_lv94._810_say = "Lokalizovali jsme v Bou\248n\253ch hor\225ch \158\237ly \200ern\233ho[ENTER]zlata a te\239 jej t\236\158\237me, jak jsi po\158adoval. Na[ENTER]p\248ed\225vku se sejdeme jak bylo pl\225nov\225no v Bou\248n\253ch[ENTER]hor\225ch. "
gameforge.main_quest_lv94._820_say = "\200ern\233 zlato... To je ruda, kter\225 v Bou\248n\253ch[ENTER]hor\225ch opravdu existuje. Pro\232 ji ale P\248isluhova\232i[ENTER]temnot pot\248ebuj\237? "
gameforge.main_quest_lv94._830_say = "Mus\237me zjistit, co maj\237 v pl\225nu. "
gameforge.main_quest_lv94._840_say = "Tady se to p\237\154e: "
gameforge.main_quest_lv94._850_sendLetter = "\200ern\233 zlato "
gameforge.main_quest_lv94._860_say = "Admir\225l Angmur by si s tebou r\225d promluvil o[ENTER]\200ern\233m zlatu. "
gameforge.main_quest_lv94._870_say = "Alchymist\249m se nepovedlo \200ern\233 zlato zanalyzovat.[ENTER]Vzorek je p\248\237li\154 mal\253. Mus\237me zjistit, jak\233[ENTER]vlastnosti m\225 a pro\232 jej P\248isluhova\232i temnot[ENTER]hledaj\237. Mohl by ses vr\225tit do Bou\248n\253ch hor a[ENTER]p\248in\233st n\225m v\237ce vzork\249 \200ern\233ho zlata? "
gameforge.main_quest_lv94._880_say = "Nejprve se vydej k alchymistovi. \216ekne ti, kolik[ENTER]vzork\249 pot\248ebuje. "
gameforge.main_quest_lv94._890_say = "Promluv si s alchymistou. "
gameforge.main_quest_lv94._900_say = "Zdrav\237m. U\158 ti Admir\225l Angmur vysv\236tlit tv\249j \250kol? "
gameforge.main_quest_lv94._910_say = "Ano. Kolik vzork\249 \200ern\233ho zlata pot\248ebuje\154? "
gameforge.main_quest_lv94._920_say = "Hmm, nech m\236 o tom chvilku p\248em\253\154let. Mysl\237m, \158e[ENTER]%d vzork\249 by mohlo b\253t pro anal\253zu dostate\232n\253ch. "
gameforge.main_quest_lv94._930_say = "Rozum\237m. "
gameforge.main_quest_lv94._940_sayTitle = "Zlato Bou\248n\253ch hor. "
gameforge.main_quest_lv94._950_sayTitle = "Zajdi za alchymistou. "
gameforge.main_quest_lv94._960_say = "Hledej vzorky \200ern\233ho zlata v Bou\248n\253ch hor\225ch. "
gameforge.main_quest_lv94._970_1_notice = "Objevil jsi \158\237lu \200ern\233ho zlata a povedlo se ti[ENTER]z\237skat vzorek rudy. "
gameforge.main_quest_lv94._970_2_notice = "Dones ji alchymistovi. "
gameforge.main_quest_lv94._980_say = "Ach, ty jsi na\154el \200ern\233 zlato. Uka\158! Hm, \158\225dn\233[ENTER]trhliny a vzorek je dostate\232n\236 velik\253... ano,[ENTER]tohle mohu pro anal\253zu pou\158\237t. Ale pot\248ebuji[ENTER]je\154t\236 %d dal\154\237ch. "
gameforge.main_quest_lv94._990_say = "S t\237mhle vzorkem nemohu nic d\236lat. Je pro anal\253zu[ENTER]p\248\237li\154 mal\253. P\248ines mi jin\253! "
