gameforge.main_quest_lv95._020_say = "Hled\225 t\236 Admir\225l Angmur. M\225 nov\233 informace o[ENTER]\200ern\233m zlat\236. "
gameforge.main_quest_lv95._030_say = "\200ern\233 zlato vytahuje energii z tvor\249 v jeho[ENTER]bl\237zkosti a p\248ed\225v\225 ji jin\233 osob\236. P\248isluhova\232i[ENTER]temnot toho cht\236j\237 vyu\158\237t a napumpovat ukradenou[ENTER]energii do Sung Mahi! Gigantsk\253 Kapit\225n H\225k m\225[ENTER]velk\233 z\225soby \200ern\233ho zlata v Bou\248n\253ch hor\225ch.[ENTER]Z\237skej je! "
