gameforge.main_quest_lv95._150_say = "Mus\237me tu z\225silku zastavit! Mysl\237me si, \158e skr\253\154[ENTER]Smrtky je z\225padn\236 od \218tesu Gautama - bezbo\158n\233[ENTER]m\237sto, neust\225le pokryt\233 mlhou. \142ij\237 tam zlob\248i a[ENTER]Lemu\248i. "
