gameforge.main_quest_lv96._340_say = "S t\237m nem\225m probl\233m. "
gameforge.main_quest_lv96._350_sayTitle = "Hled\225n\237 zlata "
gameforge.main_quest_lv96._360_say = "Vydej se k zlobr\249m, zab\237jej je a sb\237rej jejich[ENTER]Pytle s pen\236zi. Ale ne v\154echny pen\237ze jsou m\233dium[ENTER]- nech je zkontrolovat Yon-I-Walkerem. "
gameforge.main_quest_lv96._370_say = "Ano, zde c\237t\237m magickou s\237lu. "
gameforge.main_quest_lv96._380_say = "Skv\236l\233, nyn\237 m\225me dostatek zlata, kter\233 lze[ENTER]vyu\158\237t jako m\233dium. To asi moc Smrtku nepot\236\154\237.[ENTER]Tady, tohle je tv\225 odm\236na. Angmur ti d\225 dal\154\237[ENTER]\250kol. "
gameforge.main_quest_lv96._390_say = "Je\154t\236 n\225m po\248\225d chyb\237 n\236jak\233 zlato. P\248ines[ENTER]dal\154\237ch %d pytl\249. "
gameforge.main_quest_lv96._400_sendLetter = "Zabra\242 kouzlu "
gameforge.main_quest_lv96._410_say = "Hled\225 t\236 admir\225l Angmur. "
gameforge.main_quest_lv96._420_say = "Pot\248ebujeme se ujistit, \158e se P\248isluhova\232\249m[ENTER]temnot nepoda\248\237 z\237skat K\249ru Stromov\253ch d\233mon\249. "
gameforge.main_quest_lv96._430_say = "Stromov\237 d\233moni jsou jedn\237m z nejtajemn\236j\154\237ch[ENTER]druh\249 na\154eho sv\236ta a neslou\158\237 \158\225dn\233 osob\236,[ENTER]dokonce ani Sung Mahi.[ENTER]Na \218tesu Guatama existuj\237 t\248i druhy: Aku-Boku,[ENTER]Arboretum a Sycomore. Sed\248i z nich k\249ru! "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "Rozum\237m. "
gameforge.main_quest_lv96._460_sayTitle = "Por\225\158en\237 Stromov\253ch d\233mon\249 "
gameforge.main_quest_lv96._470_say = "Oloupej k\249ru z Aku-Boku, Arboreta a Sycomora. "
gameforge.main_quest_lv96._480_counterName = "(Zb\253v\225 %s : %s, %s : %s) "
gameforge.main_quest_lv96._490_say = {}
gameforge.main_quest_lv96._500_say = "Tla\232\237 n\225s \232as. Pora\158 Stromov\233 d\233mony a z\237skej[ENTER]jejich k\249ru, ne\158 se to poda\248\237 P\248isluhova\232\249m! "
gameforge.main_quest_lv96._510_1_notice = "Porazil jsi v\154echny Stromov\233 d\233mony, ale n\236kdo se[ENTER]tam dostal je\154t\236 p\248ed tebou: z kmen\249 ji\158 byla[ENTER]oloup\225na k\249ra. "
gameforge.main_quest_lv96._510_2_notice = "Dones tyto novinky Admir\225lovi Angmurovi. "
gameforge.main_quest_lv96._520_say = "Hlas se zp\236t u admir\225la Angmura "
gameforge.main_quest_lv96._530_say = "R\225d t\236 vid\237m nezran\236n\233ho! Byl jsi \250sp\236\154n\253? Co\158e?[ENTER]K\249ra byla ze Stromov\253ch d\233mon\249 oloup\225na a v\154ude[ENTER]byly stopy bitvy? Tak\158e P\248isluhova\232i temnost se[ENTER]tam dostali p\248ed n\225mi. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "Pokud maj\237 k\249ru, tak si ur\232it\236 najdou cestu, jak[ENTER]prov\233st Kouzlo \158ivota. Zd\225 se, \158e nen\237 jin\225 cesta[ENTER]- mus\237me se vydat do v\225lky. Smrtka se p\248ed n\225mi[ENTER]ale dlouho schov\225vat nebude. M\237 mu\158i jsou j\237 ji\158[ENTER]na stop\236. Zavol\225m t\236, jakmile ji najdeme. "
gameforge.main_quest_lv96._560_sayTitle = "Dobrodru\158stv\237 bude pokra\232ovat, jakmile dos\225hne\154[ENTER]\250rovn\236 97. "
gameforge.main_quest_lv96._570_counterName = "(Zb\253v\225 %s : %s, %s : %s) "
gameforge.main_quest_lv96._580_sayReward = "%s: %d kus\249 "
gameforge.main_quest_lv96._590_say = "Tak\158e zlat\233 mince slou\158\237 jako m\233dium. Dob\248e,[ENTER]porad\237m se s Yon-I-Walkerem, jak\233 by m\236ly b\253t[ENTER]na\154e dal\154\237 kroky. Brzy se ti ozvu. "
gameforge.main_quest_lv96._600_say = {}
gameforge.main_quest_lv96._610_say = {}
gameforge.main_quest_lv96._620_1_notice = "Z\237skal jsi Pytel pen\236z. "
gameforge.main_quest_lv96._620_2_notice = "Dones jej Yon-I-Walkerovi. "
gameforge.main_quest_lv96._630_say = "To jsou jen norm\225ln\237 mince, \158\225dn\233 m\233dium. Hledej[ENTER]d\225l! "
gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "Zastav Smrtku "
gameforge.main_quest_lv97._020_say = "M\237sto, kde se Smrtka skr\253v\225, bylo objeveno! Zajdi[ENTER]za Admir\225lem Angmurem, kter\253 ti sd\236l\237 v\237ce. "
gameforge.main_quest_lv97._030_say = "M\237 mu\158i kone\232n\236 objevili t\225bor Smrtky - na \250tesu[ENTER]Gautama. Skr\253v\225 se v temnot\236 hlubok\233ho lesa a[ENTER]odtud provozuje svou \232ernou magii. Nav\237c se j\237[ENTER]povedlo o\158ivit jednu z b\253val\253ch p\248isluhova\232ek[ENTER]Dra\232\237ho kultu. Spolu se te\239 pokou\154\237 vyvolat[ENTER]Kouzlo \158ivota. "
gameforge.main_quest_lv97._040_say = "Bez pomoci p\248isluhova\232ky by Smrtka nebyla schopna[ENTER]kouzlo ovl\225dat. Pora\158 P\248isluhova\232ku temnot Mu-Shu[ENTER]a uti\154 tak du\154e sv\253ch kamar\225d\249, ne\158 budou jejich[ENTER]t\236la povol\225na k boji proti n\225m. "
gameforge.main_quest_lv97._050_say = "Je t\233m\236\248 nemo\158n\233 se dostat pobl\237\158 t\233 slu\158ebnice[ENTER]bez pov\154imnut\237, abys na ni mohl za\250to\232it. Vyu\158ij[ENTER]proto t\233 chv\237le, kdy je tak pono\248ena do \232ern\233[ENTER]magie, \158e je t\233m\236\248 v transu. "
gameforge.main_quest_lv97._060_say = "Ch\225pu. "
gameforge.main_quest_lv97._070_say = "Bu\239 opatrn\253! Ve sv\233m p\249vodn\237m \158ivot\236 byla hlavn\237[ENTER]str\225\158kyn\237 nejvy\154\154\237 kn\236\158ky a byla v\253born\236[ENTER]vytr\233nov\225na nejen v magii, ale tak\233 v boji s[ENTER]me\232em. "
gameforge.main_quest_lv97._080_sayTitle = "Slu\158ebnice chr\225mu "
gameforge.main_quest_lv97._090_say = "Na \250tesu Guatama poraz Mu-Shu, slu\158ebnici chr\225mu,[ENTER]kter\225 pom\225h\225 Smrtce. "
gameforge.main_quest_lv97._100_notice = "S \250d\236sn\253m v\253k\248ikem se chr\225mov\225 slu\158ebnice po[ENTER]smrteln\233 r\225n\236 pomalu k\225c\237 k zemi. "
gameforge.main_quest_lv97._110_say = "Ty bl\225zne! Jen jsi sko\232il na n\225vnadu, kterou ti[ENTER]Smrtka p\248ipravila. Zat\237mco jsi se mnou ztr\225cel[ENTER]\232as, tak s Yah-Ki, skute\232nou slu\158ebnic\237 chr\225mu,[ENTER]za\232aly vyvol\225vat Kouzlo \158ivota. Modl\237m se za[ENTER]jejich \250sp\236ch! "
gameforge.main_quest_lv97._120_say = "Ta dvojnice t\236 naprosto zm\225tla! Po t\233, co jsi[ENTER]prohledal jej\237 t\236lo, na\154el jsi n\225hrdeln\237k podobn\253[ENTER]tomu, jak\253 m\236l u sebe Martyaxwar. A v n\225prsn\237[ENTER]kapse m\236la dokument. "
gameforge.main_quest_lv97._130_say = "Hlas se zp\236t u admir\225la Angmura "
gameforge.main_quest_lv97._140_say = "Jsi zp\236t! Porazil jsi slu\158ebnici chr\225mu? "
gameforge.main_quest_lv97._150_say = "Ne, byli jsme oklam\225ni dvojn\237kem. Skute\232n\233[ENTER]slu\158ebnice chr\225mu se poda\248ilo v klidu p\248ipravit[ENTER]vyvol\225v\225n\237 smrti. Tady, na\154el jsem tento[ENTER]dokument. "
gameforge.main_quest_lv97._160_say = "\200\225ry! Jak jsme jen na to mohli sko\232it? Pros\237m,[ENTER]uka\158 mi ten dokument. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hm, za\154ifrovan\233. Ale mo\158n\225 n\225m tahle zpr\225va[ENTER]odhal\237, kde se opravdu skr\253v\225 t\225bor. U\158 jsem[ENTER]kdysi takov\233to znaky vid\236l... Mysl\237m, \158e to byl[ENTER]Yak-Hwan, pal\225cov\253 str\225\158n\253, kter\253 mi je ned\225vno[ENTER]ukazoval. Zajdi za n\237m. M\236l by se na to pod\237vat. "
gameforge.main_quest_lv97._200_sendLetter = "Roz\154ifruj dokument. "
gameforge.main_quest_lv97._210_say = "Zajdi za Yak-Hwanem a uka\158 mu za\154ifrovan\253[ENTER]dokument. "
gameforge.main_quest_lv97._220_say = "Zdrav\237m! M\233 jm\233no je Yak-Hwan. Je pro mne \232est se[ENTER]s tebou setkat. Tv\233 \232iny jsou ji\158 legend\225rn\237! Co[ENTER]pro tebe mohu ud\236lat? Ach, za\154ifrovan\225 zpr\225va.[ENTER]Uka\158, pod\237v\225m se. "
gameforge.main_quest_lv97._230_say = "Ano, tyhle znaky bych m\236l rozlu\154tit bez probl\233m\249.[ENTER]Ale budu na to pot\248ebovat Fosiln\237 hl\237nu.[ENTER]Alchymista by m\236l pravd\236podobn\236 n\236jakou m\237t.[ENTER]Zajdi za n\237m a zeptej se ho. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Samoz\248ejm\236. "
gameforge.main_quest_lv97._270_sayTitle = "Fosiln\237 hl\237na "
gameforge.main_quest_lv97._280_say = "Zajdi za alchymistou a zeptej se ho na Fosiln\237[ENTER]hl\237nu. "
gameforge.main_quest_lv97._290_say = "Nezapomn\236l jsi na n\236co? M\225\154 mi don\233st Fosiln\237[ENTER]hl\237nu. "
gameforge.main_quest_lv97._300_notice = "Alchymista ti dal Fosiln\237 hl\237nu. Nyn\237 se vra\157 k[ENTER]Yak-Hwanovi. "
gameforge.main_quest_lv97._310_say = "Ach, Fosiln\237 hl\237na. Velmi dob\248e, m\236l bych se d\225t[ENTER]do pr\225ce. Co zjist\237m nahl\225s\237m admir\225lovi[ENTER]Angmurovi. "
gameforge.main_quest_lv97._320_sendLetter = "Skrze zadn\237 vr\225tka "
gameforge.main_quest_lv97._330_say = "Hled\225 t\236 admir\225l Angmur. "
gameforge.main_quest_lv97._340_say = "Nyn\237 v\237me, kde se nach\225z\237 slu\158ebnice chr\225mu[ENTER]Yah-Ki. Ale ta z\225kladna je \250pln\225 pevnost - v\154ude[ENTER]kolem se nach\225z\237 str\225\158e. P\248\237m\253 \250tok je \232ist\225[ENTER]sebevra\158da. "
gameforge.main_quest_lv97._350_say = "Z toho d\249vodu chceme p\248ipravit l\233\232ku. M\237 mu\158i[ENTER]hledaj\237 vhodn\233 m\237sto. Trochu zabav jejich str\225\158e,[ENTER]abys n\225m poskytl n\236jak\253 \232as. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "Nejv\236t\154\237 nebezpe\232\237 p\248ich\225z\237 od str\225\158n\237ch[ENTER]jednotek, kter\233 se naz\253vaj\237 Brig\225da \232ern\233 smrti.[ENTER]Brig\225du tvo\248\237 Moghu, Carniflex a gener\225l Albus.[ENTER]Jejich v\249dce je Skeletos. Eliminuj je d\248\237v, ne\158[ENTER]odhal\237 moje jednotky. "
gameforge.main_quest_lv97._380_say = "Dob\248e. "
gameforge.main_quest_lv97._390_sayTitle = "Brig\225da \232ern\233 smrti "
gameforge.main_quest_lv97._400_say = "Eliminuj Brig\225du \232ern\233 smrti, jej\237mi\158 \232leny jsou[ENTER]Moghu, Carnifex, gener\225l Albus a Skeletos. "
gameforge.main_quest_lv97._410_say = "Zabij \232leny Brig\225dy \232ern\233 smrti d\248\237ve, ne\158 odhal\237[ENTER]pr\249zkumn\233 jednotky. "
gameforge.main_quest_lv97._420_say = "Hlas se zp\236t u admir\225la Angmura "
gameforge.main_quest_lv97._430_say = "N\225\154 pl\225n je p\248ipraven! Zat\237mco jsi rozptyloval[ENTER]Brig\225du \232ern\233 smrti, moji mu\158i na\154li vhodn\233 m\237sto[ENTER]pro l\233\232ku. Jakmile bude vypracov\225n \250to\232n\253 pl\225n,[ENTER]tak t\236 zavol\225m. "
gameforge.main_quest_lv97._440_sendLetter = "Slu\158ebnice chr\225mu "
gameforge.main_quest_lv97._450_say = "Admir\225l Angmur pot\248ebuje tvou pomoc! "
gameforge.main_quest_lv97._460_say = "Fajn, tady jsi. Skeletos, velitel Brig\225dy \232ern\233[ENTER]smrti, p\248e\158il a za\250to\232il na m\233 mu\158e v okam\158iku,[ENTER]kdy se p\248ipravovali na \250tok na jeho z\225kladnu.[ENTER]Nikdo nep\248e\158il. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Ji\158 jsi ho jednou porazil, tak pros\237m pomoz m\253m[ENTER]lidem na \250tesu Gautama! Najdi Skeletose a zabij[ENTER]ho. Potom p\248epadni jeho z\225kladnu a zabij[ENTER]slu\158ebnici chr\225mu Yah-Ki. "
gameforge.main_quest_lv97._490_say = "Rozum\237m. "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Zabij Yah-Ki "
gameforge.main_quest_lv97._520_say = "Zabij slu\158ebnici chr\225mu Yah-Ki a t\237m ji znemo\158ni[ENTER]vyvolat arm\225du mrtv\253ch. "
gameforge.main_quest_lv97._530_say = "Rozhoduj\237c\237 den nade\154el. Pokud sel\158eme, tak n\225\154[ENTER]sv\236t bude zni\232en. Ale pokud zv\237t\236z\237me, bude se o[ENTER]na\154ich skutc\237ch vypr\225v\236t je\154t\236 stovky let. Zastav[ENTER]slu\158ebn\237ky temnoty. Zabij slu\158ku chr\225m Yah-Ki! "
gameforge.main_quest_lv97._540_say = "Pro\232 jsi tady? Bitva je\154t\236 nebyla dobojov\225na![ENTER]Zabij slu\158ebnici chr\225mu Yah-Ki! Vkl\225d\225me do tebe[ENTER]v\154echny na\154e nad\236je! "
gameforge.main_quest_lv97._550_1_notice = "Donutil jsi sv\233 protivn\237ky p\248ed tebou pokleknout[ENTER]a stal jsi se v\237t\236zem! "
gameforge.main_quest_lv97._550_2_notice = "Bohu\158el nen\237 \232as odpo\232\237vat - o\232ek\225v\225 t\236 slu\158ebnic[ENTER]chr\225mu Yah-Ki. "
gameforge.main_quest_lv97._560_notice = "Zv\237t\236zil jsi! S nelidsk\253m v\253k\248ikem, kter\253 mraz\237[ENTER]krev v \158il\225ch, se porou\232\237 Yah-Ki k zemi. "
gameforge.main_quest_lv97._570_say = "Aaaach! To nem\249\158e b\253t pravda! Pora\158ena[ENTER]smrteln\237kem... ach, Smrtko, odpus\157 mi! Selhala[ENTER]jsem. Nepovedlo se mi dokon\232it m\249j \250... "
gameforge.main_quest_lv97._580_say = "Prohledal jsi jej\237 um\237raj\237c\237 t\236lo a na\154el jsi[ENTER]zape\232et\236n\253 dopis. Dones jej admir\225lovi Angmurovi. "
gameforge.main_quest_lv97._590_say = "Ano, chvalme Dra\232\237ho boha! Jsi zp\236t a v po\248\225dku![ENTER]Porazil jsi slu\158ebnici chr\225mu? "
gameforge.main_quest_lv97._600_say = "Ano, poslal jsem ji zp\236t do pekla, odkud vylezla.[ENTER]V okam\158iku smrti prosila Smrtku, aby j\237 odpustila[ENTER]jej\237 selh\225n\237. A u sebe m\236la toto. "
gameforge.main_quest_lv97._610_say = "Zape\232et\236n\253 dopis! Uka\158 mi ho! "
gameforge.main_quest_lv97._620_sayReward = "M\225 pan\237, spolkli na\154i n\225vnadu a V\225\154 pl\225n[ENTER]fungoval. Vyvol\225n\237 va\154\237 arm\225dy mrtv\253ch \250sp\236\154n\236[ENTER]pokra\232uje a nyn\237 n\225s ji\158 nikdo nem\249\158e zastavit.[ENTER]Jakmile se bezduch\225 t\236la vydaj\237 na pochod,[ENTER]za\250to\232\237me na mys Dra\232\237ho ohn\236 a poh\248b\237me celou[ENTER]jeho populaci. Pot\233 zam\237\248\237me do Ohniv\233 zem\236, kde[ENTER]se s V\225mi spoj\237me. Sv\236t bude ho\248et pod nohami[ENTER]na\154\237 arm\225dy![ENTER]Hluboce se V\225m klan\237m, Va\154e v\236\232n\225 slu\158ebnice "
gameforge.main_quest_lv97._630_say = "Zpr\225va pro Smrtku! Ta proklet\225 \232arod\236jnice \232ek\225 v[ENTER]hloubi Ohniv\233 zem\236 se svou arm\225dou Temnoty.[ENTER]D\236kuji ti. Bez tv\233 pomoci by mys Dra\232\237ho ohn\236 a[ENTER]jeho obyvatel\233 byli zni\232eni arm\225dou mrtv\253ch.[ENTER]Nejenom \158e jsi zachr\225nil n\225s, ale tak\233 jsi dal[ENTER]klid du\154\237m na\154ich p\248edk\249. Pros\237m, p\248ijmi toto[ENTER]jako odm\236nu za tv\233 skutky. "
gameforge.main_quest_lv97._640_sayTitle = "Dobrodru\158stv\237 bude pokra\232ovat, jakmile dos\225hne\154[ENTER]\250rovn\236 98. "
gameforge.main_quest_lv97._650_say = "Pro nalezen\237 z\225kladny pot\248ebujeme spoustu \232asu.[ENTER]Tak ji\158 pros\237m \158\225dn\253 neztr\225cej! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan pot\248ebuje Fosiln\237 hl\237nu? To m\225 \154t\236st\237,[ENTER]\158e jsem je\154t\236 v\154echnu nespot\248eboval. Tady, a[ENTER]ned\236kuj.[ENTER]Dones mu ji a vy\248i\239 mu m\233 pozdravy. "
gameforge.main_quest_lv97._670_counterName = "(Zb\253v\225 %s : %s, %s : %s) "
gameforge.main_quest_lv97._680_sayReward = {}
gameforge.main_quest_lv97._690_1_notice = "Mus\237\154 eliminovat Brig\225du \232ern\233 smrti. "
gameforge.main_quest_lv97._690_2_notice = "Hlas se u admir\225la Angmura. "
gameforge.main_quest_lv97._700_sayTitle = "Zabij Skeletose, velitele Brig\225dy \232ern\233 smrti! "
gameforge.main_quest_lv97._710_say = "Slu\158ebnice chr\225mu m\249\158e b\253t pora\158ena pouze tehdy,[ENTER]pokud p\248edt\237m zabije\154 Skeletose. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Rekonstrukce pevnosti "
gameforge.main_quest_lv98._020_say = "Admir\225l Angmur pot\248ebuje tvou pomoc. Zajdi za n\237m. "
gameforge.main_quest_lv98._030_say = "D\237ky, \158e jsi p\248i\154el: Ten boj na n\225s zanechal[ENTER]stopy. Pevnost byla tak\233 napadena a na mnoha[ENTER]m\237stech byly str\158eny hradby. A m\237r asi nebude[ENTER]trvat dlouho. Mus\237me ten \232as vyu\158\237t a pevnost[ENTER]obnovit. "
gameforge.main_quest_lv98._040_say = "Abychom mohli obnovit hradby, pot\248ebujeme brn\236n\237[ENTER]kmene Crustacean\249. "
gameforge.main_quest_lv98._050_say = "Rozum\237m. Kolik je t\236ch brn\236n\237 pot\248eba? "
gameforge.main_quest_lv98._060_say = "100 by jich m\236lo sta\232it. Na kmen Crustacean\249[ENTER]m\249\158e\154 za\250to\232it v Nefritov\233m z\225livu. "
gameforge.main_quest_lv98._070_say = "Hm, t\236ch Crustace\225nsk\253ch brn\236n\237 ale nen\237[ENTER]dostatek. P\248ines je\154t\236 n\236jak\225 dal\154\237. "
gameforge.main_quest_lv98._080_1_notice = "Nasb\237ral jsi dostatek Crustace\225nsk\253ch brn\236n\237 . "
gameforge.main_quest_lv98._080_2_notice = "Dones je admir\225lovi Angmurovi. "
gameforge.main_quest_lv98._090_say = "Ano, velmi dob\248e. Crustace\225nsk\233 brn\236n\237 n\225m pom\249\158e[ENTER]zes\237lit na\154e hradby. Pros\237m, vezmi si toto jako[ENTER]odm\236nu. Zept\225m se m\253ch stavitel\249, zda pot\248ebuj\237[ENTER]je\154t\236 n\236jak\253 materi\225l a d\225m ti v\236d\236t. "
