gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ach, to jsi ty![ENTER]Nevid\236li jsme se dlouhou dobu.[ENTER]Dal\154\237 rok pr\225v\236 pro\154el, ho ho![ENTER]Mo\158n\225 se s\225m sebe pt\225\154, pro\232 jsem zp\236t ve vesnici.Nech m\236 ti to vysv\236tlit... "
gameforge.new_christmas._030_say = "\200asy jsou t\236\158k\233. Nikdo si v t\236chto dnech nechce[ENTER]kupovat knihy a podobn\233 v\236ci. A d\237ky m\233mu[ENTER]pokro\232il\233mu v\236ku je \232\237m d\225l v\237ce t\236\158\154\237 l\233tat s[ENTER]m\253mi san\236mi, ta\158en\253mi soby. Proto jsem se[ENTER]rozhodl, \158e leto\154n\237 V\225noce se budou slavit ve[ENTER]vesnici. "
gameforge.new_christmas._040_say = "Pokud bude\154 m\237t dal\154\237 ot\225zky, m\249\158e\154 se vr\225tit a[ENTER]zeptat se m\236. Vesel\233 V\225noce. "
gameforge.new_christmas._050_npcChat = "Nedal by sis sva\248\225k? "
gameforge.new_christmas._060_say = "Ho ho ho! Jsem si jist, \158e v\237\154, co to je, \158e?[ENTER]Neexistuje lep\154\237 pit\237 pro zimn\237 dny, jako je[ENTER]tento. Vezme\154 \232erven\233 v\237no, p\248id\225\154 sko\248ici a[ENTER]h\248eb\237\232ek a sva\248\237\154 to v\154e dohromady.... mmmmmm! "
gameforge.new_christmas._070_say = "V tomto studen\233m po\232as\237 dok\225\158e sklenka sva\248\225ku[ENTER]ud\236lat prav\233 z\225zraky! Dod\225 ti s\237lu a pom\249\158e ti k[ENTER]rychlej\154\237m pohyb\249m. Chce\154 to zkusit? Ano? Prima,[ENTER]tady je! "
gameforge.new_christmas._080_say = "Zd\225 se, \158e ti ten sva\248\225k chutn\225, ho ho ho![ENTER]C\237t\237\154, jak se ti uvnit\248 rozl\233v\225 teplo?[ENTER]A ta chu\157, tak sladk\225 a ovocn\225![ENTER]Vesel\233 V\225noce! "
gameforge.new_christmas._090_npcChat = "Dal\154\237 sva\248\225k pros\237m! "
