gameforge.new_christmas._110_say = "Nen\237 za\232! Musel jsi \232ekat dost dlouho.[ENTER]Tento skv\236l\253 n\225poj ti d\225 k\248\237dla, ho ho ho![ENTER]Douf\225m, \158e ti bude chutnat.[ENTER]Vesel\233 V\225noce! "
