gameforge.new_quest_lv17._130_say = "Aha, tak to je to, o co se te\239 pokou\154\237. "
gameforge.new_quest_lv17._131_say = "Od koho je ta k\249\158e? Je od Wonda-Rim, ale to jsi[ENTER]pro n\236ho zab\237jel vlky? Moc se mi nel\237b\237, \158e m\225m[ENTER]synovce, kter\253 nut\237 ostatn\237 d\236lat za n\236j jeho[ENTER]pr\225ci. Omlouv\225m se, ale j\225 to nemohu p\248ijmout, i[ENTER]kdy\158 jsem si jist, \158e t\236 to st\225lo spoustu \250sil\237 a[ENTER]\232asu. "
gameforge.new_quest_lv17._132_say_reward = "\216ekni Wonda-Rimovi, \158e jsem ho prohl\233dl. Pokud by[ENTER]mi opravdu cht\236l n\236co dok\225zat, tak m\236l j\237t ty[ENTER]vlky lovit s\225m! "
gameforge.new_quest_lv17._140_say = "Chaegirab nep\248ijal k\249\158i a nav\237c je je\154t\236 na\154tvan\253[ENTER]na Wonda-Rimovui lenost. Poslal t\236 zp\236t za[ENTER]Wonda-Rimem. "
gameforge.new_quest_lv17._141_say = "Co str\253\232ek \248\237kal? Douf\225m, \158e se mu d\225rek l\237bil. "
gameforge.new_quest_lv17._142_1_select = "Ano, byl u vytr\158en\237. "
gameforge.new_quest_lv17._142_2_select = "Ne, moc ne. "
gameforge.new_quest_lv17._143_say = "Skv\236l\233! R\225d n\236co dokazuji jin\253m lidem. A[ENTER]samoz\248ejm\236, \158e i tob\236 d\225m odm\236nu. Na, tady m\225\154. "
gameforge.new_quest_lv17._144_say_reward_a = "Obdr\158\237\154 20 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 20 000 Yang\249.[ENTER]Obdr\158\237\154 hroudu zlata. "
gameforge.new_quest_lv17._144_say_reward_b = "Lhal jsi Wonda-Rimovi a p\248i\154el jsi tak o body[ENTER]hodnosti. "
gameforge.new_quest_lv17._145_say = "On tu k\249\158i nep\248ijal? Mo\158n\225 to nebyl tak dobr\253[ENTER]n\225pad poslat s tou k\249\158i tebe, m\237sto abych j\237[ENTER]donesl s\225m. P\248\237\154t\236 to ud\236l\225m jinak. "
gameforge.new_quest_lv17._146_say_reward = "Ale nechci, aby tv\225 n\225maha p\248i\154la na zmar. Jdi za[ENTER]Yang-Shinem, on od tebe tu k\249\158i koup\237 za dobrou[ENTER]cenu. "
gameforge.new_quest_lv17._147_say = "Jak\253 ne\232ekan\253 zvrat ud\225lost\237. No, alespo\242 m\225\154[ENTER]po\248\225d tu k\249\158i. Jdi za lovcem Yang-Shinem a prodej[ENTER]mu tu k\249\158i. "
gameforge.new_quest_lv17._148_say = "Jak\253 ne\232ekan\253 zvrat ud\225lost\237. No, alespo\242 m\225\154[ENTER]po\248\225d tu k\249\158i. Jdi za lovcem Yang-Shinem a prodej[ENTER]mu tu k\249\158i. "
gameforge.new_quest_lv17._149_say = "Jak\253 ne\232ekan\253 zvrat ud\225lost\237. No, alespo\242 m\225\154[ENTER]po\248\225d tu k\249\158i. Jdi za lovcem Yang-Shinem a prodej[ENTER]mu tu k\249\158i. "
gameforge.new_quest_lv17._151_say = "K\249\158e vlka Mu-Rang? No ta se samoz\248ejm\236 hod\237.[ENTER]Ud\236l\225m si z n\237 spodn\237 pr\225dlo. Tady m\225\154 pytel[ENTER]Yang\249 za tv\233 usil\237. Jo, a v\232era jsem na\154el tuhle[ENTER]knihu, mo\158n\225 se ti bude hodit. "
gameforge.new_quest_lv17._152_say_reward = "Obdr\158\237\154 40 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 10 000 Yang\249.[ENTER]Obdr\158\237\154 knihu schopnost\237. "
