gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "Str\225\158ce v\236\158e d\233mon\249 "
gameforge.new_quest_lv22._021_say = "M\225m obavy o m\233ho bratra, str\225\158ce v\236\158e d\233mon\249. Ji\158[ENTER]dlouho se nec\237til dob\248e a nyn\237 je opravdu[ENTER]nemocn\253. M\225 velk\233 bolesti hlavy a divn\233 skvrny na[ENTER]k\249\158i, ale bohu\158el nem\249\158e opustit sv\233 m\237sto. Mohl[ENTER]bys mu od Baek-Go don\233st n\236jak\253 l\233k? "
gameforge.new_quest_lv22._022_say = "Ud\236lal bych to s\225m, ale V\236\158 d\233mon\249 je v Temn\233m[ENTER]chr\225mu, v sam\233m srdci \250dol\237 Seungryong. A cel\233 to[ENTER]m\237sto se jen hem\158\237 podivn\253mi p\248\237\154erami.... "
gameforge.new_quest_lv22._023_say = "Tak tady jsi. Zapom\236l jsi p\248\237znaky? M\236l bys[ENTER]zkusit poslouchat, kdy\158 ti n\236kdo n\236co \248\237k\225. M\249j[ENTER]bratr m\225 bolesti hlavy a divn\233 skvrny na k\249\158i. A[ENTER]te\239 b\236\158 za Baek-Go! "
gameforge.new_quest_lv22._024_select = "Pomo\158te bratrovi "
gameforge.new_quest_lv22._025_say_title = "L\233k od Baek-Go "
gameforge.new_quest_lv22._026_say = "Promluv si s Baek-Go o l\233ku pro str\225\158ce V\236\158e[ENTER]d\233mon\249. "
gameforge.new_quest_lv22._027_say = "Baek-Go je v %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "Tak\158e ty pot\248ebuje\154 l\233k? Je celkem nebezpe\232n\233[ENTER]d\225vat l\233ky bez l\233ka\248sk\233ho p\248edpisu. Mus\237\154 mi[ENTER]alespo\242 \248\237ci p\248\237znaky nemoci. "
gameforge.new_quest_lv22._032_1_select = "Bolen\237 hlavy a skrvny "
gameforge.new_quest_lv22._032_2_select = "Bolest krku a kloub\249 "
gameforge.new_quest_lv22._032_3_select = "Nev\237m. "
gameforge.new_quest_lv22._035_say = "To zn\237, jako by ho uhranuli d\233moni. A \232asto se to[ENTER]st\225v\225, kdy\158 je na bl\237zku mnoho naka\158en\253ch p\248\237\154er.[ENTER]Mysl\237m, \158e mohu p\248ipravit n\236co, co mu pom\249\158e. Ale[ENTER]budu pot\248ebovat n\236jak\233 p\248\237sady. "
gameforge.new_quest_lv22._040_say = "Pot\248ebuji: "
gameforge.new_quest_lv22._041_say_reward = "Mus\237te ulovit: "
gameforge.new_quest_lv22._042_say = "D\225le pot\248ebuji: "
gameforge.new_quest_lv22._043_say = "O takov\233 nemoci jsem nikdy nesly\154el. Jsi si jist,[ENTER]\158e ti pr\225v\236 tyhle p\248\237znaky str\225\158ce popsal? J\225[ENTER]bych se ho rad\236ji zeptal je\154t\236 jednou b\253t tebou. "
gameforge.new_quest_lv22._044_say = "Nemohu ur\232it diagn\243zu bez p\248\237znak\249. Jdi zp\236t a[ENTER]zeptej se znovu. "
gameforge.new_quest_lv22._050_set_title = "L\233k "
gameforge.new_quest_lv22._056_notice = "Prima, te\239 je\154t\236 pot\248ebuji %s l\233\232iv\253ch bylin. "
gameforge.new_quest_lv22._057_notice = "To by mohly b\253t v\154echny byliny, kter\233 jsou[ENTER]pot\248eba. B\236\158 rychle za Baek-Go. "
gameforge.new_quest_lv22._058_notice = "Dob\248e, zb\253v\225 u\158 jen %s jater. "
gameforge.new_quest_lv22._060_notice = "Ano, j\225tra. Te\239 je\154t\236 pot\248ebuji %s. "
gameforge.new_quest_lv22._061_notice = "To by mohla b\253t v\154echna j\225tra, kter\225 jsou[ENTER]pot\248eba. Vra\157 se k Baek-Go. "
gameforge.new_quest_lv22._062_notice = "Bohu\158el, tyhle j\225tra nejsou upot\248ebiteln\225. "
gameforge.new_quest_lv22._063_say = "Pot\248ebuje\154 je\154t\236 %s x l\233\232iv\233 byliny+. "
gameforge.new_quest_lv22._064_say = "Pot\248ebuje\154 je\154t\236 %s x tyg\248\237 j\225tra+. "
gameforge.new_quest_lv22._065_say = "Te\239 m\225\154 v\154echny p\248\237sady do l\233ku. B\236\158 zp\236t k[ENTER]Baek-Go. "
gameforge.new_quest_lv22._066_say = "Nasb\237rej pro Baek-Go p\248\237sady do l\233ku: "
gameforge.new_quest_lv22._070_say = "D\237ky, te\239 mohu ud\236lat l\233k na tu nemoc od d\233mon\249. "
gameforge.new_quest_lv22._071_say = "Dokon\232eno! Tady m\225\154 ten l\233k. Ale nevydr\158\237 p\248\237li\154[ENTER]dlouho, proto\158e obsahuje \158iv\233 ingredience. Tak\158e[ENTER]ho mus\237\154 doru\232it pacientovi b\236hem n\225sleduj\237c\237ch[ENTER]%s minut. "
gameforge.new_quest_lv22._072_say = "Str\225\158cova bratra m\249\158e\154 naj\237t v centru chr\225mu[ENTER]Hwang. Ale bu\239 na sv\233 cest\236 opatrn\253, \250dol\237[ENTER]Seungryong se p\248\237mo hem\158\237 nebezpe\232n\253mi p\248\237\154erami! "
gameforge.new_quest_lv22._073_say = "To nesta\232\237. To jsi ty p\248\237sady po cest\236 sem[ENTER]ztratil? Bez toho zbytku nemohu nic d\236lat. "
gameforge.new_quest_lv22._080_target = "Str\225\158ce v\236\158e d\233mon\249 "
gameforge.new_quest_lv22._082_set_clock = "Zb\253vaj\237c\237 \232as "
gameforge.new_quest_lv22._083_say = "M\225\154 po\248\225d celkem dost \232asu, ale m\236l bys[ENTER]p\248ichv\225tnout. Tak \154up, a\157 u\158 jsi v \250dol\237[ENTER]Seungryong u str\225\158ce, ne\158 \250\232inek l\233ku zmiz\237. "
gameforge.new_quest_lv22._084_say = "\200as vypr\154el, proto\158e jsi byl p\248\237li\154 pomal\253.[ENTER]P\248esto m\249\158e\154 l\233k str\225\158ci V\236\158e d\233mon\249 don\233st,[ENTER]t\248eba bude je\154t\236 \250\232inn\253. "
gameforge.new_quest_lv22._085_say = "D\237ky za ten l\233k - to sv\236d\236n\237 m\236 zabije. "
gameforge.new_quest_lv22._086_say = "No, chutn\225 to docela dob\248e. A m\225m pocit, \158e to[ENTER]sv\236d\236n\237 ustupuje. "
gameforge.new_quest_lv22._087_say = "Za tohle si zaslou\158\237\154 speci\225ln\237 odm\236nu! "
gameforge.new_quest_lv22._088_say_reward = "Obdr\158\237\154 50 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 12 000 Yang\249.[ENTER]Obdr\158\237\154 Zlat\233 boty+4.[ENTER]Obdr\158\237\154 5 fialov\253ch elix\237r\249. "
gameforge.new_quest_lv22._089_say = "Bo\158e, to chutn\225 p\248\237\154ern\236. \218\232inek ur\232it\236 vyprchal[ENTER]- jak dlouho jsi se s t\237m loudal? M\225m jazyk jak[ENTER]zaklet\225 opice. "
gameforge.new_quest_lv22._090_say = "Hmm, po\232kej chvilku... Zd\225 se, \158e se to lep\154\237.[ENTER]Ano, funguje to! Tak na tebe nebudu nep\248\237jemn\253 a[ENTER]dokonce ti d\225m i odm\236nu. "
gameforge.new_quest_lv22._091_say = "Vypad\225 to, \158e jsi ten l\233k ztratil? Tak m\249\158e\154 zase[ENTER]vyrazit a p\248in\233st v\154echny pot\248ebn\233 p\248\237sady[ENTER]Baek-Go, aby ten l\233k ud\236lal znovu. Jestli m\236 to[ENTER]bude sv\236dit je\154t\236 chv\237li, tak se stanu asi[ENTER]d\233monem taky. "
gameforge.new_quest_lv22._095_say_reward = "Obdr\158\237\154 50 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 8 000 Yang\249. "
gameforge.new_quest_lv22._098_say = "To jsi zase ztratil medic\237nu? V cel\233m sv\233m \158ivot\236[ENTER]jsem nepotkal nikoho tak zapomn\236tliv\233ho, jako jsi[ENTER]ty! Ale nen\237 tu moc, co bychom s t\237m mohli d\236lat! "
gameforge.new_quest_lv22._100_say_reward = "Obdr\158el jsi 25.000 bod\249 zku\154enost\237. "
