gameforge.new_quest_lv26._020_set_title = "Zb\236h "
gameforge.new_quest_lv26._021_say = "Yang-Shin m\225 pot\237\158e s nalezen\237m dobr\233ho m\237sta na[ENTER]lov. Zajdi za n\237m a zeptej se ho, jak mu m\249\158e\154[ENTER]pomoci. "
gameforge.new_quest_lv26._025_say = "Od t\233 doby, co se objevily kameny Metin, u\158 nic[ENTER]nen\237 jak b\253valo. Na spoust\236 m\237st je u\158 dokonce i[ENTER]nemo\158n\233 n\236co ulovit, proto\158e zv\237\248ata jsou velmi[ENTER]plach\225. Poutn\237k Nakajima \158ije v p\248\237rod\236, mysl\237m,[ENTER]\158e by mohl m\237t n\236jakou radu pro \250sp\236\154n\253 lov. Mohl[ENTER]bys ho naj\237t a zeptat se? "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "Tak\158e ty bys r\225d znal dobr\233 m\237sto na lov? Neura\158[ENTER]se, ale pokud j\225 m\225m ud\236lat n\236co pro tebe, mus\237\154[ENTER]i ty ud\236lat n\236co pro mne. "
gameforge.new_quest_lv26._032_say = "No, v\237\154... j\225 tu ne\158iji dobrovoln\236. Mus\237m se[ENTER]skr\253vat, proto\158e jsem utekl p\248ed vojenskou[ENTER]povinnost\237. Moc si p\248eji, aby moje milovan\225 \158ena[ENTER]Ah-Yu v\236d\236la, \158e jsem st\225le \158iv. Mohl bys j\237[ENTER]don\233st ode mne zpr\225vu? Ale nezapome\242, \158e je to[ENTER]jen pro Ah-Yu! Ona ti na opl\225tku \248ekne, kde jsme[ENTER]se prvn\236 pol\237bili - tam se s n\237 chci op\236t potkat[ENTER]a tak\233 je to m\237sto pro skv\236l\253 lov! "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Hledej Nakajimu "
gameforge.new_quest_lv26._037_say = "Nakajima by mohl zn\225t n\236jak\233 dobr\233 m\237sto na lov.[ENTER]Najdi ho. "
gameforge.new_quest_lv26._038_say = "Nakajima je v %s. "
gameforge.new_quest_lv26._040_say = "Ty jsi nakajima? Yang-Shin mne za tebou pos\237l\225.[ENTER]Hled\225 n\236jak\233 dobr\233 m\237sto pro lov a ty bys pr\253[ENTER]mohl o n\236jak\233m v\236d\236t? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima je zb\236h a mus\237 se p\248ed voj\225ky skr\253vat.[ENTER]Jeho \158ena Ah-Yu si mysl\237, \158e padl ve v\225lce. Dej[ENTER]j\237 v\236d\236t, \158e Nakajima je st\225le \158iv. "
gameforge.new_quest_lv26._052_say = "Ah-Yu je v %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... je na\158ivu? M\249j drah\253 man\158el \158ije?[ENTER]Nemohu ti dost pod\236kovat za tu zpr\225vu! Prvn\236 sme[ENTER]se pol\237bili v \250dol\237 Yonjang, hned se tam za n\237m[ENTER]vyprav\237m. "
gameforge.new_quest_lv26._058_say = "D\237ky, \158e jsi n\225m umo\158nil op\236tovn\233 shled\225n\237. Vem[ENTER]si tuto r\249\158i - t\248eba ji d\225\154 svoj\237 l\225sce? A te\239[ENTER]mne omluv - opravdu sp\236ch\225m! "
gameforge.new_quest_lv26._061_say = "\218dol\237 Yonjang, kde se Nakajima a Ah-Yu prvn\236[ENTER]pol\237bili, je st\225le velmi dobr\233 m\237sto k lovu. "
gameforge.new_quest_lv26._062_say = "Yang-Shin bude pot\236\154en, a\158 se to dozv\237. Jdi do %s[ENTER]a \248ekni mu tu dobrou zpr\225vu. "
gameforge.new_quest_lv26._063_say = "\218dol\237 Yonjang? To zn\237 slibn\236, dokonce jsem je\154t\236[ENTER]nesly\154el, \158e by tam padaly kameny Metin. Tam se[ENTER]pravd\236podobn\236 bude skv\236le lovit! A tady - tady je[ENTER]tv\225 odm\236na. "
gameforge.new_quest_lv26._064_sayReward = "Obdr\158\237\154 35 000 bod\249 zku\154enosti. "
gameforge.new_quest_lv26._065_sayReward = "Obdr\158\237\154 17 500 Yang\249. "
