gameforge.new_quest_lv28._016_say = "Zd\225 se, \158e Ah-Yu n\236co tr\225p\237, ale nechce to \248\237ci.[ENTER]Nav\154tiv ji a zeptej se, zda to \248ekne tob\236. "
