gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan: "
gameforge.new_quest_lv28._021_say = "Zn\225\154 Ah-Yu? Sb\237r\225 byliny pro m\233 lektvary. B\253vala[ENTER]v dobr\233 n\225lad\236, ale v\232era se to \250pln\236 zm\236nilo.[ENTER]Necht\236la mi \248\237ci, co ji tr\225p\237 - mo\158n\225 proto, \158e[ENTER]pro m\236 pracuje? Pros\237m, zajdi za n\237 a zeptej se,[ENTER]co ji tr\225p\237. "
gameforge.new_quest_lv28._022_say = "Od Yu-Hwana je moc hezk\233, \158e m\225 o mne takovou[ENTER]starost. Ale pokud m\236 neco tr\225p\237... Necht\236la jsem[ENTER]o tom mluvit, ale u\158 m\236 to t\237\158\237 opravdu moc.[ENTER]Je to o lovci Yang-Shinovi. Od t\233 doby, co[ENTER]zjistil, \158e m\249j man\158el Nakajima je zb\236h m\236[ENTER]vyd\237r\225. On ho klidn\236 ud\225 a pak Nakajimu zabij\237... "
gameforge.new_quest_lv28._023_say = "Tentokr\225t chce medv\236d\237 pracku v\253m\236nou za sv\233[ENTER]ml\232en\237. Ale j\225 te\239 nemohu j\237t na lov. Mohl bys mi[ENTER]pomoci a sehnat, co Yang-Shin \158\225d\225? "
