gameforge.new_quest_lv28._031_say_reward = "Mus\237te ulovit: "
gameforge.new_quest_lv28._032_say = "Ah-Yu t\236 po\158\225dala o spln\236n\237 Yang-Shinova[ENTER]po\158adavku. "
gameforge.new_quest_lv28._032_say_reward = "Je\154t\236 pot\248ebuje\154 %s x medv\236d\237 pracka.[ENTER]Z\237sk\225\154 je z Bery. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "M\225\154 po\158adovan\253 po\232et medv\236d\237ch pracek. Dones je[ENTER]Yang-Shinovi, abys zaplatil za Ah-Yu. "
