gameforge.new_quest_lv28._041_say_title = "Medv\236d\237 pracky "
gameforge.new_quest_lv28._042_say = "Tys mi donesl medv\236d\237 pracky? Pros\237m, nemysli si[ENTER]o mn\236 nic \154patn\233ho! \142ijeme v t\236\158k\253ch \232asech a j\225[ENTER]mus\237m \158ivit rodinu, a v t\236hle dob\225ch je t\236\158k\233[ENTER]n\236co ulovit, kdy\158 kameny Metin prom\236nily zv\237\248ata[ENTER]ve vra\158d\237c\237 bestie. \142ivot lovce nebyl nikdy tak[ENTER]nebezpe\232n\253. "
gameforge.new_quest_lv28._043_say = "Pros\237m, \248ekni Ah-Yu, \158e se u\158 nem\225 \232eho ob\225vat.[ENTER]Teda - do doby, ne\158 zase budu n\236co pot\248ebovat...[ENTER]hehehe! "
gameforge.new_quest_lv28._044_say = "Co\158e, ty m\236 chce\154 nap\225lit a nem\225\154 pracky? J\225 sem[ENTER]cht\236l p\236kn\236 \232erstv\233! "
gameforge.new_quest_lv28._045_say_reward = "Je od tebe hezk\233, \158e pom\225h\225\154 Ah-Yu. Ale tak\233 to[ENTER]znamen\225, \158e mus\237\154 ud\236lat co ti \248eknu. Tak\158e te\239[ENTER]jdi na lov a nevracej se d\248\237v, ne\158 bude\154 m\237t dv\236[ENTER]medv\236d\237 pracky! "
gameforge.new_quest_lv28._046_say = "Vy\248i\239 Ah-Yu, \158e Yang-Shin ji ji\158 nebude d\225le[ENTER]vyd\237rat, proto\158e jsi mu pomohl. "
gameforge.new_quest_lv28._051_say = "Ty jsi m\249j spasitel! Jsem ti neskonale vd\236\232n\225.[ENTER]Tady, vezmi si v\154echny m\233 Yangy. Nen\237 to mnoho,[ENTER]ale ty sis to zaslou\158il. "
gameforge.new_quest_lv28._055_1_select = "D\237ky, to se hod\237! "
gameforge.new_quest_lv28._055_2_select = "Ne, to nemohu p\248ijmout. "
gameforge.new_quest_lv28._056_say = "Je to v\154e co m\225m, ale stoj\237 mi to za to, kdy\158 se[ENTER]zbav\237m toho barbarsk\233ho hrdlo\248eza! "
gameforge.new_quest_lv28._057_say = "Ach, d\236kuji! Tv\233 m\237sto po boku Dra\232\237ho boha je[ENTER]ji\158 jist\236 p\248ipraveno! "
gameforge.new_quest_lv28._058_say_reward = "Obdr\158\237\154 %s Yang\249. "
gameforge.new_quest_lv28._059_say_reward = "Obdr\158\237\154 %s bod\249 zku\154enost\237. "
gameforge.new_quest_lv28._070_say = "Pot\248ebuji: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah: "
gameforge.new_quest_lv29._015_npcChat = "Rozbit\253 porcel\225n "
gameforge.new_quest_lv29._020_say_title = "Yonah: "
gameforge.new_quest_lv29._021_say = "M\249j milovan\253 Seladonsk\253 porcel\225n! Moje rodina ho[ENTER]m\236la po t\248i generace a nyn\237 jsou t\248i z t\236ch[ENTER]precizn\237ch v\225z rozbit\233! Zahl\233dl jsem kolem skladu[ENTER]Taurean, on za to ur\232it\236 m\249\158e! "
gameforge.new_quest_lv29._022_say = "Nakonec, nebyla by to prvn\237 hloup\225 v\236c, kterou[ENTER]ud\236lal, ale tady opravdu p\248ekro\232il hranici. N\236kdo[ENTER]by mu m\236l d\225t lekci - m\225\154 na to \232as? "
gameforge.new_quest_lv29._023_1_select = "S pot\236\154en\237m "
gameforge.new_quest_lv29._023_2_select = "To nen\237 moje v\236c "
gameforge.new_quest_lv29._024_say = "Nem\225m \232as na p\248ev\253chovu nezbedn\233ho d\236cka. Mus\237\154[ENTER]si ho chytit s\225m. I kdy\158 pochybuji, \158e to[ENTER]dok\225\158e\154... "
gameforge.new_quest_lv29._030_target = "Taurean: "
gameforge.new_quest_lv29._031_say = "Rodinn\233 d\236dictv\237 Yonaha, v\225zy z Seladonsk\233ho[ENTER]porcel\225nu, jsou rozbit\233 a Yonah si mysl\237, \158e to[ENTER]ud\236lal Taurean. Jdi za Taureanem a zjisti, jak to[ENTER]bylo. "
gameforge.new_quest_lv29._032_say = "Taurean je v %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean: "
gameforge.new_quest_lv29._034_say_reward = "Pro\232 se na m\236 tak d\237v\225\154? Nic jsem neud\236lal... "
gameforge.new_quest_lv29._035_say_reward = "Co jsi ud\236lal s Yonahov\253mi v\225zami? "
gameforge.new_quest_lv29._036_say_reward = "V\225zy? Yonah? V\249bec nev\237m, o \232em mluv\237\154! "
gameforge.new_quest_lv29._037_say_reward = "No tak mi pros\237mt\236 vysv\236tli, pro\232 jsou t\248i z nich[ENTER]rozbit\233. "
gameforge.new_quest_lv29._038_say_reward = "P\248\237sah\225m, \158e jsem dnes nebyl nikde pobl\237\158 t\236ch[ENTER]v\225z a tak\233 jsem ani nevid\236l Yonaha. Cel\253 den jsem[ENTER]bojoval s Harang. Dokonce m\236 zamknula ve stodole![ENTER]Jdi a zeptej se j\237, pokud mi nev\236\248\237\154! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean tvrd\237, \158e je nevinn\253. Hr\225l si s Harang[ENTER]cel\253 den a nemohl ty v\225zy rozb\237t. Dojdi za Harang[ENTER]a zeptej se j\237, zda je to pravda. "
gameforge.new_quest_lv29._042_say_reward = "Harang, vid\236la jsi n\236kdy te\239 Taureana? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taureana? Ano, hr\225li jsme si cel\253 den. D\236je se[ENTER]n\236co? "
gameforge.new_quest_lv29._045_say_reward = "Yonah tvrd\237, \158e mu Taurean rozbil t\248i v\225zy. "
gameforge.new_quest_lv29._046_say_reward = "Yonah je zl\253. Pron\225sleduje m\236 a Taureana kdykoliv[ENTER]se k n\236mu p\248ibl\237\158\237me. V\158dy se tak boj\237 o sv\249j[ENTER]porcel\225n. Jedin\225 osoba, kter\225 se sm\237 jeho[ENTER]porcel\225nu dotknout je pacholek. Mo\158n\225 ty v\225zy[ENTER]rozbil on? "
gameforge.new_quest_lv29._047_say = "Harang je v %s. "
gameforge.new_quest_lv29._050_target = "Pacholek: "
gameforge.new_quest_lv29._051_say = "Harang potvrdila, \158e Taurean je nevinn\253. Ale tak\233[ENTER]mohou b\253t spolu domluveni. P\248ed t\237m, ne\158 vynese\154[ENTER]rozsudek, by sis m\236l promluvit s pacholkem. "
gameforge.new_quest_lv29._052_say = "Ach, star\253 dobr\253 Yonah. Tak se boj\237 o sv\249j[ENTER]porcel\225n, \158e dokonce pron\225sleduje vesnick\233 d\236ti.[ENTER]N\236jak si neuv\236domuje, \158e kameny Metin maj\237 vliv[ENTER]na celou zemi - a dokonce i na suroviny, proto\158e[ENTER]ty u\158 tak\233 nejsou to co b\253valy. Dokonce i[ENTER]porcel\225n za\232al praskat. Ale Yonah tomu prost\236[ENTER]nechce v\236\248it... "
gameforge.new_quest_lv29._053_say = "Kdybys mu nasb\237ral n\236jak\233 seno, mohl by si jeho[ENTER]porcel\225n l\233pe uskladnit v truhl\225ch. Mysl\237m, \158e by[ENTER]to byla dobr\225 cesta, jak ho ochr\225nit. "
gameforge.new_quest_lv29._054_say = "Pacholek je v[ENTER]%s nebo %s. "
gameforge.new_quest_lv29._061_say = "Taurean nen\237 zodpov\236dn\253 za rozbit\237 Yonahov\253ch[ENTER]v\225z. Je to zhoubn\253 vliv kamen\249 Metin, kter\253 d\236l\225[ENTER]v\236ci k\248eh\232\237mi. Nasb\237rej pro Yonaha n\236jak\233 seno,[ENTER]aby si mohl l\233pe ulo\158it sv\249j porcel\225n. Jsem si[ENTER]jist, \158e ti vesni\232an\233 n\236jak\233 daj\237. "
gameforge.new_quest_lv29._062_say = "M\249\158e\154 naj\237t %s a %s u bran do vesnice. M\236l bys[ENTER]b\253t schopen z\237skat slu\154n\233 mno\158stv\237 sena z[ENTER]klobouk\249, kter\233 nos\237. "
gameforge.new_quest_lv29._063_notice = "Z toho bude p\236kn\225 hromada sena. Ale po\248\225d mi[ENTER]je\154t\236 chyb\237 %s. "
gameforge.new_quest_lv29._064_notice = "Hm, to nen\237 z obil\237, ale kokosov\253ch vl\225ken. To[ENTER]nemohu pou\158\237t. "
gameforge.new_quest_lv29._065_1_say = "Kouk\225m, \158e m\225\154 u sebe p\236knou hromadu sena. Jsem[ENTER]si jist, \158e Yonah ztichne, kdy\158 mu ji d\225\154. "
gameforge.new_quest_lv29._065_notice = "Ten klobouk nen\237 z obil\237, ale z kokosov\253ch[ENTER]vl\225ken. A tak\233 je docela po\154kozen\253... "
gameforge.new_quest_lv29._066_say = "M\249\158e\154 tak\233 lovit divok\233 p\236\154\225ky nebo siln\233 divok\233[ENTER]p\236\154\225ky, z jejich klobouk\249 lze z\237skat seno. "
gameforge.new_quest_lv29._067_say_reward = "Ji\158 jsi z\237skal %s z %s bal\237k\249 sena. "
gameforge.new_quest_lv29._068_notice = "Z\237skal jsi bal\237k sena. "
gameforge.new_quest_lv29._070_npcChat = "Bal\237k sena "
gameforge.new_quest_lv29._071_say_reward = "Taurean, ty jsi p\248edt\237m \248\237kal, \158e jsi byl ve[ENTER]stodole. Nevzal sis odtud n\236jak\233 seno? "
gameforge.new_quest_lv29._072_say_reward = "Haha, pod\237vejme... to v\154e jsem m\236l ve vlasech a[ENTER]bot\225ch. Vid\237\154? Tady je je\154t\236 tak\233 n\236co, na, vezmi[ENTER]si to! "
gameforge.new_quest_lv29._073_notice = "Nen\237 to moc sena, ale na mal\253 bal\237k to bude[ENTER]sta\232it. Tak\158e pot\248ebuji je\154t\236 %s dal\154\237ch. "
gameforge.new_quest_lv29._074_say_reward = "J\225 to nebyl, p\248\237sah\225m! Ne\248ekla ti Harang, \158e jsme[ENTER]ve stodole bojovali? "
gameforge.new_quest_lv29._075_say_reward = "Hele, nem\225\154 je\154t\236 n\236jak\233 seno, jak jsi byl v t\233[ENTER]stodole? "
gameforge.new_quest_lv29._076_say_reward = "Jak v\237\154 o stodole? Po\232kej, mo\158n\225 m\225m je\154t\236 n\236jak\233[ENTER]v \154atech... Ano, tady je! "
gameforge.new_quest_lv29._077_say_reward = "D\225\154 mi ho? "
gameforge.new_quest_lv29._078_say_reward = "Mysl\237m \158e ano.... "
gameforge.new_quest_lv29._079_say_reward = "Te\239 nem\225m \232as. Mus\237m naj\237t Taurean a vy\248e\154it s[ENTER]n\237m celou tu v\236c s v\225zami. "
gameforge.new_quest_lv29._080_npcChat = "Seno pro Yonaha "
gameforge.new_quest_lv29._081_say_reward = "Nen\237 ve st\225j\237ch n\236jak\233 seno na zemi, kter\233 bych[ENTER]mohl Yonahovi p\248in\233st? "
gameforge.new_quest_lv29._082_say_title = "Pacholek: "
gameforge.new_quest_lv29._083_say_reward = "Nem\225me moc sena. Divok\225 zv\237\248ata a bandit\233 v okol\237[ENTER]vesnice n\225m br\225n\237 v tom, abychom si jej[ENTER]usu\154ili... "
gameforge.new_quest_lv29._084_say_reward = "Ale trochu ti d\225t mohu! "
gameforge.new_quest_lv29._085_notice = "Nen\237 to opravdu nijak moc, ale na bal\237k to sta\232\237.[ENTER]Tak\158e je\154t\236 pot\248ebuji dal\154\237 %s. "
gameforge.new_quest_lv29._086_say_reward = "Ob\225v\225m se, \158e nic dal\154\237ho ji\158 pro tebe ud\236lat[ENTER]nemohu. "
gameforge.new_quest_lv29._090_send_letter = "Seno m\237sto ran "
gameforge.new_quest_lv29._091_say = "M\225\154 dostatek sena pro Yonaha. Dones ho do %s. "
gameforge.new_quest_lv29._101_say_reward = "Nen\237 to chyba Taureana. Z\225\248en\237 z kamen\249 Metin[ENTER]zap\248\237\232inilo k\248ehkost porcel\225nu. "
gameforge.new_quest_lv29._102_say_title = "Yonah: "
gameforge.new_quest_lv29._103_say_reward = "Co \248\237kal? To nem\225 smysl, ten uli\232n\237k ti lhal! "
gameforge.new_quest_lv29._104_say_reward = "Tauren si hr\225l s Harang cel\253 den ve stodole. "
gameforge.new_quest_lv29._105_say_reward = "M\225m ti p\248edat pozdravy od tv\233ho p\248\237tele pacholka[ENTER]p\248ivezl jsem ti n\236jak\233 seno. M\236lo by ti pomoci[ENTER]l\233pe uchr\225nit tv\233 v\225zy. "
gameforge.new_quest_lv29._106_say_reward = "P\248izn\225v\225m, \158e jsem trochu znechucen svou reakc\237.[ENTER]Ale m\236l bys zase v\236d\236t, \158e na sv\233m porcel\225nu[ENTER]velmi lp\237m, proto\158e vyvol\225v\225 vzpom\237nky na mou[ENTER]rodinu. Kdy\158 se v\225za rozbije, je to pro mne v\237c[ENTER]ne\158 jen zni\232en\225 v\236c.... "
gameforge.new_quest_lv29._107_say_reward = "Mus\237m se omluvit tob\236 i Taureanovi. Tady je mal\225[ENTER]odm\236na za tv\233 \250sil\237. "
gameforge.new_quest_lv29._108_notice = "Obdr\158\237\154 %s bod\249 zku\154enost\237. "
gameforge.new_quest_lv29._109_say_reward = "M\225m ti p\248edat pozdravy od tv\233ho p\248\237tele pacholka[ENTER]p\248ivezl jsem ti n\236jak\233 seno. M\236lo by ti pomoci[ENTER]l\233pe uchr\225nit tv\233 v\225zy. "
gameforge.new_quest_lv29._110_say_reward = "To je od tebe mil\233, ale mohl bys mi p\248in\233st je\154t\236[ENTER]dal\154\237ch %s bal\237k\249 sena? Abych si byl jist, \158e m\233[ENTER]v\225zy budou opravdu v bezpe\232\237? "
gameforge.new_quest_lv29._111_say_reward = "Mysl\237m, \158e naj\237t dal\154\237 seno bude t\236\158k\233. Ale ty[ENTER]v\225zy jsou pro mne sv\225tost. Kdybys mi je\154t\236 n\236jak\233[ENTER]seno p\248inesl, tak ti budu neskonale vd\236\232n\253 - a[ENTER]tak\233 ti dob\248e zaplat\237m. "
gameforge.new_quest_lv29._112_say_reward = "Ta potvora Harang je jako v\158dy s Taureanem[ENTER]domluven\225. "
gameforge.new_quest_lv29._113_say_reward = "Bohu\158el mi nikdo nev\236\248\237 kdy\158 \248\237k\225m, \158e jsem[ENTER]skute\232n\236 vid\236l kluka poflakovat se kolem[ENTER]skladi\154t\236. "
gameforge.new_quest_lv29._114_say_reward = "To je v po\248\225dku. Tady je n\236jak\233 vyrovn\225n\237 za tv\233[ENTER]\250sil\237. "
gameforge.new_quest_lv29._115_say_reward = "Tady, %s Yang\249. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Kru\232en\237 v b\248i\154e "
gameforge.new_quest_lv42._020_target = "Octavio: "
gameforge.new_quest_lv42._021_say = "Kru\232\237 mi v b\248i\154e jak divok\233mu kanci. Asi bych m\236l[ENTER]nav\154t\237vit Octavia. D\236l\225 nejlep\154\237 j\237dlo \154iroko[ENTER]daleko. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "Ty chce\154 n\236jakou pol\233vku? Tu s t\236mi hlavami?[ENTER]Promi\242, ale u\158 jsme v kuchyni nem\236li \158\225dn\233 ryby[ENTER]docela dlouho. Obvykle ale ryb\225\248 dod\225v\225[ENTER]fantastick\233 ryby. "
gameforge.new_quest_lv42._024_say = "No, ale u\158 tu nebyl p\225r dn\249. Mohl bys za n\237m[ENTER]zaj\237t a zeptat se ho, co se d\236je? "
gameforge.new_quest_lv42._025_say = "Octavio je v %s. "
gameforge.new_quest_lv42._026_select = "Vyraz\237m hledat ryb\225\248e! "
gameforge.new_quest_lv42._030_target = "Ryb\225\248: "
gameforge.new_quest_lv42._031_say = "Dny bez pot\237\158\237 na mo\248i jsou ty tam. Ryb\225\248i miz\237[ENTER]ka\158d\253 den, je to hrozn\233! Kdy\158 kdysi kameny Metin[ENTER]spadly do mo\248e, tak zm\236nily mo\248sk\233 \158ivo\232ichy na[ENTER]vra\158d\237c\237 bestie a rybolov se stal nebezpe\232n\253m. "
gameforge.new_quest_lv42._032_say = "Na\154e o\154t\236py ji\158 velryb\225m nezp\249sobuj\237 \158\225dn\225[ENTER]zran\236n\237. Jejich k\249\158e je tvrd\154\237 ne\158 k\249\158e zlobr\249! "
gameforge.new_quest_lv42._033_say = "Mo\158n\225 Yonah v\237, co d\236lat. Chodil ryba\248it velmi[ENTER]\232asto a lovil i velryby. "
gameforge.new_quest_lv42._034_say_title = "Ryb\225\248: "
gameforge.new_quest_lv42._035_say = "Octavio \232ek\225 na ryby z hlubin mo\248e. Zeptej se[ENTER]ryb\225\248e, pro\232 u\158 ryby nedod\225v\225. "
gameforge.new_quest_lv42._036_say = "Ryb\225\248 je v %s. "
gameforge.new_quest_lv42._037_send_letter = "Podivn\225 mo\248sk\225 monstra "
gameforge.new_quest_lv42._038_say = "Ryb\225\248 t\236 po\158\225dal, aby ses zeptal Yonaha na rady[ENTER]ohledn\236 lovu zl\253ch mo\248sk\253ch velryb. "
gameforge.new_quest_lv42._039_say = "Yonah je v %s. "
gameforge.new_quest_lv42._040_target = "Yonah: "
gameforge.new_quest_lv42._041_say = "Ji\158 jsem sly\154el, co se stalo s velrybami. To je[ENTER]\154patn\225 v\236c pro ryb\225\248e. I kdy\158 se odv\225\158\237 na mo\248e,[ENTER]jejich o\154tepy velryb\225m neubl\237\158\237. Kdy\158 jsem[ENTER]pracoval na velryb\225\248sk\233m \232lunu, m\236li jsme na[ENTER]velryby speci\225ln\237 zbran\236. Ty byly schopn\233[ENTER]prorazit jakoukoliv k\249\158i.... "
gameforge.new_quest_lv42._042_say = "Je to speci\225ln\237 postup, jak vytvrdit \154pi\232ky[ENTER]o\154t\236p\249 na velryby. Jedin\253, kdo um\237 ty o\154t\236py[ENTER]vyrobit, je kov\225\248. "
gameforge.new_quest_lv42._043_say_reward = "B\236\158 za kov\225\248em "
gameforge.new_quest_lv42._044_say_title = "Yonah: "
gameforge.new_quest_lv42._045_say = "Yonah doporu\232il pou\158\237vat velmi siln\233 a ostr\233[ENTER]o\154t\236py pro lov velryb. Zajdi za kov\225\248em a zeptej[ENTER]se ho, zda by je um\236l vyrobit. "
gameforge.new_quest_lv42._050_target = "Kov\225\248 "
gameforge.new_quest_lv42._051_say = "Ano, sly\154el jsem o t\236ch o\154t\236pech a um\237m je[ENTER]vyrobit. Ale aby ty o\154t\236py m\236ly pot\248ebn\233[ENTER]vlastnosti, pot\248ebuji diamantov\253 k\225men. "
gameforge.new_quest_lv42._052_say = "Pot\248ebuji: "
gameforge.new_quest_lv42._053_say_reward = "Postup: "
gameforge.new_quest_lv42._054_say_title = "Kov\225\248 "
gameforge.new_quest_lv42._060_set_title = "Diamantov\253 k\225men "
gameforge.new_quest_lv42._061_notice = "Pod\237vej. Pot\248ebuji krump\225\232, abych mohl t\236\158it[ENTER]k\225men. Jen nemohu ten sv\249j star\253 n\236jak naj\237t,[ENTER]mysl\237\154, \158e by mi Deokbae mohl ud\236lat nov\253? "
gameforge.new_quest_lv42._062_say = "Pot\248ebuje\154 je\154t\236 %s x Diamantov\253 k\225men "
gameforge.new_quest_lv42._063_say = "M\225\154 v\154e, co bylo t\248eba. Nyn\237 b\236\158 rychle za[ENTER]kov\225\248em. "
gameforge.new_quest_lv42._064_say = "V\253born\236, te\239 m\225m v\154e, co je t\248eba. P\248ij\239 v tenhle[ENTER]\232as z\237tra, budu m\237t ty o\154t\236py. \142elezo mus\237 b\253t[ENTER]kov\225no opatrn\236. "
gameforge.new_quest_lv42._065_say = "Diamantov\253 k\225men m\249\158e\154 z\237skat, pokud bude\154 pomoc\237[ENTER]krump\225\232e t\236\158it z diamantov\233 \158\237ly. "
gameforge.new_quest_lv42._066_say = "Kov\225\248 pot\248ebuje Diamantov\233 kameny, aby mohl[ENTER]vyrobit speci\225ln\237 o\154t\236py pro lov velryb. Hledej[ENTER]diamantov\233 \158\237ly. Pokud nem\225\154 krump\225\232 pro[ENTER]t\236\158bu,m\249\158e\154 si jej koupit od Deokbae. "
gameforge.new_quest_lv42._067_say = "Kov\225\248 je v %s. "
gameforge.new_quest_lv42._068_say = "Pot\248ebujeme je\154t\236 %s x diamantov\253ch kamen\249, ne\158[ENTER]budeme moci vyrobit o\154t\236py. "
gameforge.new_quest_lv42._070_set_title = "O\154t\236py "
gameforge.new_quest_lv42._071_set_clock = "Doba \232ek\225n\237 "
gameforge.new_quest_lv42._072_say = "Kov\225\248 u\158 by m\236l b\253t hotov. Jdi za n\237m a vyzvedni[ENTER]si speci\225ln\237 o\154t\236py pro lov velryb. "
