gameforge.new_quest_lv42._090_say = "Ryb\225\248i jsou nyn\237 dob\248e vybaveni a mohou op\236t[ENTER]lovit na otev\248en\233m mo\248i. Jdi za Octaviem a ujisti[ENTER]ho, \158e brzy dostane dod\225vku ryb. "
gameforge.new_quest_lv42._095_say = "Co jsi \248\237kal? M\237rumilovn\233 velryby se staly[ENTER]agresivn\237 mo\248sk\225 monstra? No to je hrozn\233...[ENTER]D\237ky, \158e jsi pomohl ryb\225\248\249m. Velk\225 \232\225st m\253ch[ENTER]pokrm\249 je na jejich dod\225vk\225ch z\225visl\225. "
