gameforge.new_quest_lv43._011_say = "U\158 jsi o Wonda-Rimovi dlouho nesly\154el. Jeho[ENTER]vztahy se str\253\232kem se pravd\236podobn\236 zlep\154ily a[ENTER]cel\225 epizoda s k\249\158emi Mu-Ranga byla zapomenuta.[ENTER]Pro\232 ho tedy nenav\154t\237v\237\154? "
