gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Vychoval m\236 str\253\232ek Chaegirab. V\158dy jsme m\236li[ENTER]dobr\233 vztahy... ale kdy\158 se ho zept\225m na m\233[ENTER]rodi\232e, tak ot\225zku ignoruje. Pr\253 jsou mrtv\237, to[ENTER]je v\154e, co mi \248ekl. "
gameforge.new_quest_lv43._023_say_reward = "Jednoho dne bych se r\225d o\158enil a m\236l vlastn\237[ENTER]rodinu, tak\158e bych opravdu r\225d v\236d\236l, odkud[ENTER]vlastn\236 poch\225z\237m. Mohl bys promluvit s m\253m[ENTER]str\253\232kem a zeptat se ho na m\233 rodi\232e? Ale ne\248\237kej[ENTER]mu, \158e t\236 pos\237l\225m. "
gameforge.new_quest_lv43._024_select = "Promluv\237m s n\237m! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim nen\237 pokrevn\237 p\248\237buzn\253 Chaegiraba, on[ENTER]ho jen vychoval. Nyn\237 p\248i\154el \232as zjistit, kdo[ENTER]byli jeho skute\232n\237 rodi\232e. Zeptej se Chaegiraba[ENTER]na Wonda-Rimovi rodi\232e. "
