gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim.... ne, nejsem jeho biologick\253 str\253\232ek.[ENTER]Nev\237m, kdo jsou jeho rodi\232e. Chr\225nil jsem ho a\158[ENTER]dosud p\248ed pravdou, proto\158e si nemysl\237m, \158e byl[ENTER]p\248ipraven to zjistit. Ale mo\158n\225 \158e te\239 p\248i\154el ten[ENTER]spr\225vn\253 \232as. "
gameforge.new_quest_lv43._033_say = "Na\154el jsem ho u hordy or\232\237ch bojovn\237k\249 v \250dol\237[ENTER]Seungryong. Pokud je n\236jak\225 nad\236je, \158e se o[ENTER]rodi\232\237ch Wonda-Rima d\225 n\236co zjistit, zjist\237\154 to[ENTER]jedin\236 od ork\249. "
gameforge.new_quest_lv43._034_say = "Mo\158n\225 jsem na n\236j byl p\248\237sn\253, ale v\158dy jsem jeho[ENTER]str\253\232ek. I kdy\158 mo\158n\225 bude \248\237kat, \158e ne. "
gameforge.new_quest_lv43._035_say_reward = "Jdi do \250dol\237 Seungryong a zab\237jej Or\232\237 bojovn\237ky,[ENTER]dokud ti ne\248eknou n\236co o rodi\232\237ch Wonda-Rima. "
gameforge.new_quest_lv43._036_say = "Ve \154pinav\233m batohu mrtv\233ho orka jsi na\154el star\253[ENTER]dopis. Je jen t\236\158ko \232iteln\253, ale jasn\236 z n\236j[ENTER]vid\237\154 jm\233no Wonda-Rima. To je to, co jsi hledal.[ENTER]Dones ten dopis Wonda-Rimovi. "
gameforge.new_quest_lv43._041_say = "Tak \154up! Nejlep\154\237 cesta, jak n\236co zjistit o[ENTER]rodi\232\237ch Wonda-Rima je zab\237jet Or\232\237 bojovn\237ky.[ENTER]Mohli by m\237t u sebe n\236jak\233 d\249kazy! "
gameforge.new_quest_lv43._043_notice = "Informace o Wonda-Rimovi... "
gameforge.new_quest_lv43._045_say = "\216ekl jsem ti v\154e co v\237m. Jedin\233 vod\237tko, kter\233[ENTER]m\225me, jsou or\232\237 bojovn\237ci. Ale zat\237m jsi s nimi[ENTER]nem\236l p\248\225telsk\253 rozhovor... "
gameforge.new_quest_lv43._049_say = "Dopis? Uka\158... Ty znaky jsou sotva k p\248e\232ten\237...[ENTER]Je to o n\225jezdu... Orkov\233 zap\225lili farmu a lid\233[ENTER]si zachr\225nili \158ivoty \250t\236kem... Museli tam nechat[ENTER]sv\233 d\236ti... A tady je jm\233no. "
gameforge.new_quest_lv43._050_say = "D\237ky, \158e jsi mi to p\248inesl. Nyn\237 kone\232n\236 v\237m, co[ENTER]se stalo. "
gameforge.new_quest_lv43._051_say = "M\236l bych si promluvit s Chaegirabem. Obvykle se[ENTER]dost\225val do pot\237\158\237, kdy\158 mne chr\225nil. Zkus\237m k[ENTER]n\236mu b\253t hodn\236j\154\237 a b\253t lep\154\237m synovcem. M\236j se,[ENTER]p\248\237teli! "
gameforge.new_quest_lv43._052_say_title = "Informace: "
gameforge.new_quest_lv43._053_say_reward = "Obdr\158\237\154 32 000 Yang\249. "
gameforge.new_quest_lv43._054_say_reward = "Obdr\158\237\154 1 250 000 bod\249 zku\154enost\237. "
gameforge.new_quest_lv43._060_say = "Mluvil jsi s m\253m str\253\232kem Chaegirabem? A? O \232em[ENTER]to mluv\237\154? Pokud nem\225\154 nic, co bys mohl uk\225zat,[ENTER]tak bys m\236l rad\236ji pokra\232ovat.[ENTER][ENTER]Zeptej se m\233ho str\253\232ka je\154t\236 jednou. Ostatn\236,[ENTER]plat\237m ti za to. "
