gameforge.new_quest_lv52._069_say_reward = "Kdybych nebyl zodpov\236dn\253 za bezpe\232nost vesnice,[ENTER]\154el bych okam\158it\236. Tak\158e vid\237m jen jednu cestu: "
gameforge.new_quest_lv52._070_say_reward = "N\236kdo jin\253 bude muset ty voj\225ky pomst\237t. Ale jak[ENTER]m\225m poslat na tak nebezpe\232nou misi dal\154\237ho[ENTER]\232lov\236ka? Mohu v\249bec n\236koho o to \158\225dat jen kv\249li[ENTER]tomu, abych se vyspal? "
