gameforge.new_quest_lv54._040_say_title = "Obchodnice: "
gameforge.new_quest_lv54._040_set_title = "\200erstv\233 dod\225vky "
gameforge.new_quest_lv54._050_target = "Obchodnice: "
gameforge.new_quest_lv54._051_say = "Ano, z\237sk\225vat \232erstv\233 z\225soby je te\239 velmi[ENTER]obt\237\158n\233. Obchodn\237 cesty jsou pom\236rn\236 nebezpe\232n\233 a[ENTER]bandit\233 a divok\233 bestie tam hl\237dkuj\237. Obchodn\237[ENTER]cestuj\237c\237, od kter\233ho z\225soby dost\225v\225m, nem\225 proti[ENTER]tygr\249m \154anci. "
gameforge.new_quest_lv54._052_say = "Mo\158n\225 velitel a jeho voj\225ci mohou pomoci. Pros\237m,[ENTER]zajdi za n\237m a zeptej se ho, zda by mohl poslat[ENTER]voj\225ky, aby ochr\225nili obchodn\237ky. "
gameforge.new_quest_lv54._054_say = "Zajdi za obchodnic\237 se sm\237\154en\253m zbo\158\237m a zjisti,[ENTER]pro\232 se opozdila s dod\225vkou \232erstv\253ch lektvar\249. "
gameforge.new_quest_lv54._055_say = "Obchodnice sm\237\154. zbo\158\237m je v %s. "
gameforge.new_quest_lv54._056_say_title = "Velitel "
gameforge.new_quest_lv54._060_say = "Ochr\225nit obchodn\237 cesty? Ano... R\225d bych to[ENTER]ud\236lal. Ale bohu\158el nem\225m dostatek voj\225k\249, aby[ENTER]ochr\225nili v\154echny obchodn\237 cestuj\237c\237 z jin\253ch[ENTER]kr\225lovstv\237. "
gameforge.new_quest_lv54._061_say = "A nav\237c, my, voj\225ci nesm\237me zab\237jet tygry. Jen[ENTER]lovci z loveck\253ch cech\249 to maj\237 povoleno. Pokud[ENTER]to poru\154\237me, nebude ve vesnici klid. "
gameforge.new_quest_lv54._062_say_reward = "M\236l by sis tud\237\158 promluvit s Yang-Shinem. Je[ENTER]\232lenem loveck\233ho cechu. Mo\158n\225 ti on pom\249\158e dostat[ENTER]ten probl\233m s tygry pod kontrolu. "
gameforge.new_quest_lv54._064_say = "Zajdi za velitelem a zkus ho p\248esv\236d\232it, aby[ENTER]ochr\225nil obchodn\237 cesty p\248ed tygry. "
gameforge.new_quest_lv54._065_say = "Velitel je v %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Mnoho m\253ch lovc\249 bylo povol\225no jako v\225le\232n\237ci a[ENTER]padli v bitv\225ch. Nyn\237 je t\233m\236\248 nemo\158n\233 udr\158ovat[ENTER]populaci divok\253ch zv\237\248at vyv\225\158enou. Divok\233 ko\232ky[ENTER]jsou docela probl\233m, proto\158e roz\154i\248uj\237 svoje[ENTER]teritorium a napadaj\237 cestovatele. "
gameforge.new_quest_lv54._072_say = "Pokud n\225m s t\237m probl\233mem pom\249\158e\154, mohu ti d\225t[ENTER]jako odm\236nu tento Tyg\248\237 \154t\237t +3, kter\253 pat\248il[ENTER]m\233mu mrtv\233mu kamar\225dovi Mi-Song. Abys jej z\237skal,[ENTER]mus\237\154 v\253razn\236 sn\237\158it populaci tygr\249. "
