gameforge.new_quest_lv54._075_say = "Mus\237te ulovit: "
gameforge.new_quest_lv54._076_say = "Vyhledej Yang-Shina a pokus se ho p\248inutit[ENTER]ochr\225nit obchodn\237 cesty p\248ed tygry. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin je v %s. "
gameforge.new_quest_lv54._080_set_title = "Tyg\248\237 ko\158e\154ina "
