gameforge.new_quest_lv54._084_say = "Pot\248ebuje\154 je\154t\236 dal\154\237ch %s mihotav\253ch tyg\248\237ch[ENTER]ko\158e\154in. "
gameforge.new_quest_lv54._085_say = "Z\237skej mihotav\233 tyg\248\237 ko\158e\154iny od proklet\253ch[ENTER]b\237l\253ch tygr\249. "
gameforge.new_quest_lv54._090_npcChat = "M\225m tyg\248\237 k\249\158i. "
gameforge.new_quest_lv54._091_say = "To nen\237 nikde bl\237zko mne. Jak bych mohl naj\237t[ENTER]zdroj t\236hle tyg\248\237ch ko\158e\154in, kdy\158 budou silnice[ENTER]zase bezpe\232n\233? "
gameforge.new_quest_lv54._092_say = "Ano, posledn\237! Ty k\249\158e mi p\248inesou velk\253 zisk...[ENTER]ehm! Ty jsi po\248\225d tady? D\237ky, \158e jsou cesty zase[ENTER]bezpe\232n\233! Jsem si jist, \158e ti velitel d\225 p\236knou[ENTER]odm\236nu. "
