gameforge.new_quest_lv7._024_say = "Je z kr\225lovstv\237 Shinsoo. Samoz\248ejm\236, \158e jsem byl[ENTER]proti tomu! Mysl\237m, \158e d\225ma z Jinno by si nem\236la[ENTER]vz\237t sn\237lka z Shinsoo. Argumenty nezabraly,[ENTER]stejn\236 s n\237m utekla do Shinsoo. "
