gameforge.new_quest_lv75._021_say = "Na\154el jsem ostatky t\236chto v\225le\232n\237k\249. Nev\237m,[ENTER]jestli jsou to ty, co Heuk-Young hled\225, ale jsem[ENTER]si jist, \158e ho budou zaj\237mat. "
