gameforge.new_quest_lv75._023_say = "Na\154el jsem star\253 kus pap\237ru, zamrzl\233ho v[ENTER]podzemn\237m ledov\233m golemovi. Sotva jej mohu[ENTER]p\248e\232\237st, ale m\249\158e to b\253t vod\237tko, kter\233 zaj\237m\225[ENTER]Heuk-Younga. "
gameforge.new_quest_lv75._024_say = "Na\154el jsem n\236kolik v\236c\237, kter\233 mohou zaj\237mat[ENTER]Heuk-Younga. M\236l bych ji j\237t nav\154t\237vit a d\225t j\237[ENTER]ten kus pap\237ru. Tak\233 j\237 budu moci pov\236d\236t o t\236lu. "
gameforge.new_quest_lv75._025_say = "Heuk-Young m\236 po\158\225dala, abych m\236l o\232i otev\248en\233 a[ENTER]hledat jak\225koliv vod\237tka, kter\225 by vedla k[ENTER]informac\237m o legend\225rn\237m Surovi. Bohu\158el nem\225m[ENTER]tu\154en\237, co vlastn\236 hled\225m... "
gameforge.new_quest_lv75._030_say = "Najdi legend\225rn\237ho bojovn\237ka Akumu. Byl to[ENTER]nejzn\225m\236j\154\237 sura, kter\253 kdy \158il - a t\233m\236\248[ENTER]neporaziteln\253. Pov\236sti \248\237kaj\237, \158e jednou dokonce[ENTER]vyzval c\237sa\248e. Mysl\237m si, \158e toto je m\237sto, kde[ENTER]se Akuma p\248ed n\236kolika stovkami let ztratil.[ENTER]Pros\237m, hledej vod\237tka, kter\225 by n\225m ho pomohla[ENTER]naj\237t. "
gameforge.new_quest_lv75._040_say = "hlup\225k "
gameforge.new_quest_lv75._050_npcChat = "Prozkoumej padl\233 v\225le\232n\237ky "
gameforge.new_quest_lv75._060_say = "Vypad\225 to jako ostatek v\225le\232n\237ka. Lev\225 ruka[ENTER]nevypad\225 jako lidsk\225... to mus\237 b\253t Sura. Mus\237m o[ENTER]tom \248\237ci Heuk-Young. "
gameforge.new_quest_lv75._070_notice = "Str\225nka z knihy... zamrzl\225 v ostatc\237ch podzemn\237ho[ENTER]ledov\233ho golema... "
gameforge.new_quest_lv75._090_say = "Bohu\158el ti nemohu p\248esn\236 \248\237ct, co p\248esn\236 hled\225me.[ENTER]Jen se prost\236 pozorn\236 d\237vej a p\248ij\239, kdy\158 najde\154[ENTER]n\236co zaj\237mav\233ho. "
gameforge.new_quest_lv75._100_say = "Cos tam na\154el? Uka\158! "
gameforge.new_quest_lv75._105_say = "Pozn\225mka... jak\253 je to druh p\237sma? Mus\237 b\253t p\236kn\236[ENTER]star\233. Mo\158n\225 si na\154el n\236co skute\232n\236 d\249le\158it\233ho.[ENTER]V\236ci, kter\233 jsou zde naps\225ny jsou mi pov\236dom\233.[ENTER]Vypad\225 to, jako kdy\158 tato str\225nka byla kdysi[ENTER]sou\232\225st\237 knihy. "
gameforge.new_quest_lv75._109_say = "Pokud bychom nalezli v\237ce str\225nek, d\225valo by n\225m[ENTER]to mo\158n\225 v\236t\154\237 smysl. Jdi a hledej dal\154\237! "
gameforge.new_quest_lv75._110_say = "Aha, zase jsi tady? Na\154el jsi n\236co? Pov\237dej! "
gameforge.new_quest_lv75._115_say = "Mrtv\253 Sura... mohl by to b\253t on, anebo prost\236 jen[ENTER]n\236kdo z jeho n\225sledovn\237k\249. Pot\248ebujeme v\237ce[ENTER]d\249kaz\249, abychom si byli jist\237. Hledej vod\237tka,[ENTER]kter\225 by n\225m \248ekla, kdo to byl. Bi\158uterii,[ENTER]pozn\225mky, nebo n\236co takov\233ho. "
gameforge.new_quest_lv75._120_say = "Kostra Sury a str\225nka z knihy? Nech m\236 se na ni[ENTER]pod\237vat... hmmm, Mo\158n\225 si na\154el Akumovy ostatky.[ENTER]Ale pot\248ebujeme v\237ce d\249kaz\249. Zkus pros\237m naj\237t[ENTER]v\237ce t\236ch str\225nek. "
gameforge.new_quest_lv75._130_say = "Na\154el jsem n\236jak\233 z\225znamy, ale nejsem si jist,[ENTER]jestli tu legend\225rn\237 Sura byl \232i nikoliv.[ENTER]Pot\248ebuji v\237ce informac\237. "
gameforge.new_quest_lv75._140_1_select = "Dob\248e "
gameforge.new_quest_lv75._140_2_select = "Ledov\225 p\248\237\154era "
gameforge.new_quest_lv75._140_3_select = "Na hran\236 zoufalstv\237 "
gameforge.new_quest_lv75._140_4_select = "Temn\253 teror "
gameforge.new_quest_lv75._140_5_select = "Tv\225\248 smrti "
gameforge.new_quest_lv75._140_6_select = "Osud v\225le\232n\237ka "
gameforge.new_quest_lv75._140_7_select = "Ne, nezaj\237m\225 mne to "
gameforge.new_quest_lv75._150_say = "Hm, mohu rozlu\154tit pouze \232\225sti v\236t. \216\237kaj\237 n\236co o[ENTER]uhlazen\233m \158ivot\236 a v\225\154ni pro dobrodru\158stv\237... "
gameforge.new_quest_lv75._160_1_say = "Text, napsan\253 na t\233 str\225nce, je \154patn\236 \232iteln\253 a[ENTER]slab\253 - jako by byl naps\225n bu\239 velmi zesl\225blou,[ENTER]nebo velmi starou osobou: ... ledov\233 p\248\237\154ery.[ENTER]Dokonce ani m\233 schopnosti Sury mi nepom\225haj\237 je[ENTER]porazit. N\236kter\233 z nich se st\225le toulaj\237 po[ENTER]jeskyn\237ch a mus\237m b\253t velmi opatrn\253, aby mne[ENTER]nena\154li. A\158 dosud mi nab\237zeli ochranu, ale nyn\237[ENTER]... V tomto m\237st\236 text miz\237... "
gameforge.new_quest_lv75._160_2_say = "Tato str\225nka je tak\233 velmi poni\232en\225. D\237ky datumu[ENTER]v horn\237m rohu m\249\158e\154 rozpoznat, \158e je to n\236jak\253[ENTER]druh den\237ku: Nen\237 to poprv\233 co si p\248eji, abych[ENTER]se choval jinak, kdy\158 jsem vstoupil do Jeskyn\236.[ENTER]Byl jsem na sebe tak hrd\253 a py\154n\253! Ale v\154echny[ENTER]tyhle v\236ci m\236 dovedou jen k m\233 smrti... Posledn\237[ENTER]slovo je lehce p\248e\154krtnuto. "
gameforge.new_quest_lv75._160_3_say = "Str\225nka je velmi po\154kozena, jsou z n\237 utrh\225ny[ENTER]kousky pap\237ru. M\249\158ete rozlu\154tit pouze \232\225st textu:[ENTER]... C\237sa\248sk\253 soud... kdy\158 mne u\232itel\233 u\232ili v\154e,[ENTER]co jsem tak zoufale cht\236l zn\225t... lehce otev\248\237t[ENTER]port\225l, ale...smrt a teror ve tm\236... Velk\253[ENTER]odtr\158en\253 kus V\225m znemo\158\242uje \232\237st d\225le. "
gameforge.new_quest_lv75._160_4_say = "Na t\233to str\225nce vid\237te skicu. Je to \158ensk\225 tv\225\248.[ENTER]Pod n\237 jsou n\236jak\225 slova v jazyce, kter\233mu[ENTER]rozum\237te. Bohu\158el, p\237smo je vybledl\233 a[ENTER]rozt\248esen\233: Smrt vystr\232ila dr\225py - to jsem[ENTER]zjistil v\232era. Sta\232il jeden pohled na p\248\237\154eru,[ENTER]ne\158 mne posedl strach a j\225 musel rychle zp\236t.[ENTER]Moje mil\225 Sunmi, kdybych to tak byl b\253val v\236d\236l![ENTER]Kdybych o t\233to nevysloviteln\233 hr\249ze v\236d\236l, nikdy[ENTER]bych sem nevkro\232il! "
gameforge.new_quest_lv75._160_5_say = "B\236hem vl\225dy dynastie Hee-Se \158il legend\225rn\237 Sura,[ENTER]naz\253van\253 Akuma. Byl tak zru\232n\253 v bitv\225ch, \158e[ENTER]t\233m\236\248 nem\236l protivn\237ka, kter\253 by jej mohl[ENTER]porazit. Jednoho dne na\154el n\236jak\233 pozn\225mky o[ENTER]tajemn\233m m\237st\236, kter\233 bylo dlouho zape\232et\236no a[ENTER]rozhodl se jej nal\233zt a prozkoumat. Dokonce[ENTER]zjistil, jak nal\233zt port\225l a pou\158\237t ho. Sv\233 l\225sce[ENTER]Sunmi sl\237bil, \158e se brzy vr\225t\237, jakmile dokon\232\237[ENTER]svou v\253pravu... ale nikdy se nevr\225til. "
gameforge.new_quest_lv75._170_say = "P\237smo vypad\225 opravdu archaicky. Je velmi[ENTER]rozt\248esen\233 a slab\233, jako kdyby autor ji\158 nem\236l[ENTER]dostatek s\237ly... "
gameforge.new_quest_lv75._171_say = "To ned\225v\225 smysl. Pot\248ebujeme v\237ce str\225nek. "
gameforge.new_quest_lv75._172_say = "Za\232\237n\225m m\237t celkem p\248edstavu, co se tu tak mohlo[ENTER]st\225t. Ale po\248\225d je tu spousta v\236c\237, u kter\253ch si[ENTER]nejsem jist. "
gameforge.new_quest_lv75._173_say = "Cht\236l bys zn\225t detaily? "
gameforge.new_quest_lv75._174_say = "Dal\154\237 str\225nka! Ten kdo ji psal musel b\253t \250pln\236[ENTER]zoufal\253. M\225m shrnout, co se tam p\237\154e? "
gameforge.new_quest_lv75._175_say = "N\236kter\233 z t\236ch str\225nek jsou v tak \154patn\233m stavu,[ENTER]\158e se jen dohaduji, co obsahuj\237. Ale ji\158 pomalu[ENTER]za\232\237n\225m tu\154it, co se v t\233 jeskyni p\248ed stovkami[ENTER]let opravdu stalo. "
gameforge.new_quest_lv75._176_say = "Ji\158 moc nechyb\237. Chce\154 v\236d\236t, co jsme zat\237m[ENTER]zjistili? "
gameforge.new_quest_lv75._177_say = "Vypad\225 to, \158e u\158 moc str\225nek nechyb\237. "
gameforge.new_quest_lv75._178_say = "Chce\154 v\236d\236t, co jsem zat\237m zjistil? "
