gameforge.new_quest_lv75._195_send_letter = "Na\154el jsem str\225nku! "
gameforge.new_quest_lv75._200_npcChat = "Prozkoumej padl\233 v\225le\232n\237ky "
gameforge.new_quest_lv75._210_say = "V lidsk\253ch kostr\225ch se nach\225zej\237 3 str\225nky.[ENTER]Zubat\225 otrhan\225 hrana nazna\232uje, \158e byly vytr\158eny[ENTER]z knihy. P\237smo je vybledl\233 a t\236\158ko se \232te. "
