gameforge.new_quest_lv75._230_say = "Zaj\237malo by mne, \232\237 ostatky to tam jsou? No,[ENTER]jedna v\236c je jist\225 - nem\236li nic, co by se dnes[ENTER]dalo pou\158\237t. "
gameforge.new_quest_lv75._240_send_letter = "M\225m str\225nky! "
gameforge.new_quest_lv75._250_say = "M\236l bych se vr\225tit k Heuk-Young. Mo\158n\225 bude[ENTER]schopna slo\158it kousky t\233to skl\225da\232ky dohromady. "
gameforge.new_quest_lv75._270_say = "P\248ekvapuje mne, kolik v\236c\237 jsi na\154el v t\236ch[ENTER]jeskyn\237ch. Ty str\225nky vypadaj\237 jako sou\232\225st[ENTER]knihy. V\236ci, kter\233 jsou tam naps\225ny, jsou opravdu[ENTER]zaj\237mav\233. D\225v\225 to smysl, pokud vezmu v \250vahu i[ENTER]dal\154\237 p\248\237b\236hy, co jsem sly\154ela.[ENTER]Pokud mi ty str\225nky d\225\154, sv\225\158u je a vytvo\248\237m z[ENTER]nich knihu. Mo\158n\225 ti p\248ijde vhod, a\158 p\249jde\154 do[ENTER]Jeskyn\236 vyhnanstv\237. A pokud ji nechce\154 - tak[ENTER]najdeme n\236koho, kdo si ji r\225d koup\237. "
gameforge.new_quest_lv75._280_say = "Sv\225zala jsem str\225nky do knihy a p\248ipojila n\236jak\233[ENTER]svoje pozn\225mky. Mo\158n\225 ti budou u\158ite\232n\233. \216eknu ti[ENTER]zbytek p\248\237b\236hu, pokud chce\154. "
gameforge.new_quest_lv75._290_1_select = "Ano, \248ekni m\237 v\237ce! "
gameforge.new_quest_lv75._290_2_select = "Ne, d\237ky, nezaj\237m\225 mne to! "
gameforge.new_quest_lv75._310_say = "Co ode mne chce\154? Nevid\237\154, \158e \232tu? "
gameforge.new_quest_lv75._320_say = "Soon: "
gameforge.new_quest_lv75._330_say = "To je opravdu zaj\237mav\225 kniha, co dr\158\237\154. Odkud je[ENTER]? Mohu se na ni pod\237vat? "
gameforge.new_quest_lv75._340_say = "To jsou pozn\225mky z Jeskyn\236 vyhnanstv\237, \158e?[ENTER]Vypadaj\237 starobyle. P\237smo je neobvykl\233 a slovn\237[ENTER]skladby velmi starom\243dn\237... To musela b\253t t\236\158k\225[ENTER]pr\225ce, ud\236lat z nich knihu. R\225d bych si j\237[ENTER]prohl\233dl. Moc r\225d. Prodal bys mi ji? "
