gameforge.new_quest_lv80._050_1_say = "M\225m pro tebe \250kol, ale je pon\236kud nebezpe\232n\253. Ale[ENTER]- bojovn\237k jako ty by to m\236l zvl\225dnout. "
gameforge.new_quest_lv80._050_2_say = "M\225m pro tebe \250kol, ale je pon\236kud nebezpe\232n\253. Na[ENTER]druhou stranu - bojovnice jako ty by to m\236la[ENTER]zvl\225dnout. "
