gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "Jsem velmi star\253 mu\158, ale p\248esto jsem \232il\253 a[ENTER]zdrav\253, m\225m na to tajn\253 recept. P\248i\154el jsem na[ENTER]to, \158e lektvar ze \154\157\225vy ko\248enu gango a hub tue[ENTER]prodlu\158uje \158ivot. Jestli chce\154 taky ochutnat[ENTER]tento lektvar, tak jdi s t\236mi p\248\237sadami k[ENTER]Yu-Hwanovi. Ur\232it\236 ti ho uva\248\237. "
gameforge.npc_talk._10_say = "Do pozoru a dr\158et postoj.[ENTER]Chovej se slu\154n\236 a neprovokuj \158\225dn\233 h\225dky. M\236l[ENTER]bys m\237t respekt k bli\158n\237m.[ENTER]Rozum\237me si? "
gameforge.npc_talk._110_npcChat = "Vypad\225\154 docela siln\236... "
gameforge.npc_talk._120_say = "Tajemstv\237 s\237ly se v na\154\237 rodin\236 p\248ed\225v\225 u\158 po[ENTER]mnoho let. Otec mi vypr\225v\236l, \158e kdy\158 se spr\225vn\253m[ENTER]zp\249sobem zpracuje zvonek na lektvar, tak ti dod\225[ENTER]na kr\225tkou dobu ohromnou s\237lu.[ENTER]Pokud v\237m, Beak-Go v\237, jak vyrobit tento lektvar.[ENTER]Mus\237\154 mu jen don\233st zvonek.  "
gameforge.npc_talk._130_npcChat = "Jdi, \248ekni to hor\225m... "
gameforge.npc_talk._140_sayTitle = "Hudebn\237k Yu-Hwan: "
gameforge.npc_talk._150_say = "A\158 tam za hory, tam za obzory...[ENTER]lalal\225\225\225 Zp\237v\225m si tady v dalek\233m \250stran\237 abych[ENTER]se nezapletl do v\225lky.[ENTER]Ale bez zem\236, kter\225 m\236 ochra\242uje, mi nebude[ENTER]dop\248\225no v\236novat se t\233to kratochv\237li... "
gameforge.npc_talk._160_npcChat = "Pro\232 tolik \232te\154? "
gameforge.npc_talk._170_sayTitle = "Knihomol Soon: "
gameforge.npc_talk._180_say = "\193, dobrodruh.[ENTER]Sv\236t je pln\253 probl\233m\249, a jen se znalostmi se d\225[ENTER]p\248e\158\237t.[ENTER]V\158dy uct\237vej tv\233 knihy.[ENTER]Ve \154patn\253ch \232asech ti porad\237, jak d\225l.[ENTER]V\236\248 mi! "
gameforge.npc_talk._190_npcChat = "M\225\154 d\236ti? "
gameforge.npc_talk._200_say = "Moment\225ln\236 \158\225dn\233 d\236ti nechci, ale... No, sb\237r\225m[ENTER]Kakikv\236ty, proto\158e kdy\158 se dob\248e p\248iprav\237, tak z[ENTER]nich je n\225poj, co ti dod\225 energii. Baek-go na to[ENTER]p\248i\154el. Pot\248ebuje jen jeden kakikv\236t na 100[ENTER]n\225poj\249. Bohu\158el maj\237 ale vedlej\154\237 \250\232inek. Pokud[ENTER]\158ena nos\237 n\225hrdeln\237k z t\236chto kv\236t\249, porod\237 syna.[ENTER]A mezi n\225mi - moje \158ena toho dost zneu\158ila. "
gameforge.npc_talk._20_npcChat = "Mmmm, p\236kn\236 to tu von\237... "
gameforge.npc_talk._210_npcChat = "Co m\225\154 s nohou? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "P\248i posledn\237 proch\225zce jsem zakopl o ko\248en gango.[ENTER]Proto\158e jsem si u toho zvrtl nohu, jsem musel za[ENTER]l\233ka\248em Baek-Go. Pov\236d\236l mi, \158e se z ko\248enu gango[ENTER]d\225 vyrobit lektvar, kter\253 hoj\237 mal\233 r\225ny. "
gameforge.npc_talk._240_npcChat = "Kdo jsi? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "Jsem Wonda-Rim, Chaegirab\249v synovec. M\249j str\253c je[ENTER]\250\158asn\253! Zn\225\154 ho? Hodn\236 experimentuje s lektvary a[ENTER]bylinkami. B\236hem sv\253ch pokus\249 zjistil, jak z\237skat[ENTER]ochranu p\248ed magickou energi\237 - sm\237ch\225n\237m 100 vod[ENTER]Bo a moru\154e. Pokud v\237m, tak Huahn-So z t\236ch[ENTER]ingredienc\237 vyr\225b\237 elix\237ry. "
gameforge.npc_talk._270_npcChat = "Pro\232 si po\248\225d tak vyd\236\154en\253? "
gameforge.npc_talk._280_sayTitle = "Zr\225dce Balso: "
gameforge.npc_talk._290_say = "Proto\158e jsem toho v boji moc nevydr\158el, zeptal[ENTER]jsem se Yu-Hwana, jestli by mi nevyrobil n\236jak\253[ENTER]lektvar, kter\253 by m\236 ochra\242oval proti zran\236n\237.[ENTER]Uva\248il mi lektvar ze zvonkov\233 \154\157\225vy a \154e\248\237ku.[ENTER]Bohu\158el to nem\236lo o\232ek\225van\253 \250\232inek. Ale tob\236 by[ENTER]ur\232it\236 v boji pomohl. "
gameforge.npc_talk._300_npcChat = "Pro\232 t\236 tolik lid\237 naz\253v\225 zr\225dcem? "
gameforge.npc_talk._30_sayTitle = "Hostinsk\253 Octavio: "
gameforge.npc_talk._310_say = "Kdysi jsem byl \232lenem bandy \200ern\233ho v\236tru.[ENTER]Ale pak jsem se k jejich zlo\232ineck\253m praktik\225m[ENTER]obr\225til z\225dy a oni mi to nikdy neodpustili.[ENTER]Zab\237jej\237 nevinn\233 lidi. Na to jsem se u\158 nemohl[ENTER]d\225l d\237vat. "
gameforge.npc_talk._320_say = "Tys tak\233 zab\237jel nevinn\233 lidi? Tak pak si sv\233[ENTER]jm\233no zaslou\158\237\154. Vzal jsi jim mo\158nost v\233st dobr\253[ENTER]\158ivot. "
gameforge.npc_talk._330_say = "\142ijeme v krut\233m sv\236t\236. Ale j\225 u\158 nebudu d\236lat nic[ENTER]zl\233ho. Nechci, aby si mne lid\233 pamatovali jako[ENTER]zr\225dce.[ENTER]Nem\225\154 pro mn\236 n\225hodou p\225r Yang\249? "
gameforge.npc_talk._340_npcChat = "Tob\236 \248\237kaj\237 u\232itel? "
gameforge.npc_talk._350_sayTitle = "U\232enec Uriel: "
gameforge.npc_talk._360_say = "Na tomto \154ir\233m sv\236t\236 je tolik v\236c\237, kter\233 se[ENTER]\232lov\236k m\249\158e nau\232it. Ignorance spojen\225 s vojenskou[ENTER]moc\237 nenad\236l\225 \158\225dnou hodnotu.[ENTER]P\248eci nechce\154 \158\237t jak ti ignorantn\237 voj\225ci, nebo[ENTER]jo? M\237t v\236domosti znamen\225 m\237t moc! "
gameforge.npc_talk._370_npcChat = "M\233 zdroje \248\237kaj\237, \158e praktikuje\154 l\233\232en\237? "
gameforge.npc_talk._380_say = "D\236l\225m co mohu. Na tomto nebezpe\232n\233m sv\236t\236 je[ENTER]ka\158d\253 den \232\237m d\225l t\237m v\237c zran\236n\253ch.[ENTER]A nem\225me dostatek l\233k\249 ani person\225lu.[ENTER]\200asy jsou krut\233! Mohl bys mi pozd\236ji pomoct? "
gameforge.npc_talk._390_npcChat = "Tak jak ti jde lov? "
gameforge.npc_talk._400_sayTitle = "Lovec Yang-Shin: "
gameforge.npc_talk._40_say = "V\237t\225me![ENTER]Na\154e restaurace pat\248\237 k velk\233mu internacion\225ln\237mu[ENTER]\248et\236zci. Jednou se k n\225m pod\237vej a dej si n\236co k[ENTER]j\237dlu. "
gameforge.npc_talk._410_say = "Hmm, od t\233 doby co padaj\237 kameny Metin, divo\232\237[ENTER]n\225m zv\237\248ata. V dne\154n\237 dob\236 \232lov\236k riskuje \158ivot i[ENTER]p\248i chyt\225n\237 ku\248at. Je to pro lovce nebezpe\232n\225[ENTER]doba. Na\154t\236st\237, j\225 jsem jeden z nejlep\154\237ch! "
gameforge.npc_talk._420_npcChat = "Odkud se bere tv\225 p\248esn\225 mu\154ka? "
gameforge.npc_talk._430_say = "Jsem nejlep\154\237 s lukem. Hehe.[ENTER]Proto\158e m\225m na to speci\225ln\237 recept![ENTER]Kdy\158 sm\237ch\225\154 \154\157\225vu z broskvov\253ch kv\236t\249 a \154e\248\237k,[ENTER]dostane\154 lektvar, kter\253 ti zv\253\154\237 pravd\236podobnost[ENTER]z\225sahu. Kdy\158 donese\154 Yu-Hwanovi p\248\237sady, tak ti[ENTER]ur\232it\236 uva\248\237 tento skv\236l\253 lektvar. "
gameforge.npc_talk._440_npcChat = "P\236kn\233 kv\236tiny... "
gameforge.npc_talk._450_say = "Sb\237r\225vali jsme s bratrem broskvov\233 kv\236ty. Te\239 u\158[ENTER]mus\237m sama. Nejsou moc p\236kn\233, ale maj\237 speci\225ln\237[ENTER]\250\232inky![ENTER]Kdy\158 donese\154 jeden kv\236t Beak-Goovi, tak ti uva\248\237[ENTER]lektvar, kter\253 ti dod\225 lehkonohou ch\249zi. "
gameforge.npc_talk._460_npcChat = "Kde je tv\249j bratr? "
gameforge.npc_talk._470_say = "Touto dobou je m\249j bratr \232asto na cest\225ch.[ENTER]D\236l\225m si starosti. "
gameforge.npc_talk._480_npcChat = "Prod\225v\225\154 r\253\158ov\233 kol\225\232e? "
gameforge.npc_talk._490_sayTitle = "Prodava\232ka r\253\158ov\253ch buchet, Yu-Rang: "
gameforge.npc_talk._500_say = "Kv\249li v\225lce je t\236\158k\233 d\236lat r\253\158ov\233 buchty. Taky[ENTER]jsem ztratila hodn\236 z\225kazn\237k\249 kv\249li bandit\249m.[ENTER]U\158 nev\237m, z \232eho m\225m \158\237t. "
gameforge.npc_talk._50_say = "I kdy\158 to je velk\225 restaurace, za\248\237zen\237 je[ENTER]p\248ekvapiv\236 jednoduch\233. "
gameforge.npc_talk._510_npcChat = "Kdo od tebe obvykle nakupuje? "
gameforge.npc_talk._520_say = "Nejv\237ce prod\225v\225m poutn\237k\249m. Jednoho dne p\248ijel[ENTER]tajemn\253 jezdec a cht\236l ode mn\236 koupit r\253\158ovou[ENTER]buchtu. Nemohl zaplatit, tak mi dal nam\237sto toho[ENTER]recept. V receptu stoj\237, jak uva\248it vodu Zin.[ENTER]Lektvar zvy\154uje rychlost \250toku. Huhan-So um\237[ENTER]uva\248it takov\253 lektvar, kdy\158 mu p\248inese\154 vodu Sim[ENTER]a rododendron. "
gameforge.npc_talk._530_npcChat = "Pro\232 vypad\225\154 tak otr\225ven\236? "
gameforge.npc_talk._540_say = "Nemohla jsem tu\154it, \158e se na\154e sladk\233 sny tak[ENTER]nemilosrdn\236 zni\232\237.[ENTER]Vzlyk, vzlyk...[ENTER]Pros\237m pomsti smrt m\233ho man\158ela. "
gameforge.npc_talk._550_npcChat = "P\248\237li\154 mnoho lid\237 padlo ve v\225lce... "
gameforge.npc_talk._560_say = "Proto\158e ve v\225lce ztr\225c\237me \232\237m d\225l t\237m v\237c mu\158\249,[ENTER]daly jsme se my \158eny dohromady a poprosily[ENTER]Huahn-So, aby zlep\154il vodu Dok, kter\225 zlep\154uje[ENTER]obranu. Po dlouh\233m v\253zkumu zjistil, \158e kdy\158 p\248id\225[ENTER]k vod\236 Dok rododendron, tak je lektvar siln\236j\154\237.[ENTER]B\236\158 k n\236mu, on ti ur\232it\236 vyrob\237 z t\236ch p\248\237sad[ENTER]tento lektvar, kter\233mu \248\237k\225 voda SamBo. "
gameforge.npc_talk._570_npcChat = "Ach, jak\233 p\236kn\233 mrn\236... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "Zase p\236kn\236 k\248i\232\237...[ENTER]Jestli chce n\236co dobr\233ho nebo...[ENTER]\225le nee! "
gameforge.npc_talk._600_npcChat = "Jak se vy dv\236 m\225te? "
gameforge.npc_talk._60_npcChat = "\216ekni mi n\236co o hrn\232\237\248stv\237. "
gameforge.npc_talk._610_say = "Moje d\237t\236! Ach...[ENTER]Man\158el padl ve v\225lce. Te\239 se mus\237m oh\225n\236t, abych[ENTER]u\158ivila sama sebe a moje d\237t\236.[ENTER]S vodou Bo jsem na\154la cestu, jak trochu vylep\154it[ENTER]moje \158ivobyt\237. Mus\237m Yu-Hwangovi don\233st 100 \154\157\225v[ENTER]z kakikv\236t\249 a jednu houbu tue. On z toho uva\248\237[ENTER]vodu Bo, kter\225 jde dob\248e na odbyt. N\236\232\237m se p\248eci[ENTER]mus\237m u\158ivit. "
gameforge.npc_talk._620_npcChat = "Jak se m\225 man\158el? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "M\249j takzvan\253 mu\158 je zamilovan\253 do jeho kn\237\158ek. U\158[ENTER]se na m\236 ani nepod\237v\225.[ENTER]A to nejsem \158\225dn\225 o\154kliv\225 \158ena. "
gameforge.npc_talk._650_npcChat = "Jak jdou obchody? "
gameforge.npc_talk._660_say = "Od t\233 doby, co propukla v\225lka, n\225m k\154eft moc[ENTER]neb\236\158\237. Odbory obchodn\237k\249 byly kdysi mocn\233. Ale[ENTER]ty \232asy u\158 pominuly.[ENTER]Divochy, v\225le\232n\237ky B\237l\233 p\248\237sahy a bandu \200ern\233ho[ENTER]v\236tru u\158 nem\249\158eme ignorovat jako d\248\237v. "
gameforge.npc_talk._670_npcChat = "Pro\232 m\225\154 tak \154patnou n\225ladu? "
gameforge.npc_talk._680_sayTitle = "Taurean: "
gameforge.npc_talk._690_say = "Harang je hrozn\225 holka![ENTER]Nesn\225\154\237m ji![ENTER]Jsem slab\253 a ona mi \232asto je\154t\236 zt\236\158uje \158ivot! "
gameforge.npc_talk._700_say = "Jsi chlap a m\225\154 svaly.[ENTER]Trochu si je potr\233nuj! "
gameforge.npc_talk._70_sayTitle = "Hrn\232\237\248 Yonah: "
gameforge.npc_talk._710_npcChat = "Co zrovna d\236l\225\154? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Zatracen\253 Taurean! \200asto si spolu hrajeme a i[ENTER]bojujeme. Zbab\236lec jeden! Kdy\158 dneska nep\248ijde[ENTER]dobrovoln\236, tak ho zml\225t\237m! "
gameforge.npc_talk._740_npcChat = "Taurean se t\236 boj\237. "
gameforge.npc_talk._750_say = "R\225da si hraji s Taureanem. \200asto se taky pereme.[ENTER]A proto\158e m\225 vlastn\236 velkou s\237lu, n\236co jsem si na[ENTER]n\236j vymyslela.[ENTER]Dozv\236d\236la jsem se toti\158 od jednoho moudr\233ho[ENTER]Ninji, \158e kdy\158 se sm\237ch\225 voda Young s moru\154\237, tak[ENTER]vznikne lektvar, kter\253 zvy\154uje rychlost \250toku.[ENTER]T\237m p\225dem mohu Taureana rychleji p\248emoct - i kdy\158[ENTER]je siln\236j\154\237.[ENTER]Jestli chce\154 taky takov\253 lektvar, tak b\236\158 k[ENTER]Huhan-Soovi. On ti ho jist\236 vyrob\237. "
gameforge.npc_talk._760_npcChat = "Nov\253 pohled... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong: "
gameforge.npc_talk._780_say = "M\249j p\248\237teli, sv\236t je pln\253 nezodpov\236zen\253ch ot\225zek.[ENTER]A j\225, j\225 jsem hleda\232 v\236domost\237. Sly\154el jsi ji\158[ENTER]n\236kdy o epick\253ch zbran\237ch a Kamenech ducha? "
gameforge.npc_talk._790_npcChat = "Co d\236l\225\154? "
gameforge.npc_talk._800_say = "Pravd\236podobn\236 v\237\154, \158e hled\225m ztracen\233 v\236domosti.[ENTER]Moment\225ln\236 hled\225m metodu, jak d\225le vylep\154it[ENTER]zbran\236 a zv\253\154it s\237lu Kamen\249 ducha. "
gameforge.npc_talk._80_say = "Co se t\253\232e hrn\232\237\248sk\233ho zbo\158\237, tak je nejlep\154\237[ENTER]v\253roba na v\253chod\236 kontinentu.[ENTER]Jednou jsem vid\236l hrn\232\237\248sk\233 zbo\158\237 odtamtud a byl[ENTER]jsem z toho \250pln\236 nad\154en\253. Je\154t\236 po\248\225d to[ENTER]zkoum\225m. Nev\237m, jak\253 trik na to pou\158\237vaj\237. "
gameforge.npc_talk._810_npcChat = "V\253zkum zbran\237... "
gameforge.npc_talk._820_say = "Zaj\237mav\233, \158e? Chce\154 o tom v\236d\236t v\237ce? Tak mi[ENTER]pros\237m p\248ines n\236jakou zbra\242 \250rovn\236 65 vylep\154enou[ENTER]na +9.Tak\233 budu pot\248ebovat Strategii proti\250toku a[ENTER]dva Po\158ehnan\233 pergameny. Pokus\237m se pak vyrobit[ENTER]epickou zbra\242. "
gameforge.npc_talk._830_say = "Bohu\158el ti ale nemohu sl\237bit, \158e se to povede. "
gameforge.npc_talk._840_npcChat = "Kameny ducha... "
gameforge.npc_talk._850_say = "Kameny ducha jsou \232asto pou\158\237v\225ny, ale p\248esto[ENTER]v\236t\154ina lid\237 nezn\225 jejich skute\232nou s\237lu. Ale[ENTER]moje v\253zkumy m\236 pomohly zjistit o nich v\237ce.[ENTER]Pokud mi p\248inese\154 K\225men ducha, vylep\154\237m ho. "
gameforge.npc_talk._90_npcChat = "Na sv\249j v\236k jsi dost \232il\253.... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "Medaile hrdiny "
gameforge.olympic_badge._020_say = "Pomoz mi! "
gameforge.olympic_badge._030_say = "Zatracen\237 zlod\236ji...[ENTER]Minulou noc se vloupali do m\233ho domu![ENTER]Ukradli mi mou Medaili hrdiny! M\249j p\248edek j\237[ENTER]dostal, kdy\158 ub\236hl 42,195 km, aby donesl zpr\225vu o[ENTER]v\237t\236zstv\237 z boji\154t\236 sv\233mu panovn\237kovi.[ENTER]A te\239 je fu\232! "
gameforge.olympic_badge._040_say = "Ach jo... m\236la velk\253 v\253znam pro mou rodinu i pro[ENTER]mne. Co m\225m te\239 k \232ertu d\236lat? "
gameforge.olympic_badge._050_say = "Pom\249\158e\154 mi? "
gameforge.olympic_badge._060_npcChat = "Medaile hrdiny "
gameforge.olympic_badge._070_say = "Kone\232n\236! Jsi zp\236t![ENTER]Na\154el jsi Medaili hrdiny? "
gameforge.olympic_badge._080_say = "Ale pro\232? Co cht\236j\237 ti zlod\236ji d\236lat s mou[ENTER]medail\237? Je pro n\236 bezcenn\225! Pom\249\158e\154 mi ji naj\237t? "
gameforge.olympic_badge._090_npcChat = "Najdi Medaili hrdiny! "
gameforge.olympic_badge._100_say = "Vr\225til ses s pr\225zdn\253ma rukama? Ach ne, to je[ENTER]zklam\225n\237. Pokud mi nepom\249\158e\154 ty, tak pak kdo?[ENTER]Pros\237m, pokra\232uj v p\225tr\225n\237! "
gameforge.olympic_badge._110_say = "Na\154el jsi mou medaili![ENTER]Ale po\232kej - to je jen jej\237 kousek. Ach ne, oni[ENTER]ji rozbili na p\236t kus\249! Pros\237m, p\248ines mi v\154echny[ENTER]kusy! Mo\158n\225 se mi povede ji pak zase slepit[ENTER]dohromady. "
gameforge.olympic_badge._120_say = "Tihle zlot\248il\237 krimin\225ln\237ci \250pln\236 zni\232ili odkaz[ENTER]m\233 rodiny! D\236kuji ti, \158e jsi na\154el v\154echny kusy.[ENTER]Nyn\237 se mohu pokusit medaili d\225t op\236t dohromady. "
gameforge.olympic_badge._130_say = "Mnohokr\225t ti d\236kuji! Z\237skal jsi zp\236t \232est m\233[ENTER]rodin\236. Samoz\248ejm\236, \158e tv\233 pot\237\158e nez\249stanou bez[ENTER]odm\236ny. Tady, ber! "
gameforge.olympic_badge._140_say = "Opravdu chce\154 odm\237tnout tento \250kol? Pokud odpov\237\154[ENTER]'Ano', pozd\236ji jej ji\158 nebude\154 moci p\248ijmout[ENTER]znovu. "
gameforge.olympic_badge._150_say = "Ch\225pu, \158e nyn\237 nem\225\154 mnoho \232asu. Vra\157 se pozd\236ji,[ENTER]a\158 ti to bude v\237ce vyhovovat. Ale nenech m\236 \232ekat[ENTER]p\248\237li\154 dlouho! "
gameforge.olympic_badge._160_say = "Bohu\158el jsi p\248ijel p\248\237li\154 pozd\236 a ji\158 mi nem\249\158e\154[ENTER]pomoci. P\248eji ti v\154e dobr\233 na tv\253ch cest\225ch! "
gameforge.olympic_badge._170_say = "Vydej se na lov p\248\237\154er, kter\233 m\236 okradly! Ale bu\239[ENTER]opatrn\253, jsou velmi siln\233 - minim\225ln\236 \250rovn\236 30.[ENTER]Pokud mi p\248inese\154 zp\236t mou Medaili hrdiny, bohat\236[ENTER]se ti odm\236n\237m! "
gameforge.olympic_badge._180_say = "Najdi Medaili hrdiny a dones ji Yu-Hwanovi. "
gameforge.olympic_badge._190_say = "Yu-Hwan pot\248ebuje tvou pomoc. Zajdi za n\237m![ENTER]Najde\154 ho v druh\233 vesnici. "
