gameforge.skill_reset2._10_npcChat = "Resetovat schopnosti "
gameforge.skill_reset2._110_say = "A\158 si to rozmysl\237\154, p\248ij\239 znovu. "
gameforge.skill_reset2._120_say = "Nem\225\154 dostatek Yang\249. Bez t\236ch ti nem\249\158u pomoct.[ENTER]Z n\236\232eho toti\158 tak\233 mus\237m \158\237t. "
gameforge.skill_reset2._130_say = "Tento p\248edm\236t ti umo\158\242uje za\232\237t kompletn\236 nov\253[ENTER]v\253cvik a zapomenout na ten p\249vodn\237. Abys jej ale[ENTER]mohl pou\158\237t, mus\237\154 m\237t alespo\242 \250rove\242 31. Pak m\225\154[ENTER]ov\154em mo\158nost zm\236nit sv\249j osud. Chce\154 se odvr\225tit[ENTER]od schopnost\237, kter\233 jsi doposud z\237skal? "
gameforge.skill_reset2._135_say = "Nem\225\154 \158\225dn\253 v\253cvik a tud\237\158 ani body, kter\233 by[ENTER]bylo mo\158n\233 zresetovat! "
gameforge.skill_reset2._140_say = "Tento p\248edm\236t lze pou\158\237t pouze od \250rovn\236 31. "
gameforge.skill_reset2._20_say = "Je\154t\236 jsi neza\232al \158\225dn\253 v\253cvik! Dokud nepou\158ije\154[ENTER]body schopnost\237, nelze je resetovat. Vra\157 se,[ENTER]pokud ud\236l\225\154 ve v\253cviku chybu. Pak ti r\225da[ENTER]pomohu. "
gameforge.skill_reset2._30_say = "Ob\225v\225m se, \158e ti nemohu pomoci. Ji\158 jsi dos\225hl[ENTER]\250rovn\236 %s, ale bohu\158el m\249\158e\154 zm\236nit v\253cvik jen do[ENTER]\250rovn\236 30. "
gameforge.skill_reset2._40_say = "Nem\225\154 \158\225dn\253 v\253cvik a tud\237\158 ani body, kter\233 by[ENTER]bylo mo\158n\233 zresetovat! "
gameforge.skill_reset2._50_say = "Ahoj, u mn\236 jsi p\248esn\236 spr\225vn\236.[ENTER]Vid\237m ve tv\253ch o\232\237ch velk\233 starosti.[ENTER]Umo\158n\237m lidem zapomenout na jejich v\253cvik, aby[ENTER]mohli za\232\237t znova.[ENTER]Cht\236l bys zapomenout na tv\249j v\253cvik a za\232\237t[ENTER]znova? Stoj\237 to %s Yang\249. "
gameforge.skill_reset2._60_select = "Neresetovat "
gameforge.skill_reset2._70_say = "Hohohoo, je mo\158n\233, \158e se nec\237t\237\154 dob\248e?[ENTER]Podle tv\233ho v\253razu v obli\232eji posuzuji, \158e[ENTER]pot\248ebuje\154 pomoc.[ENTER]Nejsi spokojen se sv\253m v\253cvikem?[ENTER]Mohl bych ti umo\158nit zapomenout na tv\249j v\253cvik,[ENTER]tak lehce jako m\225vnut\237m kouzeln\233ho proutku. "
gameforge.skill_reset2._80_say = "To znamen\225, \158e tvoje dosavadn\237 investice do[ENTER]v\253cviku by byla zase k dispozici. Bohu\158el ztrat\237\154[ENTER]v\154echny body, kter\233 jsi z\237skal \232ten\237m knih.[ENTER]Chce\154 opravdu v\154e zapomenout a za\232\237t znova?[ENTER]To by st\225lo... hmm, %s Yang\249. "
gameforge.skill_reset2._90_select = "Resetovat schopnosti "
