gameforge.spider_dungeon_2floor._40_say = "Jak mysl\237\154...[ENTER]D\225vej si na sebe pozor![ENTER]Tady naho\248e to je velmi nebezpe\232n\233. "
gameforge.spider_dungeon_3floor_boss = {}
gameforge.spider_dungeon_3floor_boss._100_say = "Chce\154 mi snad \248\237ci, \158e jsi nem\236l dost odvahy k[ENTER]tomu, aby ses vydal do Pavou\232\237ho bludi\154t\236? V\158dy\157[ENTER]jsi p\248ece dost zku\154en\253 v\225le\232n\237k, pro kter\233ho by[ENTER]p\225r potvor s osmi nohama nem\236lo b\253t probl\233mem! A[ENTER]v\237\154, \158e na vstup do pavou\232\237ho bludi\154t\236 pot\248ebuje\154[ENTER]propustku? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "P\248\237stup do l\237hn\236 "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "Nov\233 nebezpe\232\237 "
gameforge.spider_dungeon_3floor_boss._120_say = "Ud\236lal jsi p\248esn\253 opis textu na n\225hrobku. Uka\158[ENTER]jej veliteli. "
gameforge.spider_dungeon_3floor_boss._130_say = "V\253born\236, zvl\225dl jsi to! Uka\158... hmmm. Tyhle znaky[ENTER]nezn\225m, nerozum\237m ani slovu. Mo\158n\225 by ses m\236l[ENTER]zeptat u\232ence Uriela. "
gameforge.spider_dungeon_3floor_boss._140_say = "Zajdi k u\232enci Urielovi a uka\158 mu opis n\225pisu.[ENTER]Mo\158n\225 \158e bude schopen jej p\248elo\158it. "
gameforge.spider_dungeon_3floor_boss._150_say = "Velitel m\236 \158\225d\225 o dek\243dov\225n\237 t\233hle tajemn\233[ENTER]zpr\225vy? No dob\248e. M\225m r\225d v\253zvy. Polo\158 ji tady.[ENTER]Tak\158e.... no ale to je p\248\237\154ern\233! Koukej! Nap\237\154i[ENTER]p\248eklad p\248\237mo na ten pap\237r a ty to dones veliteli[ENTER]tak rychle, jak jen to bude mo\158n\233 a pak se ke m\236[ENTER]vra\157. Pokud je pravda to, co se tam p\237\154e, tak[ENTER]jsme v\154ichni ve velk\233m nebezpe\232\237! B\236\158, b\236\158! "
gameforge.spider_dungeon_3floor_boss._160_say = "Ty jsi je\154t\236 nebyl u velitele? Pros\237m! Mus\237\154 si[ENTER]posp\237\154it! Nem\225me \232as k lelkov\225n\237, on si ten vzkaz[ENTER]mus\237 p\248e\232\237st co nejd\248\237ve! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Doru\232 Urielovu zpr\225vu "
gameforge.spider_dungeon_3floor_boss._180_say = "Ten star\253 hlup\225k... je prost\233 d\236kuji p\248\237li\154?[ENTER]No dobr\225. \216\237kal, \158e ta informace je extr\233mn\236[ENTER]d\249le\158it\225, tak ji rad\236ji veliteli ihned donesu. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Urielova zpr\225va "
gameforge.spider_dungeon_3floor_boss._200_say = "Ach ne! Pokud je pravda to, co se tu p\237\154e, pak ve[ENTER]t\248et\237m pat\248e pavou\232\237ho bludi\154t\236 p\248ede pavu\232iny[ENTER]pavou\232\237 d\233mon - samotn\225 pavou\232\237 baronka! Podle[ENTER]toho n\225pisu pot\248ebuje\154 speci\225ln\237 kl\237\232, aby ses[ENTER]dostal do jej\237ho skryt\233ho doup\236te. Zajdi za[ENTER]Urielem a p\248eptej se ho na ten kl\237\232. A pak si[ENTER]shrom\225\158di n\236jak\233 voj\225ky, vyraz do Pavou\232\237ho[ENTER]bludi\154t\236 a vpadni do \250krytu t\233 pavou\232\237 baronky![ENTER]Na, tady m\225\154 dal\154\237 propustku. "
gameforge.spider_dungeon_3floor_boss._20_say = "Tato br\225na m\249\158e b\253t otev\248ena pouze pavou\232\237m[ENTER]kl\237\232em. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "Pavou\232\237 kl\237\232 "
gameforge.spider_dungeon_3floor_boss._220_say = "M\236l bych naj\237t Uriela tak rychle jak jen to bude[ENTER]mo\158n\233. "
gameforge.spider_dungeon_3floor_boss._230_say = "Aha, jsi zp\236t. Tak\158e p\248edpokl\225d\225m, \158e t\236 velitel[ENTER]pov\236\248il zni\232en\237m pavou\232\237 baronky? Samoz\248ejm\236 \158e[ENTER]vstup do jej\237 jeskyn\236 je zape\232et\236n a lze jej[ENTER]otev\248\237t pouze za pomoci pavou\232\237ho kl\237\232e. Jen\158e[ENTER]jeho v\253roba je pom\236rn\236 n\225ro\232n\225. Mus\237\154 mi p\248in\233st[ENTER]pavouk\249v pytl\237k s jedem, pytl\237k s pavou\232\237mi[ENTER]vaj\237\232ky, pavu\232inu, o\232i pavouka, pavou\232\237 nohy a[ENTER]tak\233 jed kr\225lovny pavouk\249. Z toho ti jeden kl\237\232[ENTER]vyrob\237m. "
gameforge.spider_dungeon_3floor_boss._240_say = "Chce\154, abych ti vyrobil pavou\232\237 kl\237\232? Na to[ENTER]pot\248ebuji pavouk\249v pytl\237k s jedem, pytl\237k s[ENTER]pavou\232\237mi vaj\237\232ky, pavu\232inu, o\232i pavouka, pavou\232\237[ENTER]nohy a tak\233 jed kr\225lovny pavouk\249. M\225\154 v\154echny[ENTER]tyto ingredience? "
gameforge.spider_dungeon_3floor_boss._250_say = "Fantastick\233! M\225\154 v\154echny v\236ci, kter\233 pot\248ebuji k[ENTER]v\253rob\236 pavou\232\237ho kl\237\232e. Pros\237m chvilku po\232kej.[ENTER]Nem\236lo by mi to trvat dlouho... "
gameforge.spider_dungeon_3floor_boss._260_say = "Ha, hotovo! Tady, tv\249j pavou\232\237 kl\237\232! D\237ky n\236mu se[ENTER]dostane\154 do \250krytu pavou\232\237 baronky. P\248eji tob\236 i[ENTER]tv\253m kamar\225d\249m \154t\236st\237 v boji proti t\233 dlouhonoh\233[ENTER]p\248\237\154e\248e! A posp\236\154 si, ten kl\237\232 nevydr\158\237 dlouho![ENTER]Za 24 hodin se rozpadne a budeme muset vyr\225b\236t[ENTER]nov\253! "
gameforge.spider_dungeon_3floor_boss._270_say = "Uf... no, nikdo ne se nerod\237 jako mistr sv\233ho[ENTER]\248emesla. Douf\225m \158e ch\225pe\154, \158e v\253roba toho kl\237\232e[ENTER]je velmi obt\237\158n\225 a i ta sebemen\154\237 chyba m\249\158e v\233st[ENTER]k tomu, \158e se to cel\233 nezda\248\237. Bohu\158el jsem p\248i[ENTER]tom tak\233 p\248i\154el o ve\154ker\233 pavou\232\237 ingredience,[ENTER]kter\233 jsi mi dal, tak\158e je bude\154 muset nasb\237rat[ENTER]znovu. Ale p\248\237\154t\236 se n\225m to jist\236 povede! "
gameforge.spider_dungeon_3floor_boss._280_say = "N\236co n\225m st\225le chyb\237... nemohu vyrobit pavou\232\237[ENTER]kl\237\232. Tady je seznam toho, co pot\248ebujeme:[ENTER]pavouk\249v pytl\237k s jedem, pytl\237k s pavou\232\237mi[ENTER]vaj\237\232ky, pavu\232inu, o\232i pavouka, pavou\232\237 nohy a[ENTER]tak\233 jed kr\225lovny pavouk\249. "
gameforge.spider_dungeon_3floor_boss._300_say = "Tv\249j velitel skupiny vstoupil do bludi\154t\236. Chce\154[ENTER]jej n\225sledovat? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "Reset SD3 \250kolu "
gameforge.spider_dungeon_3floor_boss._310_say = "Trvalo ti to moc dlouho. Kl\237\232 se rozpadl. Bude\154[ENTER]muset vyrobit nov\253, abys z\237skal p\248\237stup do t\233to[ENTER]lokality. "
gameforge.spider_dungeon_3floor_boss._320_say = "V hn\237zd\236 pavou\232\237 baronky se moment\225ln\236 nach\225z\237[ENTER]jin\225 skupina, kter\225 se ji sna\158\237 zab\237t. "
gameforge.spider_dungeon_3floor_boss._330_say = "M\249\158e\154 vstoupit pouze pokud p\248edchoz\237 skupina ji\158[ENTER]dokon\232ila svou misi. Pros\237me, vra\157 se za %s[ENTER]minut. "
gameforge.spider_dungeon_3floor_boss._340_say = "\200ekac\237 doba, kdy se znovu otev\248e br\225na do hn\237zda[ENTER]pavou\232\237 baronky: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s minut "
gameforge.spider_dungeon_3floor_boss._360_say = "V\225le\232n\237k, kter\253 vstoupil do jeskyn\236 p\248ed tebou se[ENTER]m\249\158e znovu za\232\237t pohybovat a\158 po deseti[ENTER]vte\248in\225ch. Pros\237me, chvilku po\232kej. "
gameforge.spider_dungeon_3floor_boss._370_say = "Chce\154 za\232\237t s \250kolem? Bude\154 m\237t na jeho dokon\232en\237[ENTER]20 minut. A\158 do vypr\154en\237 tohoto \232asu nebude nikdo[ENTER]moci opustit l\237he\242 pavou\232\237 baronky.[ENTER]Ne\158 bude\154 moci zkusit \250kol znovu, bude muset[ENTER]uplynout jedna hodina. "
gameforge.spider_dungeon_3floor_boss._380_say = "Pot\248ebuje\154 pavou\232\237 kl\237\232, abys otev\248el br\225nu. "
gameforge.spider_dungeon_3floor_boss._390_say = "Jen velitel skupiny m\249\158e pou\158\237t pavou\232\237 kl\237\232. "
gameforge.spider_dungeon_3floor_boss._400_say = "Pavou\232\237 baronka byla pora\158ena! Do t\248\237 minut budou[ENTER]v\154ichni v\225le\232n\237ci teleportov\225ni pry\232 z jeskyn\236. "
gameforge.spider_dungeon_3floor_boss._40_say = "P\248ed v\253robou kl\237\232e "
gameforge.spider_dungeon_3floor_boss._410_say = "To nefunguje! Zkus to znovu! "
gameforge.spider_dungeon_3floor_boss._420_notice = "Pozor: pavou\232\237 baronka za\232\237n\225 b\253t zu\248iv\225! Jej\237[ENTER]\250toky budou siln\236j\154\237, ale to j\237 z\225rove\242 oslab\237 v[ENTER]obran\236. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "Pavou\232\237 bludi\154t\236 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ach, to je dob\248e \158e jsi tady. M\225m pro tebe[ENTER]d\249le\158itou informaci: na\154i zv\236di objevili t\248et\237[ENTER]patro v Pavou\232\237m bludi\154ti. Tato nov\225 \250rove\242 je[ENTER]men\154\237 ne\158 ty, kter\233 zn\225me, ale d\225 se[ENTER]p\248edpokl\225dat, \158e se tam budou vyskytovat mnohem[ENTER]nebezpe\232n\236j\154\237 pavouci, ne\158 s jak\253mi jsme se dosud[ENTER]v t\233to lokalit\236 setkali. A k tomu v\154emu je\154t\236[ENTER]zv\236di objevili star\253 n\225hrobn\237 k\225men, ale[ENTER]nepovedlo se jim z n\236j opsat n\225pis. Vydej se tedy[ENTER]do t\233to nov\233 oblasti a opi\154 pro m\236 ten n\225pis.[ENTER]Tady m\225\154 propustku, aby ses tam dostal. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "N\225pis "
gameforge.spider_dungeon_3floor_boss._80_say = "Ve t\248et\237m pat\248e Pavou\232\237ho bludi\154t\236 najde\154 star\253[ENTER]n\225hrobn\237 k\225men, na kter\233m je vyryt n\225pis. Opi\154 si[ENTER]jej a dones kopii veliteli. "
gameforge.spider_dungeon_3floor_boss._90_say = "Perfektn\237, na\154el jsi star\253 n\225hrobn\237 k\225men a opsal[ENTER]sis n\225pis! Vra\157 se k veliteli a uka\158 mu opis. "
