gameforge.subquest_10._200_say = "Ach, moc ti d\236kuji. Jsem tak \154\157astn\225, kone\232n\236 m\225m[ENTER]svou zamilovanou vl\225sni\232ku zp\236t! Po\248\225d mi tak[ENTER]pom\225h\225\154... jak se ti jen odvd\236\232\237m? M\225m jezdeck\253[ENTER]l\237stek. V\237m \158e to nen\237 nic speci\225ln\237ho, ale j\225[ENTER]jej ji\158 nepot\248ebuji, proto\158e u\158 nechci opustit[ENTER]sv\249j obchod. Vem si jej jako v\253raz m\233ho vd\236ku. "
gameforge.subquest_10._20_say = "Pros\237m posly\154. Jsem v nep\248\237zniv\233 situaci.[ENTER]Na chvilku jsem opustila obchod, proto\158e jsem[ENTER]musela vy\248\237dit n\236co d\249le\158it\233ho. B\236hem m\233[ENTER]nep\248\237tomnosti mi n\236kdo ukradl moji nejobl\237ben\236j\154\237[ENTER]vl\225sni\232ku. "
