gameforge.subquest_11._110_npcChat = "Vid\236l jsi Mirinina bratra? "
gameforge.subquest_11._120_say = "Zamiloval jsem se, ani\158 bych v\236d\236l, co l\225ska[ENTER]znamen\225.... Lalal\225 Koho hled\225\154? Mirinina bratra?[ENTER]Chvilku jsme se bavili, ne\158 se vydal do hor[ENTER]hledat vz\225cn\233 byliny...[ENTER]Ale kde je te\239, nev\237m.[ENTER]Lovec z na\154\237 vesnice chod\237v\225 \232asto do kopc\249. Pro\232[ENTER]se nezept\225\154 jeho?[ENTER]l\225lal\225... l\225ska je smutn\225, ale kr\225sn\225. "
gameforge.subquest_11._130_targetVid = "Zeptej se Yang-Shina na Mirinina bratra. "
gameforge.subquest_11._140_say = "Kdo? Mirinin bratr? Hled\225val byliny v hor\225ch.[ENTER]Byl opravdu \154\157astn\253, kdy\158 na\154el n\236jakou vz\225cnou.[ENTER]Cht\236l sv\233 sest\248e koupit nov\233 \154aty a\158 je prod\225. Je[ENTER]opravdu mil\253. Mysl\237m, \158e za p\225r dn\249 bude zp\236t. Co[ENTER]mysl\237\154? "
gameforge.subquest_11._150_targetVid = "Vypr\225v\236j ty novinky Mirine. "
gameforge.subquest_11._160_npcChat = "Novinky o Mirinin\236 bratru. "
gameforge.subquest_11._170_say = "Ach! Dopis od m\233ho bratra. Tentokr\225t na\154el[ENTER]opravdu hodn\236 bylin. P\237\154e, \158e to bude chvilku[ENTER]trvat, ne\158 se vr\225t\237. Omlouv\225m se, nem\236la jsem t\236[ENTER]s t\237m obt\236\158ovat. Nem\225m moc, ale douf\225m \158e to[ENTER]p\248ijme\154 jako mou omluvu. D\236kuji ti za tvou tvrdou[ENTER]pr\225ci. "
gameforge.subquest_11._180_sayReward = "Obdr\158\237\154 122 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 5 000 Yang\249. "
gameforge.subquest_11._20_npcChat = "Najdi m\233ho bratra. "
gameforge.subquest_11._30_say = "M\249\158u t\236 poprosit o laskavost?[ENTER]M\249j bratr je u\158 dlouho pry\232 a zat\237m se mi v\249bec[ENTER]neozval.[ENTER]Pomalu si d\236l\225m starosti.[ENTER]Jestli toho po tob\236 nechci moc, mohl by ses vydat[ENTER]ho j\237t hledat? "
gameforge.subquest_11._40_say = "M\249j bratr cht\236l nav\154t\237vit hudebn\237ka Yu-Hwana v[ENTER]sousedn\237 vesnici. Pokud za Yu-Hwanem zajde\154,[ENTER]jist\236 ti \248ekne n\236jak\233 novinky o m\233m bratrovi.[ENTER]D\236kuji p\248edem. "
gameforge.subquest_11._50_select = "Vy\248\237d\237m "
gameforge.subquest_11._60_say = "Che\154 ten \250kol na v\158dy vzd\225t? "
gameforge.subquest_11._70_say = "D\236kuji.[ENTER]Pros\237m najdi mi ho.[ENTER]D\236l\225m si velk\233 starosti.[ENTER]Tak zat\237m. "
gameforge.subquest_11._80_say = "\138koda, \158e mi nechce\154 pomoct.[ENTER]Tak zat\237m. "
gameforge.subquest_11._90_say = "Chce\154 se vydat mi ho hledat?[ENTER]Moc ti d\236kuji, d\236l\225m si o n\236j velk\233 starosti.[ENTER]Hodn\236 \154t\236st\237. "
