gameforge.subquest_13._130_npcChat = "Ich brauche Eisenerz "
gameforge.subquest_13._140_say = "Ty pot\248ebuje\154 \158eleznou rudu? Mo\158n\225 ti n\236co d\225m,[ENTER]kdy\158 pro mn\236 n\236co ud\236l\225\154... "
gameforge.subquest_13._150_say = "Kdy\158 jsem ut\237kal p\248ed tygry, n\236co jsem ztratil:[ENTER]bal\237\232ek, kter\253 obsahoval d\249le\158it\233 knihy, kter\233[ENTER]byly p\248ev\225z\225ny l\225tkou. Pokud je nebudu m\237t,[ENTER]nemohu pokra\232ovat v m\233m v\253zkumu kamen\249 Metin.[ENTER]P\248ines mi ten bal\237\232ek a dostane\154 \158eleznou rudu. "
