gameforge.subquest_13._170_say = "D\237ky![ENTER]M\225m pocit, \158e t\236 pros\237m o laskavosti moc \232asto.[ENTER]Tady m\225\154 tu \158eleznou rudu.[ENTER]Douf\225m \158e spln\237 sv\249j \250\232el. "
gameforge.subquest_13._180_say = "Co\158e? Ty chce\154 je\154t\236 v\237ce \158elezn\233 rudy? Abys[ENTER]v\236d\236l, tak neroste na stromech! N\236jakou ti d\225m,[ENTER]ale prvn\236 mi ud\236l\225\154 laskavost. Tyg\248i mi ukradli[ENTER]bal\237\232ek. Byly v n\236m velmi d\249le\158it\233 knihy a j\225 je[ENTER]ztratil, kdy\158 jsem p\248ed nimi ut\237kal o \158ivot.[ENTER]Pokud je nebudu m\237t, nemohu pokra\232ovat ve v\253zkumu[ENTER]kamen\249 metin. Tak\158e mi pros\237m najdi ten bal\237\232ek. "
gameforge.subquest_13._190_say = "To u\158 jsem ti p\248eci dal.[ENTER]U\158 jsi to zapomn\236l? "
gameforge.subquest_13._200_sayTitle = "Na\154el jsi ten bal\237\232ek "
gameforge.subquest_13._20_npcChat = "Materi\225l na zbran\236. "
gameforge.subquest_13._210_say = "Na\154el jsi Uriel\249v bal\237\232ek.[ENTER]Vra\157 se k n\236mu. "
gameforge.subquest_13._220_npcChat = "D\236j mi pl\225tno. "
gameforge.subquest_13._230_say = "Tak\158e ty hled\225\154 pl\225tno. Pros\237mt\236, dej tenhle[ENTER]dopis m\233 p\248\237telkyni Ah-Yu. Nevid\236li jsme se ji\158[ENTER]docela dlouho, proto\158e ona se te\239 po\248\225d mus\237[ENTER]starat o sv\233 d\237t\236. Nebude ti to trvat dlouho a[ENTER]nen\237 to nic slo\158it\233ho. J\237 jsem dala m\233 pl\225tno.[ENTER]\216ekni j\237, \158e ho pot\248ebuje\154 a ona ti ho d\225. "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Ur\232it\236 jsi od Ah-Yu dostal pl\225tno, \158e? "
gameforge.subquest_13._250_npcChat = "Dopis od Ariyoung "
gameforge.subquest_13._260_say = "Dopis od Ariyoung? Je mil\233 o n\237 sly\154et po tak[ENTER]dlouh\233 dob\236. Docela \232asto jsme se nav\154t\236vovali a[ENTER]pov\237dali si. Ale pozd\236ji se to stalo obt\237\158n\233.[ENTER]Po\232kej. Tady se p\237\154e, \158e pot\248ebuje\154 pl\225tno?[ENTER]Ariyoung mi kdysi n\236jak\233 dala, tak ti z n\236j mohu[ENTER]trochu d\225t. D\236kuji, \158e jsi mi donesl ten dopis.[ENTER]Odep\237\154i j\237 brzy... "
