gameforge.subquest_13._30_say = "Hey, mus\237\154 pro mn\236 je\154t\236 n\236co ud\236lat.[ENTER]Pokou\154\237m se vyr\225b\236t nov\233 druhy zbran\237.[ENTER]Nen\237 lehk\233 naj\237t na to ten spr\225vn\253 materi\225l.[ENTER]M\225m hodn\236 objedn\225vek a nemohu sh\225n\236t s\225m[ENTER]materi\225l. Mohl bys mi je sehnat? "
gameforge.subquest_13._310_say = "V\253born\236. Jsi opravdu velmi rychl\253. Te\239 m\236 nech[ENTER]d\236lat na t\236ch zbran\237ch![ENTER]*bum, cink, bum*[ENTER]Tak, tady jsou. To jsou nov\233 typy zbran\237.[ENTER]Sna\158il jsem se. Douf\225m, \158e se ti l\237b\237. U\158ij si je! "
