gameforge.subquest_16._120_say = "\142ivot je kr\225sn\253... a l\225ska je taky kr\225sn\225... Ach![ENTER]To jsi zase ty! Co zas chce\154?[ENTER]Informace o panc\233\248ovan\233 kaval\233rii?[ENTER]Pro\232 se m\236 na n\236 pt\225\154? Velitel mus\237 m\237t asi velk\233[ENTER]pl\225ny, \158e? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan: "
gameforge.subquest_16._140_say = "Z t\233 doby se nedochovaly \158\225dn\233 p\237semnosti, ale j\225[ENTER]zn\225m n\236jak\233 p\237sn\236, kde se o panc\233\248ov\233 kaval\233rii[ENTER]zp\237v\225. Po\232kej, jen si nalad\237m n\225stroj....[ENTER]Aha, ty sp\236ch\225\154? Dnes ji\158 nikdo nem\225 \232as[ENTER]poslouchat... Dobr\225. Jednodu\154e \248e\232eno, Isupova[ENTER]kaval\233rie byla t\233m\236\248 neporaziteln\225. V\253te\232n\236[ENTER]vycvi\232en\237 voj\225ci, t\236\158k\225 zbroj a a p\248itom m\236li[ENTER]pohyblivost a rychlost. "
gameforge.subquest_16._150_say = "Byla to nejlep\154\237 arm\225da, jakou kdy tento[ENTER]kontinent vid\236l. Mnoho zem\237 jim podlehlo, proto\158e[ENTER]nic nebylo schopno jim vzdorovat. Dnes by to[ENTER]mohlo b\253t podobn\233. Ale pot\248ebuje\154 tvrd\233[ENTER]tr\233ninkov\233 metody a spoustu kvalitn\237ho \158eleza,[ENTER]abys takovou arm\225du postavil. M\236l by ses zeptat[ENTER]obchodn\237ho cestuj\237c\237cho a Uriela, pravd\236podobn\236[ENTER]budou v\236d\236t v\237c. "
gameforge.subquest_16._160_makequestbutton = "Jdi k obchodn\237mu cestuj\237c\237mu "
gameforge.subquest_16._170_qSetTitle = "Panc\233\248ovan\225 kaval\233rie "
gameforge.subquest_16._180_targetVid = "Obchodn\237 cestuj\237c\237: "
gameforge.subquest_16._190_sayReward = "Hudebn\237k Yu-Hwan \248\237k\225, \158e obchodn\237 cestuj\237c\237 a[ENTER]u\232enec Uriel by mohli m\237t informace o panc\233\248ov\233[ENTER]kavalerii. Nejprve jdi za obchodn\237m cestuj\237c\237cm. "
gameforge.subquest_16._200_sayTitle = "Obchodn\237 cestuj\237c\237: "
gameforge.subquest_16._20_npcChat = "Panc\233\248ovan\225 kaval\233rie "
gameforge.subquest_16._210_say = "Co chce\154 od takov\233ho jednoduch\233ho obchodn\237ka,[ENTER]jako jsem j\225? \142elezn\233 brn\236n\237 panc\233\248ovan\233[ENTER]kaval\233rie? Koho to zaj\237m\225? To jsou star\233[ENTER]pov\237da\232ky. Mus\237m si vyd\236lat na \158ivobyt\237 a nemohu[ENTER]se vykec\225vat cel\233 dny! "
gameforge.subquest_16._220_say = "Je to \232\237m d\225l t\236\158\154\237 si vyd\236lat na j\237dlo. Od t\233[ENTER]doby, co tyhle kameny padaj\237 z nebes, m\225m... Co[ENTER]\248\237k\225\154? Aha, kaval\233rie.[ENTER]Pokud v\237m, nosili speci\225ln\237 brn\236n\237 a jeho v\253roba[ENTER]vy\158aduje zvl\225\154tn\237 znalosti. Bylo to to nejlep\154\237[ENTER]brn\236n\237, jak\233 kdy bylo vyrobeno! No\158e a dokonce i[ENTER]\154\237py j\237m nemohly proniknout. "
gameforge.subquest_16._230_say = "\142e takov\233 brn\236n\237 bylo n\236co \250pln\236 zvl\225\154tn\237ho, se[ENTER]d\225 poznat podle pen\236z, kter\253ch bylo zapot\248eb\237 na[ENTER]postaven\237 kaval\233rie. \216\237k\225 se, \158e na n\236j bylo[ENTER]pot\248eba poklad\249 z cel\253ch kr\225lovstv\237! Kdybych[ENTER]tohle brn\236n\237 prod\225val, m\236l bych do smrti[ENTER]vystar\225no... "
gameforge.subquest_16._240_say = "Dnes m\249\158e b\253t brn\236n\237 vyrobeno dokonce z kamen\249[ENTER]Metin. S t\237mto nov\253m typem brn\236n\237 ji\158 nen\237 jen[ENTER]sen postavit novou panc\233\248ovou kavalerii. Ale moc[ENTER]mluv\237m, mus\237m prod\225vat. M\236j se! "
gameforge.subquest_16._250_sayTitle = "Panc\233\248ovan\225 kaval\233rie "
gameforge.subquest_16._260_say = "Obchodn\237 cestuj\237c\237 v\236d\236l n\236co o brn\236n\237 panc\233\248ov\233[ENTER]kavalerie. Te\239 jdi do vedlej\154\237 vesnice za Urielem[ENTER]a zeptej se ho na v\253cvik. "
gameforge.subquest_16._270_sayTitle = "Uriel: "
gameforge.subquest_16._280_say = "Co t\236 ke mn\236 zav\225d\237 tentokr\225t?[ENTER]Panc\233\248ovan\225 kaval\233rie?[ENTER]...no jist\236, \158e o n\237 n\236co v\237m![ENTER]Ka\158d\253 o n\237 n\236co v\237. Asi bude nav\158dy v d\236jin\225ch[ENTER]zaps\225na jako nejlep\154\237 arm\225da v\154ech dob. Ono je[ENTER]kolem n\237 spousta m\253t\249, ale tito jezdci byly[ENTER]opravdu nejob\225van\236j\154\237 voj\225ci - a po pr\225vu. "
gameforge.subquest_16._290_say = "D\237ky tvrd\233mu tr\233ninku p\248eva\158ovala panc\233\248ovan\225[ENTER]kaval\233rie nad v\154emi ostatn\237mi.[ENTER]Jen ti nejlep\154\237 z nejlep\154\237ch \250sp\236\154n\236 absolvovali[ENTER]v\253cvik.[ENTER]Nezn\225m moc t\236ch, co by dneska p\248est\225li stejn\253[ENTER]tr\233nink jako tenkr\225t. "
gameforge.subquest_16._300_say = "D\225m ti podrobn\233 informace o v\253cviku, aby sis mohl[ENTER]ud\236lat p\248esn\236j\154\237 p\248edstavu.[ENTER]V\237m, \158e zu\248\237 stra\154n\233 v\225lky, ale nejsem si jist\253,[ENTER]jestli by to byl dobr\253 n\225pad postavit je\154t\236[ENTER]jednou takovou hr\249zostra\154nou arm\225du. "
gameforge.subquest_16._30_say = "M\225m pro tebe nov\253 \250kol.[ENTER]M\225\154 povel naj\237t informace o panc\233\248ovan\233[ENTER]kaval\233rii. Byla to nejd\249le\158it\236j\154\237 jednotka v[ENTER]arm\225d\236 p\249vodn\237ho kr\225le Isupa, sjednotitele[ENTER]kontinentu. Panc\233\248ovan\225 kaval\233rie se kv\249li jej\237[ENTER]obdivuhodn\233 rychlosti a \250to\232n\233 s\237le ob\225valy[ENTER]v\154echny zem\236. "
gameforge.subquest_16._310_say = "Jdi za velitelem a pov\236z mu v\154echno, co ses[ENTER]dozv\236d\236l o panc\233\248ovan\233 kaval\233rii. "
gameforge.subquest_16._320_makequestbutton = "Jdi za velitelem "
gameforge.subquest_16._330_npcChat = "Zpr\225va o panc\233\248ovan\233 kaval\233rii "
gameforge.subquest_16._340_sayTitle = "Velitel "
gameforge.subquest_16._350_say = "Tak co, zjistil jsi n\236co? Pov\237dej...[ENTER]Aha, tak\158e to nen\237 nic v\237c ne\158 t\236\158k\233 brn\236n\237 a[ENTER]tvrd\253 tr\233nink? Pak je to tedy mo\158n\233! Takov\225[ENTER]arm\225da by mohla spojit v\154echny t\248i kr\225lovstv\237! "
gameforge.subquest_16._360_say = "Ale budu pot\248ebovat spoustu pen\236z. A spoustu[ENTER]dobr\253ch kov\225\248\249. A dobrovoln\237ky, kte\248\237 by[ENTER]podstoupili ten tvrd\253 tr\233nink. Nene, ned\237vej se[ENTER]na m\236 tak. Ty jsi ji\158 ud\236lal dost. "
gameforge.subquest_16._370_say = "Tady si vezmi svou odm\236nu a odpo\232i\242 si. Uvid\237me[ENTER]se pozd\236ji! "
gameforge.subquest_16._380_sayReward = "Obdr\158\237\154 150 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 30 000 Yang\249.[ENTER]Obdr\158\237\154 zlat\233 n\225u\154nice. "
gameforge.subquest_16._40_say = "S informacemi, kter\233 jsi z\237skal, m\249\158eme pos\237lit[ENTER]na\154i vojenskou s\237lu. Nejd\248\237v nav\154tiv hudebn\237ka[ENTER]Yu-Hwana. Jsem si jist, \158e v\237 o Isupov\236 kaval\233rii[ENTER]hodn\236. "
gameforge.subquest_16._50_say = "Jak chce\154. Uvid\237me se pozd\236ji. "
gameforge.subquest_16._60_say = "Zdalipak n\236kdy dostanu takovou kaval\233rii na[ENTER]povel? Bud' opatrn\253. "
gameforge.subquest_16._70_say = "D\237ky, d\225vej na sebe pozor. "
gameforge.subquest_16._80_sayTitle = "Panc\233\248ovan\225 kaval\233rie "
gameforge.subquest_16._90_sayReward = "Velitel \248\237k\225, \158e hudebn\237k Yu-Hwan z vedlej\154\237[ENTER]vesnice m\225 informace o panc\233\248ovan\233 kaval\233rii.[ENTER]Jdi za Yu-Hwanem, a zeptej se ho. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Promluv si s obchodnic\237 se sm\237\154en\237m zbo\158\237m "
gameforge.subquest_17._10_targetVid = "P\248\237b\236h man\158ela Ariyoung "
gameforge.subquest_17._110_say = "Jdi za obchodnic\237 se sm\237\154en\237m zbo\158\237m a zeptej se[ENTER]j\237 na man\158ela Ariyoung. "
gameforge.subquest_17._120_npcChat = "Man\158el Ariyoung "
gameforge.subquest_17._130_say = "To je smutn\253 p\248\237b\236h. Tak\158e ona nev\237, co se s[ENTER]jej\237m man\158elem stalo? Je na m\237st\236, odkud se je\154t\236[ENTER]nikdy nikdo nevr\225til...[ENTER]Jednoho dne ode\154el se zbo\158\237m zp\225tky do sv\233[ENTER]vesnice a banda \200ern\233ho v\236tru ho unesla a zabila. "
gameforge.subquest_17._140_say = "Ob\225v\225m se, \158e bude velmi zoufal\225, kdy\158 j\237 to[ENTER]\248ekne\154. Velice se milovali... Ale m\236l bys j\237 to[ENTER]p\248esto \248\237ct, nebo ji nejistota zabije. "
gameforge.subquest_17._150_targetVid = "\138patn\233 zpr\225vy "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "Obchodnice se sm\237\154en\253m zbo\158\237m m\225 \154patn\233 zpr\225vy.[ENTER]Jdi za Ariyoung a sd\236l j\237 informace o smrti[ENTER]jej\237ho man\158ela. "
gameforge.subquest_17._180_npcChat = "Tv\249j man\158el zem\248el... "
gameforge.subquest_17._190_say = "Co... co to \248\237k\225\154? On... byl zabit bandou \200ern\233ho[ENTER]v\236tru? Ach ne... je mrtv\253... co si bez n\236j po\232nu? "
gameforge.subquest_17._200_say = "Mohl bys mi pros\237mt\236 p\248in\233st t\236lo m\233ho man\158ela?[ENTER]Pak mu budu moci aslepo\242 \248\237ci sbohem. Anebo,[ENTER]pokud nen\237 mo\158n\233 jeho t\236lo p\248in\233st, p\248ines mi[ENTER]alespo\242 n\236jakou vzpom\237nku. Jsem si jista, \158e[ENTER]Goo-Pae z bandy \200ern\233ho v\236tru bude n\236co m\237t.[ENTER]Pros\237m, p\248ines mi cokoliv, co pat\248ilo m\233mu[ENTER]man\158elovi. "
gameforge.subquest_17._20_say = "Ji\158 je to hodn\236 dlouho, co jsem naposledy sly\154ela[ENTER]a om\233m man\158elovi. Tolik se boj\237m. Douf\225m, \158e se[ENTER]mu nic nestalo. J\225 v\237m: kdy\158 se ned\225 nic d\236lat,[ENTER]zb\253vaj\237 jen obavy. Ale m\233 srdce bije tak rychle,[ENTER]a j\225 jej nemohu uti\154it. "
gameforge.subquest_17._210_select = "Ano, pomohu ti. "
gameforge.subquest_17._220_say = "Vra\157 se, a\158 si to rozmysl\237\154.[ENTER]Pros\237m... "
gameforge.subquest_17._230_say = "Ty jsi nic nena\154el? P\248esto ti d\236kuji...[ENTER]Ach, j\225 uboh\225! "
gameforge.subquest_17._240_say = "Nedovede\154 si p\248edstavit, jak ti jsem vd\236\232n\225.[ENTER]Modl\237m se za tebe. "
gameforge.subquest_17._250_sendLetter = "Zabij Goo-Paey "
gameforge.subquest_17._260_say = "Banda \200ern\233ho v\236tru oloupila a zabila man\158ela[ENTER]Ariyoung. Zab\237jej Goo-pae tak dlouho, dokud z[ENTER]nich nez\237sk\225\154 na man\158ela Ariyoung n\236jakou[ENTER]upom\237nku. "
gameforge.subquest_17._270_npcChat = "O tv\233m man\158elovi... "
gameforge.subquest_17._280_say = "Jak to \154lo? Na\154el jsi n\236jakou upom\237nku na m\233ho[ENTER]man\158ela? Byl pro mne cel\253 sv\236t. Opravdu nic? "
gameforge.subquest_17._290_select = "Zat\237m ne, ale budu pokra\232ovat. "
gameforge.subquest_17._300_say = "Goo-Paey z bandy \200ern\233ho v\236tru nejsou lehk\225[ENTER]ko\248ist. Odpo\232i\242 si trochu.[ENTER]D\237ky za pomoc. "
gameforge.subquest_17._30_say = "Douf\225m, \158e obchodnice n\236co o m\233m man\158elovi[ENTER]zaslechla. M\225 hodn\236 z\225kazn\237k\249, mo\158n\225 \158e j\237 n\236kdo[ENTER]n\236co vypr\225v\236l. "
gameforge.subquest_17._310_say = "Tak to budu muset \232ekat na dal\154\237ho hrdinu, kter\253[ENTER]mi pom\249\158e.[ENTER]Sbohem. "
gameforge.subquest_17._320_say = "To je moc mil\233.[ENTER]Pros\237m dones mi pam\225tku na m\233ho man\158ela. "
gameforge.subquest_17._330_sendLetter = "Snubn\237 prsten Ariyoung "
gameforge.subquest_17._340_targetVid = "Jdi za Ariyoung "
gameforge.subquest_17._350_sayTitle = "Jdi za Ariyoung "
gameforge.subquest_17._360_say = "U jednoho ze zabit\253ch Goo-Pae jsi na\154el snubn\237[ENTER]prsten Ariyoung. Neum\237\154 si p\248edstavit lep\154\237[ENTER]vzpom\237nku. Dones prsten Ariyoung. "
gameforge.subquest_17._370_npcChat = "Na\154el jsem ten prsten. "
gameforge.subquest_17._380_say = "Tento prsten... je m\249j snubn\237 prsten! Mockr\225t[ENTER]d\236kuji! Te\239 m\249\158e m\249j man\158el odpo\232\237vat v pokoji.[ENTER]Zakopu ten prsten spole\232n\236 s jedn\237m dopisem pro[ENTER]man\158ela.[ENTER]Ode dne\154ka budu \158\237t sama.[ENTER]Ale aspo\242 m\225m jeho prsten![ENTER]To je dobr\253 pocit.[ENTER]D\236kuji ti mnohokr\225t. "
gameforge.subquest_17._390_sendLetter = "\218kol dokon\232en! "
gameforge.subquest_17._400_say = "Lid\233 mluv\237 o tv\253ch \232inech pro Ariyoung.[ENTER]Hodn\236 jich oce\242uje tvoji pomoc. "
gameforge.subquest_17._40_select = "Jdu k obchodnici. "
gameforge.subquest_17._410_sayReward = "Obdr\158\237\154 300 000 bod\249 zku\154enost\237. "
gameforge.subquest_17._420_sayReward = "Obdr\158\237\154 10 000 Yang\249. "
gameforge.subquest_17._50_select = "Ne, nem\225m \232as. "
gameforge.subquest_17._60_say = "Che\154 ten \250kol na v\158dy vzd\225t? "
gameforge.subquest_17._70_say = "Vra\157 se, a\158 si to rozmysl\237\154.[ENTER]Pros\237m... "
gameforge.subquest_17._80_say = "Nem\225\154 \232as?[ENTER]Nem\225\154 \232as pro tak snadn\253 \250kol?[ENTER]Dob\248e tedy... "
gameforge.subquest_17._90_say = "D\237ky, \158e jsi tak hodn\253.[ENTER]Ach, kde jenom m\249j man\158el m\249\158e b\253t.... "
gameforge.subquest_18 = {}
gameforge.subquest_18._100_say = "Hledej mu\158e, \232touc\237ho b\225sn\236 a nos\237c\237ho roztrhan\233[ENTER]hadry a promluv si s n\237m. "
gameforge.subquest_18._10_targetVid = "Kam se schoval? "
gameforge.subquest_18._110_npcChat = "Kde je tv\249j man\158el? "
gameforge.subquest_18._120_say = "Nev\237m, kde se m\249\158e schov\225vat. Je v tom opravdu[ENTER]dobr\253, je t\236\158k\233 ho naj\237t. M\236la bych na jeho krk[ENTER]pov\236sit zvone\232ek, jak mi doporu\232ila obchodnice. "
gameforge.subquest_18._130_npcChat = "Najdi Soona! "
gameforge.subquest_18._140_say = "Sly\154\237\154 kr\225snou b\225se\242... Om\225men slovy n\225sleduje\154[ENTER]zvuk hlasu a\158 naraz\237\154 na mu\158e v roztrhan\253ch[ENTER]hadrech...[ENTER]To mus\237 b\253t man\158el Aranyo![ENTER][ENTER]Ji\158 se chce\154 oto\232it a odej\237t, kdy\158 t\236 za rameno[ENTER]chyt\237 jeho ruk... "
gameforge.subquest_18._150_say = "Ty nejsi odsud.[ENTER]Poslala t\236 moje \158ena?[ENTER][ENTER]Sakra! V\237 kdo jsem! Co mu jen \248eknu? "
gameforge.subquest_18._153_select = "Jen proch\225z\237m. "
gameforge.subquest_18._157_select = "No, vlastn\236 "
gameforge.subquest_18._160_say = "Ah\225. T\236\154\237 m\236, haha.[ENTER]Kr\225sn\233 po\232as\237, co?[ENTER]\200etl jsi posledn\237 dobou n\236jakou kn\237\158ku?[ENTER]\200tu zrovna kn\237\158ku od Oja.[ENTER]M\249\158u ti ji v\248ele doporu\232it. "
gameforge.subquest_18._170_say = "M\225m pravdu, \158e? M\225 \158ena po\248\225d mluv\237, tak\158e nem\225m[ENTER]\232as si doma v klidu nic p\248e\232\237st. Ona mi nerozum\237[ENTER]a po\248\225d pos\237l\225 lidi, aby mne hledali... Ty jsi[ENTER]mne na\154el zde, ale j\225 chod\237m v\154ude. Co kdybys j\237[ENTER]ne\248ekl, \158e jsi mne na\154el? D\225m ti za to n\236jakou[ENTER]dobrou radu na lov. "
gameforge.subquest_18._180_sendLetter = "Zp\236t k Aranyo "
gameforge.subquest_18._190_say = "Vra\157 se k Aranyo a \248ekni j\237, \158e jsi Soona nena\154el. "
gameforge.subquest_18._200_npcChat = "Soonovo tajemstv\237 "
gameforge.subquest_18._20_sayTitle = "Aranyo: "
gameforge.subquest_18._210_say = "Nemohl jsi ho naj\237t?[ENTER]Dokonce jsem nastavila pasti. Kam se k \232ertu[ENTER]schoval? M\225m tolik pr\225ce.[ENTER]Takov\253 b\237dn\253 osud. "
gameforge.subquest_18._220_sendLetter = "Zp\236t k Soonovi "
gameforge.subquest_18._230_say = "Vra\157 se k Soonovi a \248ekni mu, \158e jsi byl \250sp\236\154n\253. "
gameforge.subquest_18._240_npcChat = "Tady jsem. "
gameforge.subquest_18._250_say = "\138lo v\154echno dob\248e? Zachr\225nil jsi mi \158ivot! Vem si[ENTER]tohle. Jak jsem sl\237bil, zde je tv\225 odm\236na. "
gameforge.subquest_18._260_sayReward = "Obdr\158\237\154 7 000 bod\249 zku\154enost\237. "
gameforge.subquest_18._270_sayReward = "Obdr\158\237\154 10 000 Yang\249. "
gameforge.subquest_18._280_say = "Jdi zp\236t k Aranyo a \248ekni j\237, kde jsi na\154el Soona. "
gameforge.subquest_18._290_npcChat = "Hra na schov\225vanou je n\225ro\232n\225 "
gameforge.subquest_18._300_say = "D\237ky, \158e jsi m\236 neprozradil. Je to nam\225hav\233, se[ENTER]schov\225vat p\248ed vlastn\237 \158enou. J\225 chci p\248ece jenom[ENTER]trochu studovat. "
gameforge.subquest_18._30_say = "M\249j man\158el je opravdu hrozn\253. A to se s\225m naz\253v\225[ENTER]u\232enec! A zat\237mco my bojujeme, abychom se[ENTER]najedli, v\154e co d\236l\225 on je \232ten\237 knih. Vid\236l jsi[ENTER]ho? Pro\232 jsem si proboha vzala takov\233ho knihomola[ENTER]? "
gameforge.subquest_18._310_npcChat = "Soon\249v pobyt "
gameforge.subquest_18._320_say = "Na\154el jsi ho?[ENTER]D\236kuji, d\236kuji ti! Kdy\158 si v\154imne, \158e ho n\236kdo[ENTER]objevil, tak by mohl ut\233ct. Vyd\225m se okam\158it\236 na[ENTER]cestu.[ENTER]Tentokr\225t ho dostanu. A tady m\225\154 na znamen\237 m\233ho[ENTER]uzn\225n\237.[ENTER]Jen po\232kej, drahou\154ku...! "
gameforge.subquest_18._33_select = "Pom\249\158u ti. "
gameforge.subquest_18._37_select = "Na tohle nem\225m \232as. "
gameforge.subquest_18._40_say = "Chce\154 ukon\232it tuto \250lohu? "
gameforge.subquest_18._50_say = "Nojo...[ENTER]t\248eba se po n\236m porozhl\237dne\154 pozd\236ji. "
gameforge.subquest_18._60_say = "T\248eba ho je\154t\236 najde\154. "
gameforge.subquest_18._70_say = "A to bych byla velmi vd\236\232n\225.[ENTER]Kdy\158 najde\154 chud\233ho pis\225lka, tak mi dej v\236d\236t.[ENTER]Domn\237v\225m se, \158e je ve vesnici stejn\236 jedin\253.[ENTER]T\248eba zrovna p\237\154e b\225se\242 nebo i dv\236 a proto se[ENTER]schov\225v\225.[ENTER]Kdy\158 p\248ijde na to, \158e ho hled\225m, mohl by[ENTER]uprchnout. Tak\158e d\225vej pozor! "
gameforge.subquest_18._80_sendLetter = "Najdi Soona "
gameforge.subquest_18._90_sayTitle = "Najdi toho knihomola "
