gameforge.subquest_19._200_say = "Prost\236 p\248ij\239 znovu pozd\236ji. "
gameforge.subquest_19._20_say = "Kejch! Kejch! Bo\158e, to ka\154l\225n\237 m\236 zni\232\237. Nem\225m[ENTER]nic, \232\237m bych uklidila sv\249j d\249m, tak\158e prach je[ENTER]\250pln\236 v\154ude. Pro\232 jen nem\225m prachovku? Vzal si ji[ENTER]m\249j syn, aby ji pou\158il u n\236jak\233 zbran\236. To[ENTER]ka\154l\225n\237 m\236 zabije! "
