gameforge.subquest_19._220_say = "D\237ky \158e se o to postar\225\154. "
gameforge.subquest_19._230_say = "Ty jsi ten dobrodruh, co tu ji\158 byl! Jak se ti[ENTER]l\237b\237 m\249j ka\154el? Kejch!Kejch! Jak vid\237\154,[ENTER]nezlep\154ilo se to. D\249m je st\225le pln\253 prachu.[ENTER][ENTER]Ach, ty jsi mi p\248inesl vl\232\237 ko\158e\154inu? To je[ENTER]\250\158asn\233! Jsi velmi u\154lechtil\253. Hned se vr\225t\237m. "
gameforge.subquest_19._240_say = "Jedna, dva. Jedna, dva... Jedna noha p\236kn\236 pres[ENTER]druhou... Tak, tady jsem. Moc ti d\236kuji! Kone\232n\236[ENTER]mohu po\248\225dn\236 uklidit sv\249j d\249m. A tady, tum\225\154,[ENTER]n\236co jsem na\154la, co ti mohu d\225t. Nev\237m, co to je[ENTER]a jestli je to cenn\233 nebo ne, ale t\248eba to pro[ENTER]tebe bude u\158ite\232n\233. Je\154t\236 jednou d\236kuji. Sbohem. "
gameforge.subquest_19._250_sendLetter = "N\236co zapr\225\154en\233ho "
