gameforge.subquest_19._290_say = "Je to kompletn\237 zbroj, ale navzdory o\232ek\225v\225n\237 je[ENTER]nepou\158iteln\225. "
gameforge.subquest_19._300_sayReward = "Obdr\158\237\154 15 000 bod\249 zku\154enost\237. "
gameforge.subquest_19._30_select = "Se\158enu ti jeden. "
gameforge.subquest_19._40_say = "V\154e je zapr\225\154en\233! Pot\248ebuji prachovku. Mohl bys[ENTER]mi pomoci? "
gameforge.subquest_19._50_say = "Ji\158 je to d\225vno, ale mysl\237m si, \158e m\249j man\158el -[ENTER]budi\158 mu zem\236 lehk\225 - ji vyrobil z vl\232\237 ko\158e\154iny.[ENTER]Kejch![ENTER][ENTER]Mohl bys uboh\233 sta\248ence sehnat vl\232\237 ko\158e\154inu?[ENTER]Z\237sk\225\154 ji od \154ed\253ch vlk\249. Opravdu bys mi hodn\236[ENTER]pomohl. "
gameforge.subquest_19._60_say = "Opravdu chce\154 zru\154it? "
gameforge.subquest_19._70_say = "\138koda, u\158 jsem si myslela, \158e mi pom\249\158e\154. T\248eba[ENTER]si to je\154t\236 rozmysl\237\154. V tom p\248\237pad\236 p\248ijd' je\154t\236[ENTER]jednou. "
