gameforge.subquest_23._350_npcChat = "Zn\225\154 ten n\225hrdeln\237k? "
gameforge.subquest_23._360_say = "Ach, ten n\225hrdeln\237k... Ten po\248\225d nos\237val m\249j[ENTER]bratr. M\225m podobn\253. V\158dy jsme je nosili, abychom[ENTER]m\236li jeden na druh\233ho vzpom\237nku a na\154li v\158dy k[ENTER]sob\236 cestu. Ale... m\249j bratr tu nen\237... A jen[ENTER]n\225hrdeln\237k na\154el cestu zp\236t. "
gameforge.subquest_23._370_say = "M\249j uboh\253 bratr...[ENTER]A v\154e jen d\237ky t\233 v\225lce. M\249j bratr prod\225val[ENTER]l\233\232iv\233 byliny, bylo to to jedin\233, co n\225m d\225valo[ENTER]n\236jak\233 pen\237ze, d\237ky nim\158 jsme si mohli koupit[ENTER]j\237dlo. V\158dy tvrd\236 pracoval, abych m\236la co j\237st. A[ENTER]te\239 je mrtv\253. Jen kv\249li m\236... "
gameforge.subquest_23._380_say = "D\236kuji, \158e si mi to donesl. Te\239 aspo\242 v\237m, co se[ENTER]stalo.[ENTER]\142\237t v nev\236domosti by bylo je\154t\236 mnohem hor\154\237.[ENTER]Nikdy bych se nedozv\236d\236la, co se bratrovi[ENTER]p\248ihodilo. "
gameforge.subquest_23._390_say = "Budu se o p\248\237v\236\154ek star\154\237ho bratra dob\248e starat a[ENTER]tob\236 d\225m ten n\225hrdeln\237k jako v\253raz m\233 vd\236\232nosti.[ENTER]Jsem si jista, \158e se ti bude hodit.[ENTER]D\236kuji ti za pomoc. Mysl\237m, \158e m\249j bratr je v[ENTER]nebi, co mysl\237\154? "
gameforge.subquest_23._400_sayReward = "Obdr\158\237\154 600 000 bod\249 zku\154enost\237.[ENTER]Obdr\158\237\154 35 000 Yang\249. "
gameforge.subquest_23._40_say = "Boj\237m se o n\236j, proto\158e o n\236m ji\158 dlouho nem\225m[ENTER]\158\225dn\233 zpr\225vy. Promi\242, ale mohl by ses po n\236m[ENTER]pod\237vat? Yu-Hwan by mohl n\236co v\236d\236t. "
gameforge.subquest_23._50_select = "Odm\237tnout "
gameforge.subquest_23._60_say = "Chce\154 hled\225n\237 vzd\225t? "
gameforge.subquest_23._70_say = "Ach...[ENTER]Po\232k\225m tady. Mo\158n\225 pozd\236ji? Pros\237m...? "
gameforge.subquest_23._80_say = "Nem\225m \232as.[ENTER]Hodn\236 \154t\236st\237 tv\233mu bratrovi. "
