gameforge.subquest_25._180_say = "Tak\158e, co m\225 Ariyoung r\225da? Ne\248ekl jsi j\237 nic o[ENTER]m\236, \158e ne? Hm, m\225 r\225da kv\236tiny, co j\237 nos\237val[ENTER]man\158el? To je ale docela daleko od vesnice a pro[ENTER]m\236 je t\236\158k\233 se tam dostat. A mohou tam b\253t[ENTER]p\248\237\154ery, jako jsou t\248eba tyg\248i. "
