gameforge.subquest_25._280_say = "Abys pomohl Huahn-So \248\237ci Ariyoung, co k n\237 c\237t\237,[ENTER]mus\237\154 z\237skat speci\225ln\237 kv\236tiny. Kv\236tiny rostou v[ENTER]rohu mapy prvn\237 vesnice. "
