gameforge.subquest_25._340_say = "Ach...[ENTER]Kdy\158 si to rozmysl\237\154, tak m\236 najde\154 tady... s[ENTER]t\236\158k\253m srdcem.[ENTER]Pros\237m pomo\158 mi. "
