gameforge.subquest_25._380_say = "Tyhle kv\236tiny vypadaj\237 jako ty, co popisovala[ENTER]Ariyoung. N\236jak\233 natrh\225m. "
gameforge.subquest_25._390_qSetTitle = "Zp\236t k Huahn-So "
gameforge.subquest_25._400_say = "Na\154el jsem obl\237ben\233 kv\236tiny Ariyoung a natrhal[ENTER]jsem je. M\236l bych je don\233st Huahn-So, aby je mohl[ENTER]d\225t Ariyoung. "
gameforge.subquest_25._40_say = "Ale proto\158e se vdala tak brzy, je z n\237 te\239 mlad\225[ENTER]vdova.[ENTER]I kdy\158 je vdan\225...[ENTER]chci, aby v\236d\236la co k n\237 c\237t\237m![ENTER]Uv\236domuju si, \158e to je to neskromn\233 p\248\225n\237, ale[ENTER]mohl bys mi p\248esto pomoct? "
