gameforge.subquest_26._180_say = "Ale nyn\237... Jsem p\248\237li\154 star\253 a unaven\253. Z t\233[ENTER]pol\233vky bych mohl z\237skat n\236jakou energii, ale[ENTER]nen\237 lehk\233 \158\225by zab\237t. Pokud mi p\248inese\154 \158ab\237[ENTER]steh\253nka na pol\233vku, ud\236l\225m n\225m tu nejlep\154\237[ENTER]pol\233vku na sv\236t\236! "
