gameforge.subquest_26._390_say = "A nikomu o tom ne\248\237kej. Obzvl\225\154t\236 ne Spr\225vci[ENTER]skladi\154t\236. R\225d mluv\237 a pokud se lid\233 dozv\237 o t\233[ENTER]pol\233vce, tak nebudu m\237t chvilku klidu, proto\158e ji[ENTER]po\248\225d n\236kdo bude cht\237t ochutnat. "
gameforge.subquest_26._400_sayReward = "Obdr\158\237\154 5 000 000 bod\249 zku\154enost\237. "
gameforge.subquest_26._40_say = "V posledn\237 dob\236 se nec\237t\237m moc dob\248e. M\233 t\236lo u\158[ENTER]nen\237 to co b\253valo. Kdy\158 jsem byl mlad\154\237, mohl[ENTER]jsem pracovat ka\158d\253 den a\158 do ve\232era a je\154t\236 u[ENTER]toho p\237t alkohol. Nyn\237 mi ale d\225 pr\225ci u\158 jen[ENTER]r\225no vst\225t. Pot\248ebuji tvou pomoc, abych mohl[ENTER]uva\248it pol\233vku ze \158ab\253ch steh\253nek, co mi vr\225t\237[ENTER]energii. "
