gameforge.subquest_27._230_say = "V\237\154, \158e jsem p\248e\232etl v\154echny knihy na sv\236t\236? Te\239[ENTER]jsem sly\154el o tajn\233 Knize chr\225mu. Pov\236sti \248\237kaj\237,[ENTER]\158e obsahuje v\154echna tajemstv\237 Temn\233ho chr\225mu. A[ENTER]tak\233 vysv\236tluje, jak se st\225t svat\253m. "
