gameforge.subquest_32._280_say = "Ok, to je prima. Byl jsi opravdu rychl\253. Mus\237\154[ENTER]udr\158ovat star\225 p\248\225telstv\237, \158e? \200asto si[ENTER]pom\225h\225me... D\236kuji ti, \158e jsi mi donesl ty \154aty.[ENTER]Pros\237m, pozdravuj ode mne Ariyoung. "
gameforge.subquest_32._290_npcChat = "Pot\248ebuji \154perk "
gameforge.subquest_32._300_say = "Hled\225\154 \154perk?[ENTER]Mohu ti jej d\225t, ale pouze pokud mi pom\249\158e\154.[ENTER]Moment\225ln\236 vyr\225b\237m speci\225ln\237 l\233k proti bolesti,[ENTER]ale pot\248ebuji jednu p\248\237sadu: tyg\248\237 j\225tra. Je[ENTER]t\236\158k\233 je z\237skat. Pot\248ebuji jich 100. "
gameforge.subquest_32._30_say = "My obchodn\237 cestuj\237c\237 nem\225me ve v\225lce lehk\233 \232asy.[ENTER]V\154ichni cht\236j\237 obchodn\237ky, ale po\158adavky se[ENTER]rychle m\236n\237, tak\158e nikdy nev\237m, zda m\225m sebou ty[ENTER]spr\225vn\233 v\236ci. A to ani nemluv\237m o nebezpe\232n\233 a[ENTER]dlouh\233 cest\236 p\248es divo\232inu, kde v\154echny ty[ENTER]p\248\237\154ery \232\237haj\237 na neopatrn\233 cestuj\237c\237. Nechce\154 si[ENTER]vyd\236lat p\225r Yang\249? Hodila by se mi pomoc. "
gameforge.subquest_32._310_say = "Tak\233 pot\248ebuji n\236jak\233 l\233\232iv\233 byliny, ale ty tak\233[ENTER]m\249\158e\154 z\237skat z tygr\249. Oni se v nich r\225di v\225lej\237,[ENTER]proto\158e maj\237 r\225di jejich v\249ni. D\225m ti ten \154perk[ENTER]za byliny a tyg\248\237 j\225tra. "
gameforge.subquest_32._320_say = "Lov tygry nebo b\237l\233 tygry. "
gameforge.subquest_32._330_say = "Co \248\237k\225\154? Dohodnem se? "
gameforge.subquest_32._340_say = "Je m\249j \250kol pro tebe moc t\236\158k\253? To se mi nezd\225![ENTER]Vra\157 se, a\158 zm\236n\237\154 n\225zor. "
gameforge.subquest_32._350_say = "Ty jde\154 tak dlouhou cestu od obchodn\237ka a pak to[ENTER]vzd\225\154? No jak chce\154...[ENTER]M\236j se. "
gameforge.subquest_32._360_say = "Dob\248e. To n\225m pom\249\158e ob\236ma, \158e? D\237ky a hodn\236[ENTER]\154t\236st\237! "
gameforge.subquest_32._370_npcChat = "Mohu te\239 dostat ten \154perk? "
gameforge.subquest_32._380_say = "Pod\237vejme se... tady je 100 tyg\248\237ch jater a[ENTER]l\233\232iv\233 byliny. D\237ky![ENTER]Tak tady m\225\154, opravdu sis ten \154perk zaslou\158il.[ENTER]M\236j se! "
gameforge.subquest_32._390_qSetTitle = "Zp\236t k obchodn\237mu cestuj\237c\237mu "
gameforge.subquest_32._400_targetVid = "Zp\236t k obchodn\237mu cestuj\237c\237mu "
gameforge.subquest_32._40_say = "Moment\225ln\236 je velk\225 popt\225vka po n\225hrdeln\237c\237ch z[ENTER]t\248enov\253ch zub\249 Ork\249. T\248enov\233 zuby Ork\249 jsou velk\233[ENTER]a tvrd\233 a dob\248e se z nich d\236laj\237 \154perky. A voj\225ci[ENTER]si mysl\237, \158e n\225hrdeln\237k ze zub\249 Siln\233ho or\232\237ho[ENTER]\154amana jim p\248inese \154t\236st\237 v boji. Mohl bys mi ty[ENTER]zuby nasb\237rat? 100 t\248enov\253ch zub\249 by mohlo b\253t[ENTER]dostate\232n\233 mno\158stv\237 pro za\232\225tek. "
gameforge.subquest_32._410_sayReward = "Zp\236t k obchodn\237mu cestuj\237c\237mu "
gameforge.subquest_32._420_sayReward = "Kone\232n\236 m\225\154 v\154echen materi\225l na n\225hrdeln\237k. Vra\157[ENTER]se k obchodn\237mu cestuj\237c\237mu. "
gameforge.subquest_32._430_npcChat = "M\225m v\154echen materi\225l "
gameforge.subquest_32._440_sayTitle = "Obchodn\237 cestuj\237c\237: "
gameforge.subquest_32._450_say = "M\225\154 v\154echen materi\225l? Tak se koukneme...[ENTER]Ano, je to opravdu v\154echno. D\237ky tob\236 mohu[ENTER]roz\154\237\248it svou nab\237dku, to je dobr\233. A tady je[ENTER]tv\249j d\237l. M\236j se.[ENTER][ENTER]Poj\239te sem, poj\239te! Je tu n\236co pro ka\158d\233ho... "
gameforge.subquest_32._460_sayReward = "Obdr\158\237\154 1 100 000 bod\249 zku\154enost\237. "
gameforge.subquest_32._470_sayReward = "Obdr\158\237\154 zlat\253 n\225ramek, zlat\253 n\225hrdeln\237k a zlat\233[ENTER]n\225u\154nice. "
gameforge.subquest_32._480_say = "Hmmm, je mi l\237to, ale n\236co chyb\237. Nepot\248ebuji[ENTER]nekompletn\237 dod\225vku. Je\154t\236 to zkus\237\154? "
gameforge.subquest_32._490_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_32._500_say = "D\237ky, \158e jsi to tak lehce nevzdal. \138t\236st\237 p\248eje[ENTER]t\236m, kte\248\237 se neboj\237 jej pokou\154et. Po\232k\225m na tebe[ENTER]tady. "
gameforge.subquest_32._50_say = "Pot\248ebuji tak\233 \154perk a nit na \154it\237. Jedno z\237sk\225\154[ENTER]od obchodnice se sm\237\154en\253m zbo\158\237m, druh\233 od[ENTER]Ariyoung. Nen\237 jednoduch\233 z\237skat tolik v\236c\237, ale[ENTER]prodej n\225hrdeln\237k\249 je dobr\253 obchod a ty za ty[ENTER]materi\225ly dostane\154 dobrou odm\236nu. Co mysl\237\154, zn\237[ENTER]ti to zaj\237mav\236? "
gameforge.subquest_32._510_say = "\218kol je moc t\236\158k\253? No, alespo\242 jsi to zkusil.[ENTER]Pokud budu m\237t n\236co leh\232\237ho, d\225m ti v\236d\236t.[ENTER]Sbohem. "
gameforge.subquest_32._520_say = "Zkus\237\154 to znova?[ENTER]Dobr\225.[ENTER]Po\232k\225m tu na tebe. "
gameforge.subquest_32._60_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_32._70_say = "Nem\225\154 \232as? To ch\225pu. Ale pros\237mt\236, p\248ij\239 a\158 bude\154[ENTER]\232as m\237t. "
gameforge.subquest_32._80_say = "Bo\158e, jak dokon\232\237m v\154echny moje zak\225zky? Sbohem! "
gameforge.subquest_32._90_say = "Vynikaj\237c\237. Po\232k\225m tu na tebe. "
