gameforge.subquest_33._100_sayTitle = "Nalezena mapa pokladu "
gameforge.subquest_33._10_targetVid = "Jdi za knihomolem. "
gameforge.subquest_33._110_say = "Ulovil jsi v\154echny 4 zv\237\248ec\237 bo\158stva okolo[ENTER]vesnice a z\237skal v\154echny 4 \232\225sti mapy pokladu.[ENTER]Dones je Soonovi. "
gameforge.subquest_33._120_sayTitle = "Lov zv\237\248ec\237ho bo\158stva "
gameforge.subquest_33._130_say = "Z\237skej v\154echny 4 \232\225sti mapy pokladu lovem[ENTER]zv\237\248ec\237ch boh\249 Lykose, Scrofy, Bery a Tigrise. "
gameforge.subquest_33._140_sayReward = "(Nalezeny \232\225sti mapy pokladu : %s ) "
gameforge.subquest_33._150_sendLetter = "Mapa pokladu "
gameforge.subquest_33._160_sayTitle = "\200\225sti mapy sesb\237r\225ny "
gameforge.subquest_33._170_say = "Vra\157 se k Soonovi a sd\236l mu, \158e jsi na\154el mapu[ENTER]pokladu. "
gameforge.subquest_33._175_npcChat = "Z\237skal jsem v\154echny \232\225sti mapy. "
gameforge.subquest_33._180_say = "Ach! Fantastick\233! V\154echny \232ty\248i \232\225sti[ENTER]pohromad\236... O tom se mi ani nezd\225lo! Nyn\237 jen[ENTER]spoj\237m ty kousky abych z\237skal mapu... tak... "
gameforge.subquest_33._190_say = "Hmmm... Divn\233. Mapa \248\237k\225, \158e poklad je ukryt na[ENTER]sk\225le nedaleko Star\233ho mu\158e. To mi nep\248ijde jako[ENTER]pravda. Jinak u\158 by byl nalezen. To je d\236tsk\253[ENTER]trik! P\248esto, chce\154 se po tom pokladu pod\237vat,[ENTER]nebo m\225m tu mapu rad\236ji sp\225lit? "
gameforge.subquest_33._200_select = "Pod\237v\225m se "
gameforge.subquest_33._20_npcChat = "O map\236 pokladu... "
gameforge.subquest_33._210_select = "Spal ji. "
gameforge.subquest_33._220_say = "Opravdu jsi si jist, \158e tu mapu nepot\248ebuje\154? "
gameforge.subquest_33._230_say = "Jak\225 slabomysln\225 poh\225dka![ENTER]Promi\242, \158e jsem t\236 poslal hledat ty \232\225sti mapy.[ENTER]J\225 je sp\225l\237m, aby se u\158 nikdo jin\253 nedal nap\225lit.[ENTER]Ale p\248esto ti d\236kuji za tv\233 \250sil\237. Sbohem. "
gameforge.subquest_33._240_say = "\200eho se boj\237\154? M\225\154 v\154echny \232\225sti mapy. Tak jdi a[ENTER]hledej. A tum\225\154, vem si tu mapu. "
gameforge.subquest_33._250_say = "Jak chce\154. Opravdu bych byl p\248ekvapen, kdybys[ENTER]n\236jak\253 poklad na\154el, ale p\248esto - hodn\236 \154t\236st\237.[ENTER]Vezmi si tu mapu. "
gameforge.subquest_33._260_say = "Mapa byla rozd\236lena na \232ty\248i \232\225sti. Pot\248ebujeme[ENTER]je v\154echny, abychom z nich sestavili mapu zp\236t! "
gameforge.subquest_33._270_select = "Zkusit znova "
gameforge.subquest_33._280_say = "Vzd\225\154 to?[ENTER]Jak chce\154... m\236j se. "
gameforge.subquest_33._290_say = "Jak jsem si myslel. Jsi pln\253 energie...[ENTER]Spol\233h\225m na tebe! "
gameforge.subquest_33._300_targetVid = "Sk\225la u starce "
gameforge.subquest_33._30_say = "Hey ty...[ENTER]Na\154el jsem ve star\253ch textech zvl\225\154tn\237 informace,[ENTER]p\237\154e se tam, \158e se v na\154\237 vesnici nal\233zaj\237 mapy[ENTER]poklad\249. Zn\225\154 zv\237\248ec\237 bo\158stva, kter\225 str\225\158\237 p\248ed[ENTER]m\236stem?[ENTER]Ps\237 bo\158stvo, medv\236d\237 bo\158stvo, tyg\248\237 bo\158stvo a[ENTER]prase\232\237 bo\158stvo. "
gameforge.subquest_33._310_sayTitle = "Hled\225n\237 pokladu "
gameforge.subquest_33._320_say = "Hm, pod sk\225lou Star\233ho mu\158e...[ENTER]Nem\225m pon\236t\237. Mo\158n\225 bych se m\236l zeptat Star\233ho[ENTER]mu\158e. Pro\232 je ale tak daleko? K \232ertu... "
gameforge.subquest_33._330_sayTitle = "Sta\248ec: "
gameforge.subquest_33._340_say = "Co hled\225\154? Poklad? Hahahaha, to bude\154 hledat[ENTER]dlouho! Uka\158 mi tu mapu... Hmmm, mysl\237m \158e je to[ENTER]t\225mhle. Hodn\236 \154t\236st\237, hihihi... "
gameforge.subquest_33._350_say = "Tohle mus\237 b\253t to m\237sto! Heur\233ka![ENTER]K \232ertu, zem\236 je hodn\236 tvrd\225. Hmm...[ENTER][ENTER]Ha, vid\237m n\236jakou truhlu! "
gameforge.subquest_33._360_sendLetter = "Ten poklad skute\232n\236 existuje! "
gameforge.subquest_33._370_sayTitle = "Zp\236t k Soonovi "
gameforge.subquest_33._380_say = "Kopal jsi na m\237st\236, kter\233 ukazovala mapa[ENTER]Zv\237\248ec\237ch bo\158stev a na\154el jsi turhlu s pokladem![ENTER]Vra\157 se zp\236t k Soonovi a zeptej se ho na[ENTER]neo\232ek\225van\253 p\248\237jem. "
gameforge.subquest_33._390_npcChat = "Na\154el jsem poklad! "
gameforge.subquest_33._400_say = "No to je ale p\248ekvapen\237! Tak se pod\237vejme...[ENTER]N\225dhera! P\248esn\236 tak byla pokladnice pops\225na ve[ENTER]star\253ch spisech. Te\239 je\154t\236 zjistit, jak ji[ENTER]otev\248\237t. Ale to nen\237 tv\249j probl\233m. D\237ky! Tady,[ENTER]vezmi si tohle jako v\253raz m\233 vd\236\232nosti! "
gameforge.subquest_33._40_say = "Starov\236k\233 p\248\237b\236hy \248\237kaj\237, \158e tito \232ty\248i bozi,[ENTER]vypadaj\237c\237 jako zv\237\248ata, rozd\236lili mapu na \232ty\248i[ENTER]\232\225sti a chr\225n\237 ji na sv\253ch \250zem\237ch. Nejsem si[ENTER]jist, \158e je to ale pravda. Mohl bys to pro mne[ENTER]zjistit? Pros\237m, ta nejistota m\236 zab\237j\237... Moc[ENTER]pros\237m, pros\237m! "
gameforge.subquest_33._410_sayReward = "Obdr\158\237\154 1 400 000 bod\249 zku\154enost\237. "
gameforge.subquest_33._420_sayReward = "Obdr\158\237\154 25 000 Yang\249. "
gameforge.subquest_33._430_sayReward = "Obdr\158\237\154 p\248\237lbu s maskou ducha+1. "
gameforge.subquest_33._440_sayReward = "Obdr\158\237\154 hradn\237 p\248\237lbu+1. "
gameforge.subquest_33._450_sayReward = "Obdr\158\237\154 ocelovou kapuci+1. "
gameforge.subquest_33._460_sayReward = "Obdr\158\237\154 sol\225rn\237 klobouk+1. "
gameforge.subquest_33._470_say = "Tak, kde je? D\236l\225\154 si ze mne legraci? Tys j\237[ENTER]opravdu nena\154el, \158e? "
gameforge.subquest_33._50_say = "Tebe star\225 mapa pokladu nezaj\237m\225? Jsi divn\253...[ENTER]Tak budu hledat dal\154\237 vod\237tka ve star\253ch textech.[ENTER]Vra\157 se, pokud zm\236n\237\154 n\225zor. "
gameforge.subquest_33._60_say = "Takov\225 dobrodru\158stv\237 se ti asi nel\237b\237?[ENTER]Jak te\239 se\158enu ty \232\225sti t\233 mapy?[ENTER][ENTER]No dobr\225... a\157 je to jak chce. M\236j se. "
gameforge.subquest_33._70_say = "Jsi opravdov\253 p\248\237tel. V\236\248\237m, \158e je najde\154. "
