gameforge.subquest_34._100_say = "Velitel m\225 st\225le probl\233m z\237skat nad bandou[ENTER]\200ern\233ho v\236tru kontrolu. Zabij gener\225ly bandy[ENTER]\200ern\233ho v\236tru Jak-To, To-Su a Gu-Ryunga. Pak se[ENTER]uklidn\237. "
gameforge.subquest_34._10_npcChat = "Co d\236l\225 banda \200ern\233ho v\236tru? "
gameforge.subquest_34._110_say = "Gener\225lov\233 zabiti! "
gameforge.subquest_34._120_select = "Ano. Zkusit znovu. "
gameforge.subquest_34._130_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_34._140_say = "Boj nen\237 snadn\253 a v\237t\236zstv\237 je je\154t\236 t\236\158\154\237.[ENTER]Obzvl\225\154t\236, pokud bojuje\154 s gener\225ly. Zkus to[ENTER]znovu. "
gameforge.subquest_34._150_say = "Jak jsem se u\158 domn\237val, je to velmi siln\225 banda.[ENTER]Na shledanou. "
gameforge.subquest_34._160_say = "Jsi velmi odv\225\158n\253![ENTER]Mysl\237m, \158e dok\225\158e\154 porazit bandu \200ern\233ho v\236tru! "
gameforge.subquest_34._170_targetVid = "Hla\154 se u velitele. "
gameforge.subquest_34._180_say = "Vra\157 se k veliteli a sd\236l mu, \158e jsi zabil[ENTER]gener\225ly. "
gameforge.subquest_34._185_npcChat = "Zabil jsem Gener\225ly! "
gameforge.subquest_34._190_say = "Hmmm... porazil jsi gener\225ly. Z toho, co banda[ENTER]\200ern\233ho v\236tru prov\225d\236la, n\225s u\158 opravdu bolela[ENTER]hlava, ale te\239 jim m\249\158eme p\236kn\236 napr\225skat. Bez[ENTER]gener\225l\249 budou jen \232aj\237\232ek. Tady je tv\225 odm\236na.[ENTER]Douf\225m, \158e t\236 zase brzy uvid\237m! "
gameforge.subquest_34._200_sayReward = "Obdr\158\237\154 1 000 000 bod\249 zku\154enost\237. "
gameforge.subquest_34._20_sayTitle = "Velitel "
gameforge.subquest_34._210_sayReward = "Obdr\158\237\154 prsten jazyk\249. "
gameforge.subquest_34._30_say = "I kdy\158 jsi porazil bandu \200ern\233ho v\236tru, je\154t\236[ENTER]po\248\225d nedala pokoj.[ENTER]M\237sto toho, aby se zklidnili, se zase chovaj\237 jak[ENTER]zdivo\232el\225 sme\232ka.[ENTER]Jestli je chceme natrvalo porazit, mus\237me zab\237t[ENTER]jejich gener\225ly. "
gameforge.subquest_34._40_say = "Jakmile budou gener\225lov\233 pora\158eni, bude snadn\233[ENTER]porazit i ostatn\237. Bude to t\236\158k\225 pr\225ce, ale[ENTER]mus\237me porazit gener\225ly bandy \200ern\233ho v\236tru[ENTER]Jak-To, To-Su a Gu-Ryunga. Pokud je poraz\237me, pak[ENTER]se zbytku bandy \200ern\233ho v\236tru nemus\237me b\225t. Budu[ENTER]se modlit za tv\233 v\237t\236zstv\237. "
gameforge.subquest_34._50_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_34._60_say = "Hmm... a\158 bude\154 p\248ipraven, p\248ijd' zas.[ENTER]Neexistuje hodn\236 tak schopn\253ch lid\237 jako jsi ty. "
gameforge.subquest_34._70_say = "Ty nem\249\158e\154...[ENTER]Jak pak m\225me porazit bandu \200ern\233ho v\236tru? "
gameforge.subquest_34._80_say = "V\236d\236l jsem, \158e se na tebe mohu spolehnout.[ENTER]Jakmile budou gener\225lov\233 vy\248\237zen\237, zbytek bandy[ENTER]\200ern\233ho v\236tru nebude probl\233m. Hodn\236 \154t\236st\237! "
gameforge.subquest_34._90_sendLetter = "Zabij gener\225ly bandy \200ern\233ho v\236tru "
