gameforge.subquest_36._100_sayTitle = "Najdi pacholka "
gameforge.subquest_36._10_targetVid = "Yonah: "
gameforge.subquest_36._110_say = "Nasb\237ral jsi 10 bal\237k\249 sena. Dones je pacholkovi,[ENTER]aby mohl nakrmit kon\236. "
gameforge.subquest_36._120_sayTitle = "Seno pro st\225je "
gameforge.subquest_36._130_say = "Ve st\225j\237ch je hlad. Z\237skej 10 bal\237k\249 sena a dones[ENTER]je pacholkovi, ne\158 kon\236 pojdou hlady! Seno m\249\158e\154[ENTER]z\237skat p\248i lovu. "
gameforge.subquest_36._140_npcChat = "Pot\248ebuje\154 seno? "
gameforge.subquest_36._150_say = "Jsi tady, proto\158e t\236 pos\237l\225 Yonah? Ji\158 jsem o[ENTER]tob\236 hodn\236 sly\154el. Ach, v\154echny m\233 kon\236 chc\237pnou[ENTER]hlady, jestoi jim ned\225me seno. Pomoz mi, a p\248ines[ENTER]mi seno pro kon\236! "
gameforge.subquest_36._160_say = "Slib je slib. A mo\158n\225 bych se pozd\236ji r\225d projel[ENTER]na koni. Mus\237m naj\237t n\236jak\233 seno! "
gameforge.subquest_36._170_say = "Omlouv\225m se. Hled\225m, ale je prost\236 nemo\158n\233 n\236jak\233[ENTER]seno z\237skat. "
gameforge.subquest_36._180_say = "J\225 v\237m, \158e nen\237 moc p\236kn\233 t\236 \158\225dat, abys ud\236lal[ENTER]mou pr\225ci, ale douf\225m, \158e to ud\236l\225\154. Mohl bys to[ENTER]zkusit znovu? Zn\225m velmi d\249le\158itou osobu v jin\233m[ENTER]kr\225lovstv\237, pokud mi pom\249\158e\154, popros\237m ji o[ENTER]laskavost pro tebe. "
gameforge.subquest_36._190_select = "Zkusit znovu "
gameforge.subquest_36._200_say = "Samoz\248ejm\236 \158e ti pom\249\158u.[ENTER]Nem\225m na to s\237lu. "
gameforge.subquest_36._20_npcChat = "St\225je maj\237 probl\233my "
gameforge.subquest_36._210_say = "Nem\249\158u tomu v\236novat \158\225dnou energii.[ENTER]Chci ti opravdu pomoci, ale nem\249\158u.[ENTER]Nejsem na to dost siln\253. "
gameforge.subquest_36._220_npcChat = "M\225m seno pro kon\236 "
gameforge.subquest_36._230_say = "M\225\154 seno? Ach, d\237ky. Nem\236li jsme pro kon\236[ENTER]dostatek \158r\225dla, tak jsem po\158\225dal Yonaha. Je to[ENTER]m\249j dobr\253 p\248\237tel. Myslel jsem si, \158e by mohl[ENTER]po\158\225dat kohokoliv, kdo by byl schopen pomoci. Ale[ENTER]ne\232ekal jsem, \158e to bude tak rychle. Jen se[ENTER]pod\237vej, jak usilovn\236 kon\236 \158erou! "
gameforge.subquest_36._240_sayReward = "Obdr\158\237\154 1 800 000 bod\249 zku\154enost\237. "
gameforge.subquest_36._250_sendLetter = "Zp\236t k Yonahovi "
gameforge.subquest_36._260_sayTitle = "Zp\236t k Yonahovi "
gameforge.subquest_36._270_say = "Donesl jsi 10 bal\237k\249 sena pro hladov\233 kon\236[ENTER]pacholkovi. Vra\157 se k Yonahovi a \248ekni mu o tom. "
gameforge.subquest_36._280_npcChat = "O kon\236 je postar\225no! "
gameforge.subquest_36._290_say = "Ahoj, tak jsi zp\225tky?[ENTER]Pravd\236podobn\236 to byla t\236\158k\225 pr\225ce, z\237skat tolik[ENTER]sena. D\237ky, \158e jsi to nevzdal. Tady je za to pro[ENTER]tebe mal\253 d\225rek. "
gameforge.subquest_36._300_sayReward = "Obr\158el jsi Knihu mis\237. "
gameforge.subquest_36._30_say = "Hej, m\225m na tebe dotaz. V\237m, \158e za st\225je je[ENTER]zodpov\236dn\253 n\236kdo jin\253, ale m\236li jsme spoustu[ENTER]pot\237\158\237 a hodila by se n\225m pomoc. B\236hem v\225lky jsou[ENTER]kon\236 hodn\236 vyt\237\158en\237, ale i ten nejsiln\236j\154\237 k\249\242 m\225[ENTER]sv\233 hranice mo\158nost\237. "
gameforge.subquest_36._40_say = "Je tam mnoho kon\237, ale ne dostatek \158r\225dla, tak\158e[ENTER]mnoho z nich chc\237pe. Mohl bys pros\237m sehnat[ENTER]n\236jak\233 \158r\225dlo, aby kon\236 z\237skali n\236jakou energii?[ENTER]nem\225m po ruce nikoho jin\233ho, koho bych mohl[ENTER]po\158\225dat. Nasb\237rej 10 bal\237k\249 sena a dones je[ENTER]pacholkovi. On o tom probl\233mu v\237. Jen mu \248ekni,[ENTER]\158e t\236 pos\237l\225m. "
gameforge.subquest_36._50_select = "Okam\158it\236 odch\225z\237m! "
gameforge.subquest_36._60_select = "Ne, to nen\237 vhodn\225 pr\225ce. "
gameforge.subquest_36._70_say = "V t\236chto \232asech v\237ce a v\237ce cestovatel\249 chce m\237t[ENTER]kon\236. Ale nikdo nemysl\237 na to, \158e pro n\236 m\225me[ENTER]m\225lo \158r\225dla. A nyn\237 hladov\236j\237 ve st\225j\237ch. Pokud[ENTER]zm\236n\237\154 n\225zor, vra\157 se. "
gameforge.subquest_36._80_say = "Ach... Kon\236 trp\237 podv\253\158ivou.[ENTER]Mus\237m se s t\237m vyrovnat. "
gameforge.subquest_36._90_say = "V\237m, \158e jsi zanepr\225zdn\236n a opravdu si cen\237m tv\233[ENTER]pomoci. V t\236chto dnech jsou kon\236 opravdu[ENTER]d\249le\158it\237. A my pro n\236 pot\248ebujeme seno. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah d\236l\225 co m\249\158e, aby vyrobil nov\253 porcel\225n,[ENTER]ale zat\237m se mu moc neda\248\237. Zajdi za u\232encem[ENTER]Urielem a zeptej se ho, zda nev\237 n\236co o[ENTER]Seladonsk\233m porcel\225nu. "
gameforge.subquest_37._10_targetVid = "Tajemstv\237 Seladonsk\233ho porcel\225nu "
gameforge.subquest_37._110_npcChat = "Zn\225\154 Seladonsk\253 porcel\225n? "
gameforge.subquest_37._120_sayTitle = "Uriel: "
gameforge.subquest_37._130_say = "Seladonsk\253 porcel\225n? No, v\237m hodn\236 o historii a[ENTER]v\236d\236, ale um\236n\237 m\236 moc nezaj\237m\225. Tak\158e se ob\225v\225m,[ENTER]\158e ti o Seladonsk\233m porcel\225nu mnoho ne\248eknu.[ENTER]Ale mo\158n\225 v\237 neco Soon? Nen\237 moc obl\237ben\253, ale[ENTER]\232te spoustu knih, tak\158e by se o n\236m mohl n\236co[ENTER]do\232\237st. "
gameforge.subquest_37._140_makequestbutton = "B\236\158 k Soonovi "
gameforge.subquest_37._150_targetVid = "Jdi za Soonem "
gameforge.subquest_37._160_say = "Bohu\158el Uriel o Seladonsk\233m porcel\225nu nic nev\237.[ENTER]Ale Soon \232te spousty knih, mo\158n\225 se o porcel\225nu[ENTER]n\236co do\232etl. Jdi za n\237m a zeptej se ho. "
gameforge.subquest_37._170_sayTitle = "Soon: "
gameforge.subquest_37._180_say = "Co chce\154? Nevyru\154uj mne, kdy\158 si \232tu![ENTER]Seladonsk\253 porcel\225n? Samoz\248ejm\236 ho zn\225m. Jen o[ENTER]n\236m jsem p\248e\232etl celou hromadu knih. Pro\232? No,[ENTER]ne\248\237kaj\237 mi knihomol jen tak, v\237 \158e rozum\237m[ENTER]v\154emu, co je naps\225no v knih\225ch. "
gameforge.subquest_37._190_say = "Mohl bych ti z hlavy napsat, jak Seladonsk\253[ENTER]porcel\225n vyrobit, ale pro\232 bych to m\236l d\236lat?[ENTER]Hmm. Dobr\225, po\232kej, m\225m n\225pad: po\158\225dal jsem[ENTER]obchodn\237ho cestuj\237c\237ho v druh\233 vesnici o knihu,[ENTER]kter\225 mi chyb\237, ale je\154t\236 sem nem\236l \232as za n\237m[ENTER]zaj\237t. Pokud mi ji p\248inese\154, tak ti pomohu s[ENTER]porcel\225nem. Tak vyra\158 na cestu! "
gameforge.subquest_37._200_makequestbutton = "K obchodn\237mu cestuj\237c\237mu "
gameforge.subquest_37._20_sayTitle = "Yonah: "
gameforge.subquest_37._210_targetVid = "B\236\158 k obchodn\237mu cestuj\237c\237mu "
gameforge.subquest_37._220_say = "Knihomol Soon v\237 v\154e o Caledonsk\233m porcel\225nu, ale[ENTER]ne\248ekne nic, dokud nebude m\237t od obchodn\237ho[ENTER]cestuj\237c\237ho knihu. Najdi obchodn\237ho cestuj\237c\237ho a[ENTER]dones Soonovi tu knihu. "
gameforge.subquest_37._230_npcChat = "Pos\237l\225 m\236 Soon... "
gameforge.subquest_37._240_say = "Hej, ty ses vr\225til, abys mi zase pomohl? Aha, ty[ENTER]chce\154 knihu pro Soona. \138el bych do m\236sta v[ENTER]nejbli\158\154\237 dob\236, ale on je hrozn\236 netrp\236liv\253 a[ENTER]\158\225d\225 ostatn\237, aby mu ji u\158 p\248inesli. Hmm. tady[ENTER]je. Nech\225pu, co Soon na t\236ch hromad\225ch pap\237ru[ENTER]vid\237. Daleko d\249le\158it\236j\154\237 je rychle vyd\236lat Yangy! "
gameforge.subquest_37._250_qSetTitle = "Zp\236t k Soonovi "
gameforge.subquest_37._260_targetVid = "Zp\236t k Soonovi "
gameforge.subquest_37._270_say = "Od obchodn\237ho cestuj\237c\237ho jsi z\237skal knihu pro[ENTER]Soona. Vra\157 se k Soonovi a dej mu tu knihu - pak[ENTER]ti prozrad\237, jak vyrobit Seladonsk\253 porcel\225n. "
gameforge.subquest_37._280_npcChat = "M\225m tu kn\237\158ku "
gameforge.subquest_37._290_say = "Hur\225! Kone\232n\236 m\225m tu novou knihu! D\237ky, d\237ky![ENTER]U\158 nezb\253v\225 moc knih, kter\233 bych nep\248e\232etl...[ENTER]Tady jsem sepsal, co je d\249le\158it\233 pro v\253robu[ENTER]Seladonsk\233ho porcel\225nu. Dr\158 se toho n\225vodu a[ENTER]vyrob\237\154 fantastick\253 porcel\225n. A te\239 promi\242, ale[ENTER]mus\237m si p\248e\232\237st tu knihu... "
gameforge.subquest_37._300_makequestbutton = "Zp\236t k Yonahovi "
gameforge.subquest_37._30_say = "Hmm... to nen\237 dobr\233. A ani tohle nen\237 ono...[ENTER]Ach, zdrav\237m! Pod\237vej: vyr\225b\237m porcel\225n bez[ENTER]p\248est\225vky, ale on se po\248\225d t\233m\236\248 okam\158it\236[ENTER]rozb\237j\237. Mysl\237m, \158e pot\248ebuji n\236jak\253 nov\253 druh[ENTER]porcel\225nu... "
gameforge.subquest_37._310_targetVid = "Dones pozn\225mky Yonahovi "
gameforge.subquest_37._320_say = "Soon dodr\158el slib a sepsal postup, jak vyrobit[ENTER]Seladonsk\253 porcel\225n. Dones pozn\225mky Yonahovi. "
gameforge.subquest_37._330_say = "Ach!!!![ENTER]Tady je naps\225no v\154e o v\253rob\236 Seladonsk\233ho[ENTER]porcel\225nu!!! D\237ky tomu se do historie zap\237\154i jako[ENTER]Mistr \248emesla! D\237ky za pomoc. Brzy ti budu[ENTER]schopen uk\225zat m\225 nejlep\154\237 keramick\225 d\237la! Na to[ENTER]se spolehni! Vyrob\237m tak skv\236l\253 Seladonsk\253[ENTER]porcel\225n, \158e vydr\158\237 cel\225 stolet\237! "
gameforge.subquest_37._340_sayReward = "Obdr\158\237\154 2 500 000 bod\249 zku\154enost\237. "
gameforge.subquest_37._350_sayReward = "Obdr\158\237\154 35 000 Yang\249. "
gameforge.subquest_37._360_sayReward = "Obdr\158\237\154 nefritov\233 boty+3 "
gameforge.subquest_37._40_say = "Vyzkou\154\237m jednu novou metodu... V\253roba[ENTER]Seladonsk\233ho porcel\225nu je velmi obt\237\158n\225, proto to[ENTER]um\237 jenom velmi m\225lo lid\237. Ale j\225 to budu[ENTER]pot\248ebovat pro moje um\236leck\225 d\237la![ENTER]V tomhle p\248\237pad\236... ano, u\232enec Uriel by to mohl[ENTER]v\236d\236t![ENTER]B\236\158 k u\232enci Urielovi a zeptej se ho na v\253robu[ENTER]Seladonsk\233ho porcel\225nu, ur\232it\236 ti porad\237! "
gameforge.subquest_37._50_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_37._60_say = "Hm, ty m\225\154 asi hodn\236 pr\225ce? Nezapome\242 se zase[ENTER]stavit a\158 bude\154 m\237t trochu \232asu. "
gameforge.subquest_37._70_say = "Chci vyr\225b\236t nejlep\154\237 porcel\225n.[ENTER]Ch\225pu... \142ij blaze... "
gameforge.subquest_37._80_say = "D\237ky. Uriel bude v\236d\236t, co d\236lat. M\236j se. "
gameforge.subquest_37._90_targetVid = "Poj\239me za Urielem "
