gameforge.subquest_38._100_say = "Byl mu ukraden kr\225sn\236 vy\248ez\225van\253 luk, kter\253 byl[ENTER]rodinn\253m d\236dictv\237m. Jdi do t\236\158k\233 opi\232\237 jeskyn\236 a[ENTER]p\248ines jej zp\236t od opic, kter\233 jej ukradly. "
gameforge.subquest_38._10_targetVid = "Myslivc\249v poklad "
gameforge.subquest_38._110_sendLetter = "Najdi kr\225sn\236 vy\248ez\225van\253 luk "
gameforge.subquest_38._120_targetVid = "Jdi za lovcem Yang-Shinem "
gameforge.subquest_38._125_say = "Na\154el jsi lovc\249v kr\225sn\236 vy\248ez\225van\253 luk. Dones jej[ENTER]zp\236t Yang-Shinovi. "
gameforge.subquest_38._130_npcChat = "Tady je ten luk... "
gameforge.subquest_38._140_say = "Ano, to je on! M\249j luk, jaj! M\225 \232est byla[ENTER]obnovena. Od t\233 doby, co jsem o n\236j p\248i\154el, jsem[ENTER]trp\236l... Jsem ti opravdu vd\236\232n\253 za tvou pomoc. Je[ENTER]pro mne \232est, \158e ti mohu d\225t toto. Nemus\237 to[ENTER]vypadat z\225zra\232n\236, ale je to od srdce, tak to[ENTER]p\248ijmi. D\236kuji ti, nyn\237 mohu \158\237t v m\237ru! "
gameforge.subquest_38._150_sayReward = "Obdr\158\237\154 1 500 000 bod\249 zku\154enost\237. "
gameforge.subquest_38._160_sayReward = "Obdr\158\237\154 35 000 Yang\249. "
gameforge.subquest_38._170_sayReward = "Obdr\158\237\154 Pl\225\154\157 state\232nosti. "
gameforge.subquest_38._180_say = "Na\154el jsi m\249j luk? Ale kde tedy je? To jsi ho[ENTER]zase ztratil? "
gameforge.subquest_38._190_select = "Budu pokra\232ovat. "
gameforge.subquest_38._200_say = "No tak jo.[ENTER]Opatruj se. "
gameforge.subquest_38._20_say = "Halo, mohl bys mne na chvilku poslouchat? Jak[ENTER]m\249\158e\154 vid\236t, jsem lovec a m\225 rodina jsou lovci[ENTER]cel\233 generace. Je to velk\225 \232est b\253t lovcem. Ale[ENTER]j\225 jsem ud\236lal velkou chybu, kter\225 m\236 po\154pin\237 v[ENTER]o\232\237ch cel\233 rodiny... "
gameforge.subquest_38._210_say = "Mohl bys to je\154t\236 zkusit? D\236kuji.[ENTER]S tv\253mi schopnostmi by to pro tebe m\236la b\253t[ENTER]hra\232ka. "
gameforge.subquest_38._30_say = "T\253k\225 se to kr\225sn\236 vy\248ez\225van\233ho luku, kter\253 byl[ENTER]kdysi d\225vno ukraden opicemi. Lovil jsem v opi\232\237ch[ENTER]jeskyn\237ch a na chvilku jsem nebyl pozorn\253 - a[ENTER]opice toho vyu\158ily a ukradly mi ten luk. "
gameforge.subquest_38._40_say = "Nikdy jsem nebyl tak hluboko v jeskyn\237ch Sangsun[ENTER]Dong, tak\158e tam nezn\225m cestu a pot\248ebuji tvoji[ENTER]pomoc. P\225r m\237stn\237ch mi \248eklo, \158e m\225\154 talent,[ENTER]proto t\236 \158\225d\225m o laskavost. Nemohu se m\253m p\248edk\249m[ENTER]bez kr\225sn\236 vy\248ez\225van\233ho luku pod\237vat do o\232\237. "
gameforge.subquest_38._50_sayTitle = "Yang-Shin: "
gameforge.subquest_38._60_say = "Hm, mus\237m ho m\237t rychle zp\225tky...[ENTER]Pros\237m p\248ijd' znovu a\158 bude\154 m\237t \232as.[ENTER]\142ij blaze. "
gameforge.subquest_38._70_say = "No, pak tedy...[ENTER]Opatruj se na cest\225ch. "
gameforge.subquest_38._80_say = "D\225 se lehce naj\237t, proto\158e to je opravdu kr\225sn\236[ENTER]vy\248ez\225van\253 luk! Dob\248e se ti za to odm\236n\237m! "
gameforge.subquest_38._90_sayTitle = "Hledej kr\225sn\236 vy\158ez\225van\253 luk "
