gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Ach, to jsi ty, jak se m\225\154? L\233\232\237\154 nemocn\233ho[ENTER]pacienta? \216ekni mi, co ho tr\225p\237...Hmm... A jak\253[ENTER]l\233k bere? Co\158e?! \142\225dn\253 div, \158e se c\237t\237 h\249\248e! Ten[ENTER]l\233k je \250pln\236 k ni\232emu! "
gameforge.subquest_39._180_say = "M\225 \154t\236st\237, \158e je po\248\225d na\158ivu. Je dost obt\237\158n\233[ENTER]naj\237t pro nemocn\233ho ten spr\225vn\253 l\233k. Ale j\225 v\237m,[ENTER]co mu pom\249\158e. Existuje bylina, kter\225 zbav\237 t\236lo[ENTER]jedu a obnov\237 zdrav\237. Bohu\158el, jej\237 hled\225n\237 je[ENTER]velmi nebezpe\232n\233. "
