gameforge.subquest_39._30_say = "D\237ky, \158e jsi mi minule p\248inesl ten l\233k. Ale je tu[ENTER]probl\233m... L\233k ztratil sv\249j \250\232inek. Mysl\237m, \158e se[ENTER]to zhor\154uje.[ENTER]*Kejch* Nutn\236 pot\248ebuji nov\253 l\233k. "
