gameforge.subquest_39._340_say = "Vypad\225 to, jako kdyby se ta nemoc mohla rozr\249st v[ENTER]epidemii, ale my zat\237m nezn\225me p\248\237\232inu. Ale v\236dci[ENTER]n\225m \248ekli, \158e l\233k m\249\158e b\253t vyroben z byliny[ENTER]Opi\232\237ho kr\225le. Co se d\236je? Na\154el jsi ji\158 tu[ENTER]bylinu? "
