gameforge.subquest_39._370_say = "Opravdu to chce\154 vzd\225t? Hmm, p\248edpokl\225d\225m, \158e t\236[ENTER]nemohu asi p\248esv\236d\232it co? Tak co m\225m d\236lat? Ta[ENTER]bylina by byla opravdov\233 po\158ehn\225n\237... "
