gameforge.subquest_39._40_say = "V\237m, \158e v nejbli\158\154\237m m\236st\236 \158ije jeden doktor.[ENTER]Mohl bys k n\236mu doj\237t a objasnit mu m\249j stav, aby[ENTER]ti \248ekl, jak mi lze pomoct?[ENTER]Jak vid\237\154, nem\249\158u v m\233m stavu opustit m\236sto. Jsem[ENTER]ti velmi vd\236\232n\253, u\158 posledn\236 jsi mi pomohl a i[ENTER]tentokr\225t se ti odm\236n\237m. "
gameforge.subquest_39._410_say = "Odm\237tl jsi pomoci lidem, trp\237c\237m nezn\225mou[ENTER]chorobou. Ztra\157 se mi z o\232\237! "
gameforge.subquest_39._420_say = "M\225\154 pravdu. N\236kdo mus\237 tu bylinu p\248in\233st, nebo[ENTER]nemocn\237 lid\233 budou velmi trp\236t. Postar\225m se o to. "
gameforge.subquest_39._430_say = "Dobr\225. Tak ut\237kej! "
gameforge.subquest_39._440_say = "Ty jsi z\237skal bylinu Opi\232\237ho kr\225le! Douf\225m, \158e[ENTER]skute\232n\236 m\249\158e vyl\233\232it tu z\225hadnou nemoc.[ENTER]Chvilinku po\232kej, p\248iprav\237m l\233k... "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Tady je ten l\233k. Ut\237kej za pacientem a dej mu to.[ENTER]M\236l by se pak c\237tit l\233pe. A tak\233 mu \248ekni, \158e je[ENTER]v\158dy lep\154\237 se zeptat doktora, kter\253 l\233k je ten[ENTER]prav\253. "
