gameforge.subquest_44._40_say = "V\237m, \158e bych m\236la v\236\248it p\248\237teli, ale j\225 chci[ENTER]v\236d\236t, jestli to opravdu ud\236lal. Je to ale pro m\236[ENTER]v pou\154ti moc nebezpe\232n\233. Ov\154em ty vypad\225\154 siln\236.[ENTER]Mohl bys to snadno ud\236lat. P\249jde\154 a koukne\154 se za[ENTER]m\236? "
gameforge.subquest_44._410_say = "Bylo to hodn\236 obt\237\158n\233, ale kone\232n\236 jsi dok\225zal[ENTER]zav\236sit zvonek na pavou\232ka. Nyn\237 jdi za Yu-Rang a[ENTER]\248ekni j\237, \158e to ud\236lal Taurean. "
