gameforge.subquest_44._430_say = "Ty jsi to ud\236lal? To je fantastick\233! Tak to[ENTER]pros\237m rychle \248ekni Yu-Rang, aby mi u\158 kone\232n\236[ENTER]uv\236\248ila. "
gameforge.subquest_44._440_npcChat = "Taurean \248\237kal pravdu. "
gameforge.subquest_44._450_say = "Jde\154 zase? Na\154el jsi pavouka se zvonkem? Tak to[ENTER]Taurean opravdu ud\236lal. Nemyslela bych si, \158e to[ENTER]dok\225\158e. Mo\158n\225 bude jednoho dne opravdov\253 mu\158.[ENTER]D\237ky za tvoji pomoc a zde je tv\225 odm\236na. "
