gameforge.subquest_44._500_say = "Mockr\225t d\237ky. Nyn\237 si ze m\236 Yu-Rang u\158 nebude[ENTER]utahovat. Ale mus\237me to dr\158et v tajnost - nav\158dy.[ENTER]Slibuje\154? Tak zat\237m.... "
