gameforge.subquest_44._80_say = "Hmmmm, ty se boj\237\154?[ENTER]Ale jsi mnohem v\236t\154\237 a siln\236j\154\237 ne\158 j\225![ENTER]Haha, jsi zbab\236lec. A j\225 se budu muset zeptat[ENTER]n\236koho jin\233ho. "
