gameforge.subquest_45._110_say = "M\225\154 nauku o chr\225mu, chr\225mov\253 \154\225l a p\248eklad Knihy[ENTER]klateb.[ENTER]Dones to Soonovi. "
gameforge.subquest_45._120_say = "Pokud pom\249\158e\154 knihomolovi Soonovi, pak bude moci[ENTER]pokra\232ovat ve sv\253ch v\253zkumech ohledn\236 Temn\233ho[ENTER]chr\225mu. Ov\154em on m\249\158e pokra\232ovat jen pokud bude[ENTER]m\237t n\225sleduj\237c\237 v\236ci: nauku o chr\225mu, chr\225mov\253[ENTER]\154\225l a p\248eklad knihy klateb. Z\237skej v\154e a pak to[ENTER]dones Soonovi. Najde\154 je v chr\225mu Hwang, kter\253 je[ENTER]v \250dol\237 Seungryong. "
gameforge.subquest_45._130_npcChat = "V\236ci z Temn\233ho chr\225mu "
gameforge.subquest_45._140_say = "Ach, tys je z\237skal! Mnohokr\225t ti d\236kuji. A co se[ENTER]t\253\232e t\236ch tajemn\253ch lid\237 v chr\225mu, je to[ENTER]jednoduch\233 - jsou nebezpe\232n\237. A ty jsi to ji\158[ENTER]ur\232it\236 zjistil. A tak\233 to vypad\225, \158e slou\158\237 zl\233mu[ENTER]bohu. Zat\237m nev\237m \158\225dn\233 podrobnosti, ale mysl\237m,[ENTER]\158e pl\225nuj\237 n\236co velmi \154patn\233ho. "
gameforge.subquest_45._150_say = "Nyn\237, kdy\158 m\225m n\236kter\233 z jejich svat\253ch v\236c\237[ENTER]douf\225m, \158e zjist\237m v\237ce. Nejlep\154\237 bude za\232\237t s[ENTER]naukou o chr\225mu.[ENTER]Pod\237vejme... Hm... Aha...[ENTER]Pro\232 se tu po\248\225d poflakuje\154? Nem\225\154 nic lep\154\237ho na[ENTER]pr\225ci? "
