gameforge.subquest_45._170_sayReward = "Obdr\158\237\154 70 000 Yang\249. "
gameforge.subquest_45._180_sayReward = "Obdr\158\237\154 Knihu n\225\232eln\237ka. "
gameforge.subquest_45._190_say = "Ty je nem\225\154?[ENTER]Nepoflakuj se kolem, kdy\158 p\248ijme\154 \250kol![ENTER]Tak d\236lej, pohyb! B\236\158! "
gameforge.subquest_45._200_select = "Zkusit znovu "
gameforge.subquest_45._20_say = "V Temn\233m chr\225mu se n\236co d\236je. Mysl\237m si, \158e jsou[ENTER]tam nebezpe\232n\233 bytosti, studuj\237c\237 starov\236k\225[ENTER]kouzla. Tajemstv\237 Temn\233ho chr\225mu jsou t\236\158ko[ENTER]pochopiteln\225, a to dokonce i pro mne. Ale jsem si[ENTER]jist, \158e z\225m\236ry t\236chto lid\237 nejsou \232ist\233. Mus\237m o[ENTER]tom zjistit v\237ce! "
