gameforge.subquest_48._200_say = "Skv\236l\233! Grilovan\253 perl\237n! Ten \154pi\243n asi opravdu[ENTER]n\236co o ryba\248en\237 v\237. "
gameforge.subquest_48._20_say = "Pohov voj\225ku![ENTER]Proto\158e jsou v\154echny sousedn\237 vesnice[ENTER]nep\248\225telsk\233, je d\249le\158it\233 m\237t tam p\248\225tele, kte\248\237[ENTER]n\225m pom\225haj\237 z\237sk\225vat informace, tak\158e m\249\158eme b\253t[ENTER]p\248ipraveni na p\248\237padn\253 \250tok. Je velmi d\249le\158it\233,[ENTER]aby tito \154pi\243ni nebyli nikdy odhaleni. "
gameforge.subquest_48._210_sayReward = "Obdr\158\237\154 t\248i grilovan\233 perl\237ny ostrob\248ich\233. "
gameforge.subquest_48._220_sendLetter = "Zp\225tky k veliteli. "
gameforge.subquest_48._230_targetVid = "Velitel "
gameforge.subquest_48._240_say = "Nebezpe\232n\225 cesta do vesnice Pyungmoo v kr\225lovstv\237[ENTER]Jinno byla \250sp\236\154n\225: obdr\158el jsi zpr\225vu od \154pi\243na,[ENTER]kter\253 se tam maskuje za ryb\225\248e. Nyn\237 se vra\157 do[ENTER]tv\233ho kr\225lovstv\237 a rychle dones ty informace[ENTER]veliteli. "
gameforge.subquest_48._250_say = "Nebezpe\232n\225 cesta do vesnice Yongan v kr\225lovstv\237[ENTER]Shinsoo byla \250sp\236\154n\225: obdr\158el jsi zpr\225vu od[ENTER]\154pi\243na, kter\253 se tam maskuje za ryb\225\248e. Nyn\237 se[ENTER]vra\157 do tv\233ho kr\225lovstv\237 a rychle dones ty[ENTER]informace veliteli. "
gameforge.subquest_48._260_say = "Nebezpe\232n\225 cesta do vesnice Joan v kr\225lovstv\237[ENTER]Chunjo byla \250sp\236\154n\225: obdr\158el jsi zpr\225vu od[ENTER]\154pi\243na, kter\253 se tam maskuje za ryb\225\248e. Nyn\237 se[ENTER]vra\157 do tv\233ho kr\225lovstv\237 a rychle dones ty[ENTER]informace veliteli. "
gameforge.subquest_48._270_npcChat = "Mise byla \250sp\236\154n\225! "
gameforge.subquest_48._280_say = "To jsou ty dokumenty? Skv\236l\233! D\237ky. Nyn\237, kdy\158[ENTER]zn\225me pl\225ny nep\248\225tel, m\249\158eme se dob\248e p\248ipravit[ENTER]na obranu. Prok\225zal jsi kr\225lovstv\237 dobrou slu\158bu! "
gameforge.subquest_48._290_sayReward = "Obdr\158\237\154 5 500 000 bod\249 zku\154enost\237. "
gameforge.subquest_48._300_sayReward = "Obdr\158el jsi 50,000 Yang\249. "
gameforge.subquest_48._30_say = "Ur\232it\236 zn\225\154 hudebn\237ka Yu-Hwana, \158e? On je ale[ENTER]tak\233 \154pion, pracuj\237c\237 pro n\225s. Jeden \154pi\243n s\225m o[ENTER]sob\236 nic neznamen\225, tak\158e jich m\225me mnohem v\237ce[ENTER]ve v\154ech kr\225lovstv\237ch. Jeden z nich je v prvn\237[ENTER]vesnici maskovan\253 jako ryb\225\248. "
gameforge.subquest_48._40_say = "Proto\158e se s n\237m nem\249\158u spojit, ani\158 bych ho[ENTER]neprozradil, pot\248ebuji pomoc n\236jak\233ho neboj\225cn\233ho[ENTER]voj\225ka. Ano, mysl\237m tebe! Mohl bys pros\237m t\236[ENTER]naj\237t toho ryb\225\248e a p\248iv\233zt mi od n\236j zpr\225vu? Je[ENTER]to opravdu \158ivotn\236 d\249le\158it\233 pro na\154e kr\225lovstv\237. "
gameforge.subquest_48._50_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_48._60_say = "Ty se pot\248ebuje\154 nejprve p\248ipravit? Fajn, ale[ENTER]vra\157 se. Budu na tebe \232ekat. A neloudej se, tu[ENTER]zpr\225vu pot\248ebuji rychle! "
gameforge.subquest_48._70_say = "Co s tebou je? Naposledy jsi pro n\225s ud\236lal[ENTER]skv\236lou pr\225ci A te\239 chce\154 svou zemi opustit?[ENTER]No, nemohu nic d\236lat. Sbohem. "
gameforge.subquest_48._80_say = "V\236d\236l jsem, \158e je na tebe spolehnut\237. Hodn\236[ENTER]\154t\236st\237 a bu\239 opatrn\253! "
gameforge.subquest_48._90_makequestbutton = "Setkat se se \154pi\243nem "
gameforge.subquest_49 = {}
gameforge.subquest_49._100_sayTitle = "Co je to bingsu? "
gameforge.subquest_49._10_targetVid = "Bingsu? "
gameforge.subquest_49._110_say = "Taurean se poh\225dal s Harang, proto\158e nev\236\248\237, \158e[ENTER]je mo\158n\233 vyrobit zmrzlinu v l\233t\236. Zajdi za Harang[ENTER]a zeptej se j\237, co v\237 o Bingsu. "
gameforge.subquest_49._120_qSetTitle = "Zeptej se Harang "
gameforge.subquest_49._130_targetVid = "Zeptej se Harang "
gameforge.subquest_49._140_npcChat = "Co je to bingsu? "
gameforge.subquest_49._150_say = "Ten Taurean si mysl\237, \158e zn\225 v\154echno. A p\248itom[ENTER]nezn\225 Bingsu! Jak m\249\158e nev\236d\236t o n\236\232em tak[ENTER]delik\225tn\237m?[ENTER]Ty taky nev\237\154 co je Bingsu? No, nejl\237p bude, kdy\158[ENTER]zajde\154 za Octaviem do sousedn\237 vesnice. Je to[ENTER]vyhl\225\154en\253 kucha\248 a zn\225 spoustu recept\249 Jednou mi[ENTER]Bingsu ud\236lal.... m\242am! Dok\225\158e ti, \158e m\225m pravdu! "
gameforge.subquest_49._160_makequestbutton = "Poj\239me za Octaviem "
gameforge.subquest_49._170_say = "Taurean chce opravdu v\236d\236t, co je Bingsu. Zajdi[ENTER]za majitelem restaurace Octaviem. Jsem si jist,[ENTER]\158e ti pom\249\158e. "
gameforge.subquest_49._180_npcChat = "V\237\154 co je Bingsu? "
gameforge.subquest_49._190_say = "Bingsu? Samoz\248ejm\236 to v\237m. Ka\158d\253 dobr\253 kucha\248 v\237,[ENTER]jak p\248ipravit Bingsu. Nejprve pot\248ebuje\154 p\225r hrud[ENTER]ledu. Pak p\248id\225\154 cukr, jemn\236 nakr\225jen\233 r\253\158ov\233[ENTER]kol\225\232ky a nakonec \232erstv\233 ovoce na ozdobu. "
gameforge.subquest_49._200_say = "A pro\232 se pt\225\154? Proto\158e se Harang a Taurean[ENTER]h\225daj\237? To nen\237 nic nov\233ho. Ale Harang m\225[ENTER]tentokr\225t pravdu. Bingsu je obzvl\225\154t\236 obl\237ben\253[ENTER]pokrm v hork\253ch letn\237ch dnech. Tauren je slu\154n\253[ENTER]kluk, i kdy\158 ob\232as trochu zlobiv\253. Pokud mi[ENTER]p\248inese\154 p\248\237sady, tak mu Bingsu ud\236l\225m. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Cht\236l bych ud\236lat Taureanovi radost a p\248ipravit[ENTER]mu Bingsu. Co mysl\237\154, m\249\158e\154 mi p\248in\233st led z hory[ENTER]Sohan? "
gameforge.subquest_49._220_say = "Opravdu chce\154 tento \250kol vzd\225t? "
gameforge.subquest_49._230_say = "Ty nem\225\154 r\225d zmrzlinu? Anebo si j\237 pr\225v\236 sn\236dl[ENTER]p\248\237li\154 mnoho? Je to pro Taureana, tak se nad t\237m[ENTER]je\154t\236 jednou zamysli. "
gameforge.subquest_49._240_say = "\138koda. Taurean bude velmi zklam\225n. Sbohem. "
gameforge.subquest_49._250_say = "Prima. Pot\248ebuji hroudy ledu ze za\232arovan\233ho[ENTER]ledovi\154t\236 na ho\248e Sohan. P\248ines mi 50 hrud ledu.[ENTER]Pak mohu ud\236lat n\236jak\233 chutn\233 Bingsu. "
gameforge.subquest_49._260_targetVid = "J\237t k Octaviovi "
gameforge.subquest_49._270_say = "%s[ENTER]M\225\154 dostatek hrud ledu pro Taureanovo Bingsu.[ENTER]Dones je Octaviovi. "
gameforge.subquest_49._275_say = "M\225m hroudu ledu "
gameforge.subquest_49._280_say = "Octavio souhlasil, \158e ud\236l\225 Bingsu pro Taurean,[ENTER]ale pot\248ebuje na to led. Zab\237jej za\232arovan\225[ENTER]ledovi\154t\236 na Ho\248e Sohan a nasb\237rej 50 hrud ledu.[ENTER]Pak je dones Octaviovi. "
gameforge.subquest_49._285_say = "Hled\225n\237 ledu "
gameforge.subquest_49._290_npcChat = "Tady, p\248inesl jsem ty hroudy ledu. "
gameforge.subquest_49._300_say = "Ano, v\253born\236! Ta nejt\236\158\154\237 \232\225st v\253roby Bingsu je[ENTER]spln\236na. Nyn\237 jen p\248id\225m trochu cukru... n\236jak\233[ENTER]ovoce... a tady to je! Zmrzlina pro Taureana.[ENTER]Dones mu ji aby zapom\236l na sv\249j vztek. "
gameforge.subquest_49._30_sayTitle = "Taurean: "
gameforge.subquest_49._310_say = "Promi\242, ale to nesta\232\237. Mus\237\154 mi p\248in\233st v\237ce,[ENTER]jinak to bude jen mal\225 porce! "
gameforge.subquest_49._320_select = "Ano. Zkusit znovu. "
gameforge.subquest_49._330_say = "V\237m \158e je to dlouh\225 cesta a p\248\237\154ery jsou siln\233.[ENTER]Pokud je to pro tebe moc t\236\158k\233, tak s t\237m ale[ENTER]nemohu nic d\236lat. M\236j se. "
gameforge.subquest_49._340_say = "Zkus to znovu! S tvoj\237 odvahou a \250sil\237m to jist\236[ENTER]dok\225\158e\154! "
gameforge.subquest_49._350_targetVid = "Bingsu? "
gameforge.subquest_49._360_say = "Je to hotovo: Octavio ud\236lal Bingsu z ledu z hory[ENTER]Sohan. Rychle dones Bingsu Taureanovi, ne\158 se[ENTER]rozte\232e. "
gameforge.subquest_49._370_npcChat = "Pros\237m! Bingsu! "
gameforge.subquest_49._380_say = "To je Bingsu? To chutn\225 opravdu skv\236le. P\248\237jemn\236[ENTER]osv\236\158uj\237c\237. Nikdy jsem nic takov\233ho je\154t\236 nejedl,[ENTER]d\237ky moc! Tak\158e Harang m\236la pravdu. V\237m \158e se j\237[ENTER]budu muset omluvit... "
gameforge.subquest_49._390_sayReward = "Obdr\158\237\154 6.000.000 bod\249 zku\154enost\237. "
gameforge.subquest_49._400_sayReward = "Obdr\158\237\154 70 000 Yang\249. "
gameforge.subquest_49._40_say = "Dneska jsem se poh\225dal s Harang. J\225... Ona tvrd\237,[ENTER]\158e existuje n\236co, co je moc dobr\233 a je to ud\236l\225no[ENTER]z ledu. Jmenuje se to Bingsu. "
gameforge.subquest_49._410_sayReward = "Obdr\158\237\154 Pergamen v\225lky. "
gameforge.subquest_49._420_say = "Jednou bingsu pro m\236, myslel\180s na to? "
gameforge.subquest_49._430_say = "Bo\158e, j\225 na to \250pln\236 zapom\236l! Hmm, m\225m se d\225l[ENTER]pokou\154et anebo to rad\236ji nechat b\253t? "
gameforge.subquest_49._440_select = "Ano, budu pokra\232ovat. "
gameforge.subquest_49._450_select = "Vzd\225v\225m to. "
gameforge.subquest_49._460_say = "Nezvl\225dnu to.[ENTER]Lituji. "
gameforge.subquest_49._50_say = "N\236co takov\233ho je mo\158n\233 jen v zim\236, kdy\158 je[ENTER]opravdu chladno. Ale ona po\248\225d tvrd\237, \158e je to[ENTER]mo\158n\233 i v l\233t\236. M\249\158e\154 pros\237mt\236 zjistit, jestli je[ENTER]mo\158n\233 Bingsu vyrobit i v l\233t\236? Teda pokud ta v\236c[ENTER]v\249bec existuje... "
gameforge.subquest_49._60_say = "Jsem si jist, \158e Bingsu je pochoutka! Opravdu si[ENTER]to nerozmysl\237\154 a nepom\249\158e\154 mi? "
gameforge.subquest_49._70_say = "Jestli se do toho chce\154 pustit pozd\236ji, \248ekni mi[ENTER]to, pros\237m. "
gameforge.subquest_49._80_say = "Opravdu bych r\225d zkusil Bingsu...[ENTER]Ale m\225\154 pravdu. Harang se pravd\236podobn\236 jen[ENTER]cht\236la vytahovat a Bingsu v\249bec neexistuje.[ENTER]Sbohem... "
gameforge.subquest_49._90_say = "D\237ky za tvou pomoc. Dej mi v\236d\236t, pokud n\236co[ENTER]zjist\237\154. Pak budu moci t\233 Harang uk\225zat! "
