gameforge.training_mount = {}
gameforge.training_mount._01_say = "Je mi l\237to, ale nem\225\154 dostate\232nou zku\154enost, abys[ENTER]vylep\154il sv\233 jezdeck\233 zv\237\248e. Mus\237\154 m\237t alespo\242[ENTER]licenci na opanc\233\248ovan\233ho kon\236. "
gameforge.training_mount._02_say = "Promi\242, ale bez odpov\237daj\237c\237ch dokument\249 nen\237[ENTER]nic, co bych pro tebe mohl ud\236lat. A u\158 mne[ENTER]nezkou\154ej znovu podv\233st, nebo za to bude\154 pykat. "
gameforge.training_mount._03_say = "Kde je tvoje Pe\232e\157 jezdeck\233ho zv\237\248ete? Nemohu[ENTER]\158\225dn\233 jezdeck\233 zv\237\248e vylep\154it bez t\233to pe\232et\236.[ENTER]Koukni se pod to\232\237c\237 se minci. M\249\158e\154 tam naj\237t[ENTER]certifik\225t, kter\253 lze vym\236nit za Pe\232e\157 jezdeck\233ho[ENTER]zv\237\248ete. "
gameforge.training_mount._04_say = "Chci nov\233 jezdeck\233 zv\237\248e! "
gameforge.training_mount._05_say = "Hej! Ty po\248\225d jezd\237\154 na koni? Opravdu? A v\237\154 o[ENTER]tom, \158e si um\237me ji\158 ocho\232it divok\225 zv\237\248ata, \158e? "
gameforge.training_mount._06_say = "Abys mohl tr\233novat divok\225 zv\237\248ata pro bitvy,[ENTER]mus\237\154 b\253t opravdu zku\154en\253 v j\237zd\236 na nich. A[ENTER]krom\236 toho bude\154 tak\233 pot\248ebovat n\225sleduj\237c\237[ENTER]v\236ci: Svitek v\253voje pro vylep\154en\237 jezdeck\233ho[ENTER]zv\237\248ete na divok\233 jezdeck\233 zv\237\248e a Svitek p\248em\236ny[ENTER]na to, abys z n\236j ud\236lal jezdeck\233 zv\237\248e odv\225\158n\233. "
gameforge.training_mount._07_say = "Pokud bude\154 m\237t n\236jak\233 ot\225zky, m\249\158e\154 za mnou[ENTER]kdykoliv p\248ij\237t. Pomohu ti jak jen budu moci. "
gameforge.training_mount._08_say = "Chci vylep\154it sv\233 jezdeck\233 zv\237\248e! "
gameforge.training_mount._09_say = "Tak\158e ty chce\154 vylep\154it sv\233 jezdeck\233 zv\237\248e? A[ENTER]v\237\154, jak to funguje? Vysv\236tl\237m ti to. "
gameforge.training_mount._10_say = "Abys vylep\154il sv\233 jezdeck\233 zv\237\248e na divok\233[ENTER]jezdeck\233 zv\237\248e bude\154 muset z\237skat Svitek v\253voje.[ENTER]A mus\237\154 naj\237t Svitek p\248em\236ny, abys mohl[ENTER]vytr\233novat divok\233 jezdeck\233 zv\237\248e na odv\225\158n\233[ENTER]jezdeck\233 zv\237\248e. \216\237k\225 se, \158e je lze naj\237t v dalek\233[ENTER]zemi, kter\225 je pln\225 nebezpe\232n\253ch tvor\249! "
gameforge.training_mount._11_say = "P\248ines mi tyto svitky a j\225 ti vylep\154\237m jezdeck\233[ENTER]zv\237\248e. St\225le jej je\154t\236 nem\225\154 vylep\154en\233, \158e ne? "
gameforge.training_mount._12_say = "Ano, chci vylep\154it sv\233 zv\237\248e! "
gameforge.training_mount._13_say = "Ne, te\239 ne. "
gameforge.training_mount._14_say = "Ach, ty m\225\154 jeden svitek u sebe! A kter\253 to je?[ENTER]Svitek v\253voje ti umo\158n\237 vytr\233novat mlad\233 divok\233[ENTER]zv\237\248e pro bitvy. Svitek p\248em\236ny ti pom\249\158e jej[ENTER]vytr\233novat v Odv\225\158n\233 jezdeck\233 zv\237\248e. "
gameforge.training_mount._15_2_say = "M\225m Svitek p\248em\236ny. "
gameforge.training_mount._15_say = "M\225m Svitek v\253voje. "
gameforge.training_mount._16_say = "Nem\225m u sebe \158\225dn\253 svitek. "
gameforge.training_mount._17_say = "No jo, pod\237vejme se - Svitek v\253voje! Tak se[ENTER]pod\237v\225me na tvou Pe\232e\157 jezdeck\233ho zv\237\248ete.[ENTER]N\236kte\248\237 lid\233 se pokou\154\237, abych p\248ijal n\236jak\233[ENTER]n\225hra\158ky! Tak\158e si ji nejprve ov\236\248\237m. Polo\158 ji[ENTER]tady. (P\248et\225hni pe\232e\157 na pacholka). "
gameforge.training_mount._18_say = "Svitek p\248em\236ny! Dosud jsem o n\236m sly\154el jen[ENTER]pov\236sti! Nikdy jsem \158\225dn\253 skute\232n\236 nevid\236l. Uka\158[ENTER]mi tvou Pe\232e\157 jezdeck\233ho zv\237\248ete. Jakmile si ji[ENTER]ov\236\248\237m, tak ti ji vym\236n\237m za lep\154\237. (P\248et\225hni[ENTER]pe\232e\157 na pacholka). "
gameforge.training_mount._19_say = "Jakmile n\236jak\253 svitek najde\154, vra\157 se ke m\236. Budu[ENTER]ti pak schopen vym\236nit tvoj\237 st\225vaj\237c\237 Jezdeckou[ENTER]pe\232e\157 za mnohem lep\154\237. "
gameforge.training_mount._20_say = "Tvoje Jezdeck\225 pe\232e\157 u\158 pamatuje lep\154\237 dny.[ENTER]Po\232kej, vym\236n\237m ti ji za novou. Tady, ber. Nyn\237[ENTER]m\249\158e\154 p\248ivolat divok\233 jezdeck\233 zv\237\248e. Vra\157 se ke[ENTER]m\236, pokud najde\154 Svitek P\248em\236ny. D\237ky n\236mu ti[ENTER]budu moci d\225t je\154t\236 lep\154\237 Jezdeckou pe\232e\157. "
gameforge.training_mount._21_say = "Tohle je Jezdeck\225 pe\232e\157, kterou jsi ode mne kdysi[ENTER]dostal. No, je p\236kn\236 obno\154en\225. Dej mi ji a j\225 ti[ENTER]vytvo\248\237m je\154t\236 siln\236j\154\237! "
gameforge.training_mount._22_say = "Tato pe\232e\157 ti umo\158n\237 p\248ivolat tv\233 p\248em\236n\236n\233[ENTER]zv\237\248e. Jeho hodnota se ned\225 ani vy\232\237slit, tak se[ENTER]o n\236j dob\248e starej! "
gameforge.training_mount._23_say = "Mohu pou\158\237t jezdeck\233 schopnosti? "
gameforge.training_mount._24_say = "Ty chce\154 pou\158\237vat jezdeck\233 schopnosti? To je tedy[ENTER]p\236kn\236 vyd\236ra\232sk\233! I kdy\158 - j\225 o nich tak\233 sn\237m...[ENTER]No dob\248e. Aby ses je mohl nau\232it, mus\237\154 zn\225t p\225r[ENTER]pravidel. "
gameforge.training_mount._25_say = "Prvn\237 a nejd\249le\158it\236j\154\237 - mus\237\154 b\253t mistr v j\237zd\236[ENTER]na zv\237\248eti, jinak se vystavuje\154 smrteln\233mu[ENTER]nebezpe\232\237. Nav\237c - tvoje zv\237\248e mus\237 b\253t[ENTER]p\248ipraveno do bitvy, proto\158e teprve pak je mo\158n\233[ENTER]vyu\158\237vat jezdeck\233 schopnosti. "
gameforge.training_mount._26_say = "Je tv\233 zv\237\248e p\248ipraveno se u\232it jezdeck\233[ENTER]schopnosti? Pokud ne, nemohu ti povolit jejich[ENTER]tr\233nink. Co bys cht\236l d\236lat? "
gameforge.training_mount._27_say = "Ch\225pu. J\225 te\239 posoud\237m tvou s\237lu a jezdeck\233[ENTER]um\236n\237. Po\232kej chvilku. "
gameforge.training_mount._28_say = "Hmmm... siln\225 p\225te\248, vynikaj\237c\237 jezdeck\233[ENTER]schopnosti a tv\233 zv\237\248e je extr\233mn\236 vytr\233nov\225no[ENTER]pro bitvy. M\249\158e\154 pou\158\237vat jezdeck\233 schopnosti. "
gameforge.training_mount._29_say = "Nyn\237 tv\233 jezdeck\233 zv\237\248e m\249\158e pou\158\237vat schopnosti.[ENTER]Samoz\248ejm\236 \158e pokud z\237sk\225\154 nov\233 zv\237\248e, bude se[ENTER]muset nejprve tyto schopnosti nau\232it. V tom[ENTER]p\248\237pad\236 za mnou zase zajdi. "
gameforge.training_mount._30_say = "Ale no tak, \248\237kal jsem ti, \158e je to moc[ENTER]nebezpe\232n\233, kdy\158 nejsi skv\236l\253 jezdec. Vra\157 se ke[ENTER]m\236, a\158 se zlep\154\237\154. "
gameforge.training_mount._31_say = "Ob\225v\225m se, \158e tv\233 zv\237\248e je\154t\236 nen\237 p\248ipraveno.[ENTER]Vra\157 se ke m\236, a\158 na n\236m bude vid\236t v\236t\154\237 touha[ENTER]vydat se do bitvy. "
gameforge.training_mount._32_say = "Mo\158n\225 by si ze sv\233ho zv\237\248ete mohl sl\233zt, kdy\158 se[ENTER]mnou mluv\237\154? M\225m bolav\253 krk a p\236kn\236 m\236 v n\236m[ENTER]t\225hne, kdy\158 se mus\237m koukat nahoru. "
gameforge.training_mount._33_say = "Pro vylep\154en\237 jezdeck\233ho zv\237\248ete nem\225\154[ENTER]odpov\237daj\237c\237 jezdeckou licenci. Mus\237\154 m\237t alespo\242[ENTER]vojensk\233ho kon\236, abys mohl tr\233novat divok\233 zv\237\248e.[ENTER]A pro zkrocen\237 odv\225\158n\233ho zv\237\248ete mus\237\154 m\237t[ENTER]licenci na opanc\233\248ovan\233ho kon\236. "
gameforge.training_mount._34_say = "Kouk\225m, \158e m\225\154 posiluj\237c\237 sva\232inku. tahle cenn\225[ENTER]l\233\232iv\225 bylina poskytne tv\233mu jezdeck\233mu zv\237\248eti[ENTER]\232istou energii - a prodlou\158\237 mu tak \158ivot o[ENTER]n\236kolik dn\249. Tak co chce\154, abych ud\236lal? M\225m[ENTER]prodlou\158it tv\233mu zv\237\248eti \158ivot nebo jej vylep\154it? "
