gameforge.training_mount._36_select_4 = "Svitek p\248em\236ny + 200 000 Yang\249 "
gameforge.training_mount._37_say = "Bohu\158el nem\225\154 posiluj\237c\237 sva\232inku, kterou je[ENTER]t\248eba pro zvolen\233 prodlou\158en\237 \158ivota. Ale jsem si[ENTER]jist, \158e ji najde\154 pod to\232\237c\237 se minc\237! "
gameforge.training_mount._38_say = "Svitek p\248em\236ny obsahuje velkou s\237lu! M\249\158e[ENTER]prodlou\158it \158ivot tv\233ho Odv\225\158n\233ho jezdeck\233ho[ENTER]zv\237\248ete a\158 o 4 dny. Pokus o prodlou\158en\237 t\236 bude[ENTER]st\225t 200 000 Yang\249. Tv\233 zv\237\248e mus\237 b\253t vy\232erp\225no[ENTER]a mus\237 mu zb\253vat m\233n\236 ne\158 1 den \158ivota.[ENTER]Samoz\248ejm\236, \158e budeme tak\233 pot\248ebovat trochu[ENTER]\154t\236st\237! Pokud prodlou\158en\237 sel\158e, doporu\232uji[ENTER]pou\158\237t posiluj\237c\237 sva\232inku. najde\154 ji pod to\232\237c\237[ENTER]se minc\237. "
gameforge.training_mount._39_say = "Tv\233 zv\237\248e m\225 st\225le p\248\237li\154 mnoho s\237ly. Svitek[ENTER]p\248em\236ny zde nebude m\237t \158\225dn\253 efekt. Vra\157 se, a\158[ENTER]bude m\237t zv\237\248e m\233n\236 ne\158 den \158ivota. "
gameforge.training_mount._40_say = "Bohu\158el ti nemohu pomoci. Bu\239 nem\225\154 Svitek[ENTER]p\248em\236ny nebo 200 000 Yang\249. "
